# 言語設定グローバル変数
_LANG = None  # 'ja' or 'en' (None = auto-detect)
_LOCALES = {}  # 翻訳辞書

def _detect_language():
    """
    OS の言語設定から自動検出
    
    優先順位:
    1. 環境変数 EVE_CLI_LANG (明示的な設定)
    2. LC_ALL, LC_MESSAGES, LANG
    3. locale.getdefaultlocale()
    4. デフォルト：en
    """
    import locale
    
    # 1. 環境変数で明示設定
    env_lang = os.environ.get('EVE_CLI_LANG')
    if env_lang:
        return 'ja' if env_lang.lower().startswith('ja') else 'en'
    
    # 2. 標準的な環境変数をチェック
    for var in ['LC_ALL', 'LC_MESSAGES', 'LANG']:
        lang = os.environ.get(var, '')
        if lang:
            if lang.startswith('ja') or 'JP' in lang:
                return 'ja'
            elif lang.startswith('en') or lang.startswith('C'):
                return 'en'
    
    # 3. locale モジュールで検出
    try:
        lang = locale.getdefaultlocale()[0] or ''
        if lang.startswith('ja'):
            return 'ja'
        return 'en'
    except Exception:
        return 'en'

def _load_locales(lang='ja'):
    """翻訳辞書を読み込み"""
    global _LOCALES
    if _LOCALES:
        return _LOCALES
    
    # locales ディレクトリのパスを特定
    script_dir = os.path.dirname(os.path.abspath(__file__))
    locales_dir = os.path.join(script_dir, 'locales')
    locale_file = os.path.join(locales_dir, f'{lang}.json')
    
    try:
        if os.path.exists(locale_file):
            with open(locale_file, 'r', encoding='utf-8') as f:
                _LOCALES = json.load(f)
        else:
            _LOCALES = {}
    except Exception:
        _LOCALES = {}
    
    return _LOCALES

def set_language(lang):
    """言語を設定（'ja' or 'en'）"""
    global _LANG
    _LANG = lang
    _LOCALES.clear()  # キャッシュクリア
    if lang == 'ja':
        _load_locales('ja')

def get_language():
    """現在の言語設定を取得"""
    global _LANG
    if _LANG is None:
        _LANG = _detect_language()
    return _LANG

def t(key, default=None, **kwargs):
    """
    翻訳キーからメッセージを取得
    
    例:
        t('errors.file_not_found', path='/tmp/test.txt')
        → "エラー：ファイルが見つかりません：/tmp/test.txt"
    """
    lang = get_language()
    if lang != 'ja':
        return default or key
    
    locales = _load_locales('ja')
    
    # キーをドットで分割してネストを辿る
    parts = key.split('.')
    value = locales
    for part in parts:
        if isinstance(value, dict) and part in value:
            value = value[part]
        else:
            return default or key
    
    # プレースホルダーを置換
    if isinstance(value, str) and kwargs:
        try:
            value = value.format(**kwargs)
        except KeyError:
            pass
    
    return value

