# ESC key interrupt monitor (Unix only)
# ════════════════════════════════════════════════════════════════════════════════

class InputMonitor:
    """Detect ESC key press for interrupt during agent execution.

    Unix-only: uses termios + tty.setcbreak for real-time key detection.
    On Windows (or when termios is unavailable), all methods are no-ops.

    Type-ahead capture is intentionally disabled. The cbreak + background-read
    approach interferes with IME composition and multi-line paste in terminals.
    The on_typeahead parameter is accepted only for backward compatibility.
    """

    def __init__(self, on_typeahead=None):
        self._pressed = threading.Event()
        self._stop_event = threading.Event()
        self._thread = None
        self._old_settings = None
        self._on_typeahead = None

    @property
    def pressed(self):
        """True if ESC was pressed since start()."""
        return self._pressed.is_set()

    def start(self):
        """Begin monitoring stdin for ESC key in a daemon thread."""
        if not HAS_TERMIOS or not sys.stdin.isatty():
            return
        self._pressed.clear()
        self._stop_event.clear()
        try:
            self._old_settings = termios.tcgetattr(sys.stdin)
        except termios.error:
            return
        try:
            tty.setcbreak(sys.stdin.fileno())
        except termios.error:
            self._old_settings = None
            return
        self._thread = threading.Thread(target=self._poll, daemon=True)
        self._thread.start()

    def _poll(self):
        """Poll stdin for ESC (0x1b) with 0.2s timeout."""
        fd = sys.stdin.fileno()
        while not self._stop_event.is_set():
            try:
                ready, _, _ = _select_mod.select([fd], [], [], 0.2)
            except (OSError, ValueError):
                break
            if ready:
                try:
                    ch = os.read(fd, 1)
                except OSError:
                    break
                if ch == b'\x1b':
                    # Could be Shift+Tab (\x1b[Z) or plain ESC
                    # Peek ahead for '[' within a short timeout
                    try:
                        r2, _, _ = _select_mod.select([fd], [], [], 0.05)
                    except (OSError, ValueError):
                        r2 = []
                    if r2:
                        ch2 = os.read(fd, 1)
                        if ch2 == b'[':
                            try:
                                r3, _, _ = _select_mod.select([fd], [], [], 0.05)
                            except (OSError, ValueError):
                                r3 = []
                            if r3:
                                os.read(fd, 1)  # consume sequence byte
                            # Any ESC sequence → treat as interrupt
                    self._pressed.set()
                    break
                elif ch == b'\x03':  # Ctrl+C
                    self._pressed.set()
                    break
                # Ignore all other bytes. Reading ahead here breaks IME and paste.

    def stop(self):
        """Stop monitoring and restore terminal settings."""
        self._stop_event.set()
        if self._thread is not None:
            self._thread.join(timeout=1)
            self._thread = None
        if self._old_settings is not None:
            try:
                termios.tcsetattr(sys.stdin, termios.TCSADRAIN, self._old_settings)
            except termios.error:
                pass
            self._old_settings = None


class ReadWriteLock:
    """Simple reader-writer lock for tool execution coordination."""

    def __init__(self):
        self._condition = threading.Condition()
        self._readers = 0
        self._writer = False

    @contextlib.contextmanager
    def read(self):
        with self._condition:
            while self._writer:
                self._condition.wait()
            self._readers += 1
        try:
            yield
        finally:
            with self._condition:
                self._readers -= 1
                if self._readers == 0:
                    self._condition.notify_all()

    @contextlib.contextmanager
    def write(self):
        with self._condition:
            while self._writer or self._readers:
                self._condition.wait()
            self._writer = True
        try:
            yield
        finally:
            with self._condition:
                self._writer = False
                self._condition.notify_all()


