# OllamaClient — Direct communication with Ollama OpenAI-compatible API
# ════════════════════════════════════════════════════════════════════════════════

class ResponseCache:
    """Simple in-memory LRU cache for LLM responses."""

    def __init__(self, max_size=50):
        self._cache = collections.OrderedDict()
        self._max_size = max_size

    @staticmethod
    def _hash_messages(messages, model):
        key_data = json.dumps({"model": model, "messages": messages[-3:]},
                              ensure_ascii=False, sort_keys=True)
        return hashlib.sha256(key_data.encode("utf-8")).hexdigest()[:32]

    def get(self, key):
        if key in self._cache:
            self._cache.move_to_end(key)
            return self._cache[key]
        return None

    def put(self, key, value):
        if key in self._cache:
            self._cache.move_to_end(key)
        else:
            if len(self._cache) >= self._max_size:
                self._cache.popitem(last=False)
        self._cache[key] = value

    def clear(self):
        self._cache.clear()


class OllamaClient:
    """Communicates with Ollama via the native /api/chat endpoint."""

    def __init__(self, config):
        self._supports_tool_streaming = None  # None=untested, True/False=detected
        self._response_cache = ResponseCache()
        self.refresh_from_config(config)

    def refresh_from_config(self, config):
        prev_base_url = getattr(self, "base_url", None)
        self.base_url = config.ollama_host
        self.api_key = getattr(config, "ollama_api_key", "")
        self.max_tokens = config.max_tokens
        self.temperature = config.temperature
        self.context_window = config.context_window
        # Preserve explicit user temperature overrides while still allowing
        # model-specific defaults to improve first-run behavior.
        self._temperature_overridden = bool(
            getattr(config, "_cli_temperature_set", False)
            or getattr(config, "temperature", Config.DEFAULT_TEMPERATURE) != Config.DEFAULT_TEMPERATURE
        )
        self.think_mode = getattr(config, 'think_mode', None)
        self.thinking_budget = getattr(config, 'thinking_budget', None)
        self.debug = config.debug
        self.timeout = 300
        if prev_base_url is not None and prev_base_url != self.base_url:
            self._supports_tool_streaming = None

    def _api_url(self, path):
        return f"{self.base_url}{path}"

    def _headers(self, *, json_body=False, extra=None):
        headers = {}
        if json_body:
            headers["Content-Type"] = "application/json"
        if self.api_key:
            headers["Authorization"] = f"Bearer {self.api_key}"
        if extra:
            headers.update(extra)
        return headers

    def _safe_headers_for_log(self, headers=None):
        """Return a copy of headers with Authorization value masked for safe logging.
        SEC-5: Prevent API key leakage in debug/error output."""
        h = dict(headers or self._headers())
        if "Authorization" in h:
            h["Authorization"] = "Bearer ***"
        return h

    def check_connection(self, retries=3):
        """Check if Ollama is reachable. Returns (ok, model_list)."""
        url = self._api_url("/api/tags")
        for attempt in range(retries):
            try:
                req = urllib.request.Request(url, headers=self._headers())
                resp = urllib.request.urlopen(req, timeout=5)
                try:
                    data = json.loads(resp.read(10 * 1024 * 1024))  # 10MB cap
                finally:
                    resp.close()
                models = [m["name"] for m in data.get("models", [])]
                return True, models
            except Exception as e:
                if attempt < retries - 1:
                    time.sleep(1)
                    continue
                return False, []

    def detect_tool_streaming(self):
        """Auto-detect if Ollama supports streaming with tool calls (0.5+).
        Calls /api/version and checks semver >= 0.5.0."""
        if self._supports_tool_streaming is not None:
            return self._supports_tool_streaming
        try:
            url = self._api_url("/api/version")
            req = urllib.request.Request(url, headers=self._headers())
            resp = urllib.request.urlopen(req, timeout=5)
            try:
                data = json.loads(resp.read(4096))
            finally:
                resp.close()
            version_str = data.get("version", "0.0.0")
            # Parse major.minor from version string (e.g. "0.5.4", "0.6.0-rc1")
            m = re.match(r"(\d+)\.(\d+)", version_str)
            if m:
                major, minor = int(m.group(1)), int(m.group(2))
                supported = (major, minor) >= (0, 5)
            else:
                supported = False
            self._supports_tool_streaming = supported
            if self.debug:
                print(f"{C.DIM}[debug] Ollama version={version_str} "
                      f"tool_streaming={'yes' if supported else 'no'}{C.RESET}",
                      file=sys.stderr)
            return supported
        except Exception:
            self._supports_tool_streaming = False
            return False

    def check_vision_support(self, model):
        """Check if a model supports vision/images via /api/show.
        Returns True if vision is likely supported, False otherwise."""
        try:
            body = json.dumps({"name": model}).encode("utf-8")
            req = urllib.request.Request(
                self._api_url("/api/show"),
                data=body,
                headers=self._headers(json_body=True),
                method="POST",
            )
            resp = urllib.request.urlopen(req, timeout=10)
            try:
                data = json.loads(resp.read(100 * 1024))
            finally:
                resp.close()
            # Check modelfile/template for vision indicators
            modelfile = data.get("modelfile", "") + data.get("template", "")
            details = data.get("details", {})
            families = details.get("families", [])
            # Known vision model families / projector indicators
            if any(f in families for f in ["clip", "mllama"]):
                return True
            if "vision" in model.lower() or "llava" in model.lower():
                return True
            if model.lower().startswith("gemma4:"):
                return True
            # Check parameters/template for image token
            template = data.get("template", "")
            if "image" in template.lower() or ".image" in template:
                return True
            return False
        except Exception:
            return True  # Assume yes if check fails (don't block user)

    def check_model(self, model_name, available_models=None):
        """Check if a specific model is available (exact or tag match).
        If available_models is provided, skip redundant check_connection() call."""
        if available_models is None:
            ok, models = self.check_connection()
            if not ok:
                return False
        else:
            models = available_models
        # Exact match or match without :latest tag (strip for robustness)
        want = model_name.strip()
        for m in models:
            ms = m.strip()
            if ms == want or ms == f"{want}:latest" or want == ms.split(":")[0]:
                return True
            # Also check if want starts with model base name (e.g. "qwen3:8b" matches "qwen3:8b-q4_0")
            if ms.startswith(f"{want}:") or ms.startswith(f"{want}-"):
                return True
        return False

    def pull_model(self, model_name):
        """Pull a model from the Ollama registry. Streams progress to stdout.

        Returns True on success, False on failure.
        """
        url = self._api_url("/api/pull")
        body = json.dumps({"name": model_name}).encode("utf-8")
        req = urllib.request.Request(
            url, data=body,
            headers=self._headers(json_body=True),
            method="POST",
        )
        try:
            resp = urllib.request.urlopen(req, timeout=600)
        except Exception as e:
            print(f"{C.RED}Failed to start pull: {e}{C.RESET}")
            return False

        last_status = ""
        try:
            for raw_line in resp:
                line = raw_line.decode("utf-8", errors="replace").strip()
                if not line:
                    continue
                try:
                    data = json.loads(line)
                except json.JSONDecodeError:
                    continue
                status = data.get("status", "")
                completed = data.get("completed", 0)
                total = data.get("total", 0)
                if total and completed:
                    pct = int(completed / total * 100)
                    bar_w = 30
                    filled = int(bar_w * pct / 100)
                    bar = "█" * filled + "░" * (bar_w - filled)
                    print(f"\r  {C.CYAN}{status}{C.RESET} [{bar}] {pct}%", end="", flush=True)
                elif status != last_status:
                    if last_status:
                        print()  # newline after previous progress bar
                    print(f"  {C.CYAN}{status}{C.RESET}", end="", flush=True)
                last_status = status
            print()  # final newline
            return True
        except Exception as e:
            print(f"\n{C.RED}Error during pull: {e}{C.RESET}")
            return False
        finally:
            resp.close()

    @staticmethod
    def _prepare_messages_for_native(messages):
        """Convert messages from internal/OpenAI format to Ollama native /api/chat format.

        - tool_calls arguments: str → dict (native API requires dict)
        - multipart image content: [{type: image_url, ...}] → images: [base64]
        - Extra fields (tool_call_id, type on tool_calls) are kept; Ollama ignores unknown fields.
        """
        result = []
        for msg in messages:
            m = dict(msg)  # shallow copy
            # Convert assistant tool_calls: arguments str→dict, strip OpenAI-only fields
            if m.get("tool_calls"):
                native_tcs = []
                for tc in m["tool_calls"]:
                    fn = tc.get("function", {})
                    args = fn.get("arguments", "{}")
                    if isinstance(args, str):
                        try:
                            args = json.loads(args)
                        except (json.JSONDecodeError, ValueError):
                            args = {}
                    native_tcs.append({"function": {"name": fn.get("name", ""), "arguments": args}})
                m["tool_calls"] = native_tcs
            # Convert multipart image content to native images field
            if isinstance(m.get("content"), list):
                texts = []
                images = []
                for part in m["content"]:
                    if isinstance(part, dict):
                        if part.get("type") == "text":
                            texts.append(part.get("text", ""))
                        elif part.get("type") == "image_url":
                            url = part.get("image_url", {}).get("url", "")
                            # Extract base64 from data URI: data:image/png;base64,<data>
                            if url.startswith("data:") and ";base64," in url:
                                b64 = url.split(";base64,", 1)[1]
                                images.append(b64)
                m["content"] = " ".join(texts) if texts else ""
                if images:
                    m["images"] = images
            result.append(m)
        return result

    @staticmethod
    def _native_to_openai_response(data):
        """Convert Ollama native /api/chat response to OpenAI-compatible format.

        This adapter lets all downstream consumers (show_sync_response, chat_sync,
        token reconciliation) work without changes.
        """
        message = data.get("message", {})
        raw_tool_calls = message.get("tool_calls") or []
        # Convert tool_calls: arguments dict→str, add id/type fields
        openai_tcs = []
        for tc in raw_tool_calls:
            fn = tc.get("function", {})
            args = fn.get("arguments", {})
            if isinstance(args, dict):
                args = json.dumps(args)
            openai_tcs.append({
                "id": f"call_{uuid.uuid4().hex[:8]}",
                "type": "function",
                "function": {"name": fn.get("name", ""), "arguments": args},
            })
        openai_msg = {
            "role": message.get("role", "assistant"),
            "content": message.get("content", "") or "",
        }
        if message.get("thinking"):
            openai_msg["thinking"] = message.get("thinking", "") or ""
        if openai_tcs:
            openai_msg["tool_calls"] = openai_tcs
        return {
            "choices": [{"message": openai_msg, "finish_reason": "stop"}],
            "usage": {
                "prompt_tokens": data.get("prompt_eval_count", 0) or 0,
                "completion_tokens": data.get("eval_count", 0) or 0,
            },
        }

    @staticmethod
    def _validate_messages_static(messages):
        """Static version of validate_message_order for use in OllamaClient.
        
        Returns (is_valid, error_message) tuple.
        """
        i = 0
        while i < len(messages):
            msg = messages[i]
            role = msg.get("role")
            
            if role == "assistant" and msg.get("tool_calls"):
                tool_call_ids = {tc.get("id") for tc in msg["tool_calls"] if tc.get("id")}
                if not tool_call_ids:
                    i += 1
                    continue
                
                found_ids = set()
                j = i + 1
                while j < len(messages) and found_ids != tool_call_ids:
                    next_msg = messages[j]
                    next_role = next_msg.get("role")
                    
                    if next_role == "tool":
                        tid = next_msg.get("tool_call_id")
                        if tid in tool_call_ids:
                            found_ids.add(tid)
                        j += 1
                    elif next_role in ("user", "assistant"):
                        missing = tool_call_ids - found_ids
                        if missing:
                            return (False, f"Missing tool results for tool_call_ids: {missing}. "
                                          f"Message order violated at index {j}.")
                        break
                    else:
                        j += 1
                
                missing = tool_call_ids - found_ids
                if missing:
                    return (False, f"Missing tool results for tool_call_ids: {missing}")
                
                i = j
            else:
                i += 1
        
        return (True, None)

    @staticmethod
    def _repair_message_order(messages):
        """Repair message order by ensuring tool results immediately follow tool_calls.
        
        This is a defensive measure to prevent 500 errors from Ollama Cloud API.
        Returns a new messages list with corrected order.
        """
        repaired = []
        i = 0
        while i < len(messages):
            msg = messages[i]
            role = msg.get("role")
            
            if role == "assistant" and msg.get("tool_calls"):
                repaired.append(msg)
                tool_call_ids = {tc.get("id") for tc in msg["tool_calls"] if tc.get("id")}
                
                # Scan ahead to find ALL tool results for this assistant message
                # Collect tool results and intervening messages separately
                tool_results = []
                intervening = []
                j = i + 1
                while j < len(messages) and tool_call_ids:
                    next_msg = messages[j]
                    next_role = next_msg.get("role")
                    
                    if next_role == "tool":
                        tid = next_msg.get("tool_call_id")
                        if tid in tool_call_ids:
                            tool_results.append(next_msg)
                            tool_call_ids.discard(tid)
                        j += 1
                    elif next_role in ("user", "assistant"):
                        # Save intervening message, keep looking for tool results
                        intervening.append(next_msg)
                        j += 1
                    else:
                        j += 1
                
                # Add all tool results immediately after assistant
                repaired.extend(tool_results)
                
                # Then add intervening messages
                repaired.extend(intervening)
                
                # Continue from where we left off
                i = j
            else:
                repaired.append(msg)
                i += 1
        
        return repaired

    def _resolve_request_temperature(self, model, tools=None, options=None):
        """Resolve request temperature from explicit overrides, task kind, and retry hints."""
        options = options or {}
        if "temperature" in options:
            try:
                return float(options["temperature"])
            except (TypeError, ValueError):
                pass

        temp = self.temperature
        if tools:
            if _is_gemma4_model(model):
                temp = min(temp, 0.25)
            else:
                _tier, _ = Config.get_model_tier(model)
                if _tier in ("S", "A") and self.think_mode is not False:
                    temp = min(temp, 0.4)
                else:
                    temp = min(temp, 0.3)

        try:
            retry_boost = float(options.get("retry_temperature_boost", 0.0) or 0.0)
        except (TypeError, ValueError):
            retry_boost = 0.0
        if retry_boost:
            temp = min(temp + retry_boost, 1.5)
        return temp

    def _merge_chat_options(self, model, temperature, options=None):
        """Build Ollama options with model-optimized sampling parameters."""
        _tier, _ = Config.get_model_tier(model)

        # Base num_predict; increase for thinking models
        _num_predict = self.max_tokens
        if self.think_mode is not False and _tier in ("S", "A"):
            _num_predict = max(_num_predict, 49152)  # 48K for thinking chain + output

        merged = {
            "num_ctx": self.context_window,
            "num_predict": _num_predict,
            "temperature": temperature,
        }

        # Gemma 4 optimized sampling (Google recommended values).
        # Keep explicit user temperatures and caller-chosen lower temperatures
        # for tool-calling reliability intact.
        if model.startswith("gemma4:"):
            if not self._temperature_overridden and temperature == self.temperature:
                merged["temperature"] = 1.0
            merged["top_p"] = 0.95
            merged["top_k"] = 64
        # Qwen3.5 / tier S-A optimized sampling
        elif _tier in ("S", "A"):
            merged["top_p"] = 0.8
            merged["top_k"] = 30
            merged["repeat_penalty"] = 1.1
        elif _tier == "B":
            merged["top_p"] = 0.9

        if not options:
            return merged

        for key, value in options.items():
            if key == "max_tokens":
                merged["num_predict"] = value
            elif key == "context_window":
                merged["num_ctx"] = value
            elif key == "retry_temperature_boost":
                continue
            else:
                merged[key] = value
        return merged

    def chat(self, model, messages, tools=None, stream=True, options=None):
        """Send chat request via Ollama native /api/chat.

        Uses the native API (not /v1/chat/completions) so that options like
        num_ctx are properly respected.  Returns OpenAI-compatible format via
        an adapter layer so all downstream consumers work unchanged.
        """
        # Cache lookup for non-streaming, no-tools calls
        _cache_key = None
        if not stream and not tools and not options:
            _cache_key = self._response_cache._hash_messages(messages, model)
            cached = self._response_cache.get(_cache_key)
            if cached is not None:
                return cached

        request_options = dict(options or {})
        temp = self._resolve_request_temperature(model, tools=bool(tools), options=request_options)
        if tools:
            # Auto-detect streaming with tools (Ollama 0.5+ supports this)
            if not self.detect_tool_streaming():
                if stream:
                    stream = False

        api_messages = self._prepare_messages_for_native(messages)
        
        # Validate message order before API call (prevent 500 errors from malformed tool_call/tool sequences)
        # Create a temporary session to validate the messages
        from types import SimpleNamespace
        _temp_session = SimpleNamespace(messages=messages, _estimate_tokens=Session._estimate_tokens)
        # Monkey-patch the validate method to work on the temp session
        _temp_session.validate_message_order = lambda: self._validate_messages_static(messages)
        _is_valid, _err_msg = _temp_session.validate_message_order()
        if not _is_valid:
            if self.debug:
                print(f"{C.DIM}[debug] Message order validation failed: {_err_msg}{C.RESET}", file=sys.stderr)
            # Auto-repair: ensure tool results immediately follow their tool_calls
            messages = self._repair_message_order(messages)
            api_messages = self._prepare_messages_for_native(messages)
        
        payload = {
            "model": model,
            "messages": api_messages,
            "stream": stream,
            "keep_alive": 300 if _is_cloud_model(model) else -1,  # Cloud: 5min, Local: keep loaded
            "options": self._merge_chat_options(model, temp, request_options),
        }
        if tools:
            payload["tools"] = tools
        # Explicitly control thinking mode for Ollama 0.6.5+ (Qwen3 / reasoning models)
        if self.think_mode is not None:
            payload["think"] = self.think_mode
        # Thinking budget: limit thinking tokens (Ollama 0.7+)
        if self.thinking_budget is not None:
            payload["think"] = True
            payload.setdefault("options", {})["thinking_budget"] = self.thinking_budget

        body = json.dumps(payload).encode("utf-8")
        req = urllib.request.Request(
            self._api_url("/api/chat"),
            data=body,
            headers=self._headers(json_body=True),
            method="POST",
        )

        if self.debug:
            print(f"{C.DIM}[debug] POST {self.base_url}/api/chat "
                  f"model={model} msgs={len(messages)} tools={len(tools or [])} "
                  f"stream={stream} num_ctx={payload['options'].get('num_ctx')}{C.RESET}", file=sys.stderr)

        try:
            resp = urllib.request.urlopen(req, timeout=self.timeout)
        except urllib.error.HTTPError as e:
            error_body = ""
            try:
                error_body = e.read().decode("utf-8", errors="replace")[:500]
            except Exception:
                pass
            finally:
                e.close()
            if e.code == 404:
                raise RuntimeError(t('errors.model_not_found', default=f"Model '{model}' not found. Run: ollama pull {model}")) from e
            elif e.code == 400:
                if "tool" in error_body.lower() or "function" in error_body.lower():
                    msg = t('errors.model_no_tool_support', default=f"Model '{model}' does not support tool/function calling.")
                    msg += " " + t('errors.model_suggest_alternative', default='Try: qwen3:8b, llama3.1:8b.')
                    raise RuntimeError(f"{msg} Error: {error_body[:200]}") from e
                elif "context" in error_body.lower() or "token" in error_body.lower():
                    msg = t('errors.context_window_exceeded', default=f"Context window exceeded for '{model}'.")
                    msg += " " + t('errors.suggest_compact', default='Use /compact or /clear.')
                    raise RuntimeError(f"{msg} Error: {error_body[:200]}") from e
                else:
                    raise RuntimeError(t('errors.model_bad_request', default=f"Bad request to Ollama (400): {error_body}")) from e
            else:
                raise RuntimeError(t('errors.ollama_http_error', default=f"Ollama HTTP error {e.code}: {error_body}")) from e

        if stream:
            return self._iter_ndjson(resp)
        else:
            try:
                raw = resp.read(10 * 1024 * 1024)  # 10MB safety cap
            finally:
                resp.close()
            try:
                data = json.loads(raw)
            except json.JSONDecodeError as e:
                raise RuntimeError(t('errors.invalid_json_ollama', default=f"Invalid JSON from Ollama: {raw[:200]}")) from e
            openai_resp = self._native_to_openai_response(data)
            if self.debug:
                usage = openai_resp.get("usage", {})
                print(f"{C.DIM}[debug] Response: prompt={usage.get('prompt_tokens',0)} "
                      f"completion={usage.get('completion_tokens',0)}{C.RESET}", file=sys.stderr)
            if _cache_key and openai_resp:
                self._response_cache.put(_cache_key, openai_resp)
            return openai_resp

    def _iter_ndjson(self, resp):
        """Iterate over NDJSON stream from Ollama native /api/chat.

        Each line is a complete JSON object.  Yields chunks converted to
        OpenAI delta format so stream_response() works without changes.
        """
        buf = b""
        MAX_BUF = 1024 * 1024  # 1MB safety limit
        CHUNK_TIMEOUT = 60  # FUN-1: max seconds to wait for next chunk
        try:
            while True:
                # FUN-1: Enforce per-chunk timeout using a threading.Event to
                # interrupt the blocking resp.read() call. signal.alarm() is not
                # used because it requires the main thread on macOS.
                _chunk_result = [None]
                _chunk_exc = [None]
                _chunk_done = threading.Event()

                def _do_read():
                    try:
                        _chunk_result[0] = resp.read(4096)
                    except Exception as _re:
                        _chunk_exc[0] = _re
                    finally:
                        _chunk_done.set()

                _reader_t = threading.Thread(target=_do_read, daemon=True)
                _reader_t.start()
                if not _chunk_done.wait(timeout=CHUNK_TIMEOUT):
                    if self.debug:
                        print(f"\n{C.DIM}[debug] NDJSON stream chunk timeout after {CHUNK_TIMEOUT}s{C.RESET}",
                              file=sys.stderr)
                    break  # Chunk timeout — stop reading

                if _chunk_exc[0] is not None:
                    _exc = _chunk_exc[0]
                    if isinstance(_exc, (ConnectionError, OSError, urllib.error.URLError)):
                        if self.debug:
                            print(f"\n{C.DIM}{t('warnings.debug_stream_error', default=f'[debug] NDJSON stream read error: {_exc}')}{C.RESET}",
                                  file=sys.stderr)
                    else:
                        if self.debug:
                            import traceback as _tb
                            print(f"\n{C.DIM}[debug] NDJSON stream unexpected error: {_exc}{C.RESET}",
                                  file=sys.stderr)
                            _tb.print_exc(file=sys.stderr)
                    break

                chunk = _chunk_result[0]
                if not chunk:
                    break
                buf += chunk
                if len(buf) > MAX_BUF and b"\n" not in buf:
                    buf = b""  # discard oversized bufferless data
                    continue
                while b"\n" in buf:
                    line_bytes, buf = buf.split(b"\n", 1)
                    line = line_bytes.decode("utf-8", errors="replace").strip()
                    if not line:
                        continue
                    try:
                        data = json.loads(line)
                    except json.JSONDecodeError:
                        continue

                    message = data.get("message", {})
                    done = data.get("done", False)

                    # Build OpenAI-compatible delta
                    delta = {}
                    thinking = message.get("thinking", "")
                    if thinking:
                        delta["thinking"] = thinking
                    content = message.get("content", "")
                    if content:
                        delta["content"] = content

                    raw_tool_calls = message.get("tool_calls") or []
                    if raw_tool_calls:
                        openai_tcs = []
                        for i, tc in enumerate(raw_tool_calls):
                            fn = tc.get("function", {})
                            args = fn.get("arguments", {})
                            if isinstance(args, dict):
                                args = json.dumps(args)
                            openai_tcs.append({
                                "index": i,
                                "id": f"call_{uuid.uuid4().hex[:8]}",
                                "function": {"name": fn.get("name", ""), "arguments": args},
                            })
                        delta["tool_calls"] = openai_tcs

                    openai_chunk = {
                        "choices": [{"delta": delta, "finish_reason": "stop" if done else None}],
                    }
                    # Attach usage on the final chunk
                    if done:
                        openai_chunk["usage"] = {
                            "prompt_tokens": data.get("prompt_eval_count", 0) or 0,
                            "completion_tokens": data.get("eval_count", 0) or 0,
                        }

                    yield openai_chunk

                    if done:
                        return
        finally:
            try:
                resp.close()
            except Exception:
                pass

    def tokenize(self, model, text):
        """Count tokens via Ollama /api/tokenize. Falls back to len//4."""
        try:
            body = json.dumps({"model": model, "text": text}).encode("utf-8")
            req = urllib.request.Request(
                self._api_url("/api/tokenize"),
                data=body,
                headers=self._headers(json_body=True),
                method="POST",
            )
            resp = urllib.request.urlopen(req, timeout=5)
            try:
                data = json.loads(resp.read(10 * 1024 * 1024))  # 10MB cap
            finally:
                resp.close()
            tokens = data.get("tokens")
            if tokens is not None:
                return len(tokens)
        except Exception as _te:
            # FUN-2: Log tokenize errors in debug mode (non-fatal, falls back to len//4)
            if self.debug:
                import traceback as _tb
                print(f"{C.DIM}[debug] tokenize error (falling back to len//4): {_te}{C.RESET}",
                      file=sys.stderr)
                _tb.print_exc(file=sys.stderr)
        return len(text) // 4

    def chat_sync(self, model, messages, tools=None, options=None):
        """Synchronous (non-streaming) chat that returns a simplified dict.

        Returns:
            {"content": str, "tool_calls": list[dict]}
            where each tool_call has keys: id, name, arguments (already parsed dict).
        """
        resp = self.chat(model=model, messages=messages, tools=tools, stream=False, options=options)
        choice = resp.get("choices", [{}])[0]
        message = choice.get("message", {})
        content = message.get("content", "") or ""
        raw_tool_calls = message.get("tool_calls", [])

        # Strip thinking traces (Qwen <think> and Gemma 4 <|channel>thought)
        content = _strip_thinking_tags(content)

        # Normalize tool_calls into a consistent format
        tool_calls = []
        for tc in raw_tool_calls:
            func = tc.get("function", {})
            tc_id = tc.get("id", f"call_{uuid.uuid4().hex[:8]}")
            name = func.get("name", "")
            raw_args = func.get("arguments", "{}")
            # Cap argument size to prevent OOM on malformed responses
            if isinstance(raw_args, str) and len(raw_args) > 102400:  # 100KB
                raw_args = raw_args[:102400]
            try:
                args = json.loads(raw_args) if isinstance(raw_args, str) else raw_args
                if not isinstance(args, dict):
                    args = {"raw": str(args)}
            except json.JSONDecodeError:
                try:
                    fixed = raw_args.replace("'", '"')
                    fixed = re.sub(r',\s*}', '}', fixed)
                    fixed = re.sub(r',\s*]', ']', fixed)
                    args = json.loads(fixed)
                except (json.JSONDecodeError, ValueError, TypeError, KeyError):
                    args = {"raw": raw_args}
            tool_calls.append({"id": tc_id, "name": name, "arguments": args})

        return {"content": content, "tool_calls": tool_calls}


# ════════════════════════════════════════════════════════════════════════════════
# RAG Engine (optional, activated by --rag / --rag-index)
# ════════════════════════════════════════════════════════════════════════════════

class RAGEngine:
    """Local RAG engine using Ollama embeddings + SQLite vector store."""

    # File extensions to index
    TEXT_EXTENSIONS = {
        '.py', '.js', '.ts', '.tsx', '.jsx', '.md', '.txt', '.json',
        '.yaml', '.yml', '.toml', '.cfg', '.ini', '.sh', '.bash',
        '.html', '.css', '.go', '.rs', '.java', '.c', '.cpp', '.h',
        '.hpp', '.rb', '.php', '.sql', '.r', '.swift', '.kt', '.vue',
        '.svelte', '.xml',
    }
    # Bare filenames (no extension) to index
    BARE_FILENAMES = {'makefile', 'dockerfile', 'readme', 'license'}
    # Directories to skip
    SKIP_DIRS = {
        '.git', '.svn', '.hg', 'node_modules', '__pycache__',
        'venv', '.venv', 'dist', 'build', '.eve', '.tox', '.mypy_cache',
    }
    # Max file size to index (256 KB)
    MAX_FILE_SIZE = 256 * 1024

    def __init__(self, config):
        self.config = config
        self.db_path = os.path.join(config.cwd, ".eve", "rag", "index.sqlite")
        self._ensure_db()

    def _ensure_db(self):
        """Create SQLite database and tables if needed."""
        os.makedirs(os.path.dirname(self.db_path), exist_ok=True)
        conn = sqlite3.connect(self.db_path)
        try:
            conn.execute("""CREATE TABLE IF NOT EXISTS documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                path TEXT NOT NULL,
                chunk_index INTEGER NOT NULL,
                content TEXT NOT NULL,
                embedding BLOB NOT NULL,
                file_hash TEXT NOT NULL,
                created_at TEXT DEFAULT CURRENT_TIMESTAMP,
                UNIQUE(path, chunk_index)
            )""")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_doc_path ON documents(path)")
            conn.execute("CREATE INDEX IF NOT EXISTS idx_doc_hash ON documents(file_hash)")
            conn.commit()
        finally:
            conn.close()

    # ── Embedding ─────────────────────────────────────────────────────────────

    def _get_embedding(self, text):
        """Get embedding vector from Ollama. Tries /api/embed first, falls back to /api/embeddings."""
        model = self.config.rag_model
        host = self.config.ollama_host.rstrip("/")
        headers = {"Content-Type": "application/json"}
        if getattr(self.config, "ollama_api_key", ""):
            headers["Authorization"] = f"Bearer {self.config.ollama_api_key}"

        # Try /api/embed (Ollama ≥ 0.4)
        try:
            url = f"{host}/api/embed"
            payload = json.dumps({"model": model, "input": text}).encode("utf-8")
            req = urllib.request.Request(url, data=payload,
                                        headers=headers)
            with urllib.request.urlopen(req, timeout=60) as resp:
                data = json.loads(resp.read())
                return data["embeddings"][0]
        except Exception:
            pass

        # Fallback: /api/embeddings (older Ollama)
        url = f"{host}/api/embeddings"
        payload = json.dumps({"model": model, "prompt": text}).encode("utf-8")
        req = urllib.request.Request(url, data=payload,
                                    headers=headers)
        with urllib.request.urlopen(req, timeout=60) as resp:
            data = json.loads(resp.read())
            return data["embedding"]

    # ── Vector serialization ──────────────────────────────────────────────────

    @staticmethod
    def _serialize_embedding(vec):
        """Serialize float list to compact binary BLOB."""
        return struct.pack(f'{len(vec)}f', *vec)

    @staticmethod
    def _deserialize_embedding(blob):
        """Deserialize BLOB back to float tuple."""
        n = len(blob) // 4  # float32 = 4 bytes
        return struct.unpack(f'{n}f', blob)

    # ── Similarity ────────────────────────────────────────────────────────────

    @staticmethod
    def _cosine_similarity(a, b):
        """Compute cosine similarity between two vectors."""
        dot = sum(x * y for x, y in zip(a, b))
        norm_a = sum(x * x for x in a) ** 0.5
        norm_b = sum(x * x for x in b) ** 0.5
        if norm_a == 0 or norm_b == 0:
            return 0.0
        return dot / (norm_a * norm_b)

    # ── Chunking ──────────────────────────────────────────────────────────────

    @staticmethod
    def _chunk_text(text, chunk_size=1000, overlap=200):
        """Split text into overlapping chunks at line boundaries."""
        lines = text.split('\n')
        chunks = []
        current = []
        current_len = 0

        for line in lines:
            line_len = len(line) + 1
            if current_len + line_len > chunk_size and current:
                chunks.append('\n'.join(current))
                # Keep overlap portion
                overlap_lines = []
                overlap_len = 0
                for prev in reversed(current):
                    if overlap_len + len(prev) + 1 > overlap:
                        break
                    overlap_lines.insert(0, prev)
                    overlap_len += len(prev) + 1
                current = overlap_lines
                current_len = overlap_len
            current.append(line)
            current_len += line_len

        if current:
            chunks.append('\n'.join(current))

        return chunks if chunks else [text]

    # ── File hash ─────────────────────────────────────────────────────────────

    @staticmethod
    def _file_hash(path):
        """Compute SHA-256 hash of a file."""
        h = hashlib.sha256()
        with open(path, "rb") as f:
            for block in iter(lambda: f.read(8192), b""):
                h.update(block)
        return h.hexdigest()

    # ── Indexing ──────────────────────────────────────────────────────────────

    def _collect_files(self, target):
        """Collect indexable files under target path."""
        target = os.path.abspath(target)
        if os.path.isfile(target):
            return [target]

        files = []
        for root, dirs, filenames in os.walk(target):
            dirs[:] = [d for d in dirs if d not in self.SKIP_DIRS and not d.startswith('.')]
            for fname in filenames:
                fpath = os.path.join(root, fname)
                try:
                    if os.path.getsize(fpath) > self.MAX_FILE_SIZE:
                        continue
                except OSError:
                    continue
                ext = os.path.splitext(fname)[1].lower()
                if ext in self.TEXT_EXTENSIONS or fname.lower() in self.BARE_FILENAMES:
                    files.append(fpath)
        return files

    def index_path(self, target_path, verbose=True):
        """Index all text files under target_path. Returns (indexed, skipped, errors)."""
        target = os.path.abspath(target_path)
        if not os.path.exists(target):
            if verbose:
                msg = t('errors.path_not_exist', default=f"Error: path '{target_path}' does not exist")
                print(f"{C.RED}{msg}{C.RESET}")
            return 0, 0, 1

        files = self._collect_files(target)
        if not files:
            if verbose:
                print(f"{C.YELLOW}No indexable files found in '{target_path}'{C.RESET}")
            return 0, 0, 0

        conn = sqlite3.connect(self.db_path)
        try:
            indexed, skipped, errors = 0, 0, 0

            for fpath in files:
                rel_path = os.path.relpath(fpath, self.config.cwd)
                try:
                    fhash = self._file_hash(fpath)

                    # Skip if already indexed with same hash
                    row = conn.execute(
                        "SELECT file_hash FROM documents WHERE path = ? LIMIT 1",
                        (rel_path,),
                    ).fetchone()
                    if row and row[0] == fhash:
                        skipped += 1
                        continue

                    # Remove stale entries
                    conn.execute("DELETE FROM documents WHERE path = ?", (rel_path,))

                    with open(fpath, "r", errors="replace") as f:
                        content = f.read()
                    if not content.strip():
                        skipped += 1
                        continue

                    chunks = self._chunk_text(content)
                    for i, chunk in enumerate(chunks):
                        if not chunk.strip():
                            continue
                        embedding = self._get_embedding(chunk)
                        emb_blob = self._serialize_embedding(embedding)
                        conn.execute(
                            "INSERT OR REPLACE INTO documents "
                            "(path, chunk_index, content, embedding, file_hash) "
                            "VALUES (?, ?, ?, ?, ?)",
                            (rel_path, i, chunk, emb_blob, fhash),
                        )

                    conn.commit()
                    indexed += 1
                    if verbose:
                        print(f"  {C.GREEN}✓{C.RESET} {rel_path} ({len(chunks)} chunks)")

                except Exception as e:
                    errors += 1
                    if verbose:
                        print(f"  {C.RED}✗{C.RESET} {rel_path}: {e}")

            conn.commit()
        finally:
            conn.close()

        if verbose:
            print(f"\n{C.GREEN}Indexing complete:{C.RESET} "
                  f"{indexed} files indexed, {skipped} unchanged, {errors} errors")
            db_size = os.path.getsize(self.db_path)
            print(f"{C.DIM}Database: {self.db_path} ({db_size // 1024} KB){C.RESET}")

        return indexed, skipped, errors

    # ── Query ─────────────────────────────────────────────────────────────────

    def query(self, query_text, top_k=None):
        """Query the index. Returns list of (path, content, similarity)."""
        if top_k is None:
            top_k = self.config.rag_topk

        if not os.path.exists(self.db_path):
            return []

        query_emb = self._get_embedding(query_text)

        conn = sqlite3.connect(self.db_path)
        try:
            # Phase 1: fetch path + embedding only for scoring (no content needed yet)
            # Note: all embedding BLOBs are loaded into memory at once. For very large
            # indexes (tens of thousands of chunks) this can become a bottleneck; a
            # complete fix would require an external vector DB (e.g. sqlite-vec) and is
            # left as a known limitation of the current implementation.
            rows = conn.execute(
                "SELECT path, chunk_index, embedding FROM documents"
            ).fetchall()

            if not rows:
                return []

            scored = []
            for path, chunk_index, emb_blob in rows:
                emb = self._deserialize_embedding(emb_blob)
                sim = self._cosine_similarity(query_emb, emb)
                scored.append((sim, path, chunk_index))

            scored.sort(key=lambda x: x[0], reverse=True)
            top = scored[:top_k]

            # Phase 2: fetch content only for the top-k winners
            results = []
            for sim, path, chunk_index in top:
                row = conn.execute(
                    "SELECT content FROM documents WHERE path = ? AND chunk_index = ?",
                    (path, chunk_index),
                ).fetchone()
                if row:
                    results.append((path, row[0], sim))

            return results
        finally:
            conn.close()

    def format_context(self, results):
        """Format query results as context block for system prompt injection."""
        if not results:
            return ""
        lines = ["[LOCAL CONTEXT START]"]
        for path, content, sim in results:
            lines.append(f"--- {path} (relevance: {sim:.3f}) ---")
            # Truncate very long chunks
            if len(content) > 2000:
                content = content[:2000] + "\n... (truncated)"
            lines.append(content)
        lines.append("[LOCAL CONTEXT END]")
        return "\n".join(lines)

    def get_stats(self):
        """Return index statistics."""
        if not os.path.exists(self.db_path):
            return {"chunks": 0, "files": 0, "db_size": 0}
        conn = sqlite3.connect(self.db_path)
        try:
            chunks = conn.execute("SELECT COUNT(*) FROM documents").fetchone()[0]
            files = conn.execute("SELECT COUNT(DISTINCT path) FROM documents").fetchone()[0]
        finally:
            conn.close()
        db_size = os.path.getsize(self.db_path)
        return {"chunks": chunks, "files": files, "db_size": db_size}


# ════════════════════════════════════════════════════════════════════════════════
# Code Intelligence — lightweight symbol indexing
# ════════════════════════════════════════════════════════════════════════════════

class CodeIntelligence:
    """Lightweight code intelligence: symbol index, go-to-definition, find-references.
    Uses regex-based parsing (no external dependencies)."""

    # Language-specific patterns for symbol extraction
    _PATTERNS = {
        ".py": [
            (r'^\s*(?:async\s+)?def\s+(\w+)\s*\(', "function"),
            (r'^\s*class\s+(\w+)', "class"),
            (r'^(\w+)\s*=', "variable"),
        ],
        ".js": [
            (r'(?:function\s+(\w+)|(?:const|let|var)\s+(\w+)\s*=\s*(?:async\s+)?\(?.*?\)?\s*=>|(?:const|let|var)\s+(\w+)\s*=\s*function)', "function"),
            (r'class\s+(\w+)', "class"),
            (r'(?:export\s+)?(?:const|let|var)\s+(\w+)\s*=', "variable"),
        ],
        ".ts": [
            (r'(?:function\s+(\w+)|(?:const|let|var)\s+(\w+)\s*(?::\s*\S+\s*)?=\s*(?:async\s+)?\(?.*?\)?\s*=>|(?:const|let|var)\s+(\w+)\s*(?::\s*\S+\s*)?=\s*function)', "function"),
            (r'(?:export\s+)?(?:abstract\s+)?class\s+(\w+)', "class"),
            (r'(?:export\s+)?interface\s+(\w+)', "interface"),
            (r'(?:export\s+)?type\s+(\w+)', "type"),
        ],
        ".go": [
            (r'^func\s+(?:\(\w+\s+\*?\w+\)\s+)?(\w+)\(', "function"),
            (r'^type\s+(\w+)\s+struct', "struct"),
            (r'^type\s+(\w+)\s+interface', "interface"),
        ],
        ".rs": [
            (r'(?:pub\s+)?fn\s+(\w+)', "function"),
            (r'(?:pub\s+)?struct\s+(\w+)', "struct"),
            (r'(?:pub\s+)?trait\s+(\w+)', "trait"),
            (r'(?:pub\s+)?enum\s+(\w+)', "enum"),
        ],
        ".rb": [
            (r'^\s*def\s+(\w+)', "method"),
            (r'^\s*class\s+(\w+)', "class"),
            (r'^\s*module\s+(\w+)', "module"),
        ],
        ".java": [
            (r'(?:public|private|protected|static|\s)+[\w<>\[\]]+\s+(\w+)\s*\(', "method"),
            (r'(?:public\s+)?(?:abstract\s+)?class\s+(\w+)', "class"),
            (r'(?:public\s+)?interface\s+(\w+)', "interface"),
        ],
    }
    # Map extensions to canonical groups
    _EXT_MAP = {
        ".jsx": ".js", ".mjs": ".js", ".cjs": ".js",
        ".tsx": ".ts", ".mts": ".ts",
    }

    _SKIP_DIRS = {".git", "node_modules", "__pycache__", ".venv", "venv",
                  "dist", "build", ".next", ".nuxt", "target", ".tox"}

    def __init__(self, cwd, max_files=500):
        self.cwd = cwd
        self.max_files = max_files
        self._index = {}  # symbol_name -> list of {file, line, kind}

    def build_index(self):
        """Scan project files and build symbol index."""
        self._index.clear()
        file_count = 0
        for root, dirs, files in os.walk(self.cwd):
            # Skip hidden and build directories
            dirs[:] = [d for d in dirs if d not in self._SKIP_DIRS and not d.startswith(".")]
            for fname in files:
                if file_count >= self.max_files:
                    return len(self._index)
                ext = os.path.splitext(fname)[1].lower()
                canon_ext = self._EXT_MAP.get(ext, ext)
                if canon_ext not in self._PATTERNS:
                    continue
                fpath = os.path.join(root, fname)
                if os.path.islink(fpath):
                    continue
                try:
                    fsize = os.path.getsize(fpath)
                    if fsize > 500_000:  # 500KB max
                        continue
                    with open(fpath, encoding="utf-8", errors="replace") as f:
                        self._index_file(f, fpath, canon_ext)
                    file_count += 1
                except (OSError, UnicodeDecodeError):
                    pass
        return len(self._index)

    def _index_file(self, f, fpath, canon_ext):
        """Index symbols from a single file."""
        rel = os.path.relpath(fpath, self.cwd)
        patterns = self._PATTERNS[canon_ext]
        compiled = [(re.compile(p), kind) for p, kind in patterns]
        for line_num, line in enumerate(f, 1):
            for pat, kind in compiled:
                m = pat.search(line)
                if m:
                    # Get first non-None group
                    name = None
                    for g in m.groups():
                        if g:
                            name = g
                            break
                    if name and len(name) > 1:  # skip single-char vars
                        self._index.setdefault(name, []).append({
                            "file": rel, "line": line_num, "kind": kind
                        })

    def find_definition(self, symbol):
        """Find definitions of a symbol. Returns list of {file, line, kind}."""
        results = self._index.get(symbol, [])
        # Prioritize class/function over variable
        priority = {"class": 0, "struct": 0, "trait": 0, "interface": 0,
                    "function": 1, "method": 1, "module": 1,
                    "type": 2, "enum": 2, "variable": 3}
        return sorted(results, key=lambda r: priority.get(r["kind"], 9))

    def find_references(self, symbol, max_results=50):
        """Find references to a symbol across the codebase using grep."""
        refs = []
        for root, dirs, files in os.walk(self.cwd):
            dirs[:] = [d for d in dirs if d not in self._SKIP_DIRS and not d.startswith(".")]
            for fname in files:
                ext = os.path.splitext(fname)[1].lower()
                canon = self._EXT_MAP.get(ext, ext)
                if canon not in self._PATTERNS:
                    continue
                fpath = os.path.join(root, fname)
                if os.path.islink(fpath):
                    continue
                try:
                    with open(fpath, encoding="utf-8", errors="replace") as f:
                        for line_num, line in enumerate(f, 1):
                            if symbol in line:
                                refs.append({
                                    "file": os.path.relpath(fpath, self.cwd),
                                    "line": line_num,
                                    "text": line.strip()[:120],
                                })
                                if len(refs) >= max_results:
                                    return refs
                except (OSError, UnicodeDecodeError):
                    pass
        return refs

    def search_symbols(self, query, max_results=20):
        """Fuzzy search symbols by name prefix or substring."""
        query_lower = query.lower()
        results = []
        for name, defs in self._index.items():
            if query_lower in name.lower():
                for d in defs:
                    results.append({"name": name, **d})
                    if len(results) >= max_results:
                        return results
        return results

    @property
    def symbol_count(self):
        return sum(len(v) for v in self._index.values())

    def repo_map(self, max_lines=200):
        """Generate a structural map of the repository for LLM context.

        Returns a text summary of the project structure including:
        - File tree (directories and key files)
        - Class/function definitions per file
        """
        if not self._index:
            self.build_index()
        # Group symbols by file
        file_symbols = {}
        for name, defs in self._index.items():
            for d in defs:
                fpath = d["file"]
                kind = d["kind"]
                file_symbols.setdefault(fpath, []).append((kind, name, d["line"]))
        # Sort files, then symbols within each file by line number
        lines = ["# Repository Map", ""]
        line_count = 2
        for fpath in sorted(file_symbols.keys()):
            if line_count >= max_lines:
                lines.append(f"... ({len(file_symbols) - len(lines)} more files)")
                break
            syms = sorted(file_symbols[fpath], key=lambda s: s[2])
            lines.append(f"## {fpath}")
            line_count += 1
            for kind, name, lineno in syms:
                if line_count >= max_lines:
                    break
                indent = "  " if kind in ("function", "method", "variable") else ""
                lines.append(f"{indent}- {kind} {name} (L{lineno})")
                line_count += 1
            lines.append("")
            line_count += 1
        return "\n".join(lines)


# ════════════════════════════════════════════════════════════════════════════════
# Headless Output Collector — structured JSON output for CI/CD
# ════════════════════════════════════════════════════════════════════════════════

class HeadlessOutputCollector:
    """Collects tool calls, results, and assistant text for structured JSON output.

    Used in headless/CI mode to produce machine-readable output.
    Each event is flushed as a single JSON line to stdout (stream-json mode)
    or accumulated for a final summary (json mode).
    """

    def __init__(self, output_format="json", model="", session_id=""):
        self._output_format = output_format  # "json" or "stream-json"
        self._model = model
        self._session_id = session_id
        self._events = []
        self._lock = threading.Lock()
        self._tool_call_count = 0
        self._last_text = ""

    def tool_call(self, tool_name, params):
        """Record a tool invocation."""
        event = {
            "type": "tool_call",
            "tool": tool_name,
            "params": params,
            "timestamp": time.time(),
        }
        with self._lock:
            self._events.append(event)
            self._tool_call_count += 1
        if self._output_format == "stream-json":
            self._flush_line(event)

    def tool_result(self, tool_name, result, is_error=False):
        """Record a tool execution result."""
        # Truncate long results for structured output
        output = str(result)
        if len(output) > 10000:
            output = output[:10000] + "... (truncated)"
        event = {
            "type": "tool_result",
            "tool": tool_name,
            "output": output,
            "is_error": is_error,
            "timestamp": time.time(),
        }
        with self._lock:
            self._events.append(event)
        if self._output_format == "stream-json":
            self._flush_line(event)

    def assistant_text(self, text):
        """Record assistant text output."""
        if not text:
            return
        event = {
            "type": "assistant",
            "content": text,
            "timestamp": time.time(),
        }
        with self._lock:
            self._events.append(event)
            self._last_text = text
        if self._output_format == "stream-json":
            self._flush_line(event)

    def _flush_line(self, event):
        """Write a single JSON line to stdout (thread-safe via _lock)."""
        try:
            print(json.dumps(event, ensure_ascii=False), flush=True)
        except Exception:
            pass

    def get_summary(self):
        """Return final summary dict for json output mode."""
        with self._lock:
            return {
                "role": "assistant",
                "content": self._last_text,
                "model": self._model,
                "session_id": self._session_id,
                "tool_calls": self._tool_call_count,
                "events": self._events,
            }


# ════════════════════════════════════════════════════════════════════════════════
# Structured Output Schema Helpers
# ════════════════════════════════════════════════════════════════════════════════

def _extract_json_from_response(text):
    """Extract JSON object from assistant response text.

    Tries raw parse first, then looks for ```json fenced blocks.
    Returns parsed dict/list or None.
    """
    if not text:
        return None
    text = text.strip()
    # Try direct parse
    try:
        return json.loads(text)
    except (json.JSONDecodeError, ValueError):
        pass
    # Try extracting from ```json ... ``` block
    m = re.search(r'```(?:json)?\s*\n?([\s\S]*?)\n?```', text)
    if m:
        try:
            return json.loads(m.group(1).strip())
        except (json.JSONDecodeError, ValueError):
            pass
    # Try finding first { ... } or [ ... ] span
    for opener, closer in [("{", "}"), ("[", "]")]:
        start = text.find(opener)
        if start >= 0:
            depth = 0
            in_str = False
            esc = False
            for i in range(start, len(text)):
                c = text[i]
                if esc:
                    esc = False
                    continue
                if c == "\\":
                    esc = True
                    continue
                if c == '"' and not esc:
                    in_str = not in_str
                    continue
                if in_str:
                    continue
                if c == opener:
                    depth += 1
                elif c == closer:
                    depth -= 1
                    if depth == 0:
                        try:
                            return json.loads(text[start:i + 1])
                        except (json.JSONDecodeError, ValueError):
                            break
    return None


_SCHEMA_TYPE_MAP = {
    "string": str,
    "number": (int, float),
    "integer": int,
    "boolean": bool,
    "array": list,
    "object": dict,
    "null": type(None),
}


def _validate_against_schema(data, schema):
    """Basic JSON schema validation without external dependencies.

    Checks type, required, and properties (one level deep).
    Returns (valid: bool, errors: list[str]).
    """
    errors = []
    if not isinstance(schema, dict):
        return True, []

    # Type check
    expected_type = schema.get("type")
    if expected_type:
        py_types = _SCHEMA_TYPE_MAP.get(expected_type)
        if py_types and not isinstance(data, py_types):
            errors.append(f"Expected type '{expected_type}', got '{type(data).__name__}'")
            return False, errors

    # Required fields (only for objects)
    if isinstance(data, dict):
        for field in schema.get("required", []):
            if field not in data:
                errors.append(f"Missing required field: '{field}'")

        # Property type checks (one level)
        props = schema.get("properties", {})
        for key, prop_schema in props.items():
            if key in data:
                prop_type = prop_schema.get("type")
                if prop_type:
                    py_types = _SCHEMA_TYPE_MAP.get(prop_type)
                    if py_types and not isinstance(data[key], py_types):
                        errors.append(f"Field '{key}': expected '{prop_type}', got '{type(data[key]).__name__}'")

    # Array items type check
    if isinstance(data, list) and "items" in schema:
        item_type = schema["items"].get("type")
        if item_type:
            py_types = _SCHEMA_TYPE_MAP.get(item_type)
            if py_types:
                for i, item in enumerate(data):
                    if not isinstance(item, py_types):
                        errors.append(f"Item [{i}]: expected '{item_type}', got '{type(item).__name__}'")
                        break  # Report first error only

    return len(errors) == 0, errors


# ════════════════════════════════════════════════════════════════════════════════
# Tool Base Class + Registry
# ════════════════════════════════════════════════════════════════════════════════

class ToolResult:
    """Result of a tool execution."""
    __slots__ = ("id", "output", "is_error")

    def __init__(self, tool_call_id, output, is_error=False):
        self.id = tool_call_id
        self.output = output
        self.is_error = is_error


class Tool(ABC):
    """Base class for all tools."""
    name = ""
    description = ""
    parameters = {}  # JSON Schema
    lock_mode = "write"
    parallel_safe = False

    def __init__(self, cwd=None):
        self.cwd = os.path.realpath(cwd) if cwd else None

    @abstractmethod
    def execute(self, params):
        """Execute the tool. Returns string output."""
        ...

    def _base_dir(self):
        return self.cwd or os.getcwd()

    def execution_lock(self):
        return self.lock_mode

    def _is_path_within_repo(self, file_path):
        """Check if file_path is within the repo directory."""
        try:
            real_path = os.path.realpath(file_path)
            real_repo = os.path.realpath(self._base_dir())
            # Ensure the resolved path starts with the repo path
            return real_path.startswith(real_repo + os.sep) or real_path == real_repo
        except (OSError, ValueError):
            return False

    def get_schema(self):
        """Return OpenAI function calling schema."""
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self.description,
                "parameters": self.parameters,
            },
        }


# ════════════════════════════════════════════════════════════════════════════════
# Sandbox Runtime — Docker/Podman container isolation for Bash execution
# ════════════════════════════════════════════════════════════════════════════════

class SandboxRuntime:
    """Docker/Podman container sandbox for executing Bash commands in isolation.

    Provides process-level isolation with:
    - Volume mount of project directory (read-write)
    - Dropped capabilities (--cap-drop ALL)
    - Read-only root filesystem (--read-only --tmpfs /tmp)
    - Optional network isolation (--network none)
    - User namespace mapping to host user
    """

    def __init__(self, cwd, image="python:3-slim", no_network=False):
        self.cwd = cwd
        self.image = image
        self.no_network = no_network
        self._runtime = self._detect_runtime()

    @staticmethod
    def _detect_runtime():
        """Detect available container runtime: docker or podman."""
        for rt in ("docker", "podman"):
            if shutil.which(rt):
                try:
                    result = subprocess.run(
                        [rt, "info"], capture_output=True, timeout=10,
                    )
                    if result.returncode == 0:
                        return rt
                except (subprocess.TimeoutExpired, OSError):
                    pass
        return None

    @property
    def is_available(self):
        """Check if container runtime is available."""
        return self._runtime is not None

    @property
    def runtime_name(self):
        return self._runtime or "none"

    def run_command(self, command, timeout_s=120, env=None):
        """Execute a command inside a container.

        Args:
            command: Shell command string
            timeout_s: Timeout in seconds
            env: Optional dict of environment variables to pass

        Returns:
            tuple: (output_string, return_code)
        """
        if not self._runtime:
            raise RuntimeError("No container runtime available")

        import shlex
        cmd = [self._runtime, "run", "--rm"]

        # Security hardening
        cmd.extend(["--cap-drop", "ALL"])
        cmd.extend(["--security-opt", "no-new-privileges"])
        cmd.extend(["--read-only"])
        cmd.extend(["--tmpfs", "/tmp:rw,noexec,nosuid,size=256m"])

        # User mapping (match host user to avoid permission issues)
        try:
            uid = os.getuid()
            gid = os.getgid()
            cmd.extend(["--user", f"{uid}:{gid}"])
        except AttributeError:
            pass  # Windows — skip user mapping

        # Network isolation
        if self.no_network:
            cmd.extend(["--network", "none"])

        # Mount project directory
        quoted_cwd = self.cwd
        cmd.extend(["-v", f"{quoted_cwd}:{quoted_cwd}:rw"])
        cmd.extend(["-w", quoted_cwd])

        # Pass environment variables
        if env:
            for k, v in env.items():
                cmd.extend(["-e", f"{k}={v}"])

        # Image and command
        cmd.extend([self.image, "sh", "-c", command])

        try:
            result = subprocess.run(
                cmd,
                capture_output=True,
                text=True,
                timeout=timeout_s,
                stdin=subprocess.DEVNULL,
            )
            output = result.stdout
            if result.stderr:
                output += result.stderr
            return output.rstrip(), result.returncode
        except subprocess.TimeoutExpired:
            return f"Command timed out after {timeout_s}s (sandbox)", 124
        except OSError as e:
            return f"Sandbox execution error: {e}", 1


class BashTool(Tool):
    name = "Bash"
    lock_mode = "write"
    description = """bash コマンドをサブプロセスで実行する。

使い分けの指針:
- ファイル読み込みには Read ツールを使うこと（cat の代替）
- ファイル書き込みには Write/Edit ツールを使うこと
- ファイル検索には Glob/Grep ツールを使うこと
- このツールはシステムコマンドや複合パイプライン専用

制約事項:
- バックグラウンド実行（&, nohup, setsid）は不可（run_in_background フラグを使用）
- curl|sh 等のパイプシェルは安全のためブロック
- タイムアウト：デフォルト 120 秒（最大 600 秒）
- 機密環境変数は自動除去される"""
    parameters = {
        "type": "object",
        "properties": {
            "command": {
                "type": "string",
                "description": "The bash command to execute",
            },
            "timeout": {
                "type": "number",
                "description": "Timeout in milliseconds (max 600000, default 120000)",
            },
            "run_in_background": {
                "type": "boolean",
                "description": "Run command in background and return a task ID immediately (default: false)",
            },
        },
        "required": ["command"],
    }

    def __init__(self, cwd=None, config=None):
        super().__init__(cwd)
        self._config = config
        self._sandbox = None  # lazy-init SandboxRuntime

    def _get_sandbox(self):
        """Lazy-initialize sandbox runtime if configured."""
        if self._sandbox is not None:
            return self._sandbox
        if self._config and getattr(self._config, "sandbox", None):
            sandbox_mode = self._config.sandbox
            image = getattr(self._config, "sandbox_image", "python:3-slim")
            no_network = getattr(self._config, "sandbox_no_network", False)
            rt = SandboxRuntime(self.cwd, image=image, no_network=no_network)
            if sandbox_mode == "auto":
                self._sandbox = rt if rt.is_available else False
            elif rt.is_available:
                self._sandbox = rt
            else:
                print(f"Warning: --sandbox {sandbox_mode} requested but "
                      f"{sandbox_mode} is not available. Falling back to host execution.",
                      file=sys.stderr)
                self._sandbox = False
            if self._sandbox and self._sandbox is not False:
                print(f"  Sandbox: {self._sandbox.runtime_name} ({image})"
                      f"{' [no-network]' if no_network else ''}", file=sys.stderr)
        else:
            self._sandbox = False
        return self._sandbox if self._sandbox is not False else None

    def _build_clean_env(self):
        """Build sanitized environment dict, applying shell env policy."""
        return _build_sanitized_env(self._config, kind="shell")

    @staticmethod
    def _build_exec_args(command):
        if _requires_shell_execution(command):
            return command, True
        try:
            return shlex.split(command), False
        except ValueError:
            return command, True

    def execute(self, params):
        command = params.get("command", "")
        try:
            timeout_ms = max(float(params.get("timeout", 120000)), 1000)
        except (ValueError, TypeError):
            timeout_ms = 120000
        timeout_s = min(timeout_ms / 1000, 600)

        if not command:
            return "Error: no command provided"

        # Prune completed bg tasks older than 1 hour
        now = time.time()
        with _bg_tasks_lock:
            to_remove = [k for k, v in _bg_tasks.items()
                         if v.get("result") is not None and now - v.get("start", 0) > 3600]
            for k in to_remove:
                del _bg_tasks[k]

        # bg_status: check result of a background task (before security checks)
        bg_match = re.match(r'^bg_status\s+(bg_\d+)$', command.strip())
        if bg_match:
            tid = bg_match.group(1)
            with _bg_tasks_lock:
                entry = _bg_tasks.get(tid)
            if not entry:
                runtime_state = _get_active_runtime_state()
                if runtime_state is not None:
                    job = runtime_state.get_job(tid)
                    if job:
                        state = job.get("state", "unknown")
                        if state in ("finished", "failed"):
                            summary = job.get("result_summary") or job.get("error_summary") or "(no output)"
                            return f"Task {tid} {state}:\n{summary}"
                        return (
                            f"Task {tid} is {state}. "
                            f"Command: {job.get('command_or_prompt', '') or '(unknown)'}"
                        )
                return f"Error: unknown background task '{tid}'"
            if entry["result"] is None:
                elapsed = int(time.time() - entry["start"])
                return f"Task {tid} still running ({elapsed}s elapsed). Command: {entry['command']}"
            result = entry["result"]
            # Evict completed task after returning its result
            with _bg_tasks_lock:
                _bg_tasks.pop(tid, None)
            return f"Task {tid} completed:\n{result}"

        # --- Security checks (apply to BOTH foreground and background) ---

        # Detect background/async commands (comprehensive patterns)
        _BG_PATTERNS = [
            r'&\s*$',               # trailing &
            r'&\s*\)',              # & before closing paren
            r'&\s*;',              # & before semicolon
            r'\bnohup\b',          # nohup
            r'\bsetsid\b',         # setsid
            r'\bdisown\b',         # disown
            r'\bscreen\s+-[dDm]',  # detached screen
            r'\btmux\b.*\b(new|send)',  # tmux new/send
            r'\bat\s+now\b',       # at scheduler
            r"bash\s+-c\s+['\"].*&",  # bash -c with background
            r"sh\s+-c\s+['\"].*&",    # sh -c with background
        ]
        for pat in _BG_PATTERNS:
            if re.search(pat, command):
                return ("Error: background/async commands are not supported in this environment. "
                        "Commands must complete and return output. Remove async patterns and try again.")

        # Block dangerous commands (defense-in-depth, even in -y mode)
        _DANGEROUS_PATTERNS = [
            r'\bcurl\b.*\|\s*\bsh\b',       # curl pipe to shell
            r'\bwget\b.*\|\s*\bsh\b',       # wget pipe to shell
            r'\|\s*(?:env\s+)?(?:sh|bash|zsh|dash|ksh|fish)\b',
            r'\|\s*(?:python|python3|perl|ruby|node|php)\b',
            r'\b(?:sh|bash|zsh|dash|ksh|fish)\s+-c\b',
            r'[`][^`]+[`]',
            r'\$\([^)]+\)',
            r'<\([^)]+\)',
            r'\brm\s+-rf\s+/',              # rm -rf from root
            r'\bmkfs\b',                     # format filesystem
            r'\bdd\b.*\bof=/dev/',          # dd to device
            r'>\s*/etc/',                    # overwrite system files
            r'\beval\b.*\bbase64\b',        # eval with base64 decode
        ]
        for pat in _DANGEROUS_PATTERNS:
            if re.search(pat, command, re.IGNORECASE):
                return ("Error: this command pattern is blocked for safety. "
                        "If you need to run this, do it manually outside eve-coder.")

        # Block commands that could tamper with permission/config files
        _PROTECTED_BASENAMES = {"permissions.json", ".eve-coder.json", "config.json"}
        _WRITE_INDICATORS = (">", ">>", "tee ", "mv ", "cp ", "echo ", "cat ",
                             "sed ", "dd ", "install ", "printf ", "perl ",
                             "python", "ruby ", "bash -c", "sh -c", "ln ")
        cmd_lower = command.lower()
        for ppath in _PROTECTED_BASENAMES:
            if ppath in cmd_lower and any(w in cmd_lower for w in _WRITE_INDICATORS):
                return f"Error: writing to {ppath} via shell is blocked for security. Use the config system instead."

        # --- End security checks ---

        # run_in_background: spawn in thread, return task ID immediately
        if params.get("run_in_background", False):
            with _bg_tasks_lock:
                _bg_task_counter[0] += 1
                task_id = f"bg_{_bg_task_counter[0]}"
            # Build sanitized env for background commands (same as foreground)
            bg_clean_env = self._build_clean_env()
            def _run_bg(tid, cmd, t_s):
                state = "finished"
                proc = None
                try:
                    _bg_pgroup = platform.system() != "Windows"
                    exec_args, use_shell = self._build_exec_args(cmd)
                    proc = subprocess.Popen(
                        exec_args, shell=use_shell, stdin=subprocess.DEVNULL,
                        stdout=subprocess.PIPE, stderr=subprocess.PIPE,
                        text=True, encoding="utf-8", errors="replace",
                        cwd=self._base_dir(), env=bg_clean_env,
                        start_new_session=_bg_pgroup,
                    )
                    stdout, stderr = proc.communicate(timeout=t_s)
                    out = (stdout or "") + ("\n" + stderr if stderr else "")
                    if proc.returncode != 0:
                        state = "failed"
                        out += f"\n(exit code: {proc.returncode})"
                    if len(out) > 30000:
                        out = out[:15000] + "\n...(truncated)...\n" + out[-15000:]
                except subprocess.TimeoutExpired:
                    state = "failed"
                    # Kill entire process group on Unix, then the process itself
                    if hasattr(os, "killpg"):
                        try:
                            os.killpg(os.getpgid(proc.pid), signal.SIGKILL)
                        except (OSError, ProcessLookupError):
                            pass
                    proc.kill()
                    try:
                        proc.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        pass  # Process may be truly stuck — OS will reap eventually
                    out = (f"Error: background command timed out after {int(t_s)}s.\n"
                           f"  Command: {cmd[:200]}{'...' if len(cmd) > 200 else ''}\n"
                           "  Hint: break into smaller steps or increase timeout.")
                except Exception as e:
                    state = "failed"
                    out = f"Error: {e}"
                finally:
                    if proc is not None:
                        for _stream in (proc.stdout, proc.stderr):
                            if _stream is not None:
                                try:
                                    _stream.close()
                                except Exception:
                                    pass
                with _bg_tasks_lock:
                    _bg_tasks[tid]["result"] = out.strip() or "(no output)"
                runtime_state = _get_active_runtime_state()
                if runtime_state is not None:
                    runtime_state.upsert_job(
                        tid,
                        "bash",
                        state,
                        command_or_prompt=cmd,
                        result_summary=out if state == "finished" else "",
                        error_summary=out if state != "finished" else "",
                    )
            with _bg_tasks_lock:
                # Evict completed tasks older than 1 hour, then enforce cap
                now = time.time()
                stale = [k for k, v in _bg_tasks.items()
                         if v.get("result") is not None and now - v.get("start", 0) > 3600]
                for k in stale:
                    del _bg_tasks[k]
                if len(_bg_tasks) >= MAX_BG_TASKS:
                    # Remove oldest completed task
                    oldest = min((k for k, v in _bg_tasks.items() if v.get("result") is not None),
                                 key=lambda k: _bg_tasks[k].get("start", 0), default=None)
                    if oldest:
                        del _bg_tasks[oldest]
                    else:
                        return f"Error: too many background tasks ({MAX_BG_TASKS}). Wait for some to complete."
                _bg_tasks[task_id] = {"thread": None, "result": None,
                                       "command": command, "start": time.time()}
            t = threading.Thread(target=_run_bg, args=(task_id, command, timeout_s), daemon=True)
            with _bg_tasks_lock:
                _bg_tasks[task_id]["thread"] = t
            runtime_state = _get_active_runtime_state()
            if runtime_state is not None:
                runtime_state.upsert_job(
                    task_id,
                    "bash",
                    "running",
                    command_or_prompt=command,
                )
            t.start()
            return f"Background task started: {task_id}\nUse Bash(command='bg_status {task_id}') to check result."

        try:
            # Sandbox routing: if sandbox is configured, execute via container
            sandbox = self._get_sandbox()
            if sandbox:
                clean_env = self._build_clean_env()
                output, returncode = sandbox.run_command(command, timeout_s=timeout_s, env=clean_env)
                if returncode != 0:
                    return f"{output}\n(exit code: {returncode})"
                return output if output else "(no output)"

            clean_env = self._build_clean_env()
            # Use process group on Unix to ensure all child processes are killed on timeout
            use_pgroup = platform.system() != "Windows"
            exec_args, use_shell = self._build_exec_args(command)
            popen_kwargs = {
                "shell": use_shell,
                "stdin": subprocess.DEVNULL,
                "stdout": subprocess.PIPE,
                "stderr": subprocess.PIPE,
                "text": True,
                "encoding": "utf-8",
                "errors": "replace",
                "cwd": self._base_dir(),
                "env": clean_env,
            }
            if use_pgroup:
                popen_kwargs["start_new_session"] = True  # create new process group
            # Use Popen instead of run() to access PID for process group cleanup on timeout
            proc = None
            try:
                proc = subprocess.Popen(exec_args, **popen_kwargs)
                try:
                    stdout, stderr = proc.communicate(timeout=timeout_s)
                except subprocess.TimeoutExpired:
                    # Kill entire process group (not just shell) to prevent zombies
                    if use_pgroup:
                        try:
                            os.killpg(os.getpgid(proc.pid), signal.SIGKILL)
                        except (OSError, ProcessLookupError):
                            pass
                    proc.kill()
                    try:
                        proc.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        pass
                    # Hang diagnosis: provide actionable context for timeout
                    _diag_lines = [
                        f"Error: command timed out after {int(timeout_s)}s and was killed.",
                        f"  Command: {command[:200]}{'...' if len(command) > 200 else ''}",
                        "  Possible causes:",
                        "    - Interactive prompt waiting for input (add -y/--yes or echo | ...)",
                        "    - Network request to unreachable host (check connectivity)",
                        "    - Infinite loop or deadlock in the program",
                        "    - Large dataset processing (increase timeout parameter)",
                        "  Next steps:",
                        "    - Break the command into smaller parts to isolate the slow step",
                        "    - Add timeout/--max-time flag to sub-commands (e.g. curl --max-time 30)",
                        f"    - Increase timeout: Bash(command='...', timeout={int(min(timeout_ms * 2, 600000))})",
                    ]
                    return "\n".join(_diag_lines)
                output = ""
                if stdout:
                    output += stdout
                if stderr:
                    if output:
                        output += "\n"
                    output += stderr
                if proc.returncode != 0:
                    output += f"\n(exit code: {proc.returncode})"
                if not output.strip():
                    output = "(no output)"
                # Truncate very long output
                if len(output) > 30000:
                    output = output[:15000] + "\n\n... (truncated) ...\n\n" + output[-15000:]
                return output.strip()
            finally:
                if proc is not None:
                    for _stream in (proc.stdout, proc.stderr):
                        if _stream is not None:
                            try:
                                _stream.close()
                            except Exception:
                                pass
        except Exception as e:
            return f"Error: {e}"


IMAGE_EXTENSIONS = {".png", ".jpg", ".jpeg", ".gif", ".bmp", ".webp", ".svg", ".ico", ".tiff", ".tif"}
IMAGE_MAX_SIZE = 10 * 1024 * 1024  # 10MB limit for image files
AUDIO_EXTENSIONS = {".mp3", ".wav", ".flac", ".aac", ".ogg", ".m4a", ".opus"}
AUDIO_MAX_SIZE = 20 * 1024 * 1024  # 20MB limit for audio files


_MEDIA_TYPES = {
    ".png": "image/png",
    ".jpg": "image/jpeg",
    ".jpeg": "image/jpeg",
    ".gif": "image/gif",
    ".bmp": "image/bmp",
    ".webp": "image/webp",
    ".svg": "image/svg+xml",
    ".ico": "image/x-icon",
    ".tiff": "image/tiff",
    ".tif": "image/tiff",
    ".mp3": "audio/mpeg",
    ".wav": "audio/wav",
    ".flac": "audio/flac",
    ".aac": "audio/aac",
    ".ogg": "audio/ogg",
    ".m4a": "audio/mp4",
    ".opus": "audio/opus",
}


def _extract_image_paths(text):
    """Extract image file paths from text (handles drag & drop into terminal).
    Returns (cleaned_text, list_of_image_paths)."""
    import shlex
    image_paths = []
    remaining_parts = []

    # Split by whitespace but respect quotes
    try:
        tokens = shlex.split(text)
    except ValueError:
        tokens = text.split()

    for token in tokens:
        # Strip file:// prefix (macOS Finder drag)
        cleaned = token
        if cleaned.startswith("file://"):
            cleaned = urllib.parse.unquote(cleaned[7:])
        # Strip surrounding quotes
        cleaned = cleaned.strip("'\"")
        # Check if it looks like an image path
        ext = os.path.splitext(cleaned)[1].lower()
        if ext in IMAGE_EXTENSIONS and os.path.isfile(cleaned):
            image_paths.append(cleaned)
        else:
            remaining_parts.append(token)

    cleaned_text = " ".join(remaining_parts)
    return cleaned_text, image_paths


def _read_image_as_base64(file_path):
    """Read image file and return (base64_data, media_type) or (None, error_msg)."""
    ext = os.path.splitext(file_path)[1].lower()
    if ext not in IMAGE_EXTENSIONS:
        return None, f"Not an image file: {file_path}"
    try:
        file_size = os.path.getsize(file_path)
    except OSError as e:
        return None, f"Cannot read file: {e}"
    if file_size > IMAGE_MAX_SIZE:
        return None, f"Image too large ({file_size // 1_000_000}MB, max 10MB)"
    if file_size == 0:
        return None, "Image file is empty"
    media_type = _MEDIA_TYPES.get(ext, "application/octet-stream")
    try:
        with open(file_path, "rb") as f:
            data = base64.b64encode(f.read()).decode("ascii")
        return (data, media_type), None
    except Exception as e:
        err_msg = t('errors.image_read_error', default=f"Error reading image: {e}")
        return None, err_msg


def _read_audio_as_base64(file_path):
    """Read audio file and return (base64_data, media_type) or (None, error_msg)."""
    ext = os.path.splitext(file_path)[1].lower()
    if ext not in AUDIO_EXTENSIONS:
        return None, f"Not an audio file: {file_path}"
    try:
        file_size = os.path.getsize(file_path)
    except OSError as e:
        return None, f"Cannot read file: {e}"
    if file_size > AUDIO_MAX_SIZE:
        return None, f"Audio too large ({file_size // 1_000_000}MB, max 20MB)"
    if file_size == 0:
        return None, "Audio file is empty"
    media_type = _MEDIA_TYPES.get(ext, "audio/octet-stream")
    try:
        with open(file_path, "rb") as f:
            data = base64.b64encode(f.read()).decode("ascii")
        return (data, media_type), None
    except Exception as e:
        err_msg = t('errors.audio_read_error', default=f"Error reading audio: {e}")
        return None, err_msg


def _clipboard_image_to_file():
    """Save clipboard image to a temp file (macOS only). Returns file path or None."""
    if platform.system() != "Darwin":
        return None
    try:
        # Check if clipboard has image data
        result = subprocess.run(
            ["osascript", "-e", "clipboard info"],
            capture_output=True, text=True, timeout=5
        )
        has_image = any(x in result.stdout for x in ["PNGf", "TIFF", "public.png", "public.tiff"])
        if not has_image:
            return None
        # Save clipboard image as PNG
        tmp_path = os.path.join(tempfile.gettempdir(), f"eve-clipboard-{uuid.uuid4().hex[:8]}.png")
        subprocess.run(
            ["osascript", "-e",
             f'set fp to POSIX file "{tmp_path}"\n'
             'set imgData to the clipboard as «class PNGf»\n'
             'set fh to open for access fp with write permission\n'
             'write imgData to fh\n'
             'close access fh'],
            capture_output=True, text=True, timeout=10
        )
        if os.path.isfile(tmp_path) and os.path.getsize(tmp_path) > 0:
            return tmp_path
        return None
    except Exception:
        return None


def _build_multimodal_content(text, image_data_list):
    """Build OpenAI-compatible multipart content with text and images.
    image_data_list: list of (base64_data, media_type) tuples.
    Returns a list suitable for message content field."""
    parts = []
    if text.strip():
        parts.append({"type": "text", "text": text})
    for b64_data, media_type in image_data_list:
        parts.append({
            "type": "image_url",
            "image_url": {"url": f"data:{media_type};base64,{b64_data}"}
        })
    return parts if len(parts) > 1 or not text.strip() else text


class ReadTool(Tool):
    name = "Read"
    lock_mode = "read"
    parallel_safe = True
    description = "Read a file from the filesystem. Returns content with line numbers. Can also read image files for multimodal models and identify audio inputs."
    parameters = {
        "type": "object",
        "properties": {
            "file_path": {
                "type": "string",
                "description": "Absolute path to the file to read",
            },
            "offset": {
                "type": "number",
                "description": "Line number to start reading from (1-based)",
            },
            "limit": {
                "type": "number",
                "description": "Number of lines to read",
            },
        },
        "required": ["file_path"],
    }

    def execute(self, params):
        file_path = params.get("file_path", "")
        try:
            offset = int(params.get("offset", 1))
        except (ValueError, TypeError):
            offset = 1
        try:
            limit = int(params.get("limit", 2000))
        except (ValueError, TypeError):
            limit = 2000

        if not file_path:
            return "Error: no file_path provided"
        if not os.path.isabs(file_path):
            file_path = os.path.join(self._base_dir(), file_path)

        # Security: Ensure file is within repo directory
        if not self._is_path_within_repo(file_path):
            return f"Error: access denied - file is outside repository: {file_path}"

        # Resolve symlinks to detect escapes
        try:
            real_path = os.path.realpath(file_path)
        except (OSError, ValueError):
            return f"Error: cannot resolve path: {file_path}"
        if not os.path.exists(real_path):
            return f"Error: file not found: {file_path}"
        if os.path.isdir(real_path):
            return f"Error: {file_path} is a directory, not a file"
        # Double-check after resolution
        if not self._is_path_within_repo(real_path):
            return f"Error: access denied - resolved path is outside repository"
        # Use resolved path for actual reading
        file_path = real_path

        # Detect file extension for special handling
        _, ext = os.path.splitext(file_path)
        ext_lower = ext.lower()

        # PDF reading — basic text extraction (stdlib only, no pdfminer/PyPDF2 needed)
        if ext_lower == ".pdf":
            return self._read_pdf(file_path, params)

        # Jupyter notebook reading — parse and format cells with outputs
        if ext_lower == ".ipynb":
            try:
                nb_size = os.path.getsize(file_path)
                if nb_size > 50_000_000:  # 50MB
                    return f"Error: notebook too large ({nb_size // 1_000_000}MB). Max 50MB."
                with open(file_path, "r", encoding="utf-8") as f:
                    nb = json.load(f)
                cells = nb.get("cells", [])
                if not cells:
                    return "(empty notebook)"
                parts = []
                for i, cell in enumerate(cells):
                    ctype = cell.get("cell_type", "code")
                    source = "".join(cell.get("source", []))
                    parts.append(f"--- Cell {i} [{ctype}] ---")
                    parts.append(source)
                    # Show text outputs for code cells
                    for out in cell.get("outputs", []):
                        if out.get("output_type") == "stream":
                            parts.append(f"[stdout] {''.join(out.get('text', []))}")
                        elif out.get("output_type") in ("execute_result", "display_data"):
                            text_data = out.get("data", {}).get("text/plain", [])
                            if text_data:
                                parts.append(f"[output] {''.join(text_data)}")
                        elif out.get("output_type") == "error":
                            parts.append(f"[error] {out.get('ename','')}: {out.get('evalue','')}")
                return "\n".join(parts)
            except json.JSONDecodeError:
                return "Error: invalid .ipynb JSON"
            except Exception as e:
                return f"Error reading notebook: {e}"

        # Image file handling — read as base64 for multimodal models
        if ext_lower in IMAGE_EXTENSIONS:
            try:
                file_size = os.path.getsize(file_path)
            except OSError as e:
                return f"Error: cannot determine file size: {e}"
            if file_size > IMAGE_MAX_SIZE:
                return f"Error: image too large ({file_size // 1_000_000}MB). Max 10MB for images."
            if file_size == 0:
                return "Error: image file is empty (0 bytes)."
            media_type = _MEDIA_TYPES.get(ext_lower, "application/octet-stream")
            try:
                with open(file_path, "rb") as f:
                    data = base64.b64encode(f.read()).decode("ascii")
                return json.dumps({
                    "type": "image",
                    "media_type": media_type,
                    "data": data,
                })
            except Exception as e:
                return f"Error reading image file: {e}"

        if ext_lower in AUDIO_EXTENSIONS:
            try:
                file_size = os.path.getsize(file_path)
            except OSError as e:
                return f"Error: cannot determine file size: {e}"
            if file_size > AUDIO_MAX_SIZE:
                return f"Error: audio too large ({file_size // 1_000_000}MB). Max 20MB for audio files."
            if file_size == 0:
                return "Error: audio file is empty (0 bytes)."
            media_type = _MEDIA_TYPES.get(ext_lower, "audio/octet-stream")
            return (
                f"[Audio file detected: {os.path.basename(file_path)} ({media_type}, {file_size} bytes)]\n"
                "Ollama's current chat API does not accept audio attachments yet, so this CLI cannot forward "
                "the audio contents to the model directly. Ask for a transcript or use a speech-to-text step first."
            )

        # Check file size (100MB limit)
        try:
            file_size = os.path.getsize(file_path)
            if file_size > 100_000_000:
                return f"Error: file too large ({file_size // 1_000_000}MB). Max 100MB."
        except OSError as e:
            return f"Error: cannot determine file size: {e}"

        # Check for binary files
        try:
            # SEC-2: TOCTOU mitigation — verify inode consistency after open to detect
            # symlink races between realpath() resolution and the actual open().
            pre_stat = os.stat(file_path)
            with open(file_path, "rb") as f:
                post_stat = os.fstat(f.fileno())
                if pre_stat.st_ino != post_stat.st_ino or pre_stat.st_dev != post_stat.st_dev:
                    return "Error: access denied - file changed during open (possible symlink race)"
                sample = f.read(8192)
                if b"\x00" in sample:
                    size = post_stat.st_size
                    return f"(binary file, {size} bytes)"
        except Exception as e:
            return f"Error reading file: {e}"

        try:
            from itertools import islice
            # Use islice for efficient partial reads (skips lines at C level)
            start = max(0, offset - 1)
            output_parts = []
            total_lines = None
            with open(file_path, "r", encoding="utf-8", errors="replace") as f:
                for i, line in enumerate(islice(f, start, start + limit)):
                    lineno = start + i
                    # Truncate very long lines
                    if len(line) > 2000:
                        line = line[:2000] + "...(truncated)\n"
                    output_parts.append(f"{lineno + 1:>6}\t{line}")
                # Count remaining lines to detect truncation
                remaining = sum(1 for _ in f)
                if remaining > 0:
                    total_lines = start + len(output_parts) + remaining

            if not output_parts:
                return "(empty file)"
            result = "".join(output_parts)
            if total_lines is not None:
                shown_start = start + 1
                shown_end = start + len(output_parts)
                result += (f"\n(truncated: showing lines {shown_start}-{shown_end} "
                           f"of {total_lines} total. Use offset/limit to read more.)")
            return result
        except Exception as e:
            return f"Error reading file: {e}"

    def _read_pdf(self, file_path, params):
        """Extract text from PDF files using stdlib only.

        Uses a simple stream-object parser to extract text from PDF content streams.
        Handles basic text operators (Tj, TJ, ', \"). Not a full PDF parser —
        encrypted, image-only, or complex-layout PDFs may return minimal text.
        """
        try:
            file_size = os.path.getsize(file_path)
            if file_size > 100_000_000:  # 100MB
                return f"Error: PDF too large ({file_size // 1_000_000}MB). Max 100MB."
            with open(file_path, "rb") as f:
                data = f.read()
        except Exception as e:
            return f"Error reading PDF: {e}"

        pages_param = params.get("pages", "")
        import zlib as _zlib

        # Extract all stream objects (contain page content)
        all_text = []
        stream_pat = re.compile(rb'stream\r?\n(.*?)endstream', re.DOTALL)
        for match in stream_pat.finditer(data):
            raw = match.group(1)
            # Try FlateDecode decompression
            try:
                raw = _zlib.decompress(raw)
            except Exception:
                pass  # might not be compressed
            # Extract text from PDF operators: Tj, TJ, ', "
            text_parts = []
            for m in re.finditer(rb'\(([^)]*)\)\s*Tj', raw):
                text_parts.append(m.group(1).decode("latin-1", errors="replace"))
            # TJ array: [(text) num (text) ...] TJ
            for m in re.finditer(rb'\[(.*?)\]\s*TJ', raw, re.DOTALL):
                for s in re.finditer(rb'\(([^)]*)\)', m.group(1)):
                    text_parts.append(s.group(1).decode("latin-1", errors="replace"))
            # ' and " operators
            for m in re.finditer(rb'\(([^)]*)\)\s*[\'""]', raw):
                text_parts.append(m.group(1).decode("latin-1", errors="replace"))
            if text_parts:
                page_text = "".join(text_parts)
                # Decode PDF escape sequences
                page_text = page_text.replace("\\n", "\n").replace("\\r", "\r")
                page_text = page_text.replace("\\t", "\t").replace("\\(", "(").replace("\\)", ")")
                page_text = re.sub(r'\\(\d{1,3})', lambda m: chr(int(m.group(1), 8)), page_text)
                all_text.append(page_text)

        if not all_text:
            return "(PDF contains no extractable text — may be image-only or encrypted)"

        # Apply page filtering if requested
        if pages_param:
            try:
                selected = set()
                for part in pages_param.split(","):
                    part = part.strip()
                    if "-" in part:
                        start, end = part.split("-", 1)
                        for p in range(int(start), int(end) + 1):
                            selected.add(p)
                    else:
                        selected.add(int(part))
                filtered = []
                for i, text in enumerate(all_text, 1):
                    if i in selected:
                        filtered.append(f"--- Page {i} ---\n{text}")
                if not filtered:
                    return f"Error: requested pages {pages_param} not found (PDF has {len(all_text)} pages)"
                return "\n\n".join(filtered)
            except (ValueError, TypeError):
                return f"Error: invalid pages parameter: {pages_param}"

        # Return all pages with page markers
        parts = []
        for i, text in enumerate(all_text, 1):
            parts.append(f"--- Page {i} ---\n{text}")
        result = "\n\n".join(parts)
        # Truncate if very large
        if len(result) > 500_000:
            result = result[:500_000] + f"\n...(truncated, {len(all_text)} total pages)"
        return result


def _is_protected_path(file_path):
    """Check if a file path points to a protected config/permission file."""
    _PROTECTED_BASENAMES = {"permissions.json", ".eve-coder.json", "config.json"}
    try:
        real = os.path.realpath(file_path)
        basename = os.path.basename(real)
        if basename in _PROTECTED_BASENAMES:
            return True
        # Check both eve-cli and legacy eve-coder config directories
        for dirname in ("eve-cli", "eve-coder"):
            config_dir = os.path.join(os.path.expanduser("~"), ".config", dirname)
            real_config_dir = os.path.realpath(config_dir)
            if real.startswith(real_config_dir + os.sep) or real == real_config_dir:
                return True
    except (OSError, ValueError):
        pass
    return False


def _path_is_within_root(path, root):
    """Return True when path resolves inside root (or equals root)."""
    return path == root or path.startswith(root + os.sep)


def _resolve_repo_path(base_dir, target_path, require_exists=False, path_label="path"):
    """Resolve a path and enforce repository containment."""
    repo_root = os.path.realpath(base_dir or os.getcwd())
    candidate = target_path if os.path.isabs(target_path) else os.path.join(repo_root, target_path)
    try:
        if os.path.islink(candidate):
            return None, f"Error: refusing to access through symlink: {candidate}"
        resolved = os.path.realpath(candidate)
    except (OSError, ValueError):
        return None, f"Error: cannot resolve path: {candidate}"
    if require_exists and not os.path.exists(resolved):
        return None, f"Error: {path_label} not found: {candidate}"
    if not _path_is_within_root(resolved, repo_root):
        return None, f"Error: access denied - {path_label} is outside repository: {candidate}"
    return resolved, None


def _resolve_repo_storage_path(base_dir, *parts):
    """Resolve a repo-local storage path and reject symlinked path components."""
    abs_base = os.path.abspath(base_dir or os.getcwd())
    repo_root = os.path.realpath(abs_base)
    candidate = os.path.join(abs_base, *parts)
    try:
        resolved = os.path.realpath(candidate)
    except (OSError, ValueError) as e:
        raise OSError(f"cannot resolve path: {candidate}") from e
    if not _path_is_within_root(resolved, repo_root):
        raise OSError(f"resolved path is outside repository: {candidate}")

    cur = candidate
    while True:
        if os.path.lexists(cur) and os.path.islink(cur):
            raise OSError(f"symlink path component not allowed: {cur}")
        if os.path.abspath(cur) == abs_base:
            break
        parent = os.path.dirname(cur)
        if parent == cur:
            break
        cur = parent
    return resolved


def _normalize_patch_target_path(raw_path):
    """Normalize unified-diff paths like a/foo, b/foo, or /dev/null."""
    if not isinstance(raw_path, str):
        return ""
    token = raw_path.strip().split("\t", 1)[0].strip()
    if not token:
        return ""
    if token == "/dev/null":
        return token
    if token.startswith("a/") or token.startswith("b/"):
        token = token[2:]
    return token


def _read_text_file_for_patch(file_path):
    try:
        with open(file_path, "rb") as bf:
            sample = bf.read(8192)
            if b"\x00" in sample:
                return None, f"Error: {file_path} appears to be a binary file — patching refused."
        with open(file_path, "r", encoding="utf-8", errors="replace", newline="") as f:
            return f.read(), None
    except OSError as e:
        return None, f"Error reading file: {e}"


def _split_patch_lines_with_endings(text):
    lines = text.splitlines(keepends=True)
    if text and not text.endswith(("\n", "\r")) and lines:
        return lines
    return lines


def _apply_unified_patch_to_text(original_text, hunks):
    original_lines = _split_patch_lines_with_endings(original_text)
    out_lines = []
    cursor = 0
    for hunk in hunks:
        old_start = max(1, int(hunk["old_start"]))
        target_index = max(0, old_start - 1)
        if target_index < cursor:
            return None, "Error: overlapping hunks are not supported."
        if target_index > len(original_lines):
            return None, "Error: patch hunk starts past end of file."
        out_lines.extend(original_lines[cursor:target_index])
        cursor = target_index
        for sign, text in hunk["lines"]:
            if sign == " ":
                if cursor >= len(original_lines) or original_lines[cursor] != text:
                    return None, "Error: patch context does not match file contents."
                out_lines.append(original_lines[cursor])
                cursor += 1
            elif sign == "-":
                if cursor >= len(original_lines) or original_lines[cursor] != text:
                    return None, "Error: patch removal does not match file contents."
                cursor += 1
            elif sign == "+":
                out_lines.append(text)
        # Ignore old/new counts; verified by context/removals above.
    out_lines.extend(original_lines[cursor:])
    return "".join(out_lines), None


def _parse_unified_patch_text(patch_text):
    """Parse a limited unified diff for text files.

    Supports:
    - one or more file sections
    - ---/+++ headers
    - @@ hunk headers
    - added/removed/context lines
    """
    if not isinstance(patch_text, str) or not patch_text.strip():
        return None, "Error: patch cannot be empty"
    lines = patch_text.splitlines(keepends=True)
    files = []
    i = 0
    while i < len(lines):
        line = lines[i]
        if line.startswith(("diff --git ", "index ", "new file mode ", "deleted file mode ")):
            i += 1
            continue
        if not line.startswith("--- "):
            i += 1
            continue
        if i + 1 >= len(lines) or not lines[i + 1].startswith("+++ "):
            return None, "Error: malformed patch header"
        old_path = _normalize_patch_target_path(line[4:])
        new_path = _normalize_patch_target_path(lines[i + 1][4:])
        if old_path == "/dev/null" and new_path == "/dev/null":
            return None, "Error: patch cannot target /dev/null on both sides"
        entry = {"old_path": old_path, "new_path": new_path, "hunks": []}
        i += 2
        while i < len(lines):
            cur = lines[i]
            if cur.startswith(("diff --git ", "--- ")):
                break
            if cur.startswith("@@"):
                m = re.match(r"^@@ -(\d+)(?:,(\d+))? \+(\d+)(?:,(\d+))? @@", cur)
                if not m:
                    return None, f"Error: invalid patch hunk header: {cur.strip()}"
                hunk = {
                    "old_start": int(m.group(1)),
                    "old_count": int(m.group(2) or "1"),
                    "new_start": int(m.group(3)),
                    "new_count": int(m.group(4) or "1"),
                    "lines": [],
                }
                i += 1
                while i < len(lines):
                    body = lines[i]
                    if body.startswith(("diff --git ", "--- ", "@@")):
                        break
                    if body.startswith("\\ No newline at end of file"):
                        i += 1
                        continue
                    if not body or body[0] not in (" ", "+", "-"):
                        return None, f"Error: invalid patch body line: {body.rstrip()}"
                    hunk["lines"].append((body[0], body[1:]))
                    i += 1
                entry["hunks"].append(hunk)
                continue
            i += 1
        if not entry["hunks"]:
            return None, f"Error: patch for {new_path or old_path} has no hunks"
        files.append(entry)
    if not files:
        return None, "Error: no file sections found in patch"
    return files, None


_TOOL_EXECUTION_RWLOCK = ReadWriteLock()


class WriteTool(Tool):
    name = "Write"
    description = """新規ファイルを作成する、または既存ファイルを全上書きする。

重要:
- 既存ファイルの一部を変更する場合は Edit ツールを使うこと
- 大きなファイル（500 行超）は分割して生成することを検討
- パスはプロジェクトルートからの相対パスまたは絶対パスで指定"""
    parameters = {
        "type": "object",
        "properties": {
            "file_path": {
                "type": "string",
                "description": "Absolute path to write to",
            },
            "content": {
                "type": "string",
                "description": "The content to write",
            },
        },
        "required": ["file_path", "content"],
    }
    lock_mode = "write"

    MAX_WRITE_SIZE = 10 * 1024 * 1024  # 10MB write size limit

    def execute(self, params):
        file_path = params.get("file_path", "")
        content = params.get("content", "")

        if not file_path:
            return "Error: no file_path provided"
        if len(content) > self.MAX_WRITE_SIZE:
            return (f"Error: content too large ({len(content) // 1_000_000}MB). "
                    f"Max write size is {self.MAX_WRITE_SIZE // (1024*1024)}MB. Split into smaller writes.")
        file_path, path_error = _resolve_repo_path(self._base_dir(), file_path, path_label="file")
        if path_error:
            if "symlink" in path_error.lower():
                return path_error.replace("access through", "write through")
            return path_error

        # Block writes to protected config/permission files
        if _is_protected_path(file_path):
            return f"Error: writing to {os.path.basename(file_path)} is blocked for security. Use the config system instead."

        tmp_path = None
        try:
            # Backup for /undo — use separate variable to preserve new content
            if os.path.exists(file_path):
                try:
                    with open(file_path, "r", encoding="utf-8", errors="replace") as uf:
                        old_content = uf.read(1_048_576 + 1)  # 1MB + 1 to detect overflow
                    if len(old_content) <= 1_048_576:
                        _undo_stack.append((file_path, old_content))
                    # else: skip — file too large to store in undo stack
                except Exception:
                    pass

            dirname = os.path.dirname(file_path)
            if dirname:
                os.makedirs(dirname, exist_ok=True)
            # Atomic write: mkstemp + rename (crash-safe, no predictable name)
            fd, tmp_path = tempfile.mkstemp(dir=dirname or ".", suffix=".eve_tmp")
            try:
                with os.fdopen(fd, "w", encoding="utf-8") as f:
                    f.write(content)
                # SEC-4: Restrict permissions on sensitive files (new files only)
                _is_new_file = not os.path.exists(file_path)
                if _is_new_file:
                    _basename_lower = os.path.basename(file_path).lower()
                    _SENSITIVE_PATTERNS = (".env", "secret", "credential", "key", "token", "password", "passwd")
                    if any(p in _basename_lower for p in _SENSITIVE_PATTERNS):
                        os.chmod(tmp_path, 0o600)
                os.replace(tmp_path, file_path)
            except Exception:
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                raise
            lines = content.count("\n") + (1 if content and not content.endswith("\n") else 0)
            return f"Wrote {len(content)} bytes ({lines} lines) to {file_path}"
        except Exception as e:
            # Clean up temp file on error
            try:
                if tmp_path and os.path.exists(tmp_path):
                    os.unlink(tmp_path)
            except Exception:
                pass
            return f"Error writing file: {e}"


class EditTool(Tool):
    name = "Edit"
    description = """既存ファイルの特定箇所を置換編集する。

重要:
- 新規ファイル作成には Write ツールを使うこと
- old_string は一意に特定できる十分なコンテキストを含めること
- 同じ文字列が複数箇所にある場合は replace_all パラメータを使うこと"""
    parameters = {
        "type": "object",
        "properties": {
            "file_path": {
                "type": "string",
                "description": "Absolute path to the file to edit",
            },
            "old_string": {
                "type": "string",
                "description": "The exact text to find and replace",
            },
            "new_string": {
                "type": "string",
                "description": "The replacement text",
            },
            "replace_all": {
                "type": "boolean",
                "description": "Replace all occurrences (default: false)",
            },
        },
        "required": ["file_path", "old_string", "new_string"],
    }
    lock_mode = "write"

    def execute(self, params):
        file_path = params.get("file_path", "")
        old_string = params.get("old_string", "")
        new_string = params.get("new_string", "")
        replace_all = params.get("replace_all", False)

        if not file_path:
            return "Error: no file_path provided"
        if not old_string:
            return "Error: old_string cannot be empty"
        if old_string == new_string:
            return "Error: old_string and new_string are identical"
        file_path, path_error = _resolve_repo_path(
            self._base_dir(), file_path, require_exists=True, path_label="file"
        )
        if path_error:
            if "symlink" in path_error.lower():
                return path_error.replace("access through", "edit through")
            return path_error

        # Block edits to protected config/permission files
        if _is_protected_path(file_path):
            return f"Error: editing {os.path.basename(file_path)} is blocked for security. Use the config system instead."

        # File size guard — prevent OOM on huge files
        try:
            file_size = os.path.getsize(file_path)
            if file_size > 50 * 1024 * 1024:  # 50MB
                return f"Error: file too large for editing ({file_size // 1_000_000}MB). Max 50MB."
        except OSError:
            pass

        # Detect binary files before editing (prevent corruption)
        try:
            with open(file_path, "rb") as bf:
                sample = bf.read(8192)
                if b"\x00" in sample:
                    return f"Error: {file_path} appears to be a binary file — editing refused."
        except OSError:
            pass

        try:
            with open(file_path, "r", encoding="utf-8", errors="replace") as f:
                content = f.read()
        except Exception as e:
            return f"Error reading file: {e}"

        # Try raw match first to avoid rewriting untouched content (R4-05 phantom diffs fix)
        used_normalized = False
        count = content.count(old_string)
        if count == 0:
            # Fallback: normalize Unicode (NFC) for reliable matching (macOS uses NFD)
            norm_content = unicodedata.normalize("NFC", content)
            norm_old = unicodedata.normalize("NFC", old_string)
            count = norm_content.count(norm_old)
            if count == 0:
                return "Error: old_string not found in file. Read the file first to verify exact content, including whitespace and indentation."
            used_normalized = True
        if count > 1 and not replace_all:
            return (f"Error: old_string found {count} times. "
                    f"Provide more context to make it unique, or set replace_all=true.")

        if used_normalized:
            # Normalize for matching only — avoid rewriting untouched content
            norm_new = unicodedata.normalize("NFC", new_string)
            if replace_all:
                new_content = norm_content.replace(norm_old, norm_new)
            else:
                new_content = norm_content.replace(norm_old, norm_new, 1)
        else:
            if replace_all:
                new_content = content.replace(old_string, new_string)
            else:
                new_content = content.replace(old_string, new_string, 1)

        # Backup for /undo (cap at 1MB per entry; deque maxlen=20 handles limit)
        try:
            if len(content) <= 1_048_576:
                _undo_stack.append((file_path, content))
        except Exception:
            pass

        try:
            # Atomic write: mkstemp + rename (crash-safe, no predictable name)
            dirname = os.path.dirname(file_path)
            fd, tmp_path = tempfile.mkstemp(dir=dirname or ".", suffix=".eve_tmp")
            try:
                with os.fdopen(fd, "w", encoding="utf-8") as f:
                    f.write(new_content)
                os.replace(tmp_path, file_path)
            except Exception:
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                raise
            # Generate compact diff for display
            diff_lines = []
            old_lines = content.splitlines(keepends=True)
            new_lines = new_content.splitlines(keepends=True)
            import difflib
            for group in difflib.SequenceMatcher(None, old_lines, new_lines).get_grouped_opcodes(3):
                for tag, i1, i2, j1, j2 in group:
                    if tag == "equal":
                        for ln in old_lines[i1:i2]:
                            diff_lines.append(f" {ln.rstrip()}")
                    elif tag == "replace":
                        for ln in old_lines[i1:i2]:
                            diff_lines.append(f"-{ln.rstrip()}")
                        for ln in new_lines[j1:j2]:
                            diff_lines.append(f"+{ln.rstrip()}")
                    elif tag == "delete":
                        for ln in old_lines[i1:i2]:
                            diff_lines.append(f"-{ln.rstrip()}")
                    elif tag == "insert":
                        for ln in new_lines[j1:j2]:
                            diff_lines.append(f"+{ln.rstrip()}")
                diff_lines.append("---")
            # Trim trailing separator and cap length
            if diff_lines and diff_lines[-1] == "---":
                diff_lines.pop()
            diff_text = "\n".join(diff_lines[:40])
            if len(diff_lines) > 40:
                diff_text += "\n... (diff truncated)"
            return f"Edited {file_path} ({count} replacement{'s' if count > 1 else ''})\n{diff_text}"
        except Exception as e:
            return f"Error writing file: {e}"


class ApplyPatchTool(Tool):
    name = "ApplyPatch"
    description = (
        "Apply a text patch across one or more files. "
        "Accepts unified diff with ---/+++/@@ hunks. "
        "Use this for coordinated multi-hunk edits that are harder to express with Edit."
    )
    parameters = {
        "type": "object",
        "properties": {
            "patch": {
                "type": "string",
                "description": "Unified diff patch text covering one or more files",
            },
        },
        "required": ["patch"],
    }
    MAX_PATCH_SIZE = 512 * 1024
    lock_mode = "write"

    def _write_text(self, file_path, content):
        dirname = os.path.dirname(file_path)
        if dirname:
            os.makedirs(dirname, exist_ok=True)
        fd, tmp_path = tempfile.mkstemp(dir=dirname or ".", suffix=".eve_tmp")
        try:
            with os.fdopen(fd, "w", encoding="utf-8", newline="") as f:
                f.write(content)
            os.replace(tmp_path, file_path)
        except Exception:
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise

    def execute(self, params):
        patch_text = params.get("patch", "")
        if not isinstance(patch_text, str) or not patch_text.strip():
            return "Error: patch cannot be empty"
        if len(patch_text.encode("utf-8")) > self.MAX_PATCH_SIZE:
            return f"Error: patch too large ({len(patch_text)} chars). Max {self.MAX_PATCH_SIZE} bytes."

        parsed, parse_error = _parse_unified_patch_text(patch_text)
        if parse_error:
            return parse_error

        operations = []
        rollback = []
        try:
            for entry in parsed:
                old_path = entry["old_path"]
                new_path = entry["new_path"]
                if old_path != "/dev/null" and new_path != "/dev/null" and old_path != new_path:
                    return f"Error: rename patches are not supported ({old_path} -> {new_path})"
                target_spec = new_path if new_path != "/dev/null" else old_path
                require_exists = old_path != "/dev/null"
                resolved_path, path_error = _resolve_repo_path(
                    self._base_dir(), target_spec, require_exists=require_exists, path_label="file"
                )
                if path_error:
                    if "symlink" in path_error.lower():
                        return path_error.replace("access through", "patch through")
                    return path_error
                if _is_protected_path(resolved_path):
                    return f"Error: patching {os.path.basename(resolved_path)} is blocked for security. Use the config system instead."

                existed = os.path.exists(resolved_path)
                if old_path == "/dev/null":
                    if existed:
                        return f"Error: patch expects a new file but it already exists: {target_spec}"
                    original_text = ""
                else:
                    original_text, read_error = _read_text_file_for_patch(resolved_path)
                    if read_error:
                        return read_error

                new_content, apply_error = _apply_unified_patch_to_text(original_text, entry["hunks"])
                if apply_error:
                    return f"{apply_error} ({target_spec})"
                if new_path == "/dev/null" and new_content:
                    return f"Error: delete patch for {target_spec} must remove all content before deleting the file"

                rollback.append((resolved_path, existed, original_text if existed else None))
                operations.append((resolved_path, old_path, new_path, new_content))

            for resolved_path, old_path, new_path, new_content in operations:
                if new_path == "/dev/null":
                    os.unlink(resolved_path)
                    continue
                self._write_text(resolved_path, new_content)

            parts = []
            for resolved_path, old_path, new_path, new_content in operations:
                if old_path == "/dev/null":
                    action = "created"
                elif new_path == "/dev/null":
                    action = "deleted"
                else:
                    action = "patched"
                parts.append(f"- {action}: {os.path.relpath(resolved_path, self._base_dir())}")
            return f"Applied patch to {len(operations)} file(s)\n" + "\n".join(parts)
        except Exception as e:
            for resolved_path, existed, original_text in reversed(rollback):
                try:
                    if existed and original_text is not None:
                        self._write_text(resolved_path, original_text)
                    elif not existed and os.path.exists(resolved_path):
                        os.unlink(resolved_path)
                except Exception:
                    pass
            return f"Error applying patch: {e}"


# Global configuration for parallel file operations
_MAX_PARALLEL_FILES = 5  # Default max parallelism
_SHOW_PROGRESS = True    # Show progress indicators
DEFAULT_SUBAGENT_MAX_TURNS = 15
HARD_MAX_SUBAGENT_TURNS = 20


def _normalize_subagent_max_turns(value, default=DEFAULT_SUBAGENT_MAX_TURNS):
    try:
        turns = int(value)
    except (TypeError, ValueError):
        return default
    return max(1, min(turns, HARD_MAX_SUBAGENT_TURNS))


def _get_default_subagent_max_turns(config):
    return _normalize_subagent_max_turns(
        getattr(config, "default_subagent_max_turns", DEFAULT_SUBAGENT_MAX_TURNS)
    )

class MultiEditTool(Tool):
    """Apply multiple file edits in a single tool call with parallel execution."""
    name = "MultiEdit"
    description = (
        "Apply multiple edits across one or more files in a single call. "
        "Each edit specifies a file_path, old_string, and new_string. "
        "Use this when you need to make coordinated changes across files "
        "(e.g., rename a function and update all call sites). "
        "Files are processed in parallel (max 5 concurrent) for better performance."
    )
    parameters = {
        "type": "object",
        "properties": {
            "edits": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "file_path": {"type": "string", "description": "Absolute path to the file"},
                        "old_string": {"type": "string", "description": "Exact string to find"},
                        "new_string": {"type": "string", "description": "Replacement string"},
                    },
                    "required": ["file_path", "old_string", "new_string"],
                },
                "description": "List of edits to apply",
            },
        },
        "required": ["edits"],
    }
    lock_mode = "write"

    # Thread-safe locks for file operations
    _file_locks = {}
    _file_locks_lock = threading.Lock()

    def _get_file_lock(self, path):
        """Get or create a lock for a specific file path."""
        with self._file_locks_lock:
            if path not in self._file_locks:
                self._file_locks[path] = threading.Lock()
            return self._file_locks[path]

    def _validate_and_apply_edit(self, edit, index):
        """Validate and apply a single edit. Returns (success, result_message)."""
        fpath = edit.get("file_path", "")
        old_s = edit.get("old_string", "")
        new_s = edit.get("new_string", "")

        if not fpath or not os.path.isabs(fpath):
            return False, f"[{index+1}] Error: invalid path '{fpath}'"
        resolved_path, path_error = _resolve_repo_path(
            self._base_dir(), fpath, require_exists=True, path_label="file"
        )
        if path_error:
            if "symlink" in path_error.lower():
                return False, f"[{index+1}] Error: symlink not allowed '{fpath}'"
            return False, f"[{index+1}] {path_error}"
        if _is_protected_path(fpath):
            return False, f"[{index+1}] Error: protected path '{fpath}'"

        if not os.path.isfile(resolved_path):
            return False, f"[{index+1}] Error: file not found '{fpath}'"

        # Acquire lock for this specific file to prevent concurrent writes
        lock = self._get_file_lock(resolved_path)
        with lock:
            try:
                with open(resolved_path, "r", encoding="utf-8", errors="replace") as f:
                    content = f.read()

                if old_s not in content:
                    return False, f"[{index+1}] Error: old_string not found in {os.path.basename(resolved_path)}"

                count = content.count(old_s)
                warning = ""
                if count > 1:
                    warning = f" [{count} occurrences, replacing first only]"

                new_content = content.replace(old_s, new_s, 1)
                dirname = os.path.dirname(resolved_path)
                fd, tmp_path = tempfile.mkstemp(dir=dirname or ".", suffix=".eve_tmp")
                try:
                    with os.fdopen(fd, "w", encoding="utf-8", newline="") as f:
                        f.write(new_content)
                    os.replace(tmp_path, resolved_path)
                except Exception:
                    try:
                        os.unlink(tmp_path)
                    except OSError:
                        pass
                    raise

                return True, f"[{index+1}] OK: {os.path.basename(resolved_path)}{warning}"
            except OSError as e:
                return False, f"[{index+1}] Error: {e}"

    def execute(self, params):
        edits = params.get("edits", [])
        if not edits:
            return "Error: no edits provided"
        if len(edits) > 20:
            return "Error: too many edits (max 20)"

        results = [None] * len(edits)
        success_count = 0

        # Show progress if enabled
        if _SHOW_PROGRESS and len(edits) > 1:
            print(f"\n{C.CYAN}Processing {len(edits)} file(s) in parallel (max {_MAX_PARALLEL_FILES} concurrent)...{C.RESET}")

        # Process edits in parallel using ThreadPoolExecutor
        with concurrent.futures.ThreadPoolExecutor(max_workers=_MAX_PARALLEL_FILES) as executor:
            # Submit all tasks
            future_to_index = {
                executor.submit(self._validate_and_apply_edit, edit, i): i
                for i, edit in enumerate(edits)
            }

            # Collect results as they complete
            for future in concurrent.futures.as_completed(future_to_index):
                index = future_to_index[future]
                try:
                    success, result_msg = future.result()
                    results[index] = result_msg
                    if success:
                        success_count += 1

                    # Show progress update
                    if _SHOW_PROGRESS and len(edits) > 1:
                        completed = sum(1 for r in results if r is not None)
                        status = f"{C.GREEN}✓{C.RESET}" if success else f"{C.RED}✗{C.RESET}"
                        fname = os.path.basename(edits[index].get("file_path", "unknown"))
                        print(f"  {status} {fname} ({completed}/{len(edits)})")

                except Exception as e:
                    results[index] = f"[{index+1}] Error: {e}"

        # Filter out None results and build final output
        final_results = [r for r in results if r is not None]
        summary = f"\n{C.BOLD}MultiEdit: {success_count}/{len(edits)} edits applied{C.RESET}\n"
        return summary + "\n".join(final_results)


class GlobTool(Tool):
    name = "Glob"
    lock_mode = "read"
    parallel_safe = True
    description = """ファイル名のパターン検索を行う。ワイルドカード（*、?）を使用してファイルを finding。

使い方:
- '**/*.py': 再帰的に Python ファイルを検索
- 'src/**/*.ts': src ディレクトリ内の TypeScript ファイルを検索
- 結果は修正時間順にソートされて返される

制約:
- .git, node_modules, __pycache__, venv などのディレクトリは自動スキップ
- 最大 200 件まで"""
    parameters = {
        "type": "object",
        "properties": {
            "pattern": {
                "type": "string",
                "description": "Glob pattern (e.g. '**/*.py', 'src/**/*.ts')",
            },
            "path": {
                "type": "string",
                "description": "Directory to search in (default: cwd)",
            },
        },
        "required": ["pattern"],
    }

    # Directories to skip
    SKIP_DIRS = {".git", "node_modules", "__pycache__", ".venv", "venv",
                 ".tox", ".mypy_cache", ".pytest_cache", "dist", "build",
                 ".next", ".nuxt", "coverage", ".cache"}

    MAX_RESULTS = 200  # bounded result set to prevent memory blowup

    def execute(self, params):
        import heapq
        pattern = params.get("pattern", "")
        base = params.get("path", self._base_dir())

        if not pattern:
            return "Error: no pattern provided"
        if not os.path.isabs(base):
            base = os.path.join(self._base_dir(), base)

        # Security: Ensure base directory is within repo
        if not self._is_path_within_repo(base):
            return "Error: access denied - search path is outside repository"

        # Bounded heap to avoid collecting millions of matches into memory
        heap = []  # min-heap of (mtime, path) — keeps newest MAX_RESULTS items
        total_found = 0

        # Use pathlib.glob for ** patterns (fnmatch doesn't support **)
        if "**" in pattern:
            try:
                base_path = Path(base)
                real_base = base_path.resolve()
                for full_path in base_path.glob(pattern):
                    if not full_path.is_file():
                        continue
                    # Verify resolved path stays within base (prevents symlink escape)
                    try:
                        resolved = full_path.resolve()
                        if not str(resolved).startswith(str(real_base) + os.sep) and resolved != real_base:
                            continue
                    except (OSError, ValueError):
                        continue
                    parts = full_path.relative_to(base_path).parts
                    if any(p in self.SKIP_DIRS for p in parts):
                        continue
                    try:
                        mtime = full_path.stat().st_mtime
                    except OSError:
                        mtime = 0
                    total_found += 1
                    if len(heap) < self.MAX_RESULTS:
                        heapq.heappush(heap, (mtime, str(full_path)))
                    elif mtime > heap[0][0]:
                        heapq.heapreplace(heap, (mtime, str(full_path)))
            except Exception:
                pass
        else:
            # Use os.walk with early dir pruning (fast, skips node_modules/.git early)
            seen_dirs = set()  # prevent symlink loops
            try:
                for root, dirs, files in os.walk(base, followlinks=False):
                    try:
                        real_root = os.path.realpath(root)
                        if real_root in seen_dirs:
                            dirs[:] = []
                            continue
                        seen_dirs.add(real_root)
                    except OSError:
                        pass
                    dirs[:] = [d for d in dirs if d not in self.SKIP_DIRS]
                    for name in files:
                        full = os.path.join(root, name)
                        rel = os.path.relpath(full, base)
                        if fnmatch.fnmatch(rel, pattern) or fnmatch.fnmatch(name, pattern):
                            try:
                                mtime = os.path.getmtime(full)
                            except OSError:
                                mtime = 0
                            total_found += 1
                            if len(heap) < self.MAX_RESULTS:
                                heapq.heappush(heap, (mtime, full))
                            elif mtime > heap[0][0]:
                                heapq.heapreplace(heap, (mtime, full))
            except PermissionError:
                pass

        if not heap:
            return f"No files matching '{pattern}' found in {base}"

        # Sort by mtime descending (newest first)
        matches = sorted(heap, reverse=True)

        if total_found > self.MAX_RESULTS:
            return (f"Found {total_found} files. Showing newest {self.MAX_RESULTS}:\n" +
                    "\n".join(m[1] for m in matches))
        return "\n".join(m[1] for m in matches)


class GrepTool(Tool):
    name = "Grep"
    lock_mode = "read"
    parallel_safe = True
    description = """ファイル内容を正規表現で検索する。一致した行とファイルパスを返す。

重要:
- 正規表現パターンを使用
- 大文字小文字区別なし検索は -i フラグ
- 出力モード：content（行表示）, files_with_matches（ファイル一覧）, count（件数）
- 文脈行数指定：-A（後）, -B（前）, -C（前後）"""
    parameters = {
        "type": "object",
        "properties": {
            "pattern": {
                "type": "string",
                "description": "Regular expression pattern to search for",
            },
            "path": {
                "type": "string",
                "description": "File or directory to search in (default: cwd)",
            },
            "glob": {
                "type": "string",
                "description": "Glob pattern to filter files (e.g. '*.py')",
            },
            "-i": {
                "type": "boolean",
                "description": "Case insensitive search",
            },
            "output_mode": {
                "type": "string",
                "description": "Output mode: 'content', 'files_with_matches', 'count'",
            },
            "-A": {"type": "number", "description": "Lines after match"},
            "-B": {"type": "number", "description": "Lines before match"},
            "-C": {"type": "number", "description": "Lines of context (before and after)"},
            "head_limit": {
                "type": "number",
                "description": "Max results to return",
            },
        },
        "required": ["pattern"],
    }

    SKIP_DIRS = GlobTool.SKIP_DIRS
    BINARY_EXTS = {".png", ".jpg", ".jpeg", ".gif", ".bmp", ".ico", ".pdf",
                   ".zip", ".tar", ".gz", ".bz2", ".7z", ".rar", ".exe",
                   ".dll", ".so", ".dylib", ".class", ".pyc", ".o", ".a",
                   ".woff", ".woff2", ".ttf", ".eot", ".mp3", ".mp4",
                   ".mov", ".avi", ".wmv", ".flv", ".wav", ".ogg",
                   ".db", ".sqlite", ".wasm", ".pkl", ".npy", ".parquet", ".bin"}

    def execute(self, params):
        pat_str = params.get("pattern", "")
        search_path = params.get("path", self._base_dir())
        glob_filter = params.get("glob")
        case_insensitive = params.get("-i", False)
        output_mode = params.get("output_mode", "files_with_matches")
        try:
            after = min(int(params.get("-A", 0)), 100)
        except (ValueError, TypeError):
            after = 0
        try:
            before = min(int(params.get("-B", 0)), 100)
        except (ValueError, TypeError):
            before = 0
        try:
            context = min(int(params.get("-C", 0)), 100)
        except (ValueError, TypeError):
            context = 0
        try:
            head_limit = int(params.get("head_limit", 1000))
        except (ValueError, TypeError):
            head_limit = 1000

        if context:
            after = max(after, context)
            before = max(before, context)

        if not pat_str:
            return "Error: no pattern provided"
        # Security: Ensure search path is within repo
        if not self._is_path_within_repo(search_path):
            return "Error: access denied - search path is outside repository"
        # ReDoS protection: limit pattern length and reject nested quantifiers
        if len(pat_str) > 500:
            return "Error: regex pattern too long (max 500 chars)"
        _REDOS_RE = re.compile(r'(\([^)]*[+*][^)]*\))[+*]|(\([^)]*\|[^)]*\))[+*]')
        if _REDOS_RE.search(pat_str):
            return "Error: regex pattern contains nested quantifiers (potential ReDoS)"
        if not os.path.isabs(search_path):
            search_path = os.path.join(self._base_dir(), search_path)

        flags = re.IGNORECASE if case_insensitive else 0
        try:
            # SEC-3: Compile regex with threading-based timeout (1s) to prevent ReDoS.
            # signal.alarm() is not used because it requires the main thread on macOS.
            import threading as _threading
            _compiled_pattern = [None]
            _compile_error = [None]
            def _compile_regex():
                try:
                    _compiled_pattern[0] = re.compile(pat_str, flags)
                except re.error as _e:
                    _compile_error[0] = _e
            _t = _threading.Thread(target=_compile_regex, daemon=True)
            _t.start()
            _t.join(timeout=1.0)
            if _t.is_alive():
                return "Error: regex compilation timed out (potential ReDoS pattern)"
            if _compile_error[0] is not None:
                raise _compile_error[0]
            pattern = _compiled_pattern[0]
        except re.error as e:
            return f"Error: invalid regex: {e}"

        results = []
        file_counts = {}

        MAX_GREP_FILE_SIZE = 50 * 1024 * 1024  # 50MB — skip very large files

        def search_file(filepath):
            _, ext = os.path.splitext(filepath)
            if ext.lower() in self.BINARY_EXTS:
                return
            if glob_filter and not fnmatch.fnmatch(os.path.basename(filepath), glob_filter):
                return
            # Skip very large files to avoid performance issues
            try:
                if os.path.getsize(filepath) > MAX_GREP_FILE_SIZE:
                    return
            except OSError:
                return
            # Binary probe: check for null bytes in first 8KB (same pattern as ReadTool)
            try:
                with open(filepath, "rb") as bf:
                    sample = bf.read(8192)
                    if b'\x00' in sample:
                        return  # binary file, skip
            except OSError:
                return
            try:
                # Use streaming read with rolling buffer for context lines
                # Avoids loading entire file into memory (fix for large files)
                with open(filepath, "r", encoding="utf-8", errors="replace") as f:
                    if before or after:
                        # Need context: read into list but cap at 100K lines
                        lines = []
                        for i, l in enumerate(f):
                            lines.append(l)
                            if i >= 100_000:
                                break
                    else:
                        lines = None  # stream mode
            except (OSError, UnicodeDecodeError):
                return

            if lines is not None:
                # Context mode (with -A/-B/-C)
                for lineno, line in enumerate(lines, 1):
                    if pattern.search(line):
                        if output_mode == "files_with_matches":
                            if filepath not in file_counts:
                                file_counts[filepath] = 0
                                results.append(filepath)
                            file_counts[filepath] += 1
                            return
                        elif output_mode == "count":
                            file_counts[filepath] = file_counts.get(filepath, 0) + 1
                        else:  # content with context
                            start = max(0, lineno - 1 - before)
                            end = min(len(lines), lineno + after)
                            for i in range(start, end):
                                prefix = ">" if i == lineno - 1 else " "
                                results.append(f"{filepath}:{i+1}:{prefix}{lines[i].rstrip()}")
                            results.append("--")
            else:
                # Streaming mode (no context needed) — memory efficient
                try:
                    with open(filepath, "r", encoding="utf-8", errors="replace") as f:
                        for lineno, line in enumerate(f, 1):
                            if pattern.search(line):
                                if output_mode == "files_with_matches":
                                    if filepath not in file_counts:
                                        file_counts[filepath] = 0
                                        results.append(filepath)
                                    file_counts[filepath] += 1
                                    return
                                elif output_mode == "count":
                                    file_counts[filepath] = file_counts.get(filepath, 0) + 1
                                else:
                                    results.append(f"{filepath}:{lineno}:{line.rstrip()}")
                except (OSError, UnicodeDecodeError):
                    return

        if os.path.isfile(search_path):
            search_file(search_path)
        else:
            _result_count = [0]  # mutable counter for incremental limit
            for root, dirs, files in os.walk(search_path):
                dirs[:] = [d for d in dirs if d not in self.SKIP_DIRS]
                for name in files:
                    search_file(os.path.join(root, name))
                    # Check count incrementally to avoid scanning entire tree
                    if output_mode == "files_with_matches":
                        if len(results) >= head_limit:
                            break
                    elif output_mode == "content":
                        if len(results) >= head_limit:
                            break
                    else:  # count mode - scan all
                        pass
                if len(results) >= head_limit:
                    break

        if output_mode == "count":
            return "\n".join(f"{fp}:{cnt}" for fp, cnt in sorted(file_counts.items()))

        if not results:
            return f"No matches found for '{pat_str}' in {search_path}"

        return "\n".join(results[:head_limit])


class WebFetchTool(Tool):
    name = "WebFetch"
    lock_mode = "read"
    description = "Fetch content from a URL. Returns the text content of the page."
    parameters = {
        "type": "object",
        "properties": {
            "url": {
                "type": "string",
                "description": "The URL to fetch",
            },
            "prompt": {
                "type": "string",
                "description": "What to extract from the page (optional, for context)",
            },
        },
        "required": ["url"],
    }

    @staticmethod
    def _is_private_ip(hostname):
        """Check if a hostname resolves to a private/loopback/reserved IP. Fail-closed."""
        import socket
        import ipaddress
        # Additional SSRF-sensitive network ranges to block explicitly
        _BLOCKED_NETWORKS_V4 = [
            ipaddress.ip_network("169.254.0.0/16"),   # link-local (incl. AWS/GCP/Azure metadata 169.254.169.254)
            ipaddress.ip_network("100.64.0.0/10"),     # CGNAT (Shared Address Space)
            ipaddress.ip_network("224.0.0.0/4"),       # IPv4 multicast
        ]
        _BLOCKED_NETWORKS_V6 = [
            ipaddress.ip_network("fe80::/10"),         # IPv6 link-local
            ipaddress.ip_network("ff00::/8"),          # IPv6 multicast
        ]
        try:
            for info in socket.getaddrinfo(hostname, None):
                ip_str = info[4][0]
                addr = ipaddress.ip_address(ip_str)
                if addr.is_private or addr.is_loopback or addr.is_reserved or addr.is_link_local:
                    return True
                # Block additional SSRF-sensitive ranges
                if isinstance(addr, ipaddress.IPv4Address):
                    for net in _BLOCKED_NETWORKS_V4:
                        if addr in net:
                            return True
                elif isinstance(addr, ipaddress.IPv6Address):
                    for net in _BLOCKED_NETWORKS_V6:
                        if addr in net:
                            return True
                # Block IPv4-mapped IPv6 (::ffff:127.0.0.1)
                if hasattr(addr, 'ipv4_mapped') and addr.ipv4_mapped:
                    mapped = addr.ipv4_mapped
                    if mapped.is_private or mapped.is_loopback or mapped.is_reserved:
                        return True
                    for net in _BLOCKED_NETWORKS_V4:
                        if mapped in net:
                            return True
        except (socket.gaierror, ValueError, OSError):
            return True  # fail-closed: if DNS fails, block the request
        return False

    @staticmethod
    def _resolve_public_ip(hostname, port):
        """Resolve hostname and return a public IP literal for pinned connections."""
        import socket
        import ipaddress
        _BLOCKED_NETWORKS_V4 = [
            ipaddress.ip_network("169.254.0.0/16"),
            ipaddress.ip_network("100.64.0.0/10"),
            ipaddress.ip_network("224.0.0.0/4"),
        ]
        _BLOCKED_NETWORKS_V6 = [
            ipaddress.ip_network("fe80::/10"),
            ipaddress.ip_network("ff00::/8"),
        ]
        try:
            infos = socket.getaddrinfo(hostname, port, type=socket.SOCK_STREAM)
        except (socket.gaierror, ValueError, OSError) as e:
            raise urllib.error.URLError(f"DNS resolution failed for {hostname}: {e}")
        for info in infos:
            ip_str = info[4][0]
            addr = ipaddress.ip_address(ip_str)
            if addr.is_private or addr.is_loopback or addr.is_reserved or addr.is_link_local:
                continue
            if isinstance(addr, ipaddress.IPv4Address):
                if any(addr in net for net in _BLOCKED_NETWORKS_V4):
                    continue
            elif isinstance(addr, ipaddress.IPv6Address):
                if any(addr in net for net in _BLOCKED_NETWORKS_V6):
                    continue
            if hasattr(addr, "ipv4_mapped") and addr.ipv4_mapped:
                mapped = addr.ipv4_mapped
                if mapped.is_private or mapped.is_loopback or mapped.is_reserved:
                    continue
                if any(mapped in net for net in _BLOCKED_NETWORKS_V4):
                    continue
            return ip_str
        raise urllib.error.URLError(f"All resolved addresses for {hostname} are private or blocked")

    def _fetch_pinned(self, url, timeout=30, max_redirects=5):
        """Fetch a URL by connecting to a resolved public IP to avoid DNS rebinding."""
        import http.client
        import socket
        import ssl

        class _PinnedHTTPConnection(http.client.HTTPConnection):
            def __init__(self, host, port=None, *, connect_host=None, timeout=None):
                super().__init__(host, port=port, timeout=timeout)
                self._connect_host = connect_host or host

            def connect(self):
                self.sock = socket.create_connection(
                    (self._connect_host, self.port),
                    self.timeout,
                    self.source_address,
                )
                if self._tunnel_host:
                    self._tunnel()

        class _PinnedHTTPSConnection(http.client.HTTPSConnection):
            def __init__(self, host, port=None, *, connect_host=None, timeout=None, context=None):
                super().__init__(host, port=port, timeout=timeout, context=context)
                self._connect_host = connect_host or host

            def connect(self):
                sock = socket.create_connection(
                    (self._connect_host, self.port),
                    self.timeout,
                    self.source_address,
                )
                if self._tunnel_host:
                    self.sock = sock
                    self._tunnel()
                    sock = self.sock
                self.sock = self._context.wrap_socket(sock, server_hostname=self.host)

        current_url = url
        for _ in range(max_redirects + 1):
            parsed = urllib.parse.urlparse(current_url)
            scheme = (parsed.scheme or "https").lower()
            if scheme not in ("http", "https"):
                raise urllib.error.URLError(
                    t('errors.url_redirect_blocked_scheme', default=f"Redirect to blocked scheme: {scheme}")
                )
            if parsed.username or "@" in (parsed.netloc or ""):
                raise urllib.error.URLError("URLs with credentials (user@host) are not allowed")
            hostname = parsed.hostname or ""
            if not hostname:
                raise urllib.error.URLError("Missing hostname")
            port = parsed.port or (443 if scheme == "https" else 80)
            connect_ip = self._resolve_public_ip(hostname, port)

            path = urllib.parse.quote(parsed.path or "/", safe="/%:@!$&'()*+,;=-._~")
            if parsed.params:
                path += ";" + urllib.parse.quote(parsed.params, safe="%:@!$&'()*+,;=-._~")
            if parsed.query:
                path += "?" + urllib.parse.quote(parsed.query, safe="=&%:@!$'()*+,;/-._~")

            host_header = hostname if parsed.port is None else f"{hostname}:{parsed.port}"
            headers = {
                "Host": host_header,
                "User-Agent": f"eve-cli/{__version__} (+https://github.com/NPO-Everyone-Engineer/eve-cli)",
            }

            conn = None
            resp = None
            try:
                if scheme == "https":
                    conn = _PinnedHTTPSConnection(
                        hostname,
                        port=port,
                        connect_host=connect_ip,
                        timeout=timeout,
                        context=ssl.create_default_context(),
                    )
                else:
                    conn = _PinnedHTTPConnection(
                        hostname,
                        port=port,
                        connect_host=connect_ip,
                        timeout=timeout,
                    )
                conn.request("GET", path, headers=headers)
                resp = conn.getresponse()
                if resp.status in (301, 302, 303, 307, 308):
                    location = resp.getheader("Location", "")
                    if not location:
                        raise urllib.error.URLError("Redirect response missing Location header")
                    current_url = urllib.parse.urljoin(current_url, location)
                    continue
                return resp.getheader("Content-Type", ""), resp.read(5 * 1024 * 1024)
            finally:
                if resp is not None:
                    try:
                        resp.close()
                    except Exception:
                        pass
                if conn is not None:
                    try:
                        conn.close()
                    except Exception:
                        pass

        raise urllib.error.URLError("Too many redirects")

    def execute(self, params):
        url = params.get("url", "")
        if not url:
            return "Error: no url provided"

        # Block dangerous schemes (file://, ftp://, data://, etc.)
        parsed_url = urllib.parse.urlparse(url)
        if parsed_url.scheme and parsed_url.scheme.lower() not in ("http", "https", ""):
            return f"Error: unsupported URL scheme '{parsed_url.scheme}'. Only http/https allowed."
        if url.startswith("//"):
            return "Error: scheme-relative URLs are not allowed. Use a full https:// URL."

        # Strip userinfo from URL (block user@host attacks)
        if parsed_url.username or "@" in (parsed_url.netloc or ""):
            return "Error: URLs with credentials (user@host) are not allowed."

        # Upgrade http to https
        if url.startswith("http://"):
            url = "https://" + url[7:]
        elif not url.startswith("https://"):
            url = "https://" + url

        # Validate initial request target — block private/loopback IPs (SSRF prevention)
        parsed_final = urllib.parse.urlparse(url)
        hostname = parsed_final.hostname or ""
        if self._is_private_ip(hostname):
            return f"Error: request to private/internal IP blocked (SSRF protection): {hostname}"

        try:
            content_type, raw = self._fetch_pinned(url, timeout=30)

            if "text" not in content_type and "json" not in content_type and "xml" not in content_type:
                return f"(binary content: {content_type}, {len(raw)} bytes)"

            # Cap raw bytes before decoding and regex processing to avoid
            # quadratic blowup on huge HTML pages
            raw = raw[:300000]
            # Parse charset from Content-Type header (e.g. "text/html; charset=shift_jis")
            charset = "utf-8"
            ct_match = re.search(r'charset=([^\s;]+)', content_type, re.IGNORECASE)
            if ct_match:
                charset = ct_match.group(1).strip("'\"")
            try:
                text = raw.decode(charset, errors="replace")
            except (LookupError, UnicodeDecodeError):
                text = raw.decode("utf-8", errors="replace")

            # Simple HTML to text conversion
            if "html" in content_type:
                text = self._html_to_text(text)

            # Truncate
            if len(text) > 50000:
                text = text[:50000] + "\n\n... (truncated)"

            return text
        except urllib.error.HTTPError as e:
            return f"HTTP Error {e.code}: {e.reason}"
        except Exception as e:
            return f"Error fetching URL: {e}"

    def _html_to_text(self, html):
        """Simple HTML tag removal."""
        # Remove script and style
        html = re.sub(r"<script[^>]*>.*?</script>", "", html, flags=re.DOTALL)
        html = re.sub(r"<style[^>]*>.*?</style>", "", html, flags=re.DOTALL)
        # Remove tags
        html = re.sub(r"<[^>]+>", " ", html)
        # Decode entities
        html = html_module.unescape(html)
        # Collapse whitespace
        html = re.sub(r"\s+", " ", html)
        html = re.sub(r"\n\s*\n+", "\n\n", html)
        return html.strip()


class WebSearchTool(Tool):
    """Web search via DuckDuckGo HTML endpoint."""
    name = "WebSearch"
    lock_mode = "read"
    description = "Search the web using DuckDuckGo. Returns titles, URLs, and snippets."
    parameters = {
        "type": "object",
        "properties": {
            "query": {
                "type": "string",
                "description": "The search query",
            },
        },
        "required": ["query"],
    }

    _last_search_time = 0.0
    _search_count = 0
    _search_lock = threading.Lock()
    _MIN_INTERVAL = 2.0  # minimum seconds between searches
    _MAX_SEARCHES_PER_SESSION = 50

    def execute(self, params):
        query = params.get("query", "")
        if not query:
            return "Error: no query provided"

        # Rate limiting to prevent IP bans (thread-safe)
        with WebSearchTool._search_lock:
            now = time.time()
            if self._search_count >= self._MAX_SEARCHES_PER_SESSION:
                return "Error: search limit reached for this session. Use WebFetch on specific URLs instead."
            elapsed = now - WebSearchTool._last_search_time
            if elapsed < self._MIN_INTERVAL:
                time.sleep(self._MIN_INTERVAL - elapsed)
            WebSearchTool._last_search_time = time.time()
            WebSearchTool._search_count += 1

        return self._ddg_search(query)

    def _ddg_search(self, query, max_results=8):
        """Search DuckDuckGo HTML endpoint. Zero dependencies (stdlib only)."""
        # Detect CJK locale for DDG region parameter
        _ddg_locale = ""
        _accept_lang = "en-US,en;q=0.9"
        try:
            import locale
            _loc = (locale.getlocale()[0] or os.environ.get("LANG", "")).lower()
        except Exception:
            _loc = os.environ.get("LANG", "").lower()
        if "ja" in _loc:
            _ddg_locale = "&kl=jp-ja"
            _accept_lang = "ja,en;q=0.9"
        elif "zh" in _loc:
            _ddg_locale = "&kl=cn-zh"
            _accept_lang = "zh,en;q=0.9"
        elif "ko" in _loc:
            _ddg_locale = "&kl=kr-kr"
            _accept_lang = "ko,en;q=0.9"
        search_url = "https://html.duckduckgo.com/html/?q=" + urllib.parse.quote(query) + _ddg_locale
        req = urllib.request.Request(search_url, headers={
            "User-Agent": f"eve-cli/{__version__} (+https://github.com/NPO-Everyone-Engineer/eve-cli)",
            "Accept-Language": _accept_lang,
        })
        try:
            resp = urllib.request.urlopen(req, timeout=30)
            try:
                html = resp.read(2 * 1024 * 1024).decode("utf-8", errors="replace")
            finally:
                resp.close()
        except Exception as e:
            return f"Web search failed (network error): {e}"

        # Detect CAPTCHA / rate limiting (avoid false positives from <meta name="robots"> or snippet text)
        _html_low = html.lower()
        _is_captcha = ("captcha" in _html_low or "verify you are human" in _html_low
                        or "are you a robot" in _html_low or "unusual traffic" in _html_low)
        if _is_captcha and 'class="result__a"' not in html:
            # Only bail if CAPTCHA detected AND no real results present
            return "Web search blocked by CAPTCHA. You may be rate-limited. Try again later or use WebFetch on a specific URL."

        results = []
        # Match <a> with class=result__a and href, regardless of attribute order
        link_pat = re.compile(
            r'<a\s+[^>]*(?:class="[^"]*result__a[^"]*"[^>]*href="([^"]*)"'
            r'|href="([^"]*)"[^>]*class="[^"]*result__a[^"]*")[^>]*>(.*?)</a>',
            re.DOTALL,
        )
        snippet_pat = re.compile(
            r'<a\s+[^>]*class="[^"]*result__snippet[^"]*"[^>]*>(.*?)</a>',
            re.DOTALL,
        )

        raw_links = link_pat.findall(html)
        snippets = snippet_pat.findall(html)
        # Alternation produces (url1, url2, title) — pick non-empty url
        links = [(u1 or u2, title) for u1, u2, title in raw_links]

        for i, (raw_url, raw_title) in enumerate(links[:max_results + 5]):
            title = html_module.unescape(re.sub(r"<[^>]+>", "", raw_title)).strip()
            if not title:
                continue

            url = raw_url
            if "uddg=" in url:
                m = re.search(r"uddg=([^&]+)", url)
                if m:
                    url = urllib.parse.unquote(m.group(1))
            elif url.startswith("//"):
                url = "https:" + url

            # Skip ad results
            if "/y.js?" in url or "ad_provider" in url or "duckduckgo.com/y.js" in url:
                continue

            snippet = ""
            if i < len(snippets):
                snippet = html_module.unescape(re.sub(r"<[^>]+>", "", snippets[i])).strip()

            results.append({"title": title, "url": url, "snippet": snippet})
            if len(results) >= max_results:
                break

        if not results:
            return f'No search results found for "{query}".'

        output = f"Search results for: {query}\n\n"
        for i, r in enumerate(results, 1):
            output += f"{i}. {r['title']}\n   {r['url']}\n"
            if r["snippet"]:
                output += f"   {r['snippet']}\n"
            output += "\n"
        return output


class NotebookEditTool(Tool):
    name = "NotebookEdit"
    lock_mode = "write"
    description = "Edit a Jupyter notebook (.ipynb) cell. Supports replace, insert, and delete."
    parameters = {
        "type": "object",
        "properties": {
            "notebook_path": {
                "type": "string",
                "description": "Absolute path to the .ipynb file",
            },
            "cell_number": {
                "type": "number",
                "description": "0-indexed cell number to edit",
            },
            "new_source": {
                "type": "string",
                "description": "New content for the cell",
            },
            "cell_type": {
                "type": "string",
                "description": "Cell type: 'code' or 'markdown'",
            },
            "edit_mode": {
                "type": "string",
                "description": "Edit mode: 'replace', 'insert', or 'delete'",
            },
        },
        "required": ["notebook_path"],
    }

    VALID_CELL_TYPES = {"code", "markdown", "raw"}

    def execute(self, params):
        nb_path = params.get("notebook_path", "")
        try:
            cell_num = int(params.get("cell_number", 0))
        except (ValueError, TypeError):
            return "Error: cell_number must be a number"
        new_source = params.get("new_source", "")
        cell_type = params.get("cell_type")  # None = preserve existing in replace mode
        edit_mode = params.get("edit_mode", "replace")

        if not nb_path:
            return "Error: no notebook_path provided"
        nb_path, path_error = _resolve_repo_path(
            self._base_dir(), nb_path, require_exists=True, path_label="notebook"
        )
        if path_error:
            if "symlink" in path_error.lower():
                return path_error.replace("access through", "edit notebook through")
            return path_error
        # Block edits to protected config/permission files
        if _is_protected_path(nb_path):
            return f"Error: editing {os.path.basename(nb_path)} is blocked for security."
        # H11: Validate cell_type (None is allowed — means "preserve existing" in replace mode)
        if cell_type is not None and cell_type not in self.VALID_CELL_TYPES:
            return f"Error: invalid cell_type '{cell_type}'. Must be: code, markdown, or raw"
        # C12: Reject negative cell_number for insert
        if cell_num < 0:
            return "Error: cell_number cannot be negative"
        if edit_mode in ("replace", "insert") and not isinstance(new_source, str):
            return "Error: new_source must be a string"
        if edit_mode in ("replace", "insert") and not new_source:
            return "Error: new_source is required for replace/insert modes"

        try:
            with open(nb_path, "r", encoding="utf-8") as f:
                nb = json.load(f)
        except json.JSONDecodeError as e:
            return f"Error: notebook is not valid JSON: {e}"
        except Exception as e:
            return f"Error reading notebook: {e}"

        # Validate notebook structure
        if not isinstance(nb, dict):
            return "Error: notebook file is not a JSON object — may be corrupted"
        if "cells" not in nb:
            return "Error: notebook has no 'cells' key — may be corrupted"
        cells = nb["cells"]
        if not isinstance(cells, list):
            return "Error: notebook 'cells' is not a list — may be corrupted"

        if edit_mode == "insert":
            # For insert, cell_type defaults to "code" if not specified
            ct = cell_type or "code"
            new_cell = {
                "cell_type": ct,
                "metadata": {},
                "source": new_source.splitlines(True),
            }
            if ct == "code":
                new_cell["outputs"] = []
                new_cell["execution_count"] = None
            cells.insert(cell_num, new_cell)
        elif edit_mode == "delete":
            if cell_num >= len(cells):
                return f"Error: cell {cell_num} out of range (0-{len(cells)-1})"
            cells.pop(cell_num)
        else:  # replace
            if cell_num >= len(cells):
                return f"Error: cell {cell_num} out of range (0-{len(cells)-1})"
            old_type = cells[cell_num].get("cell_type", "code")
            # Preserve existing cell_type when not explicitly specified
            effective_type = cell_type if cell_type is not None else old_type
            cells[cell_num]["source"] = new_source.splitlines(True)
            cells[cell_num]["cell_type"] = effective_type
            # C11: Clean up fields when changing cell_type
            if old_type == "code" and effective_type != "code":
                cells[cell_num].pop("outputs", None)
                cells[cell_num].pop("execution_count", None)
            elif old_type != "code" and effective_type == "code":
                cells[cell_num].setdefault("outputs", [])
                cells[cell_num].setdefault("execution_count", None)

        nb["cells"] = cells
        try:
            # Atomic write: write to temp file, then rename
            dirname = os.path.dirname(nb_path)
            fd, tmp_path = tempfile.mkstemp(dir=dirname, suffix=".ipynb.tmp")
            try:
                with os.fdopen(fd, "w", encoding="utf-8") as f:
                    json.dump(nb, f, ensure_ascii=False, indent=1)
                os.replace(tmp_path, nb_path)
            except Exception:
                try:
                    os.unlink(tmp_path)
                except OSError:
                    pass
                raise
            return f"Notebook {edit_mode}d cell {cell_num} in {nb_path}"
        except Exception as e:
            return f"Error writing notebook: {e}"


# ════════════════════════════════════════════════════════════════════════════════
# Durable Session Runtime State
# ════════════════════════════════════════════════════════════════════════════════


class SessionRuntimeStore:
    """Persist execution state alongside the JSONL transcript."""

    DB_SUFFIX = ".state.sqlite3"

    def __init__(self, config, session_id):
        self.config = config
        self.session_id = re.sub(r'[^A-Za-z0-9_\-]', '', session_id or "")[:64] or "session"
        self.path = os.path.join(config.sessions_dir, f"{self.session_id}{self.DB_SUFFIX}")
        self._lock = threading.Lock()
        os.makedirs(config.sessions_dir, exist_ok=True)
        self._init_db()

    def _connect(self):
        conn = sqlite3.connect(self.path, timeout=30, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        return conn

    @staticmethod
    def _encode_meta(value):
        return json.dumps(value, ensure_ascii=False)

    @staticmethod
    def _decode_meta(value):
        if value is None:
            return None
        try:
            return json.loads(value)
        except (TypeError, json.JSONDecodeError):
            return value

    def _init_db(self):
        # SEC-4: Restrict DB file permissions on creation
        _db_is_new = not os.path.exists(self.path)
        with self._lock, self._connect() as conn:
            if _db_is_new and os.path.exists(self.path):
                try:
                    os.chmod(self.path, 0o600)
                except OSError:
                    pass
            conn.executescript("""
                CREATE TABLE IF NOT EXISTS metadata (
                    key TEXT PRIMARY KEY,
                    value TEXT NOT NULL
                );
                CREATE TABLE IF NOT EXISTS tasks (
                    task_id TEXT PRIMARY KEY,
                    subject TEXT NOT NULL,
                    description TEXT NOT NULL,
                    active_form TEXT NOT NULL,
                    status TEXT NOT NULL
                );
                CREATE TABLE IF NOT EXISTS task_deps (
                    task_id TEXT NOT NULL,
                    dep_kind TEXT NOT NULL,
                    dep_task_id TEXT NOT NULL,
                    PRIMARY KEY (task_id, dep_kind, dep_task_id)
                );
                CREATE TABLE IF NOT EXISTS checkpoints (
                    checkpoint_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    position INTEGER NOT NULL,
                    label TEXT NOT NULL,
                    git_ref TEXT,
                    created_at REAL NOT NULL,
                    snapshot_dir TEXT,
                    status_lines_json TEXT NOT NULL,
                    untracked_files_json TEXT NOT NULL
                );
                CREATE TABLE IF NOT EXISTS jobs (
                    job_id TEXT PRIMARY KEY,
                    job_type TEXT NOT NULL,
                    state TEXT NOT NULL,
                    command_or_prompt TEXT,
                    started_at REAL,
                    finished_at REAL,
                    last_heartbeat_at REAL,
                    result_summary TEXT,
                    error_summary TEXT,
                    external_ref TEXT
                );
                CREATE TABLE IF NOT EXISTS verifier_runs (
                    verifier_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    verifier_type TEXT NOT NULL,
                    command TEXT,
                    status TEXT NOT NULL,
                    started_at REAL NOT NULL,
                    finished_at REAL NOT NULL,
                    summary TEXT,
                    output_path TEXT
                );
                CREATE TABLE IF NOT EXISTS resume_events (
                    event_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    event_type TEXT NOT NULL,
                    message TEXT NOT NULL,
                    created_at REAL NOT NULL
                );
            """)
            conn.execute(
                "INSERT OR IGNORE INTO metadata (key, value) VALUES (?, ?)",
                ("schema_version", self._encode_meta(1)),
            )
            conn.execute(
                "INSERT OR IGNORE INTO metadata (key, value) VALUES (?, ?)",
                ("session_id", self._encode_meta(self.session_id)),
            )

    def ensure_defaults(self, **defaults):
        now = time.time()
        existing_created = self.get_meta("created_at")
        payload = {}
        if existing_created is None:
            payload["created_at"] = now
        payload["updated_at"] = now
        for key, value in defaults.items():
            if value is not None and self.get_meta(key) is None:
                payload[key] = value
        if payload:
            self.update_runtime(**payload)

    def get_meta(self, key, default=None):
        with self._lock, self._connect() as conn:
            row = conn.execute("SELECT value FROM metadata WHERE key = ?", (key,)).fetchone()
        if not row:
            return default
        value = self._decode_meta(row["value"])
        return default if value is None else value

    def update_runtime(self, **fields):
        if not fields:
            return
        with self._lock, self._connect() as conn:
            conn.executemany(
                "INSERT OR REPLACE INTO metadata (key, value) VALUES (?, ?)",
                [(key, self._encode_meta(value)) for key, value in fields.items()],
            )

    def load_runtime(self):
        with self._lock, self._connect() as conn:
            rows = conn.execute("SELECT key, value FROM metadata").fetchall()
        return {row["key"]: self._decode_meta(row["value"]) for row in rows}

    def save_task_store(self, store):
        store = copy.deepcopy(store or {"next_id": 1, "tasks": {}})
        with self._lock, self._connect() as conn:
            conn.execute("DELETE FROM task_deps")
            conn.execute("DELETE FROM tasks")
            conn.execute(
                "INSERT OR REPLACE INTO metadata (key, value) VALUES (?, ?)",
                ("next_task_id", self._encode_meta(int(store.get("next_id", 1)))),
            )
            for tid, task in sorted(store.get("tasks", {}).items(), key=lambda item: int(item[0])):
                conn.execute(
                    "INSERT INTO tasks (task_id, subject, description, active_form, status) VALUES (?, ?, ?, ?, ?)",
                    (
                        str(tid),
                        task.get("subject", ""),
                        task.get("description", ""),
                        task.get("activeForm", ""),
                        task.get("status", "pending"),
                    ),
                )
                for dep_kind in ("blocks", "blockedBy"):
                    for dep_task_id in task.get(dep_kind, []):
                        conn.execute(
                            "INSERT INTO task_deps (task_id, dep_kind, dep_task_id) VALUES (?, ?, ?)",
                            (str(tid), dep_kind, str(dep_task_id)),
                        )

    def load_task_store(self):
        store = {"next_id": int(self.get_meta("next_task_id", 1) or 1), "tasks": {}}
        with self._lock, self._connect() as conn:
            task_rows = conn.execute(
                "SELECT task_id, subject, description, active_form, status FROM tasks ORDER BY CAST(task_id AS INTEGER)"
            ).fetchall()
            dep_rows = conn.execute(
                "SELECT task_id, dep_kind, dep_task_id FROM task_deps ORDER BY task_id, dep_kind, dep_task_id"
            ).fetchall()
        for row in task_rows:
            store["tasks"][row["task_id"]] = {
                "id": row["task_id"],
                "subject": row["subject"],
                "description": row["description"],
                "activeForm": row["active_form"],
                "status": row["status"],
                "blocks": [],
                "blockedBy": [],
            }
        for row in dep_rows:
            task = store["tasks"].get(row["task_id"])
            if task:
                task.setdefault(row["dep_kind"], []).append(row["dep_task_id"])
        return store

    def save_checkpoints(self, checkpoints):
        checkpoints = copy.deepcopy(checkpoints or [])
        with self._lock, self._connect() as conn:
            conn.execute("DELETE FROM checkpoints")
            for position, cp in enumerate(checkpoints):
                conn.execute(
                    """
                    INSERT INTO checkpoints
                    (position, label, git_ref, created_at, snapshot_dir, status_lines_json, untracked_files_json)
                    VALUES (?, ?, ?, ?, ?, ?, ?)
                    """,
                    (
                        position,
                        cp.get("label", ""),
                        cp.get("git_ref", ""),
                        float(cp.get("timestamp", time.time())),
                        cp.get("snapshot_dir"),
                        self._encode_meta(cp.get("status_lines", [])),
                        self._encode_meta(cp.get("untracked_files", [])),
                    ),
                )

    def load_checkpoints(self):
        with self._lock, self._connect() as conn:
            rows = conn.execute(
                """
                SELECT position, label, git_ref, created_at, snapshot_dir, status_lines_json, untracked_files_json
                FROM checkpoints
                ORDER BY position ASC
                """
            ).fetchall()
        checkpoints = []
        for row in rows:
            checkpoints.append({
                "git_ref": row["git_ref"],
                "label": row["label"],
                "timestamp": row["created_at"],
                "status_lines": self._decode_meta(row["status_lines_json"]) or [],
                "snapshot_dir": row["snapshot_dir"],
                "untracked_files": self._decode_meta(row["untracked_files_json"]) or [],
            })
        return checkpoints

    def upsert_job(self, job_id, job_type, state, command_or_prompt="", result_summary="", error_summary="", external_ref=""):
        now = time.time()
        existing = self.get_job(job_id)
        started_at = existing.get("started_at", now) if existing else now
        finished_at = now if state in ("finished", "failed", "orphaned", "unknown") else None
        with self._lock, self._connect() as conn:
            conn.execute(
                """
                INSERT OR REPLACE INTO jobs
                (job_id, job_type, state, command_or_prompt, started_at, finished_at, last_heartbeat_at,
                 result_summary, error_summary, external_ref)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    job_id,
                    job_type,
                    state,
                    command_or_prompt,
                    started_at,
                    finished_at,
                    now,
                    _summarize_output_text(result_summary, 2000),
                    _summarize_output_text(error_summary, 2000),
                    external_ref,
                ),
            )

    def get_job(self, job_id):
        with self._lock, self._connect() as conn:
            row = conn.execute("SELECT * FROM jobs WHERE job_id = ?", (job_id,)).fetchone()
        return dict(row) if row else None

    def list_jobs(self):
        with self._lock, self._connect() as conn:
            rows = conn.execute("SELECT * FROM jobs ORDER BY started_at DESC, job_id DESC").fetchall()
        return [dict(row) for row in rows]

    def reconcile_running_jobs(self):
        now = time.time()
        with self._lock, self._connect() as conn:
            cur = conn.execute(
                """
                UPDATE jobs
                SET state = 'orphaned', finished_at = ?, last_heartbeat_at = ?
                WHERE state = 'running'
                """,
                (now, now),
            )
            changed = cur.rowcount or 0
        if changed:
            self.record_resume_event("job_reconciled", f"Marked {changed} running job(s) as orphaned during resume.")
        return changed

    def record_verifier_run(self, verifier_type, command, status, summary="", output_path=None):
        now = time.time()
        with self._lock, self._connect() as conn:
            conn.execute(
                """
                INSERT INTO verifier_runs (verifier_type, command, status, started_at, finished_at, summary, output_path)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    verifier_type,
                    command,
                    status,
                    now,
                    now,
                    _summarize_output_text(summary, 2000),
                    output_path,
                ),
            )

    def latest_verifier_run(self):
        with self._lock, self._connect() as conn:
            row = conn.execute(
                """
                SELECT verifier_type, command, status, finished_at, summary, output_path
                FROM verifier_runs
                ORDER BY verifier_id DESC
                LIMIT 1
                """
            ).fetchone()
        return dict(row) if row else None

    def list_resume_events(self, limit=5):
        limit = max(1, int(limit or 1))
        with self._lock, self._connect() as conn:
            rows = conn.execute(
                """
                SELECT event_type, message, created_at
                FROM resume_events
                ORDER BY event_id DESC
                LIMIT ?
                """,
                (limit,),
            ).fetchall()
        events = [dict(row) for row in rows]
        events.reverse()
        return events

    def record_resume_event(self, event_type, message):
        with self._lock, self._connect() as conn:
            conn.execute(
                "INSERT INTO resume_events (event_type, message, created_at) VALUES (?, ?, ?)",
                (event_type, message, time.time()),
            )

    def get_resume_summary(self):
        runtime = self.load_runtime()
        with self._lock, self._connect() as conn:
            pending_tasks = conn.execute(
                "SELECT COUNT(*) FROM tasks WHERE status IN ('pending', 'in_progress')"
            ).fetchone()[0]
            running_jobs = conn.execute(
                "SELECT COUNT(*) FROM jobs WHERE state = 'running'"
            ).fetchone()[0]
            orphaned_jobs = conn.execute(
                "SELECT COUNT(*) FROM jobs WHERE state = 'orphaned'"
            ).fetchone()[0]
            latest_checkpoint = conn.execute(
                "SELECT label FROM checkpoints ORDER BY position DESC LIMIT 1"
            ).fetchone()
        return {
            "last_known_phase": runtime.get("last_known_phase"),
            "plan_mode": bool(runtime.get("plan_mode", False)),
            "active_plan_path": runtime.get("active_plan_path"),
            "autotest_enabled": bool(runtime.get("autotest_enabled", False)),
            "watcher_enabled": bool(runtime.get("watcher_enabled", False)),
            "resume_hint": runtime.get("resume_hint"),
            "verification_required": bool(runtime.get("verification_required", False)),
            "pending_verification": runtime.get("pending_verification") or [],
            "last_verification_status": runtime.get("last_verification_status"),
            "pending_tasks": pending_tasks,
            "running_jobs": running_jobs,
            "orphaned_jobs": orphaned_jobs,
            "latest_checkpoint": latest_checkpoint["label"] if latest_checkpoint else None,
            "latest_verifier": self.latest_verifier_run(),
            "recent_events": self.list_resume_events(limit=3),
        }


# ════════════════════════════════════════════════════════════════════════════════
# Task Management (in-memory store)
# ════════════════════════════════════════════════════════════════════════════════

_task_store = {"next_id": 1, "tasks": {}}
_task_store_lock = threading.Lock()  # Thread safety for parallel tool execution

# Undo stack for file modifications (max 20)
_undo_stack = collections.deque(maxlen=20)  # deque of (filepath, original_content)


def _snapshot_task_store_locked():
    return copy.deepcopy({
        "next_id": _task_store["next_id"],
        "tasks": _task_store["tasks"],
    })


def _replace_task_store(snapshot):
    snapshot = snapshot or {"next_id": 1, "tasks": {}}
    with _task_store_lock:
        _task_store["next_id"] = int(snapshot.get("next_id", 1) or 1)
        _task_store["tasks"] = copy.deepcopy(snapshot.get("tasks", {}))


def _persist_task_store(snapshot=None):
    runtime_state = _get_active_runtime_state()
    if runtime_state is None:
        return
    if snapshot is None:
        with _task_store_lock:
            snapshot = _snapshot_task_store_locked()
    runtime_state.save_task_store(snapshot)


def _restore_task_store(runtime_state):
    if runtime_state is None:
        _replace_task_store({"next_id": 1, "tasks": {}})
        return
    _replace_task_store(runtime_state.load_task_store())


class TaskCreateTool(Tool):
    name = "TaskCreate"
    description = (
        "Create a new task to track work. Returns the new task ID. "
        "Use this to break down complex work into trackable steps."
    )
    parameters = {
        "type": "object",
        "properties": {
            "subject": {
                "type": "string",
                "description": "Brief imperative title (e.g. 'Fix login bug')",
            },
            "description": {
                "type": "string",
                "description": "Detailed description of what needs to be done",
            },
            "activeForm": {
                "type": "string",
                "description": "Present-continuous form shown while in progress (e.g. 'Fixing login bug')",
            },
        },
        "required": ["subject", "description"],
    }

    MAX_TASKS = 200  # prevent unbounded memory growth

    def execute(self, params):
        subject = params.get("subject", "").strip()
        description = params.get("description", "").strip()
        active_form = params.get("activeForm", "").strip()
        if not subject:
            return "Error: subject is required"
        if not description:
            return "Error: description is required"
        with _task_store_lock:
            if len(_task_store["tasks"]) >= self.MAX_TASKS:
                return f"Error: task limit reached ({self.MAX_TASKS}). Delete old tasks before creating new ones."
            tid = str(_task_store["next_id"])
            _task_store["next_id"] += 1
            _task_store["tasks"][tid] = {
                "id": tid,
                "subject": subject,
                "description": description,
                "activeForm": active_form or f"Working on: {subject}",
                "status": "pending",
                "blocks": [],
                "blockedBy": [],
            }
            snapshot = _snapshot_task_store_locked()
        _persist_task_store(snapshot)
        return f"Created task #{tid}: {subject}"


class TaskListTool(Tool):
    name = "TaskList"
    description = "List all tasks with their id, subject, status, and blockedBy fields."
    parameters = {
        "type": "object",
        "properties": {},
    }

    STATUS_ICONS = {
        "pending": "⬜",
        "in_progress": "🔄",
        "completed": "✅",
        "skipped": "⏭️",
        "deleted": "❌",
    }

    def execute(self, params):
        with _task_store_lock:
            tasks = _task_store["tasks"]
            if not tasks:
                return "No tasks."
            
            # Count statistics
            total = len(tasks)
            completed = sum(1 for t in tasks.values() if t["status"] == "completed")
            in_progress = sum(1 for t in tasks.values() if t["status"] == "in_progress")
            pending = sum(1 for t in tasks.values() if t["status"] == "pending")
            
            # Build task list with icons
            lines = []
            for tid, t in sorted(tasks.items(), key=lambda x: int(x[0])):
                icon = self.STATUS_ICONS.get(t["status"], "⬜")
                blocked = ""
                open_blockers = [b for b in t.get("blockedBy", []) if b in tasks and tasks[b]["status"] != "completed"]
                if open_blockers:
                    blocked = f"  {C.DIM}blockedBy: [{', '.join(open_blockers)}]{C.RESET}"
                lines.append(f"  {icon} {t['subject']}{blocked}")
            
            # Build header with progress
            header = f"{C.BOLD}📋 タスク進捗{C.RESET}\n"
            progress = f"[進行状況：{completed}/{total} 完了"
            if in_progress > 0:
                progress += f", {in_progress} 件中"
            progress += "]"
            
            result = header + "\n" + "\n".join(lines) + "\n\n" + progress
        
        return result


class TaskGetTool(Tool):
    name = "TaskGet"
    description = "Get full details of a task by its ID."
    parameters = {
        "type": "object",
        "properties": {
            "taskId": {
                "type": "string",
                "description": "The task ID to retrieve",
            },
        },
        "required": ["taskId"],
    }

    def execute(self, params):
        tid = str(params.get("taskId", "")).strip()
        if not tid:
            return "Error: taskId is required"
        snapshot = None
        with _task_store_lock:
            task = _task_store["tasks"].get(tid)
            if not task:
                return f"Error: task #{tid} not found"
            lines = [
                f"Task #{tid}",
                f"  Subject: {task['subject']}",
                f"  Status: {task['status']}",
                f"  ActiveForm: {task.get('activeForm', '')}",
                f"  Description: {task['description']}",
            ]
            if task.get("blocks"):
                lines.append(f"  Blocks: [{', '.join(task['blocks'])}]")
            if task.get("blockedBy"):
                lines.append(f"  BlockedBy: [{', '.join(task['blockedBy'])}]")
        return "\n".join(lines)


class TaskUpdateTool(Tool):
    name = "TaskUpdate"
    description = (
        "Update an existing task. Can change status, subject, description, "
        "and manage dependency links (addBlocks, addBlockedBy)."
    )
    parameters = {
        "type": "object",
        "properties": {
            "taskId": {
                "type": "string",
                "description": "The task ID to update",
            },
            "status": {
                "type": "string",
                "description": "New status: pending, in_progress, completed, skipped, or deleted",
            },
            "subject": {
                "type": "string",
                "description": "New subject",
            },
            "description": {
                "type": "string",
                "description": "New description",
            },
            "addBlocks": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Task IDs that this task blocks",
            },
            "addBlockedBy": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Task IDs that block this task",
            },
        },
        "required": ["taskId"],
    }

    VALID_STATUSES = {"pending", "in_progress", "completed", "skipped", "deleted"}

    def execute(self, params):
        tid = str(params.get("taskId", "")).strip()
        if not tid:
            return "Error: taskId is required"
        with _task_store_lock:
            task = _task_store["tasks"].get(tid)
            if not task:
                return f"Error: task #{tid} not found"

            status = params.get("status")
            if status:
                if status not in self.VALID_STATUSES:
                    return f"Error: invalid status '{status}'. Must be: {', '.join(sorted(self.VALID_STATUSES))}"
                if status == "deleted":
                    del _task_store["tasks"][tid]
                    # Clean up references in other tasks
                    for other_task in _task_store["tasks"].values():
                        if tid in other_task.get("blocks", []):
                            other_task["blocks"].remove(tid)
                        if tid in other_task.get("blockedBy", []):
                            other_task["blockedBy"].remove(tid)
                    snapshot = _snapshot_task_store_locked()
                    _persist_task_store(snapshot)
                    return f"Deleted task #{tid}"
                task["status"] = status

            if "subject" in params and params["subject"]:
                task["subject"] = params["subject"]
            if "description" in params and params["description"]:
                task["description"] = params["description"]

            # Helper: detect cycles via DFS
            def _has_cycle(start, direction="blocks"):
                visited = set()
                stack = [start]
                while stack:
                    node = stack.pop()
                    if node in visited:
                        continue
                    visited.add(node)
                    t = _task_store["tasks"].get(node)
                    if t:
                        stack.extend(t.get(direction, []))
                return visited

            for block_id in params.get("addBlocks", []):
                # Cycle check: if block_id already blocks tid (directly or transitively)
                if tid in _has_cycle(block_id, "blocks"):
                    return f"Error: adding block #{block_id} would create a dependency cycle"
                if block_id not in task["blocks"]:
                    task["blocks"].append(block_id)
                other = _task_store["tasks"].get(block_id)
                if other and tid not in other["blockedBy"]:
                    other["blockedBy"].append(tid)

            for blocker_id in params.get("addBlockedBy", []):
                # Cycle check: if tid already blocks blocker_id
                if blocker_id in _has_cycle(tid, "blocks"):
                    return f"Error: adding blockedBy #{blocker_id} would create a dependency cycle"
                if blocker_id not in task["blockedBy"]:
                    task["blockedBy"].append(blocker_id)
                other = _task_store["tasks"].get(blocker_id)
                if other and tid not in other["blocks"]:
                    other["blocks"].append(tid)
            snapshot = _snapshot_task_store_locked()
        _persist_task_store(snapshot)
        return f"Updated task #{tid}: [{task['status']}] {task['subject']}"


# ════════════════════════════════════════════════════════════════════════════════
# AskUserQuestion — Interactive prompt during execution
# ════════════════════════════════════════════════════════════════════════════════

class AskUserQuestionTool(Tool):
    """Ask the user a clarifying question during execution.

    Use this when you need user input to proceed, such as:
    - Choosing between implementation approaches
    - Clarifying ambiguous requirements
    - Getting decisions on design choices
    """
    name = "AskUserQuestion"
    description = (
        "Ask the user a question during execution. Present options for them to choose from. "
        "Use when you need clarification to proceed. Returns the user's answer."
    )
    parameters = {
        "type": "object",
        "properties": {
            "question": {
                "type": "string",
                "description": "The question to ask the user",
            },
            "options": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Options for the user to choose from (2-5 options). User can also type a custom answer.",
            },
        },
        "required": ["question"],
    }

    def execute(self, params):
        question = params.get("question", "")
        options = params.get("options", [])
        if not question:
            return "Error: question is required"
        if _active_notifier is not None:
            _active_notifier.notify("question", {
                "event": "question",
                "question": question[:2000],
                "options": list(options[:10]) if isinstance(options, list) else [],
                "cwd": os.getcwd(),
            })

        # ── Channel mode: route question through channel_manager ──
        ctx = _active_channel_context
        if ctx is not None:
            cm = ctx["channel_manager"]
            src = ctx["source_msg"]
            # Format question for channel
            q_text = f"**Question:** {question}\n"
            if options:
                for i, opt in enumerate(options, 1):
                    q_text += f"  {i}. {opt}\n"
                q_text += "Reply with a number or type your answer."
            else:
                q_text += "Type your answer."
            answer = cm.ask_question(src, q_text, timeout=300)
            if not answer or answer.startswith("(no response"):
                return "User provided no answer (channel timeout)."
            answer = answer.strip()
            if options and answer.isdigit():
                idx = int(answer) - 1
                if 0 <= idx < len(options):
                    return f"User chose: {options[idx]}"
            return f"User answered: {answer}"

        # ── Terminal mode: original input() flow ──
        # Stop tool status spinner before prompting (prevents \r overwrite of input)
        if _active_tui is not None:
            _active_tui.stop_spinner()

        # Temporarily teardown scroll region for proper input handling
        _scroll_mode_active = False
        if _active_scroll_region is not None and _active_scroll_region._active:
            _scroll_mode_active = True
            _active_scroll_region.teardown()

        try:
            with _print_lock:
                print(f"\n{_ansi(C.CYAN)}{_ansi(C.BOLD)}Question:{_ansi(C.RESET)} {question}")
                if options:
                    for i, opt in enumerate(options, 1):
                        print(f"  {_ansi(C.CYAN)}{i}.{_ansi(C.RESET)} {opt}")
                    print(f"  {_ansi(C.DIM)}Enter number or type your own answer:{_ansi(C.RESET)}")
                else:
                    print(f"  {_ansi(C.DIM)}Type your answer:{_ansi(C.RESET)}")

            try:
                # Avoid ANSI codes in input() prompt on macOS - causes IME/input issues.
                answer = input("  > ").strip()
                # Strip terminal escape sequences (same as TUI.get_input)
                import re as _re
                answer = _re.sub(r'\x1b\[[0-9;]*[a-zA-Z~]', '', answer)
                answer = _strip_shift_enter_garbage(answer)
                answer = answer.strip()
            except (EOFError, KeyboardInterrupt):
                return "User cancelled the question."

            if not answer:
                return "User provided no answer."

            # If user entered a number, map to option
            if options and answer.isdigit():
                idx = int(answer) - 1
                if 0 <= idx < len(options):
                    return f"User chose: {options[idx]}"

            return f"User answered: {answer}"
        finally:
            # Restore scroll region if it was active
            if _scroll_mode_active and _active_scroll_region is not None:
                _active_scroll_region.setup()




# ════════════════════════════════════════════════════════════════════════════════
# AskUserQuestionBatch — Multiple questions in one prompt
# ════════════════════════════════════════════════════════════════════════════════

class AskUserQuestionBatchTool(Tool):
    """Ask multiple questions to the user in a single prompt.

    Use this when you need multiple clarifications at once, such as:
    - Multiple design choices to decide
    - Several configuration options
    - A questionnaire with multiple items

    The user can answer by entering numbers for each question (e.g., "1, 2, 1, 3")
    or by typing custom answers (e.g., "A, B, C, custom answer").
    """
    name = "AskUserQuestionBatch"
    description = (
        "Ask multiple questions to the user in a single prompt. "
        "Present multiple questions with options for each. "
        "Use when you need multiple clarifications at once to avoid repeated prompts. "
        "Returns the user's answers for all questions."
    )
    parameters = {
        "type": "object",
        "properties": {
            "questions": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "question": {
                            "type": "string",
                            "description": "The question text",
                        },
                        "options": {
                            "type": "array",
                            "items": {"type": "string"},
                            "description": "Options for this question (2-5 options). User can also type a custom answer.",
                        },
                    },
                    "required": ["question"],
                },
                "description": "Array of questions to ask (1-10 questions)",
            },
        },
        "required": ["questions"],
    }

    @staticmethod
    def _format_questions_text(questions):
        """Format questions for display (shared between terminal and channel modes)."""
        lines = []
        for i, q in enumerate(questions, 1):
            q_text = q.get("question", "")
            q_options = q.get("options", [])
            lines.append(f"Q{i}. {q_text}")
            if q_options:
                for j, opt in enumerate(q_options, ord('A')):
                    lines.append(f"  {chr(j)}. {opt}")
        lines.append("")
        lines.append("Reply with answers separated by commas (e.g. A, B, C or 1, 2, custom answer)")
        return "\n".join(lines)

    @staticmethod
    def _parse_batch_answers(answer, questions):
        """Parse comma-separated answers and map to options."""
        answers = [a.strip() for a in answer.split(',')]
        results = []
        for i, q in enumerate(questions, 1):
            q_options = q.get("options", [])
            user_answer = answers[i-1] if i-1 < len(answers) else "(no answer)"
            if q_options and user_answer.isdigit():
                idx = int(user_answer) - 1
                if 0 <= idx < len(q_options):
                    user_answer = q_options[idx]
            elif q_options and len(user_answer) == 1 and user_answer.upper().isalpha():
                idx = ord(user_answer.upper()) - ord('A')
                if 0 <= idx < len(q_options):
                    user_answer = q_options[idx]
            results.append({"question_number": i, "question": q.get("question", ""), "answer": user_answer})
        return "User answered:\n" + "\n".join(f"Q{r['question_number']}: {r['answer']}" for r in results)

    def execute(self, params):
        questions = params.get("questions", [])
        if not questions:
            return "Error: questions array is required"
        if _active_notifier is not None:
            _active_notifier.notify("question", {
                "event": "question",
                "questions": questions[:10],
                "cwd": os.getcwd(),
            })

        if len(questions) > 10:
            return "Error: maximum 10 questions allowed"

        # ── Channel mode: route questions through channel_manager ──
        ctx = _active_channel_context
        if ctx is not None:
            cm = ctx["channel_manager"]
            src = ctx["source_msg"]
            q_text = self._format_questions_text(questions)
            answer = cm.ask_question(src, q_text, timeout=300)
            if not answer or answer.startswith("(no response"):
                return "User provided no answer (channel timeout)."
            return self._parse_batch_answers(answer.strip(), questions)

        # ── Terminal mode: original input() flow ──
        # Stop tool status spinner before prompting (prevents \r overwrite of input)
        if _active_tui is not None:
            _active_tui.stop_spinner()

        # Temporarily teardown scroll region for proper input handling
        _scroll_mode_active = False
        if _active_scroll_region is not None and _active_scroll_region._active:
            _scroll_mode_active = True
            _active_scroll_region.teardown()

        try:
            # Display all questions
            with _print_lock:
                print(f"\n{_ansi(C.CYAN)}{_ansi(C.BOLD)}{'='*60}{_ansi(C.RESET)}")
                print(f"{_ansi(C.CYAN)}{_ansi(C.BOLD)}質問：{len(questions)}件{_ansi(C.RESET)}")
                print(f"{_ansi(C.CYAN)}{_ansi(C.BOLD)}{'='*60}{_ansi(C.RESET)}\n")

                for i, q in enumerate(questions, 1):
                    q_text = q.get("question", "")
                    q_options = q.get("options", [])
                    print(f"{_ansi(C.BOLD)}Q{i}. {q_text}{_ansi(C.RESET)}")
                    if q_options:
                        for j, opt in enumerate(q_options, ord('A')):
                            print(f"  - {chr(j)}. {opt}")
                    print()

                print(f"{_ansi(C.DIM)}回答形式:{_ansi(C.RESET)}")
                print(f"  例：A, B, C または 1, 2, 3 または A, B, カスタム回答")
                print(f"  {_ansi(C.DIM)}各質問の答えをカンマ区切りで入力してください:{_ansi(C.RESET)}")

            try:
                # Avoid ANSI codes in input() prompt on macOS - causes IME/input issues.
                answer = input("  > ").strip()
                # Strip terminal escape sequences (same as TUI.get_input)
                import re as _re
                answer = _re.sub(r'\x1b\[[0-9;]*[a-zA-Z~]', '', answer)
                answer = _strip_shift_enter_garbage(answer)
                answer = answer.strip()
            except (EOFError, KeyboardInterrupt):
                return "User cancelled the question."

            if not answer:
                return "User provided no answer."

            return self._parse_batch_answers(answer, questions)
        finally:
            # Restore scroll region if it was active
            if _scroll_mode_active and _active_scroll_region is not None:
                _active_scroll_region.setup()



# Sub-Agent — Spawns a mini agent loop in a separate thread
# ════════════════════════════════════════════════════════════════════════════════

class SubAgentTool(Tool):
    """Launch a sub-agent to handle a research or analysis task autonomously.

    The sub-agent runs its own agent loop with a separate conversation context.
    By default it only has access to read-only tools (Read, Glob, Grep,
    WebFetch, WebSearch). Set allow_writes=true to grant Bash/Write/Edit/ApplyPatch.
    """
    name = "SubAgent"
    description = (
        "Launch a sub-agent to handle a task autonomously in a separate thread. "
        "The sub-agent can use tools to research, read files, search code, etc. "
        "Returns the sub-agent's final text response. Use for tasks that require "
        "multiple tool calls but don't need your direct supervision."
    )

    # Read-only tools allowed by default
    READ_ONLY_TOOLS = frozenset({"Read", "Glob", "Grep", "WebFetch", "WebSearch"})
    # Additional tools when allow_writes is True
    WRITE_TOOLS = frozenset({"Bash", "Write", "Edit", "ApplyPatch", "MultiEdit", "NotebookEdit"})
    NETWORK_TOOLS = frozenset({"WebFetch", "WebSearch"})
    # Hard cap on max_turns to prevent runaway loops
    HARD_MAX_TURNS = HARD_MAX_SUBAGENT_TURNS

    def __init__(self, config, client, registry, permissions=None, tui=None):
        self._config = config
        self._client = client
        self._registry = registry
        self._permissions = permissions
        self._tui = tui

    def set_tui(self, tui):
        self._tui = tui

    @staticmethod
    def _make_isolated_tool(name, cwd):
        cwd_aware = {
            "Bash": BashTool,
            "Read": ReadTool,
            "Write": WriteTool,
            "Edit": EditTool,
            "ApplyPatch": ApplyPatchTool,
            "MultiEdit": MultiEditTool,
            "Glob": GlobTool,
            "Grep": GrepTool,
            "NotebookEdit": NotebookEditTool,
        }
        tool_cls = cwd_aware.get(name)
        return tool_cls(cwd=cwd) if tool_cls else None

    def _build_tool_map(self, allowed_tools, cwd):
        tool_map = {}
        for name in allowed_tools:
            tool = self._make_isolated_tool(name, cwd)
            if tool is None:
                tool = self._registry.get(name)
            if tool is not None:
                tool_map[tool.name] = tool
        return tool_map

    @classmethod
    def _base_allowed_tools(cls, allow_writes):
        allowed_tools = set(cls.READ_ONLY_TOOLS)
        if allow_writes:
            allowed_tools |= cls.WRITE_TOOLS
        return allowed_tools

    @classmethod
    def _resolve_allowed_tools(cls, persona_tools, allow_writes):
        allowed_tools = cls._base_allowed_tools(allow_writes)
        if not persona_tools:
            return allowed_tools
        return allowed_tools.intersection({str(tool_name) for tool_name in persona_tools if tool_name})

    @property
    def parameters(self):
        return {
            "type": "object",
            "properties": {
                "prompt": {
                    "type": "string",
                    "description": "The task for the sub-agent to perform",
                },
                "agent_name": {
                    "type": "string",
                    "description": "Name of a defined agent persona from .eve-cli/agents/*.md (e.g. 'code-reviewer'). Overrides default system prompt with the agent's persona.",
                },
                "max_turns": {
                    "type": "integer",
                    "description": (
                        f"Max agent loop iterations "
                        f"(default {_get_default_subagent_max_turns(self._config)}, hard cap {self.HARD_MAX_TURNS})"
                    ),
                },
                "allow_writes": {
                    "type": "boolean",
                    "description": "Allow write tools: Bash, Write, Edit (default false)",
                },
                "isolation": {
                    "type": "string",
                    "enum": ["none", "worktree"],
                    "description": "Isolation mode: 'worktree' runs in a temporary git worktree (default: none)",
                },
            },
            "required": ["prompt"],
        }

    @staticmethod
    def _load_agent_persona(config, agent_name):
        """Load an agent persona from .eve-cli/agents/ or ~/.config/eve-cli/agents/.

        Returns (system_prompt, allowed_tools, model) or (None, None, None) if not found.
        """
        for _apath in _trusted_agent_persona_paths(config):
            if os.path.splitext(os.path.basename(_apath))[0] != agent_name:
                continue
            try:
                _acontent = _read_text_file_guarded(_apath, 8000)
            except OSError:
                continue
            # Parse frontmatter
            fm, body = {}, _acontent
            if _acontent.startswith("---"):
                parts = _acontent.split("---", 2)
                if len(parts) >= 3:
                    for line in parts[1].strip().split("\n"):
                        line = line.strip()
                        if not line or line.startswith("#"):
                            continue
                        if ":" in line:
                            key, val = line.split(":", 1)
                            key = key.strip()
                            val = val.strip().strip("\"'")
                            if key == "tools" and val.startswith("[") and val.endswith("]"):
                                val = [t.strip() for t in val[1:-1].split(",") if t.strip()]
                            fm[key] = val
                    body = parts[2].strip()
            _tools = fm.get("tools")
            if isinstance(_tools, str):
                _tools = [t.strip() for t in _tools.split(",") if t.strip()]
            _model = fm.get("model")
            return body, _tools, _model
        return None, None, None

    @staticmethod
    def _build_sub_system_prompt(config, persona_prompt=None):
        """Build a system prompt for the sub-agent, optionally using a persona."""
        if persona_prompt:
            return (
                f"{persona_prompt}\n\n"
                f"Working directory: {config.cwd}\n"
                f"Platform: {platform.system().lower()}\n"
            )
        return (
            "You are a sub-agent assistant. Complete the given task using the available tools. "
            "Be thorough but concise. When you have enough information, provide a clear final answer. "
            "Do NOT ask follow-up questions — just complete the task and respond.\n"
            f"Working directory: {config.cwd}\n"
            f"Platform: {platform.system().lower()}\n"
        )

    @staticmethod
    def _format_result_payload(result_text, *, ok, duration, error=None,
                               worktree_path=None, worktree_branch=None):
        return {
            "ok": bool(ok),
            "result": result_text,
            "summary": _summarize_output_text(result_text, 240),
            "error": error,
            "duration": duration,
            "worktree_path": worktree_path,
            "worktree_branch": worktree_branch,
        }

    def execute(self, params):
        prompt = params.get("prompt", "")
        if not prompt:
            return "Error: prompt is required"

        max_turns = _normalize_subagent_max_turns(
            params.get("max_turns", _get_default_subagent_max_turns(self._config)),
            default=_get_default_subagent_max_turns(self._config),
        )

        allow_writes = params.get("allow_writes", False)
        structured_result = bool(params.get("_structured_result", False))
        runtime_state = _get_active_runtime_state()
        if allow_writes and runtime_state is not None and runtime_state.get_meta("plan_mode", False):
            error_text = (
                "Error: allow_writes is not permitted while plan mode is active. "
                "Use /approve to switch to Act mode before delegating write-capable sub-agents."
            )
            if structured_result:
                return self._format_result_payload(error_text, ok=False, duration=0.0, error=error_text)
            return error_text

        # Worktree isolation setup
        isolation = params.get("isolation", "none")
        worktree_path = None
        worktree_branch = None
        wt_manager = None

        if isolation == "worktree" and allow_writes:
            wt_manager = GitWorktree(self._config.cwd)
            worktree_path, worktree_branch = wt_manager.create()
            if worktree_path:
                sub_config = copy.copy(self._config)
                sub_config.cwd = worktree_path
                with _print_lock:
                    _scroll_aware_print(
                        f"  {C.DIM}  \u21b3 Worktree: {worktree_path} (branch: {worktree_branch}){C.RESET}")
            else:
                sub_config = self._config
                with _print_lock:
                    _scroll_aware_print(
                        f"  {C.DIM}  \u21b3 Worktree creation failed, running in main directory{C.RESET}")
        else:
            sub_config = self._config

        # Load agent persona if specified
        _agent_name = params.get("agent_name", "")
        _persona_prompt = None
        _persona_tools = None
        _persona_model = None
        if _agent_name:
            _persona_prompt, _persona_tools, _persona_model = self._load_agent_persona(
                self._config, _agent_name)
            if _persona_prompt is None:
                _avail_msg = f"Error: agent persona '{_agent_name}' not found. "
                _avail_msg += "Place agent files in .eve-cli/agents/<name>.md"
                if structured_result:
                    return self._format_result_payload(_avail_msg, ok=False, duration=0.0, error=_avail_msg)
                return _avail_msg

        # Determine allowed tool set (persona tools can narrow, but never expand, parent permissions)
        allowed_tools = self._resolve_allowed_tools(_persona_tools, allow_writes)
        sub_tools = self._build_tool_map(allowed_tools, sub_config.cwd)

        # Print minimal status (with optional agent label for parallel runs)
        agent_label = params.get("_agent_label", "") or _agent_name
        label_str = f" [{agent_label}]" if agent_label else ""
        prompt_preview = prompt[:80] + ("..." if len(prompt) > 80 else "")
        _sub_start = time.time()
        with _print_lock:
            _scroll_aware_print(f"\n  {_ansi(chr(27)+'[38;5;141m')}🤖{label_str} Sub-agent working on: {prompt_preview}{C.RESET}",
                  flush=True)

        # Build tool schemas for the sub-agent (only allowed tools)
        schemas = [tool.get_schema() for tool in sub_tools.values()]

        # Build sub-agent conversation
        messages = [
            {"role": "system", "content": self._build_sub_system_prompt(sub_config, persona_prompt=_persona_prompt)},
            {"role": "user", "content": prompt},
        ]

        result_text = ""
        last_text = ""
        error_text = None

        for turn in range(max_turns):
            try:
                _sub_model = _persona_model or self._config.sidecar_model or self._config.model
                resp = self._client.chat_sync(
                    model=_sub_model,
                    messages=messages,
                    tools=schemas if schemas else None,
                )
            except Exception as e:
                result_text = f"Sub-agent error on turn {turn + 1}: {e}"
                error_text = result_text
                break

            text = resp.get("content", "")
            tool_calls = resp.get("tool_calls", [])
            last_text = text

            # Also check for XML tool calls in text (Qwen compatibility)
            if not tool_calls and text:
                extracted, cleaned = _extract_tool_calls_from_text(
                    text, known_tools=list(sub_tools.keys())
                )
                if extracted:
                    # Convert extracted format to chat_sync format
                    tool_calls = []
                    for etc in extracted:
                        func = etc.get("function", {})
                        raw_args = func.get("arguments", "{}")
                        try:
                            args = json.loads(raw_args) if isinstance(raw_args, str) else raw_args
                        except json.JSONDecodeError:
                            args = {"raw": raw_args}
                        tool_calls.append({
                            "id": etc.get("id", f"call_{uuid.uuid4().hex[:8]}"),
                            "name": func.get("name", ""),
                            "arguments": args,
                        })
                    text = cleaned

            # Add assistant message to sub-conversation
            if tool_calls:
                # Build OpenAI-format tool_calls for the message
                oai_tool_calls = []
                for tc in tool_calls:
                    oai_tool_calls.append({
                        "id": tc["id"],
                        "type": "function",
                        "function": {
                            "name": tc["name"],
                            "arguments": json.dumps(tc["arguments"], ensure_ascii=False),
                        },
                    })
                messages.append({
                    "role": "assistant",
                    "content": text or None,
                    "tool_calls": oai_tool_calls,
                })
            else:
                messages.append({"role": "assistant", "content": text or ""})

            # If no tool calls, the sub-agent is done
            if not tool_calls:
                result_text = text
                break

            # Execute each tool call
            for tc in tool_calls:
                tc_name = tc["name"]
                tc_id = tc["id"]
                tc_args = tc["arguments"]

                if tc_name not in sub_tools:
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc_id,
                        "content": f"Error: tool '{tc_name}' is not allowed in this sub-agent",
                    })
                    continue

                tool = sub_tools.get(tc_name)
                if not tool:
                    messages.append({
                        "role": "tool",
                        "tool_call_id": tc_id,
                        "content": f"Error: unknown tool '{tc_name}'",
                    })
                    continue

                # SubAgent must respect the parent permission system.
                if (tc_name in self.WRITE_TOOLS or tc_name in self.NETWORK_TOOLS) and self._permissions is not None:
                    if not self._permissions.check(tc_name, tc_args, self._tui):
                        messages.append({
                            "role": "tool",
                            "tool_call_id": tc_id,
                            "content": "Error: permission denied by parent permission manager",
                        })
                        continue

                try:
                    output = tool.execute(tc_args)
                except Exception as e:
                    output = f"Error: {e}"

                # Truncate large outputs to prevent context blowup
                output_str = str(output) if output is not None else ""
                if len(output_str) > 10000:
                    output_str = output_str[:10000] + "\n...(truncated)"

                messages.append({
                    "role": "tool",
                    "tool_call_id": tc_id,
                    "content": output_str,
                })

            # Context window guard: estimate total message size
            total_chars = sum(len(str(m.get("content", ""))) for m in messages)
            max_chars = 80000  # ~20K tokens, safe for most models
            if total_chars > max_chars:
                # Truncate older tool results (preserve system + user + last 4 messages)
                for i in range(2, len(messages) - 4):
                    c = messages[i].get("content", "")
                    if messages[i].get("role") == "tool" and isinstance(c, str) and len(c) > 500:
                        messages[i]["content"] = c[:500] + "\n...(truncated by sub-agent context limit)"
        else:
            # Reached max_turns without a final text response
            result_text = (
                f"Sub-agent reached max turns ({max_turns}). "
                f"Last response: {last_text[:2000]}"
            )
            error_text = result_text

        # Worktree cleanup
        if worktree_path and wt_manager:
            try:
                has_changes = wt_manager.has_changes(worktree_path)
                if has_changes:
                    diff_preview = wt_manager.get_diff(worktree_path)
                    result_text += f"\n\n[Worktree changes on branch: {worktree_branch}]\n"
                    if diff_preview:
                        result_text += f"```diff\n{diff_preview[:3000]}\n```\n"
                    result_text += f"To apply: git merge {worktree_branch}"
                    # Don't remove worktree if it has changes
                    with _print_lock:
                        _scroll_aware_print(
                            f"  {C.DIM}  \u21b3 Worktree preserved (has changes): {worktree_path}{C.RESET}")
                else:
                    # Clean up: no changes
                    wt_manager.remove(worktree_path, worktree_branch)
                    with _print_lock:
                        _scroll_aware_print(
                            f"  {C.DIM}  \u21b3 Worktree cleaned up (no changes){C.RESET}")
            except Exception:
                # Best-effort cleanup on error
                try:
                    wt_manager.remove(worktree_path, worktree_branch)
                except Exception:
                    pass

        _sub_elapsed = time.time() - _sub_start
        with _print_lock:
            print(f"  {_ansi(chr(27)+'[38;5;141m')}🤖{label_str} Sub-agent finished ({_sub_elapsed:.1f}s){C.RESET}",
                  flush=True)

        # Truncate final result to prevent bloating parent context
        if len(result_text) > 20000:
            result_text = result_text[:20000] + "\n...(truncated)"

        if structured_result:
            return self._format_result_payload(
                result_text,
                ok=error_text is None,
                duration=_sub_elapsed,
                error=error_text,
                worktree_path=worktree_path,
                worktree_branch=worktree_branch,
            )
        return result_text


# ════════════════════════════════════════════════════════════════════════════════
# MCP Client — Model Context Protocol (stdio JSON-RPC 2.0)
# ════════════════════════════════════════════════════════════════════════════════

class MCPClient:
    """Communicates with an MCP server over stdin/stdout using JSON-RPC 2.0."""

    def __init__(self, name, command, args=None, env=None, startup_timeout=30, tool_timeout=30):
        self.name = name
        self.command = command
        self.args = args or []
        self.env = env or {}
        self.startup_timeout = max(1, int(startup_timeout or 30))
        self.tool_timeout = max(1, int(tool_timeout or 30))
        self._proc = None
        self._request_id = 0
        self._tools = {}  # name -> schema

    def start(self):
        """Start the MCP server subprocess."""
        full_env = {}
        for key in ("PATH", "HOME", "USER", "LOGNAME", "SHELL", "TERM", "LANG", "TMPDIR", "TMP", "TEMP"):
            if key in os.environ:
                full_env[key] = os.environ[key]
        full_env.update(self.env)
        try:
            self._proc = subprocess.Popen(
                [self.command] + self.args,
                stdin=subprocess.PIPE,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env=full_env,
                start_new_session=True,
            )
        except (FileNotFoundError, PermissionError) as e:
            raise RuntimeError(t('errors.mcp_server_start_failed', default=f"MCP server '{self.name}' failed to start: {e}"))

    def stop(self):
        """Stop the MCP server subprocess."""
        if self._proc and self._proc.poll() is None:
            try:
                self._proc.stdin.close()
                self._proc.wait(timeout=5)
            except Exception:
                try:
                    self._proc.kill()
                except Exception:
                    pass

    def _send(self, method, params=None, timeout=None):
        """Send a JSON-RPC 2.0 request and return the result."""
        if not self._proc or self._proc.poll() is not None:
            raise RuntimeError(t('errors.mcp_server_not_running', default=f"MCP server '{self.name}' is not running"))
        self._request_id += 1
        request = {
            "jsonrpc": "2.0",
            "id": self._request_id,
            "method": method,
        }
        if params is not None:
            request["params"] = params
        data = json.dumps(request) + "\n"
        try:
            self._proc.stdin.write(data.encode("utf-8"))
            self._proc.stdin.flush()
            # Use select() with timeout to prevent infinite blocking
            # (npx/MCP servers may take time to start or hang on first launch)
            import select as _sel_mod
            timeout_s = max(1, int(timeout or self.tool_timeout))
            ready, _, _ = _sel_mod.select([self._proc.stdout], [], [], timeout_s)
            if not ready:
                raise RuntimeError(
                    f"MCP server '{self.name}' did not respond within {timeout_s}s. "
                    f"The server may still be starting (e.g. npx downloading packages). "
                    f"Try running the MCP command manually first: {self.command} {' '.join(self.args)}"
                )
            line = self._proc.stdout.readline()
            if not line:
                raise RuntimeError(t('errors.mcp_server_closed_unexpectedly', default=f"MCP server '{self.name}' closed unexpectedly"))
            response = json.loads(line.decode("utf-8"))
            if "error" in response:
                err = response["error"]
                raise RuntimeError(f"MCP error ({err.get('code', '?')}): {err.get('message', '?')}")
            return response.get("result", {})
        except (BrokenPipeError, OSError) as e:
            raise RuntimeError(t('errors.mcp_communication_failed', default=f"MCP server '{self.name}' communication failed: {e}"))

    def initialize(self):
        """Initialize the MCP connection and discover tools."""
        result = self._send("initialize", {
            "protocolVersion": "2024-11-05",
            "capabilities": {},
            "clientInfo": {"name": "eve-coder", "version": __version__}
        }, timeout=self.startup_timeout)
        # Send initialized notification (no response expected)
        notif = json.dumps({"jsonrpc": "2.0", "method": "notifications/initialized"}) + "\n"
        try:
            self._proc.stdin.write(notif.encode("utf-8"))
            self._proc.stdin.flush()
        except Exception:
            pass
        return result

    def list_tools(self):
        """Discover available tools from the MCP server."""
        result = self._send("tools/list", timeout=self.startup_timeout)
        tools = result.get("tools", [])
        self._tools = {t["name"]: t for t in tools}
        return tools

    def call_tool(self, name, arguments):
        """Call a tool on the MCP server."""
        result = self._send("tools/call", {"name": name, "arguments": arguments}, timeout=self.tool_timeout)
        # Extract text content from MCP response
        content = result.get("content", [])
        texts = []
        for item in content:
            if isinstance(item, dict) and item.get("type") == "text":
                texts.append(item.get("text", ""))
            elif isinstance(item, str):
                texts.append(item)
        return "\n".join(texts) if texts else json.dumps(result)


# ════════════════════════════════════════════════════════════════════════════════
# MCP Server Mode — expose eve-coder tools via JSON-RPC 2.0 over stdio
# ════════════════════════════════════════════════════════════════════════════════

class _MCPChatTool:
    """Synthetic tool for MCP server mode: send a prompt to the AI model."""

    name = "Chat"

    def get_schema(self):
        return {
            "type": "function",
            "function": {
                "name": "Chat",
                "description": "Send a prompt to the AI model and get a text response",
                "parameters": {
                    "type": "object",
                    "properties": {
                        "prompt": {"type": "string", "description": "The prompt to send"},
                        "model": {"type": "string", "description": "Optional model override"},
                    },
                    "required": ["prompt"],
                },
            },
        }

    def __init__(self, config, client):
        self._config = config
        self._client = client

    def execute(self, params):
        prompt = params.get("prompt", "")
        model = params.get("model") or self._config.model
        if not prompt:
            return "Error: prompt is required"
        messages = [
            {"role": "system", "content": "You are a helpful assistant."},
            {"role": "user", "content": prompt},
        ]
        try:
            resp = self._client.chat(model=model, messages=messages, tools=None, stream=False)
            choices = resp.get("choices", [])
            if choices:
                content = choices[0].get("message", {}).get("content", "")
            else:
                content = resp.get("message", {}).get("content", "")
            # Strip thinking traces (Qwen <think> and Gemma 4 <|channel>thought)
            content = _strip_thinking_tags(content)
            return content or "(empty response)"
        except Exception as e:
            return f"Chat error: {e}"


class MCPServer:
    """Run eve-coder as an MCP server, exposing built-in tools over JSON-RPC 2.0 stdio."""

    EXPOSED_TOOLS = frozenset({
        "Bash", "Read", "Write", "Edit", "Glob", "Grep", "WebFetch", "WebSearch", "Chat",
    })

    def __init__(self, config, client=None):
        self.config = config
        self.registry = ToolRegistry()
        self.registry.register_defaults()
        # Register Chat tool if Ollama client is available
        if client:
            self.registry.register(_MCPChatTool(config, client))

    def run(self):
        """Main event loop: read JSON-RPC requests from stdin, write responses to stdout."""
        # Disable any buffering on stdout for clean JSON-RPC
        import io as _io
        if hasattr(sys.stdout, 'buffer'):
            sys.stdout = _io.TextIOWrapper(sys.stdout.buffer, encoding='utf-8', line_buffering=True)
        for line in sys.stdin:
            line = line.strip()
            if not line:
                continue
            try:
                request = json.loads(line)
            except json.JSONDecodeError:
                self._send_error(None, -32700, "Parse error")
                continue
            req_id = request.get("id")
            method = request.get("method", "")
            params = request.get("params", {})
            # Notifications (no id) — acknowledge silently
            if req_id is None:
                if method == "notifications/initialized":
                    pass  # No response needed for notifications
                continue
            if method == "initialize":
                self._handle_initialize(req_id, params)
            elif method == "tools/list":
                self._handle_tools_list(req_id)
            elif method == "tools/call":
                self._handle_tools_call(req_id, params)
            else:
                self._send_error(req_id, -32601, f"Method not found: {method}")

    def _handle_initialize(self, req_id, params):
        """Respond with server capabilities."""
        result = {
            "protocolVersion": "2024-11-05",
            "capabilities": {
                "tools": {},
            },
            "serverInfo": {
                "name": "eve-coder",
                "version": __version__,
            },
        }
        self._send_response(req_id, result)

    def _handle_tools_list(self, req_id):
        """Return available tools in MCP schema format."""
        tools = []
        for schema in self.registry.get_schemas():
            func = schema.get("function", {})
            name = func.get("name", "")
            if name not in self.EXPOSED_TOOLS:
                continue
            tools.append({
                "name": name,
                "description": func.get("description", ""),
                "inputSchema": func.get("parameters", {"type": "object", "properties": {}}),
            })
        self._send_response(req_id, {"tools": tools})

    def _handle_tools_call(self, req_id, params):
        """Execute a tool and return the result."""
        tool_name = params.get("name", "")
        arguments = params.get("arguments", {})
        if tool_name not in self.EXPOSED_TOOLS:
            self._send_error(req_id, -32602, f"Tool not exposed: {tool_name}")
            return
        tool = self.registry.get(tool_name)
        if not tool:
            self._send_error(req_id, -32602, f"Tool not found: {tool_name}")
            return
        try:
            result = tool.execute(arguments)
            result_text = str(result) if result is not None else ""
            is_error = False
            if isinstance(result, ToolResult):
                result_text = result.output
                is_error = result.is_error
            self._send_response(req_id, {
                "content": [{"type": "text", "text": result_text}],
                "isError": is_error,
            })
        except Exception as e:
            self._send_response(req_id, {
                "content": [{"type": "text", "text": f"Tool execution error: {e}"}],
                "isError": True,
            })

    def _send_response(self, req_id, result):
        """Write a JSON-RPC success response."""
        msg = {"jsonrpc": "2.0", "id": req_id, "result": result}
        try:
            print(json.dumps(msg, ensure_ascii=False), flush=True)
        except Exception:
            pass

    def _send_error(self, req_id, code, message):
        """Write a JSON-RPC error response."""
        msg = {"jsonrpc": "2.0", "id": req_id, "error": {"code": code, "message": message}}
        try:
            print(json.dumps(msg, ensure_ascii=False), flush=True)
        except Exception:
            pass


def _run_mcp_server(config):
    """Entry point for MCP server mode."""
    config.yes_mode = True  # In server mode, the MCP client manages permissions
    # Try to create OllamaClient for Chat tool support
    client = None
    if config.model:
        try:
            client = OllamaClient(config)
        except Exception:
            pass  # Chat tool won't be available
    server = MCPServer(config, client=client)
    try:
        server.run()
    except (KeyboardInterrupt, EOFError):
        pass


class MCPTool(Tool):
    """Wraps an MCP server tool as a eve-coder tool."""

    def __init__(self, mcp_client, mcp_tool_schema):
        self._mcp = mcp_client
        self._schema = mcp_tool_schema
        self.name = f"mcp_{mcp_client.name}_{mcp_tool_schema['name']}"
        self._mcp_tool_name = mcp_tool_schema["name"]

    def get_schema(self):
        """Convert MCP tool schema to OpenAI function calling format."""
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": self._schema.get("description", f"MCP tool: {self._mcp_tool_name}"),
                "parameters": self._schema.get("inputSchema", {"type": "object", "properties": {}}),
            }
        }

    # SEC-7: Maximum MCP tool output size (100KB) to prevent context flooding
    _MCP_OUTPUT_MAX_BYTES = 100 * 1024

    # SEC-7: XML tags that could cause prompt injection if echoed into context
    _PROMPT_INJECT_TAGS = re.compile(
        r'</?(?:system|instructions?|prompt|context|assistant|user)\b[^>]*>',
        re.IGNORECASE,
    )

    @classmethod
    def _sanitize_mcp_output(cls, text):
        """Strip prompt-injection tags and enforce size limit on MCP tool output."""
        if not isinstance(text, str):
            return text
        # Enforce size limit first
        if len(text) > cls._MCP_OUTPUT_MAX_BYTES:
            text = text[:cls._MCP_OUTPUT_MAX_BYTES] + "\n...(output truncated at 100KB)"
        # Escape/remove dangerous XML tags that could inject into system context
        text = cls._PROMPT_INJECT_TAGS.sub(lambda m: m.group(0).replace("<", "&lt;").replace(">", "&gt;"), text)
        return text

    def execute(self, params):
        try:
            result = self._mcp.call_tool(self._mcp_tool_name, params)
            return self._sanitize_mcp_output(result)
        except RuntimeError as e:
            return f"MCP tool error: {e}"


_MCP_COMMAND_ALLOWLIST = frozenset({
    "npx", "node", "python3", "python", "uvx", "bunx", "deno",
})


def _is_allowed_mcp_command(command):
    """Check if MCP server command is in the allowlist."""
    base = os.path.basename(command.split()[0]) if command else ""
    return base in _MCP_COMMAND_ALLOWLIST


def _normalize_mcp_server_config(name, srv):
    if not isinstance(srv, dict) or "command" not in srv:
        return None
    enabled_tools = [str(item).strip() for item in srv.get("enabled_tools", []) if str(item).strip()]
    disabled_tools = [str(item).strip() for item in srv.get("disabled_tools", []) if str(item).strip()]
    env = srv.get("env", {})
    if not isinstance(env, dict):
        env = {}
    env_vars = [str(item).strip() for item in srv.get("env_vars", []) if str(item).strip()]
    try:
        startup_timeout = max(1, int(srv.get("startup_timeout_sec", 30)))
    except (TypeError, ValueError):
        startup_timeout = 30
    try:
        tool_timeout = max(1, int(srv.get("tool_timeout_sec", 30)))
    except (TypeError, ValueError):
        tool_timeout = 30
    return {
        "name": name,
        "command": srv["command"],
        "args": srv.get("args", []),
        "env": {str(k): str(v) for k, v in env.items()},
        "env_vars": env_vars,
        "enabled": bool(srv.get("enabled", True)),
        "required": bool(srv.get("required", False)),
        "enabled_tools": enabled_tools,
        "disabled_tools": disabled_tools,
        "startup_timeout_sec": startup_timeout,
        "tool_timeout_sec": tool_timeout,
    }


def _repo_key(config):
    return os.path.realpath(config.cwd)


def _repo_relpath(config, fpath):
    cwd = _repo_key(config)
    real = os.path.realpath(fpath)
    return os.path.relpath(real, cwd) if real != cwd else "."


def _compute_repo_hashes(config, paths):
    """Return {repo-relative path: sha256} for regular files inside the repo."""
    cwd = _repo_key(config)
    hashes = {}
    for fpath in sorted(set(paths)):
        try:
            real = os.path.realpath(fpath)
        except (OSError, ValueError):
            continue
        if real != cwd and not real.startswith(cwd + os.sep):
            continue
        if not os.path.isfile(real) or os.path.islink(real):
            continue
        digest = _compute_file_hash(real)
        if digest:
            hashes[_repo_relpath(config, real)] = digest
    return hashes


def _path_within_root(path, root):
    """Return True when path resolves inside root (or equals root)."""
    if not path or not root:
        return False
    try:
        real_path = os.path.realpath(path)
        real_root = os.path.realpath(root)
    except (OSError, ValueError):
        return False
    return real_path == real_root or real_path.startswith(real_root + os.sep)


def _get_repo_scope_hashes(entry, scope):
    if not isinstance(entry, dict):
        return None
    if scope == "mcp" and entry.get("mcp_hash"):
        return {os.path.join(".eve-cli", "mcp.json"): entry.get("mcp_hash")}
    scope_data = entry.get(scope)
    if not isinstance(scope_data, dict):
        return None
    hashes = scope_data.get("hashes")
    if not isinstance(hashes, dict):
        return None
    return {str(k): str(v) for k, v in hashes.items()}


def _remember_repo_scope_trust(config, scope, hashes):
    trusted = _load_trusted_repos(config)
    cwd = _repo_key(config)
    entry = trusted.get(cwd)
    if not isinstance(entry, dict):
        entry = {}
    entry[scope] = {
        "trusted": True,
        "trusted_at": datetime.now().isoformat(),
        "hashes": dict(hashes),
    }
    if scope == "mcp":
        entry["trusted"] = True
        entry["mcp_hash"] = hashes.get(os.path.join(".eve-cli", "mcp.json"), "")
        entry["trusted_at"] = datetime.now().isoformat()
    trusted[cwd] = entry
    _save_trusted_repos(config, trusted)


def _prompt_repo_trust(config, scope, title, warning, hashes, preview_paths=None):
    """Prompt once to trust repo-controlled content for a specific scope."""
    if not hashes:
        return False
    if not sys.stdin.isatty():
        return False

    preview_paths = preview_paths or []
    print(f"\n{C.YELLOW}╭─ {title} ─{C.RESET}")
    print(f"{C.YELLOW}│{C.RESET} {t('prompts.repo_trust_scope', 'Scope')}: {scope}")
    print(f"{C.YELLOW}│{C.RESET} {t('prompts.repo_trust_repo', 'Repo')}: {_repo_key(config)}")
    print(f"{C.YELLOW}│{C.RESET} {t('prompts.repo_trust_files', 'Files')}:")
    for rel in hashes.keys():
        print(f"{C.YELLOW}│{C.RESET}   {C.WHITE}{rel}{C.RESET}")
    if preview_paths:
        print(f"{C.YELLOW}│{C.RESET}")
        for fpath in preview_paths[:2]:
            rel = _repo_relpath(config, fpath)
            print(f"{C.YELLOW}│{C.RESET} {t('prompts.repo_trust_preview', 'Preview')}: {C.WHITE}{rel}{C.RESET}")
            try:
                with open(fpath, "r", encoding="utf-8", errors="replace") as f:
                    for line in f.read(600).splitlines()[:6]:
                        print(f"{C.YELLOW}│{C.RESET} {C.DIM}{line}{C.RESET}")
            except OSError:
                print(f"{C.YELLOW}│{C.RESET} {C.DIM}{t('warnings.repo_trust_unreadable', '[unreadable]')}{C.RESET}")
    print(f"{C.YELLOW}│{C.RESET}")
    print(f"{C.YELLOW}│{C.RESET} {_ansi(chr(27)+'[38;5;196m')}{warning}{C.RESET}")
    print(f"{C.YELLOW}│{C.RESET}  {t('prompts.repo_trust_choices', '[y] Trust  [n] Skip (default)')}")
    print(f"{C.YELLOW}╰──────────────────────────────────────────{C.RESET}")
    try:
        ans = input(f"  {C.YELLOW}? {C.RESET}").strip().lower()
    except (EOFError, KeyboardInterrupt):
        ans = ""
    if ans in ("y", "yes"):
        _remember_repo_scope_trust(config, scope, hashes)
        print(f"{C.GREEN}{t('info.repo_content_trusted', 'Repo content trusted for scope: {scope}.', scope=scope)}{C.RESET}")
        return True
    return False


def _ensure_repo_scope_trusted(config, scope, title, warning, paths, preview_paths=None):
    """Return True if repo-controlled files for a scope are trusted."""
    hashes = _compute_repo_hashes(config, paths)
    if not hashes:
        return False
    trusted = _load_trusted_repos(config)
    entry = trusted.get(_repo_key(config))
    previous_hashes = _get_repo_scope_hashes(entry, scope)
    if previous_hashes == hashes:
        return True
    if previous_hashes:
        msg = t('warnings.trusted_repo_changed', default=f"Warning: trusted repo content for scope '{scope}' has changed.")
        print(f"{C.YELLOW}{msg}{C.RESET}",
              file=sys.stderr)
    return _prompt_repo_trust(config, scope, title, warning, hashes, preview_paths=preview_paths)


def _read_text_file_guarded(path, max_bytes, encoding="utf-8", errors="replace"):
    fd = None
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW
    pre_stat = os.lstat(path)
    if not stat.S_ISREG(pre_stat.st_mode):
        raise OSError(errno.EINVAL, "not a regular file")
    try:
        fd = os.open(path, flags)
        post_stat = os.fstat(fd)
        if pre_stat.st_ino != post_stat.st_ino or pre_stat.st_dev != post_stat.st_dev:
            raise OSError(errno.EAGAIN, "file changed during open")
        with os.fdopen(fd, "r", encoding=encoding, errors=errors) as f:
            fd = None
            return f.read(max_bytes)
    finally:
        if fd is not None:
            os.close(fd)


def _list_markdown_files(dir_path):
    paths = []
    if not os.path.isdir(dir_path):
        return paths
    try:
        for entry in sorted(os.listdir(dir_path)):
            if not entry.endswith(".md"):
                continue
            fpath = os.path.join(dir_path, entry)
            if os.path.islink(fpath) or not os.path.isfile(fpath):
                continue
            paths.append(fpath)
    except OSError:
        return []
    return paths


def _trusted_agent_persona_paths(config):
    project_paths = _list_markdown_files(os.path.join(config.cwd, ".eve-cli", "agents"))
    global_paths = _list_markdown_files(os.path.join(config.config_dir, "agents"))
    load_project_agents = True
    if project_paths:
        load_project_agents = _ensure_repo_scope_trusted(
            config,
            "agents",
            t("warnings.project_agents_trust_required", "Project Agent Personas Trust Required"),
            t(
                "warnings.project_agents_injected",
                "Project agent personas override sub-agent prompts and can influence tool usage.",
            ),
            project_paths,
            preview_paths=project_paths,
        )
    return (project_paths if load_project_agents else []) + global_paths


def _get_trusted_repos_path(config):
    return os.path.join(config.config_dir, "trusted_repos.json")


def _load_trusted_repos(config):
    path = _get_trusted_repos_path(config)
    if not os.path.isfile(path) or os.path.islink(path):
        return {}
    try:
        with open(path, encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except (OSError, json.JSONDecodeError):
        return {}


def _save_trusted_repos(config, data):
    path = _get_trusted_repos_path(config)
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
    except OSError:
        pass


def _compute_file_hash(fpath):
    try:
        with open(fpath, "rb") as f:
            return hashlib.sha256(f.read()).hexdigest()
    except OSError:
        return ""


def _compute_mcp_trust_hashes(config, proj_mcp_path):
    """Compute trust hashes for MCP config and any repo assets it references."""
    hashes = {}
    try:
        with open(proj_mcp_path, encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict) or "mcpServers" not in data:
            return {}
        # Always hash the mcp.json itself
        mcp_hash = _compute_file_hash(proj_mcp_path)
        if mcp_hash:
            hashes[os.path.join(".eve-cli", "mcp.json")] = mcp_hash
        # Extract referenced repo assets from command/args
        cwd = _repo_key(config)
        for name, srv in data["mcpServers"].items():
            if not isinstance(srv, dict):
                continue
            cmd = srv.get("command", "")
            args = srv.get("args", [])
            # Collect all potential file references from command and args
            all_parts = cmd.split() + args
            for part in all_parts:
                # Check if part looks like a file path within repo
                if not part:
                    continue
                # Resolve relative to cwd if not absolute
                if not os.path.isabs(part):
                    part = os.path.join(cwd, part)
                try:
                    real = os.path.realpath(part)
                except (OSError, ValueError):
                    continue
                # Only include if within repo and is a regular file
                if real != cwd and real.startswith(cwd + os.sep) and os.path.isfile(real) and not os.path.islink(real):
                    rel = _repo_relpath(config, real)
                    if rel and rel not in hashes:
                        h = _compute_file_hash(real)
                        if h:
                            hashes[rel] = h
    except (OSError, json.JSONDecodeError):
        pass
    return hashes


def _is_mcp_trusted(config, proj_mcp_path):
    """Check if the project MCP config is trusted. Prompt user if not."""
    hashes = _compute_mcp_trust_hashes(config, proj_mcp_path)
    if not hashes:
        return False
    trusted = _load_trusted_repos(config)
    entry = trusted.get(_repo_key(config))
    previous_hashes = _get_repo_scope_hashes(entry, "mcp")
    if previous_hashes == hashes:
        return True
    if previous_hashes:
        print(f"{C.YELLOW}{t('warnings.trusted_mcp_changed', default='Warning: trusted MCP config or referenced assets have changed.')}{C.RESET}",
              file=sys.stderr)
    return _prompt_repo_trust(
        config,
        "mcp",
        "MCP Trust Required",
        "Project MCP files can start local processes and expose external tools.",
        hashes,
        preview_paths=[proj_mcp_path],
    )


def _load_mcp_servers(config):
    """Load MCP server configurations from config directory and project."""
    servers = {}
    # Global MCP config is always trusted
    mcp_config = os.path.join(config.config_dir, "mcp.json")
    if os.path.isfile(mcp_config) and not os.path.islink(mcp_config):
        try:
            with open(mcp_config, encoding="utf-8") as f:
                data = json.load(f)
            if isinstance(data, dict) and "mcpServers" in data:
                for name, srv in data["mcpServers"].items():
                    normalized = _normalize_mcp_server_config(name, srv)
                    if normalized:
                        servers[name] = normalized
        except (OSError, json.JSONDecodeError) as e:
            print(f"{C.YELLOW}{t('warnings.mcp_json_load_failed', default=f'Warning: Could not load mcp.json: {e}')}{C.RESET}", file=sys.stderr)
    # Project-level MCP requires explicit trust
    proj_mcp = os.path.join(config.cwd, ".eve-cli", "mcp.json")
    if os.path.isfile(proj_mcp) and not os.path.islink(proj_mcp):
        if _is_mcp_trusted(config, proj_mcp):
            try:
                with open(proj_mcp, encoding="utf-8") as f:
                    data = json.load(f)
                if isinstance(data, dict) and "mcpServers" in data:
                    for name, srv in data["mcpServers"].items():
                        normalized = _normalize_mcp_server_config(name, srv)
                        if normalized:
                            cmd = normalized["command"]
                            if _is_allowed_mcp_command(cmd):
                                servers[name] = normalized
                            else:
                                msg = t('warnings.mcp_server_blocked', default=f"MCP server '{name}' blocked — command '{cmd}' is not in allowlist")
                                print(f"{C.YELLOW}{msg}{C.RESET}",
                                      file=sys.stderr)
            except (OSError, json.JSONDecodeError):
                pass
        else:
            print(f"{C.YELLOW}Project MCP config found but not trusted. "
                  f"Use /browser setup or manually trust.{C.RESET}", file=sys.stderr)
    try:
        ext_mgr = ExtensionManager(config)
        for name, srv in ext_mgr.load_mcp_configs().items():
            normalized = _normalize_mcp_server_config(name, srv)
            if normalized:
                cmd = normalized["command"]
                if _is_allowed_mcp_command(cmd):
                    servers[name] = normalized
                else:
                    msg = t('warnings.mcp_server_blocked', default=f"MCP server '{name}' blocked — command '{cmd}' is not in allowlist")
                    print(f"{C.YELLOW}{msg}{C.RESET}", file=sys.stderr)
    except Exception:
        pass
    return servers


def _save_mcp_config(path, data):
    """Safely write MCP server configuration to a JSON file."""
    os.makedirs(os.path.dirname(path), exist_ok=True)
    tmp = path + ".tmp"
    try:
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data, f, ensure_ascii=False, indent=2)
        os.replace(tmp, path)
    except OSError:
        if os.path.exists(tmp):
            os.unlink(tmp)
        raise


def _init_mcp_clients(config, registry, permissions):
    """Initialize MCP server connections and register their tools. Returns client list."""
    clients = []
    mcp_server_configs = _load_mcp_servers(config)
    for srv_name, srv_config in mcp_server_configs.items():
        if not srv_config.get("enabled", True):
            continue
        try:
            full_env = dict(srv_config.get("env", {}))
            for env_name in srv_config.get("env_vars", []):
                if env_name in os.environ:
                    full_env[env_name] = os.environ[env_name]
            mcp = MCPClient(
                name=srv_name,
                command=srv_config["command"],
                args=srv_config.get("args", []),
                env=full_env,
                startup_timeout=srv_config.get("startup_timeout_sec", 30),
                tool_timeout=srv_config.get("tool_timeout_sec", 30),
            )
            mcp.start()
            mcp.initialize()
            tools = mcp.list_tools()
            enabled_tools = set(srv_config.get("enabled_tools", []))
            disabled_tools = set(srv_config.get("disabled_tools", []))
            if enabled_tools:
                tools = [tool_schema for tool_schema in tools if tool_schema.get("name") in enabled_tools]
            if disabled_tools:
                tools = [tool_schema for tool_schema in tools if tool_schema.get("name") not in disabled_tools]
            for tool_schema in tools:
                mcp_tool = MCPTool(mcp, tool_schema)
                registry.register(mcp_tool)
                permissions.ASK_TOOLS.add(mcp_tool.name)
            clients.append(mcp)
            if config.debug:
                print(f"{C.DIM}[debug] MCP '{srv_name}': {len(tools)} tools registered{C.RESET}", file=sys.stderr)
        except Exception as e:
            if srv_config.get("required"):
                raise RuntimeError(f"Required MCP server '{srv_name}' failed: {e}")
            print(f"{C.YELLOW}Warning: MCP server '{srv_name}' failed: {e}{C.RESET}", file=sys.stderr)
    return clients


# ════════════════════════════════════════════════════════════════════════════════
# Extension Manager — install/uninstall/list community extensions
# ════════════════════════════════════════════════════════════════════════════════

class ExtensionManager:
    """Manage community extensions (skills and MCP configs) from GitHub repos.

    Extensions are installed to ~/.config/eve-cli/extensions/<name>/ and must
    contain an extension.json manifest file.
    """

    _ALLOWED_FILE_EXTS = {".md", ".json", ".yaml", ".yml", ".txt"}
    _NAME_PATTERN = re.compile(r'^[a-zA-Z0-9][a-zA-Z0-9_-]{0,63}$')

    def __init__(self, config):
        self.config = config
        self.extensions_dir = os.path.join(config.config_dir, "extensions")
        self._trusted_path = os.path.join(config.config_dir, "trusted_extensions.json")

    def _validate_manifest(self, data):
        """Validate extension.json manifest. Returns (ok, error_message)."""
        name = data.get("name", "")
        if not self._NAME_PATTERN.match(name):
            return False, f"Invalid extension name: '{name}' (must be alphanumeric/hyphen, 1-64 chars)"

        ext_type = data.get("type", "")
        if ext_type not in ("skill", "mcp", "mixed"):
            return False, f"Invalid type: '{ext_type}' (must be skill, mcp, or mixed)"

        files = data.get("files", [])
        if not isinstance(files, list) or not files:
            return False, "Manifest must have a non-empty 'files' list"

        for fpath in files:
            if not isinstance(fpath, str):
                return False, f"Invalid file entry: {fpath}"
            # Path traversal check
            normalized = os.path.normpath(fpath)
            if normalized.startswith("..") or os.path.isabs(normalized):
                return False, f"Path traversal detected: '{fpath}'"
            # File extension check
            _, ext = os.path.splitext(fpath)
            if ext.lower() not in self._ALLOWED_FILE_EXTS:
                return False, f"Disallowed file type: '{fpath}' (allowed: {self._ALLOWED_FILE_EXTS})"

        return True, ""

    def _resolve_extension_source_path(self, root_dir, relpath):
        """Resolve a cloned extension file and reject symlink/path escapes."""
        normalized = os.path.normpath(relpath)
        if normalized.startswith("..") or os.path.isabs(normalized):
            raise OSError(f"path escape detected: {relpath}")
        parts = [part for part in normalized.replace("\\", "/").split("/") if part and part != "."]
        resolved = _resolve_repo_storage_path(root_dir, *parts)
        if not os.path.isfile(resolved):
            raise OSError(f"missing file: {relpath}")
        return resolved

    def _load_trusted(self):
        """Load trusted extensions list."""
        try:
            if os.path.isfile(self._trusted_path) and not os.path.islink(self._trusted_path):
                with open(self._trusted_path, encoding="utf-8", errors="replace") as f:
                    return json.load(f)
        except (json.JSONDecodeError, OSError):
            pass
        return {}

    def _save_trusted(self, trusted):
        """Save trusted extensions list."""
        try:
            os.makedirs(os.path.dirname(self._trusted_path), exist_ok=True)
            with open(self._trusted_path, "w", encoding="utf-8") as f:
                json.dump(trusted, f, ensure_ascii=False, indent=2)
        except OSError:
            pass

    def install(self, github_url, yes_mode=False):
        """Install extension from GitHub URL.

        Args:
            github_url: GitHub repository URL
            yes_mode: Skip confirmation prompt if True

        Returns:
            tuple: (success: bool, message: str)
        """
        # URL validation
        try:
            from urllib.parse import urlparse
            parsed = urlparse(github_url)
            if parsed.netloc not in ("github.com", "www.github.com"):
                return False, f"Only GitHub URLs are allowed (got: {parsed.netloc})"
            if not parsed.path or parsed.path.count("/") < 2:
                return False, f"Invalid GitHub URL: {github_url}"
        except Exception as e:
            return False, f"Invalid URL: {e}"

        # Clone to temp directory
        import tempfile
        tmp_dir = tempfile.mkdtemp(prefix="eve-ext-")
        try:
            result = subprocess.run(
                ["git", "clone", "--depth", "1", github_url, tmp_dir],
                capture_output=True, text=True, timeout=60,
            )
            if result.returncode != 0:
                return False, f"git clone failed: {result.stderr.strip()}"

            # Read and validate manifest
            try:
                manifest_path = self._resolve_extension_source_path(tmp_dir, "extension.json")
            except OSError as e:
                return False, f"Invalid extension layout: {e}"

            with open(manifest_path, encoding="utf-8", errors="replace") as f:
                manifest = json.load(f)

            ok, err = self._validate_manifest(manifest)
            if not ok:
                return False, f"Invalid manifest: {err}"

            name = manifest["name"]
            ext_type = manifest.get("type", "unknown")
            desc = manifest.get("description", "(no description)")
            version = manifest.get("version", "0.0.0")

            # Check if already installed
            dest_dir = os.path.join(self.extensions_dir, name)
            if os.path.isdir(dest_dir):
                return False, f"Extension '{name}' is already installed. Use 'eve-cli uninstall {name}' first."

            # Confirmation prompt
            if not yes_mode:
                print(f"\n  Extension: {name} v{version}")
                print(f"  Type: {ext_type}")
                print(f"  Description: {desc}")
                print(f"  Source: {github_url}")
                print(f"  Files: {', '.join(manifest.get('files', []))}")
                try:
                    confirm = input(f"\n  Install this extension? [y/N]: ").strip().lower()
                    if confirm not in ("y", "yes"):
                        return False, "Installation cancelled."
                except (EOFError, KeyboardInterrupt):
                    return False, "Installation cancelled."

            file_sources = []
            for fpath in manifest.get("files", []):
                try:
                    src = self._resolve_extension_source_path(tmp_dir, fpath)
                except OSError as e:
                    return False, f"Invalid extension file '{fpath}': {e}"
                file_sources.append((fpath, src))

            # Copy validated files to extensions directory
            os.makedirs(dest_dir, exist_ok=True)
            # Copy manifest
            shutil.copy2(manifest_path, os.path.join(dest_dir, "extension.json"))
            # Copy listed files
            for fpath, src in file_sources:
                dst = os.path.join(dest_dir, fpath)
                os.makedirs(os.path.dirname(dst), exist_ok=True)
                shutil.copy2(src, dst)

            # Add to trusted list
            trusted = self._load_trusted()
            trusted[name] = {"url": github_url, "version": version, "type": ext_type}
            self._save_trusted(trusted)

            return True, f"Extension '{name}' v{version} installed successfully."

        except subprocess.TimeoutExpired:
            return False, "git clone timed out."
        except (json.JSONDecodeError, OSError, KeyError) as e:
            return False, f"Installation error: {e}"
        finally:
            # FUN-5: Cleanup temp directory with warning on failure
            if os.path.exists(tmp_dir):
                try:
                    shutil.rmtree(tmp_dir)
                except OSError as _rm_err:
                    print(f"警告: 拡張機能の一時ディレクトリの削除に失敗しました: {tmp_dir}: {_rm_err}",
                          file=sys.stderr)

    def uninstall(self, name):
        """Remove an installed extension.

        Returns:
            tuple: (success: bool, message: str)
        """
        if not self._NAME_PATTERN.match(name):
            return False, f"Invalid extension name: '{name}'"

        dest_dir = os.path.join(self.extensions_dir, name)
        if not os.path.isdir(dest_dir):
            return False, f"Extension '{name}' is not installed."

        # Verify it's not a symlink
        if os.path.islink(dest_dir):
            return False, f"Refusing to remove symlink: {dest_dir}"

        try:
            shutil.rmtree(dest_dir)
        except OSError as e:
            return False, f"Failed to remove: {e}"

        # Remove from trusted list
        trusted = self._load_trusted()
        trusted.pop(name, None)
        self._save_trusted(trusted)

        return True, f"Extension '{name}' uninstalled."

    def list_extensions(self):
        """List installed extensions.

        Returns:
            list of dict: [{name, version, type, description}]
        """
        extensions = []
        if not os.path.isdir(self.extensions_dir):
            return extensions

        for entry in sorted(os.listdir(self.extensions_dir)):
            ext_dir = os.path.join(self.extensions_dir, entry)
            if not os.path.isdir(ext_dir) or os.path.islink(ext_dir):
                continue
            manifest_path = os.path.join(ext_dir, "extension.json")
            if not os.path.isfile(manifest_path):
                continue
            try:
                with open(manifest_path, encoding="utf-8", errors="replace") as f:
                    manifest = json.load(f)
                extensions.append({
                    "name": manifest.get("name", entry),
                    "version": manifest.get("version", "?"),
                    "type": manifest.get("type", "?"),
                    "description": manifest.get("description", ""),
                })
            except (json.JSONDecodeError, OSError):
                extensions.append({"name": entry, "version": "?", "type": "?", "description": "(invalid manifest)"})

        return extensions

    def load_skills(self):
        """Load skills from installed extensions.

        Returns:
            dict: name -> {"content": str, "skill_dir": str}
        """
        skills = {}
        if not os.path.isdir(self.extensions_dir):
            return skills

        for entry in os.listdir(self.extensions_dir):
            ext_dir = os.path.join(self.extensions_dir, entry)
            if not os.path.isdir(ext_dir) or os.path.islink(ext_dir):
                continue
            # Load manifest to check type
            manifest_path = os.path.join(ext_dir, "extension.json")
            if not os.path.isfile(manifest_path):
                continue
            try:
                with open(manifest_path, encoding="utf-8", errors="replace") as f:
                    manifest = json.load(f)
            except (json.JSONDecodeError, OSError):
                continue

            ext_type = manifest.get("type", "")
            if ext_type not in ("skill", "mixed"):
                continue

            # Find .md files in skills/ subdirectory or listed files
            for fpath in manifest.get("files", []):
                if not fpath.endswith(".md"):
                    continue
                full_path = os.path.join(ext_dir, fpath)
                if not os.path.isfile(full_path) or os.path.islink(full_path):
                    continue
                try:
                    with open(full_path, encoding="utf-8", errors="replace") as f:
                        content = f.read(51200)  # 50KB cap per skill
                    skill_name = os.path.splitext(os.path.basename(fpath))[0]
                    # Prefix with extension name to avoid collisions
                    qualified_name = f"ext:{entry}:{skill_name}"
                    skills[qualified_name] = {
                        "content": content,
                        "skill_dir": os.path.dirname(full_path),
                        "path": full_path,
                    }
                except OSError:
                    pass

        return skills

    def load_mcp_configs(self):
        """Load MCP configs from installed extensions.

        Returns:
            dict: server_name -> config_dict (same format as mcp.json)
        """
        servers = {}
        if not os.path.isdir(self.extensions_dir):
            return servers

        for entry in os.listdir(self.extensions_dir):
            ext_dir = os.path.join(self.extensions_dir, entry)
            if not os.path.isdir(ext_dir) or os.path.islink(ext_dir):
                continue
            manifest_path = os.path.join(ext_dir, "extension.json")
            if not os.path.isfile(manifest_path):
                continue
            try:
                with open(manifest_path, encoding="utf-8", errors="replace") as f:
                    manifest = json.load(f)
            except (json.JSONDecodeError, OSError):
                continue

            if manifest.get("type", "") not in ("mcp", "mixed"):
                continue

            # Look for mcp.json in the extension directory
            mcp_path = os.path.join(ext_dir, "mcp.json")
            if os.path.isfile(mcp_path) and not os.path.islink(mcp_path):
                try:
                    with open(mcp_path, encoding="utf-8", errors="replace") as f:
                        mcp_data = json.load(f)
                    if isinstance(mcp_data, dict):
                        server_map = mcp_data.get("mcpServers", mcp_data)
                        if not isinstance(server_map, dict):
                            continue
                        for sname, sconfig in server_map.items():
                            if not isinstance(sconfig, dict) or "command" not in sconfig:
                                continue
                            servers[f"ext_{entry}_{sname}"] = sconfig
                except (json.JSONDecodeError, OSError):
                    pass

        return servers


def _handle_extension_command(argv, config):
    """Handle eve-cli install/uninstall/extensions subcommands.

    Args:
        argv: sys.argv[1:] (e.g., ["install", "https://github.com/..."])
        config: Config instance

    Returns:
        int: exit code
    """
    ext_mgr = ExtensionManager(config)

    if not argv:
        return 1

    subcmd = argv[0]

    if subcmd == "install":
        if len(argv) < 2:
            print("Usage: eve-cli install <github-url>", file=sys.stderr)
            return 1
        url = argv[1]
        yes = "--yes" in argv or "-y" in argv
        ok, msg = ext_mgr.install(url, yes_mode=yes)
        print(msg)
        return 0 if ok else 1

    elif subcmd == "uninstall":
        if len(argv) < 2:
            print("Usage: eve-cli uninstall <name>", file=sys.stderr)
            return 1
        ok, msg = ext_mgr.uninstall(argv[1])
        print(msg)
        return 0 if ok else 1

    elif subcmd == "extensions":
        sub2 = argv[1] if len(argv) > 1 else "list"
        if sub2 == "list":
            exts = ext_mgr.list_extensions()
            if not exts:
                print("No extensions installed.")
                return 0
            print(f"  {'Name':<30} {'Version':<10} {'Type':<8} Description")
            print(f"  {'-'*30} {'-'*10} {'-'*8} {'-'*30}")
            for e in exts:
                print(f"  {e['name']:<30} {e['version']:<10} {e['type']:<8} {e['description'][:40]}")
            return 0
        else:
            print(f"Unknown subcommand: extensions {sub2}", file=sys.stderr)
            return 1

    return 1


# ════════════════════════════════════════════════════════════════════════════════
# Skills — SKILL.md loading (compatible with Gemini CLI format)
# ════════════════════════════════════════════════════════════════════════════════

def _load_skills(config):
    """Load SKILL.md files from standard locations.

    Returns dict: name -> {"content": str, "skill_dir": str}
    """
    skills = {}  # name -> {"content": ..., "skill_dir": ...}
    global_skill_dir = os.path.join(config.config_dir, "skills")
    project_skill_dirs = [
        os.path.join(config.cwd, ".eve-cli", "skills"),
        os.path.join(config.cwd, "skills"),
    ]
    project_skill_paths = []
    for skill_dir in project_skill_dirs:
        if not os.path.isdir(skill_dir):
            continue
        try:
            for entry in os.listdir(skill_dir):
                if not entry.endswith(".md"):
                    continue
                fpath = os.path.join(skill_dir, entry)
                if os.path.islink(fpath) or not os.path.isfile(fpath):
                    continue
                project_skill_paths.append(fpath)
        except OSError:
            pass
    load_project_skills = True
    if project_skill_paths:
        load_project_skills = _ensure_repo_scope_trusted(
            config,
            "skills",
            t("warnings.project_skills_trust_required", "Project Skills Trust Required"),
            t(
                "warnings.project_skills_injected",
                "Project skills are injected into the agent prompt and can influence tool usage.",
            ),
            project_skill_paths,
            preview_paths=project_skill_paths,
        )
    skill_dirs = [global_skill_dir]
    if load_project_skills:
        skill_dirs.extend(project_skill_dirs)
    for skill_dir in skill_dirs:
        if not os.path.isdir(skill_dir):
            continue
        try:
            for entry in os.listdir(skill_dir):
                if not entry.endswith(".md"):
                    continue
                fpath = os.path.join(skill_dir, entry)
                if os.path.islink(fpath) or not os.path.isfile(fpath):
                    continue
                try:
                    fsize = os.path.getsize(fpath)
                    if fsize > 50000:  # 50KB max per skill
                        continue
                    with open(fpath, encoding="utf-8") as f:
                        content = f.read(50000)
                    name = entry[:-3]  # remove .md
                    skills[name] = {"content": content, "skill_dir": skill_dir, "path": fpath}
                except (OSError, UnicodeDecodeError):
                    pass
        except OSError:
            pass

    # Merge skills from installed extensions
    try:
        ext_mgr = ExtensionManager(config)
        ext_skills = ext_mgr.load_skills()
        skills.update(ext_skills)
    except Exception:
        pass  # extension loading failure is non-fatal

    if config.skill_enable_patterns or config.skill_disable_patterns:
        skills = {
            name: info for name, info in skills.items()
            if _skill_is_enabled(
                config,
                name,
                info.get("path") or os.path.join(info.get("skill_dir", ""), f"{name}.md"),
            )
        }

    return skills


def _expand_skill_variables(content, arguments="", skill_dir="", cwd=""):
    """Replace skill variables ($ARGUMENTS, $0, $1, ..., $SKILL_DIR, $CWD) in content."""
    result = content
    result = result.replace("$ARGUMENTS", arguments)
    result = result.replace("$SKILL_DIR", skill_dir)
    result = result.replace("$CWD", cwd)
    # Split arguments into positional params and replace $0, $1, ...
    parts = arguments.split() if arguments else []
    # Replace positional variables $0..$9 (higher indices unlikely needed)
    for i in range(10):
        token = "$" + str(i)
        if token in result:
            value = parts[i] if i < len(parts) else ""
            result = result.replace(token, value)
    return result


def _expand_shell_injections(content, cwd="", *, allow_commands=False, source_name="content"):
    """Expand !`command` shell injection patterns in command/skill content.

    Replaces each !`command` with the stdout of running the command.
    Timeout: 10s per command, max 5 injections per content.
    """
    _SHELL_INJECT_RE = re.compile(r'!\`([^`]+)\`')
    matches = list(_SHELL_INJECT_RE.finditer(content))
    if not matches:
        return content, None
    if not allow_commands:
        blocked = matches[0].group(1).strip()
        preview = blocked[:120] + ("..." if len(blocked) > 120 else "")
        return None, (
            f"Error: !`command` expansion is blocked in {source_name} for security. "
            f"Use explicit tool calls instead. Blocked command: {preview}"
        )
    result = content
    count = 0
    for match in reversed(matches):  # reverse to preserve offsets
        if count >= 5:
            break
        cmd = match.group(1).strip()
        if not cmd:
            continue
        # SEC-6: Strip shell injection metacharacters from command string before execution.
        # This prevents chained commands via ; && || | > < ` $() even when allow_commands=True.
        import shlex as _shlex
        _SHELL_METACHAR_RE = re.compile(r'[;&|><`]|\$\(|\$\{')
        if _SHELL_METACHAR_RE.search(cmd):
            output = f"(command blocked: shell metacharacters not allowed: {cmd[:80]})"
            result = result[:match.start()] + output + result[match.end():]
            count += 1
            continue
        try:
            # Use shell=False with shlex.split to prevent shell injection
            try:
                cmd_args = _shlex.split(cmd)
            except ValueError as _shlex_err:
                output = f"(command blocked: invalid shell syntax: {_shlex_err})"
                result = result[:match.start()] + output + result[match.end():]
                count += 1
                continue
            proc = subprocess.run(
                cmd_args, shell=False, capture_output=True, text=True,
                encoding="utf-8", errors="replace",
                cwd=cwd or None, timeout=10,
            )
            output = (proc.stdout or "").strip()
            if proc.returncode != 0 and proc.stderr:
                output += f"\n(stderr: {proc.stderr.strip()[:200]})"
            # Truncate very long output
            if len(output) > 5000:
                output = output[:2500] + "\n...(truncated)...\n" + output[-2500:]
        except subprocess.TimeoutExpired:
            output = f"(command timed out: {cmd[:80]})"
        except Exception as e:
            output = f"(command failed: {e})"
        result = result[:match.start()] + output + result[match.end():]
        count += 1
    return result, None


# ════════════════════════════════════════════════════════════════════════════════
# Git Change Tracker
# ════════════════════════════════════════════════════════════════════════════════

class GitChangeTracker:
    """Tracks files changed by agent tool execution during the current session."""

    MAX_EVENTS = 100

    def __init__(self, cwd):
        self.cwd = cwd
        self._events = []  # list of (action, rel_path, timestamp)
        self._lock = threading.Lock()
        self._is_git_repo = os.path.isdir(os.path.join(cwd, ".git"))

    def _relpath(self, file_path):
        try:
            real = os.path.realpath(file_path)
            cwd_real = os.path.realpath(self.cwd)
            if real.startswith(cwd_real + os.sep):
                return os.path.relpath(real, cwd_real)
        except (OSError, ValueError):
            pass
        return file_path

    def record(self, action, file_path):
        rel_path = self._relpath(file_path)
        with self._lock:
            self._events.append((action, rel_path, time.time()))
            if len(self._events) > self.MAX_EVENTS:
                self._events = self._events[-self.MAX_EVENTS:]

    def recent_events(self, limit=5):
        with self._lock:
            items = list(self._events)
        seen = set()
        recent = []
        for action, rel_path, ts in reversed(items):
            if rel_path in seen:
                continue
            seen.add(rel_path)
            recent.append((action, rel_path, ts))
            if len(recent) >= limit:
                break
        return recent

    def format_recent(self, limit=5):
        icons = {
            "create": "+",
            "write": "~",
            "edit": "~",
            "notebook": "~",
            "delete": "-",
        }
        lines = []
        for action, rel_path, _ts in self.recent_events(limit):
            lines.append(f"{icons.get(action, '~')} {rel_path} ({action})")
        return lines

    def git_dirty_summary(self, limit=5):
        if not self._is_git_repo:
            return None
        try:
            result = subprocess.run(
                ["git", "status", "--porcelain"],
                cwd=self.cwd, capture_output=True, text=True, timeout=5
            )
        except (FileNotFoundError, subprocess.TimeoutExpired):
            return None
        if result.returncode != 0:
            return None
        lines = [line.rstrip() for line in result.stdout.splitlines() if line.strip()]
        if not lines:
            return {"count": 0, "paths": []}
        paths = []
        for line in lines[:limit]:
            raw = _git_status_path(line)
            if " -> " in raw:
                raw = raw.split(" -> ", 1)[1]
            paths.append(raw)
        return {"count": len(lines), "paths": paths}


def _git_status_path(line):
    """Extract the file path from a git status --porcelain line."""
    if not line:
        return ""
    if len(line) > 3 and line[2] == " ":
        return line[3:]
    stripped = line.lstrip()
    if len(stripped) > 2 and stripped[1] == " ":
        return stripped[2:]
    return stripped


# ════════════════════════════════════════════════════════════════════════════════
# Git Checkpoint & Rollback
# ════════════════════════════════════════════════════════════════════════════════

class GitCheckpoint:
    """Manages git-based checkpoints for safe rollback."""

    MAX_CHECKPOINTS = 20

    def __init__(self, cwd, runtime_state=None):
        self.cwd = cwd
        self.runtime_state = runtime_state
        self._checkpoints = []  # list of dicts with stash snapshot metadata
        self._is_git_repo = self._check_git()
        if self.runtime_state is not None:
            self._checkpoints = self.runtime_state.load_checkpoints()

    def _check_git(self):
        """Check if cwd is inside a git repo."""
        try:
            result = subprocess.run(
                ["git", "rev-parse", "--is-inside-work-tree"],
                cwd=self.cwd, capture_output=True, timeout=5
            )
            return result.returncode == 0
        except (FileNotFoundError, subprocess.TimeoutExpired):
            return False

    def _run_git(self, args, timeout=10):
        """Run a git command and return (success, stdout)."""
        try:
            result = subprocess.run(
                ["git"] + args,
                cwd=self.cwd, capture_output=True, text=True, timeout=timeout
            )
            output = result.stdout.strip()
            if not output:
                output = result.stderr.strip()
            return result.returncode == 0, output
        except (FileNotFoundError, subprocess.TimeoutExpired):
            return False, ""

    def _get_status_lines(self):
        ok, status = self._run_git(["status", "--porcelain"])
        if not ok:
            return []
        return [line for line in status.splitlines() if line.strip()]

    def _get_untracked_files(self):
        try:
            result = subprocess.run(
                ["git", "ls-files", "--others", "--exclude-standard", "-z"],
                cwd=self.cwd, capture_output=True, timeout=10
            )
        except (FileNotFoundError, subprocess.TimeoutExpired):
            return []
        if result.returncode != 0:
            return []
        raw = result.stdout.decode("utf-8", errors="replace")
        return [path for path in raw.split("\0") if path]

    def _snapshot_untracked_files(self, files):
        snapshot_dir = tempfile.mkdtemp(prefix="eve-checkpoint-")
        os.chmod(snapshot_dir, 0o700)  # SEC-4: restrict snapshot dir permissions
        saved = []
        try:
            for rel_path in files:
                abs_path = os.path.join(self.cwd, rel_path)
                if os.path.islink(abs_path) or not os.path.isfile(abs_path):
                    continue
                dst_path = os.path.join(snapshot_dir, rel_path)
                os.makedirs(os.path.dirname(dst_path), exist_ok=True)
                shutil.copy2(abs_path, dst_path)
                saved.append(rel_path)
        except Exception:
            shutil.rmtree(snapshot_dir, ignore_errors=True)
            raise
        return snapshot_dir, saved

    def _trim_checkpoints(self):
        if len(self._checkpoints) <= self.MAX_CHECKPOINTS:
            return
        old = self._checkpoints.pop(0)
        self._drop_stash_entry(old.get("git_ref"))
        snap_dir = old.get("snapshot_dir")
        if snap_dir:
            shutil.rmtree(snap_dir, ignore_errors=True)

    def _persist(self):
        if self.runtime_state is not None:
            self.runtime_state.save_checkpoints(self._checkpoints)

    def _drop_stash_entry(self, git_ref):
        if not git_ref:
            return
        ok, output = self._run_git(["stash", "list", "--format=%H%x00%gd"])
        if not ok or not output:
            return
        for line in output.splitlines():
            parts = line.split("\x00", 1)
            if len(parts) != 2:
                continue
            sha, stash_ref = parts
            if sha == git_ref:
                self._run_git(["stash", "drop", stash_ref])
                return

    def _build_checkpoint(self, label):
        if not self._is_git_repo:
            return None
        status_lines = self._get_status_lines()
        if not status_lines:
            return None
        ok, ref = self._run_git(["stash", "create"])
        git_ref = ref.strip() if ok else ""
        if git_ref:
            self._run_git(["stash", "store", "-m", f"eve-checkpoint: {label}", git_ref])
        untracked_files = self._get_untracked_files()
        snapshot_dir = None
        saved_untracked = []
        if untracked_files:
            snapshot_dir, saved_untracked = self._snapshot_untracked_files(untracked_files)
        return {
            "git_ref": git_ref,
            "label": label,
            "timestamp": time.time(),
            "status_lines": status_lines,
            "snapshot_dir": snapshot_dir,
            "untracked_files": saved_untracked,
        }

    def create(self, label="auto"):
        """Create a non-invasive checkpoint. Returns True if created."""
        checkpoint = self._build_checkpoint(label)
        if checkpoint is None:
            return False
        self._checkpoints.append(checkpoint)
        self._trim_checkpoints()
        self._persist()
        return True

    def _restore_untracked(self, checkpoint):
        snap_dir = checkpoint.get("snapshot_dir")
        if not snap_dir:
            return True, ""
        for rel_path in checkpoint.get("untracked_files", []):
            src_path = os.path.join(snap_dir, rel_path)
            dst_path = os.path.join(self.cwd, rel_path)
            try:
                os.makedirs(os.path.dirname(dst_path), exist_ok=True)
                shutil.copy2(src_path, dst_path)
            except Exception as e:
                return False, f"Failed to restore untracked file '{rel_path}': {e}"
        return True, ""

    def _apply_checkpoint(self, checkpoint):
        ok, output = self._run_git(["reset", "--hard", "HEAD"], timeout=20)
        if not ok:
            return False, f"Rollback failed during reset: {output}"
        ok, output = self._run_git(["clean", "-fd"], timeout=20)
        if not ok:
            return False, f"Rollback failed during clean: {output}"
        git_ref = checkpoint.get("git_ref")
        if git_ref:
            ok, output = self._run_git(["stash", "apply", "--index", git_ref], timeout=20)
            if not ok:
                return False, f"Rollback failed while applying checkpoint: {output}"
        ok, output = self._restore_untracked(checkpoint)
        if not ok:
            return False, output
        return True, f"Rolled back to checkpoint: {checkpoint['label']}"

    def rollback(self):
        """Rollback to the last checkpoint. Returns (success, message)."""
        if not self._is_git_repo:
            return False, "Not a git repository"
        if not self._checkpoints:
            return False, "No checkpoints available"
        checkpoint = self._checkpoints[-1]
        backup = self._build_checkpoint("rollback-backup")
        ok, message = self._apply_checkpoint(checkpoint)
        if ok:
            self._checkpoints.pop()
            self._drop_stash_entry(checkpoint.get("git_ref"))
            snap_dir = checkpoint.get("snapshot_dir")
            if snap_dir:
                shutil.rmtree(snap_dir, ignore_errors=True)
            if backup is not None:
                self._drop_stash_entry(backup.get("git_ref"))
                snap_dir = backup.get("snapshot_dir")
                if snap_dir:
                    shutil.rmtree(snap_dir, ignore_errors=True)
            self._persist()
            return True, message
        if backup is not None:
            restore_ok, restore_msg = self._apply_checkpoint(backup)
            if not restore_ok:
                message = f"{message}. Also failed to restore current changes: {restore_msg}"
            self._drop_stash_entry(backup.get("git_ref"))
            snap_dir = backup.get("snapshot_dir")
            if snap_dir:
                shutil.rmtree(snap_dir, ignore_errors=True)
        self._persist()
        return False, message

    def summary(self):
        return {
            "count": len(self._checkpoints),
            "latest": self._checkpoints[-1]["label"] if self._checkpoints else None,
        }

    def list_checkpoints(self):
        """List available checkpoints."""
        items = []
        for cp in reversed(self._checkpoints):
            summary = ", ".join(_git_status_path(line).strip() for line in cp.get("status_lines", [])[:3])
            if len(cp.get("status_lines", [])) > 3:
                summary += ", ..."
            items.append({
                "label": cp["label"],
                "timestamp": cp["timestamp"],
                "summary": summary or "working tree snapshot",
            })
        return items


# ════════════════════════════════════════════════════════════════════════════════
# Git Worktree — Isolated sub-agent execution
# ════════════════════════════════════════════════════════════════════════════════

class GitWorktree:
    """Manages temporary git worktrees for isolated sub-agent execution."""

    def __init__(self, cwd):
        self.cwd = cwd
        self._is_git_repo = os.path.isdir(os.path.join(cwd, ".git"))

    def create(self, branch_prefix="eve-worktree"):
        """Create a temporary worktree. Returns (worktree_path, branch_name) or (None, None)."""
        if not self._is_git_repo:
            return None, None
        branch_name = f"{branch_prefix}-{uuid.uuid4().hex[:8]}"
        worktree_path = os.path.join(tempfile.gettempdir(), f"eve-wt-{uuid.uuid4().hex[:8]}")
        try:
            # Create worktree with new branch from current HEAD
            proc = subprocess.run(
                ["git", "worktree", "add", "-b", branch_name, worktree_path],
                capture_output=True, text=True, timeout=30, cwd=self.cwd,
            )
            if proc.returncode != 0:
                return None, None
            return worktree_path, branch_name
        except (subprocess.TimeoutExpired, OSError):
            return None, None

    def remove(self, worktree_path, branch_name=None):
        """Remove a worktree and optionally its branch."""
        if not worktree_path or not os.path.isdir(worktree_path):
            return
        try:
            subprocess.run(
                ["git", "worktree", "remove", "--force", worktree_path],
                capture_output=True, text=True, timeout=15, cwd=self.cwd,
            )
        except (subprocess.TimeoutExpired, OSError):
            # Fallback: try to remove directory
            try:
                shutil.rmtree(worktree_path, ignore_errors=True)
                subprocess.run(
                    ["git", "worktree", "prune"],
                    capture_output=True, text=True, timeout=10, cwd=self.cwd,
                )
            except Exception:
                pass
        # Clean up branch
        if branch_name:
            try:
                subprocess.run(
                    ["git", "branch", "-D", branch_name],
                    capture_output=True, text=True, timeout=10, cwd=self.cwd,
                )
            except Exception:
                pass

    def has_changes(self, worktree_path):
        """Check if worktree has uncommitted changes."""
        if not worktree_path or not os.path.isdir(worktree_path):
            return False
        try:
            proc = subprocess.run(
                ["git", "status", "--porcelain"],
                capture_output=True, text=True, timeout=10, cwd=worktree_path,
            )
            return bool(proc.stdout.strip())
        except Exception:
            return False

    def get_diff(self, worktree_path):
        """Get diff of changes in worktree."""
        if not worktree_path:
            return ""
        try:
            proc = subprocess.run(
                ["git", "diff"],
                capture_output=True, text=True, timeout=15, cwd=worktree_path,
            )
            return proc.stdout[:10000]
        except Exception:
            return ""


# ════════════════════════════════════════════════════════════════════════════════
# Auto Test/Lint Loop
# ════════════════════════════════════════════════════════════════════════════════

class AutoTestRunner:
    """Runs configured test/lint commands after file modifications."""

    MAX_RETRY_ATTEMPTS = 2
    RETRYABLE_FAILURE_KINDS = frozenset({"timeout", "tool-missing", "unknown"})

    def __init__(self, cwd):
        self.cwd = cwd
        self.enabled = False
        self.test_cmd = None
        self.lint_cmd = ["python3", "-m", "py_compile"]
        self._auto_detect()
        self._detect_lint_tool()

    @staticmethod
    def _cmd_to_text(cmd):
        return " ".join(cmd) if cmd else "(none)"

    def describe(self):
        return {
            "lint": self._cmd_to_text(self.lint_cmd),
            "test": self._cmd_to_text(self.test_cmd),
        }

    def _pytest_available(self):
        return shutil.which("pytest") is not None

    def _looks_like_pytest_config(self, path):
        if not os.path.isfile(path):
            return False
        if os.path.basename(path) == "pytest.ini":
            return True
        try:
            with open(path, "r", encoding="utf-8", errors="replace") as f:
                content = f.read(20000)
        except OSError:
            return False
        return ("[tool.pytest.ini_options]" in content
                or "[pytest]" in content
                or "tool:pytest" in content)

    def _auto_detect(self):
        """Auto-detect test/lint commands from project files."""
        tests_dir = os.path.join(self.cwd, "tests")
        has_tests_dir = os.path.isdir(tests_dir)
        has_tests_pkg = os.path.isfile(os.path.join(tests_dir, "__init__.py"))
        has_test_files = False
        if has_tests_dir:
            try:
                has_test_files = any(
                    name.startswith("test") and name.endswith(".py")
                    for name in os.listdir(tests_dir)
                )
            except OSError:
                has_test_files = False

        for marker in ["pytest.ini", "setup.cfg", "pyproject.toml"]:
            cfg_path = os.path.join(self.cwd, marker)
            if self._looks_like_pytest_config(cfg_path) and self._pytest_available():
                self.test_cmd = ["python3", "-m", "pytest", "-x", "--tb=short", "-q"]
                break

        if not self.test_cmd and has_tests_pkg:
            self.test_cmd = ["python3", "-m", "unittest", "discover", "-s", "tests", "-t", ".", "-v"]
        elif not self.test_cmd and has_test_files:
            self.test_cmd = ["python3", "-m", "unittest", "discover", "-s", ".", "-p", "test*.py", "-v"]
        elif not self.test_cmd and os.path.isfile(os.path.join(self.cwd, "package.json")):
            self.test_cmd = ["npm", "test"]

    def _detect_lint_tool(self):
        """Upgrade lint command to a better tool if available."""
        # Python: prefer ruff > flake8 > py_compile
        if shutil.which("ruff"):
            self.lint_cmd = ["ruff", "check", "--fix"]
        elif shutil.which("flake8"):
            self.lint_cmd = ["flake8", "--max-line-length=120"]
        # Node.js: prefer eslint if available and project uses it
        if os.path.isfile(os.path.join(self.cwd, "package.json")):
            if shutil.which("eslint") or os.path.isfile(os.path.join(self.cwd, "node_modules", ".bin", "eslint")):
                self.lint_cmd = ["npx", "eslint", "--fix"]

    def _run_verifier_step(self, name, command, timeout, file_path=None):
        invoked = list(command) + ([file_path] if file_path else [])
        command_text = self._cmd_to_text(invoked)
        try:
            result = subprocess.run(
                invoked,
                cwd=self.cwd,
                capture_output=True,
                text=True,
                timeout=timeout,
            )
        except FileNotFoundError as e:
            output = str(e)
            return {
                "name": name,
                "command": command_text,
                "status": "failed:tool-missing",
                "failure_kind": "tool-missing",
                "retryable": True,
                "output": output,
            }
        except subprocess.TimeoutExpired as e:
            output = str(e)
            return {
                "name": name,
                "command": command_text,
                "status": "failed:timeout",
                "failure_kind": "timeout",
                "retryable": True,
                "output": output,
            }
        output = (result.stdout + "\n" + result.stderr).strip()
        if result.returncode == 0:
            return {
                "name": name,
                "command": command_text,
                "status": "passed",
                "failure_kind": None,
                "retryable": False,
                "output": "",
            }
        if len(output) > 3000:
            output = output[:3000] + "\n...(truncated)"
        failure_kind = _classify_verifier_failure(f"{name} failure:\n{output}")
        return {
            "name": name,
            "command": command_text,
            "status": f"failed:{failure_kind}",
            "failure_kind": failure_kind,
            "retryable": failure_kind in self.RETRYABLE_FAILURE_KINDS,
            "output": output,
        }

    @staticmethod
    def _latest_failures(step_results):
        latest = {}
        for step in step_results:
            latest[step["name"]] = step
        return [step for step in latest.values() if step["status"] != "passed"]

    @staticmethod
    def _format_failure_output(pipeline):
        failed_steps = [step for step in pipeline.get("steps", []) if step["status"] != "passed"]
        if not failed_steps:
            return None
        lines = []
        if pipeline.get("retry_attempted"):
            lines.append(f"Retry policy: reran failed verifier because {pipeline.get('retry_reason', 'the failure looked retryable')}.")
            lines.append("")
        for step in failed_steps:
            lines.append(f"{step['name']} [{step['status']}]")
            lines.append(f"Command: {step['command']}")
            if step.get("output"):
                lines.append(step["output"])
            lines.append("")
        return "\n".join(lines).strip()

    def _build_pipeline_summary(self, pipeline):
        if pipeline.get("ok"):
            if pipeline.get("retry_attempted"):
                return f"Verifier recovered after retry ({pipeline.get('retry_reason', 'retry policy')})."
            return "Verifier pipeline passed."
        failed_steps = self._latest_failures(pipeline.get("steps", []))
        if not failed_steps:
            return "Verifier pipeline failed."
        labels = ", ".join(f"{step['name']}={step['failure_kind'] or 'unknown'}" for step in failed_steps)
        suffix = ""
        if pipeline.get("retry_attempted"):
            suffix = f" after retry ({pipeline.get('retry_reason', 'retry policy')})"
        return f"Verifier failed: {labels}{suffix}."

    def run_pipeline(self, file_path):
        """Run compile/lint/test verification with light retry policy."""
        if not self.enabled:
            return None
        step_defs = []
        if file_path.endswith(".py") and self.lint_cmd:
            step_defs.append(("lint", self.lint_cmd, 30, file_path))
        if self.test_cmd:
            step_defs.append(("test", self.test_cmd, 120, None))
        if not step_defs:
            return {
                "ok": True,
                "status": "passed",
                "failure_kind": None,
                "retry_attempted": False,
                "retry_reason": None,
                "attempts": 0,
                "steps": [],
                "summary": "Verifier pipeline has no configured steps.",
                "error_output": None,
            }

        attempts = 0
        retry_attempted = False
        retry_reason = None
        all_steps = []
        current_steps = list(step_defs)
        final_failures = []
        while current_steps and attempts < self.MAX_RETRY_ATTEMPTS:
            attempts += 1
            failed_step_defs = []
            attempt_failures = []
            for name, command, timeout, target_path in current_steps:
                step = self._run_verifier_step(name, command, timeout, target_path)
                step["attempt"] = attempts
                all_steps.append(step)
                if step["status"] != "passed":
                    attempt_failures.append(step)
                    failed_step_defs.append((name, command, timeout, target_path))
            if not attempt_failures:
                pipeline = {
                    "ok": True,
                    "status": "passed",
                    "failure_kind": None,
                    "retry_attempted": retry_attempted,
                    "retry_reason": retry_reason,
                    "attempts": attempts,
                    "steps": all_steps,
                }
                pipeline["summary"] = self._build_pipeline_summary(pipeline)
                pipeline["error_output"] = None
                return pipeline
            final_failures = attempt_failures
            retryable = all(step.get("retryable") for step in attempt_failures)
            if retryable and attempts < self.MAX_RETRY_ATTEMPTS:
                retry_attempted = True
                retry_reason = ", ".join(sorted(set(step.get("failure_kind") or "unknown" for step in attempt_failures)))
                current_steps = failed_step_defs
                continue
            break

        failure_kind = final_failures[0].get("failure_kind") if final_failures else "unknown"
        pipeline = {
            "ok": False,
            "status": f"failed:{failure_kind}",
            "failure_kind": failure_kind,
            "retry_attempted": retry_attempted,
            "retry_reason": retry_reason,
            "attempts": attempts,
            "steps": all_steps,
        }
        pipeline["summary"] = self._build_pipeline_summary(pipeline)
        pipeline["error_output"] = self._format_failure_output(pipeline)
        return pipeline

    def run_after_edit(self, file_path):
        """Run tests/lint after a file was modified. Returns error output or None."""
        pipeline = self.run_pipeline(file_path)
        if not pipeline or pipeline.get("ok"):
            return None
        return pipeline.get("error_output")


# ════════════════════════════════════════════════════════════════════════════════
# File Watcher — poll-based file change detection (stdlib only)
# ════════════════════════════════════════════════════════════════════════════════

class FileWatcher:
    """Watches project files for external changes using mtime polling."""

    # Default patterns to watch
    WATCH_EXTENSIONS = frozenset({
        ".py", ".js", ".ts", ".jsx", ".tsx", ".html", ".css", ".json",
        ".yaml", ".yml", ".toml", ".md", ".txt", ".sh", ".sql", ".go",
        ".rs", ".java", ".c", ".cpp", ".h", ".hpp", ".rb", ".php",
    })
    # Directories to skip
    SKIP_DIRS = frozenset({
        ".git", "node_modules", "__pycache__", ".venv", "venv", ".tox",
        "dist", "build", ".next", ".cache", "target", ".idea", ".vscode",
    })
    MAX_FILES = 5000  # Don't track more than this many files
    POLL_INTERVAL = 2.0  # seconds between polls

    def __init__(self, cwd):
        self.cwd = cwd
        self.enabled = False
        self._snapshots = {}  # path -> (mtime, size)
        self._changes = []  # list of (type, path) pending changes
        self._lock = threading.Lock()
        self._thread = None
        self._stop_event = threading.Event()

    def _scan(self):
        """Scan project files and return {path: (mtime, size)} dict."""
        result = {}
        count = 0
        for root, dirs, files in os.walk(self.cwd):
            # Skip unwanted directories
            dirs[:] = [d for d in dirs if d not in self.SKIP_DIRS and not d.startswith(".")]
            for fname in files:
                ext = os.path.splitext(fname)[1].lower()
                if ext not in self.WATCH_EXTENSIONS:
                    continue
                fpath = os.path.join(root, fname)
                try:
                    st = os.stat(fpath)
                    result[fpath] = (st.st_mtime, st.st_size)
                except OSError:
                    pass
                count += 1
                if count >= self.MAX_FILES:
                    return result
        return result

    def _detect_changes(self, old, new):
        """Compare two snapshots and return list of (type, path) changes."""
        changes = []
        for path, (mtime, size) in new.items():
            if path not in old:
                changes.append(("created", path))
            elif old[path] != (mtime, size):
                changes.append(("modified", path))
        for path in old:
            if path not in new:
                changes.append(("deleted", path))
        return changes

    def start(self):
        """Start background polling thread."""
        if self._thread and self._thread.is_alive():
            return
        self.enabled = True
        self._stop_event.clear()
        self._snapshots = self._scan()
        self._thread = threading.Thread(target=self._poll_loop, daemon=True)
        self._thread.start()

    def stop(self):
        """Stop background polling."""
        self.enabled = False
        self._stop_event.set()
        if self._thread:
            self._thread.join(timeout=5)
            self._thread = None

    def _poll_loop(self):
        """Background polling loop."""
        while not self._stop_event.is_set():
            self._stop_event.wait(self.POLL_INTERVAL)
            if self._stop_event.is_set():
                break
            try:
                new_snap = self._scan()
                changes = self._detect_changes(self._snapshots, new_snap)
                if changes:
                    with self._lock:
                        self._changes.extend(changes)
                    self._snapshots = new_snap
            except Exception:
                pass

    def get_pending_changes(self):
        """Get and clear pending file changes. Returns list of (type, path)."""
        with self._lock:
            changes = self._changes[:]
            self._changes.clear()
        return changes

    def format_changes(self, changes):
        """Format changes into a human-readable string for LLM injection."""
        if not changes:
            return ""
        lines = ["[File Watcher] External file changes detected:"]
        icons = {"created": "+", "modified": "~", "deleted": "-"}
        for ctype, cpath in changes[:20]:  # cap at 20
            relpath = os.path.relpath(cpath, self.cwd)
            lines.append(f"  {icons.get(ctype, '?')} {relpath} ({ctype})")
        if len(changes) > 20:
            lines.append(f"  ... and {len(changes) - 20} more")
        return "\n".join(lines)

    def refresh_snapshot(self):
        """Force refresh the snapshot (call after our own writes)."""
        try:
            self._snapshots = self._scan()
        except Exception:
            pass


# ════════════════════════════════════════════════════════════════════════════════
# Multi-Agent Coordinator — parallel agent execution
# ════════════════════════════════════════════════════════════════════════════════

class MultiAgentCoordinator:
    """Coordinates multiple sub-agents running in parallel."""

    MAX_PARALLEL = 4  # max concurrent agents

    def __init__(self, config, client, registry, permissions, tui=None):
        self._config = config
        self._client = client
        self._registry = registry
        self._permissions = permissions
        self._tui = tui

    def set_tui(self, tui):
        self._tui = tui

    def run_parallel(self, tasks):
        """Run multiple sub-agent tasks in parallel.

        Args:
            tasks: list of {"prompt": str, "max_turns": int, "allow_writes": bool}

        Returns:
            list of {"prompt": str, "result": str, "duration": float, "error": str|None}
        """
        tasks = tasks[:self.MAX_PARALLEL]
        total = len(tasks)
        results = [None] * total
        _done_count = [0]  # mutable for closure

        def _run_one(idx, task):
            start = time.time()
            try:
                # Inject agent label for UI display
                labeled_task = dict(task)
                labeled_task["_agent_label"] = f"Agent {idx + 1}/{total}"
                labeled_task["_structured_result"] = True
                sub = SubAgentTool(self._config, self._client, self._registry, self._permissions, self._tui)
                result = sub.execute(labeled_task)
                if isinstance(result, dict):
                    result_text = result.get("result", "")
                    error_text = result.get("error")
                else:
                    result_text = result
                    error_text = None
                results[idx] = {
                    "prompt": task.get("prompt", "")[:100],
                    "result": result_text,
                    "duration": time.time() - start,
                    "error": error_text,
                    "structured": result if isinstance(result, dict) else None,
                }
            except Exception as e:
                results[idx] = {
                    "prompt": task.get("prompt", "")[:100],
                    "result": "",
                    "duration": time.time() - start,
                    "error": str(e),
                    "structured": None,
                }
            _done_count[0] += 1

        # Heartbeat thread: show progress every 10 seconds
        _heartbeat_stop = threading.Event()

        def _heartbeat():
            _hb_start = time.time()
            while not _heartbeat_stop.wait(10):
                elapsed = time.time() - _hb_start
                done = _done_count[0]
                _sr = _active_scroll_region
                msg = (f"⏳ Parallel agents: "
                       f"{done}/{total} done, {elapsed:.0f}s elapsed...")
                _lock = _sr._lock if (_sr is not None and _sr._active) else _print_lock
                with _lock:
                    print(f"\r  {_ansi(chr(27)+'[38;5;226m')}{msg}{C.RESET}   ", end="", flush=True)

        hb_thread = threading.Thread(target=_heartbeat, daemon=True)
        hb_thread.start()

        threads = []
        for i, task in enumerate(tasks):
            t = threading.Thread(target=_run_one, args=(i, task), daemon=True)
            threads.append(t)
            t.start()

        for t in threads:
            t.join(timeout=300)  # 5 min max per agent

        _heartbeat_stop.set()
        hb_thread.join(timeout=2)
        # Clear heartbeat line
        _sr = _active_scroll_region
        _lock = _sr._lock if (_sr is not None and _sr._active) else _print_lock
        with _lock:
            print(f"\r{' ' * 70}\r", end="", flush=True)

        # Mark timed-out agents
        for i, r in enumerate(results):
            if r is None:
                results[i] = {
                    "prompt": tasks[i].get("prompt", "")[:100] if i < len(tasks) else "",
                    "result": "",
                    "duration": 300.0,
                    "error": "Agent timed out (300s limit)",
                    "structured": None,
                }

        return results


class ParallelAgentTool(Tool):
    """Launch multiple sub-agents in parallel to handle independent tasks."""
    name = "ParallelAgents"
    description = (
        "Launch 2-4 sub-agents in parallel, each handling an independent task. "
        "Each agent runs its own tool loop. Use when you have multiple independent "
        "research or analysis tasks that can run simultaneously. "
        "Returns all results when all agents complete."
    )

    def __init__(self, coordinator):
        self._coordinator = coordinator

    @property
    def parameters(self):
        # Get dynamic max based on machine specs
        max_parallel = _get_subagent_max_parallel()
        return {
            "type": "object",
            "properties": {
                "tasks": {
                    "type": "array",
                    "description": f"Array of task objects (max {max_parallel} tasks based on system specs)",
                    "items": {
                        "type": "object",
                        "properties": {
                            "prompt": {"type": "string", "description": "Task for this agent"},
                            "max_turns": {
                                "type": "integer",
                                "description": (
                                    f"Max turns per agent "
                                    f"(default {_get_default_subagent_max_turns(self._coordinator._config)})"
                                ),
                            },
                            "allow_writes": {"type": "boolean", "description": "Allow write tools"},
                        },
                        "required": ["prompt"],
                    },
                    "minItems": 1,
                    "maxItems": max_parallel,
                },
            },
            "required": ["tasks"],
        }

    def execute(self, params):
        tasks = params.get("tasks", [])
        if not tasks:
            return "Error: at least one task is required"
        
        # Get dynamic max and clamp tasks
        max_parallel = _get_subagent_max_parallel()
        original_count = len(tasks)
        if len(tasks) > max_parallel:
            tasks = tasks[:max_parallel]
            with _print_lock:
                _scroll_aware_print(f"{C.DIM}  Note: Clamped from {original_count} to {max_parallel} tasks (system limit){C.RESET}", flush=True)

        with _print_lock:
            _scroll_aware_print(f"\n  {_ansi(chr(27)+'[38;5;141m')}🤖 Launching {len(tasks)} parallel agents...{C.RESET}",
                  flush=True)

        results = self._coordinator.run_parallel(tasks)

        succeeded = sum(1 for r in results if not r["error"])
        failed = len(results) - succeeded
        total_time = max((r["duration"] for r in results), default=0)

        output_parts = []
        for i, r in enumerate(results):
            status = "FAIL" if r["error"] else "OK"
            prompt_display = r['prompt'][:80]
            output_parts.append(f"┌─── Agent {i+1}/{len(results)} [{status}] ───")
            output_parts.append(f"│ Task: {prompt_display}")
            output_parts.append(f"│ Time: {r['duration']:.1f}s")
            if r["error"]:
                output_parts.append(f"│ Error: {r['error']}")
            else:
                # Indent result lines for readability, truncate very long results
                result_text = r["result"]
                if len(result_text) > 3000:
                    result_text = result_text[:3000] + "\n...(result truncated)"
                for line in result_text.split("\n"):
                    output_parts.append(f"│ {line}")
            output_parts.append(f"└{'─' * 40}")

        summary = f"Summary: {succeeded}/{len(results)} succeeded"
        if failed:
            summary += f", {failed} failed"
        summary += f" (total wall time: {total_time:.1f}s)"
        output_parts.append(summary)

        with _print_lock:
            _scroll_aware_print(f"  {_ansi(chr(27)+'[38;5;141m')}🤖 All {len(results)} agents finished "
                  f"({succeeded} OK, {failed} failed, {total_time:.1f}s){C.RESET}",
                  flush=True)

        return "\n".join(output_parts)


# ════════════════════════════════════════════════════════════════════════════════
# Agent Teams
# ════════════════════════════════════════════════════════════════════════════════

class AgentTeam:
    """Coordinates a team of agents working on a shared task list.

    Lead agent: the main agent that creates and assigns tasks
    Teammates: sub-agents that pick up and complete assigned tasks
    Communication: via the shared _task_store
    """

    MAX_TEAMMATES = 4  # Dynamic: updated in __init__ based on system specs
    MAX_TEAM_DURATION = 600  # 10 min hard cap

    def __init__(self, config, client, registry, permissions):
        self._config = config
        self._client = client
        self._registry = registry
        self._permissions = permissions
        self._teammates = {}   # name -> thread
        self._results = {}     # name -> result_text
        self._stop_event = threading.Event()
        # Override with dynamic max based on system specs
        self.MAX_TEAMMATES = _get_team_max_agents()

    def run(self, goal, num_teammates=2, allow_writes=False):
        """Run a team session: create tasks from goal, then dispatch teammates.

        1. Use LLM to decompose the goal into tasks
        2. Launch teammates that pick up pending tasks
        3. Wait for all tasks to complete or timeout
        4. Return combined results
        """
        num_teammates = max(1, min(num_teammates, self.MAX_TEAMMATES))

        # Step 1: Decompose goal into tasks using LLM
        with _print_lock:
            _scroll_aware_print(
                f"\n  {_ansi(chr(27)+'[38;5;198m')}Team Mode: {num_teammates} agents{C.RESET}")
            _scroll_aware_print(
                f"  {C.DIM}Goal: {goal[:100]}{'...' if len(goal) > 100 else ''}{C.RESET}")

        decompose_prompt = (
            f"Decompose this goal into {num_teammates + 1}-{num_teammates + 3} independent tasks "
            f"that can be worked on in parallel. Output ONLY a JSON array of task objects:\n"
            f'[{{"subject": "...", "description": "..."}}]\n\n'
            f"Goal: {goal}"
        )
        try:
            resp = self._client.chat_sync(
                model=self._config.model,
                messages=[
                    {"role": "system", "content": "Output only valid JSON. No explanation."},
                    {"role": "user", "content": decompose_prompt},
                ],
                tools=None,
            )
            content = resp.get("content", "")
            # Extract JSON array from response
            json_match = re.search(r'\[.*\]', content, re.DOTALL)
            if json_match:
                tasks_data = json.loads(json_match.group())
            else:
                tasks_data = json.loads(content)
        except Exception as e:
            return f"Failed to decompose goal: {e}"

        if not isinstance(tasks_data, list) or not tasks_data:
            return "Failed to decompose goal into tasks."

        # Step 2: Create tasks in the task store
        task_ids = []
        with _task_store_lock:
            for td in tasks_data[:8]:  # cap at 8 tasks
                if not isinstance(td, dict) or not td.get("subject"):
                    continue
                tid = str(_task_store["next_id"])
                _task_store["next_id"] += 1
                _task_store["tasks"][tid] = {
                    "id": tid,
                    "subject": td["subject"],
                    "description": td.get("description", td["subject"]),
                    "activeForm": f"Working on: {td['subject']}",
                    "status": "pending",
                    "blocks": [],
                    "blockedBy": [],
                }
                task_ids.append(tid)
            snapshot = _snapshot_task_store_locked()
        _persist_task_store(snapshot)

        if not task_ids:
            return "No tasks created from goal decomposition."

        with _print_lock:
            _scroll_aware_print(
                f"  {C.DIM}Created {len(task_ids)} tasks: "
                f"{', '.join(f'#{t}' for t in task_ids)}{C.RESET}")

        # Step 3: Launch teammate threads
        self._stop_event.clear()
        self._results.clear()

        def _teammate_worker(name, teammate_idx):
            """Teammate worker: pick up pending tasks and complete them."""
            while not self._stop_event.is_set():
                # Find a pending task to work on
                task_to_work = None
                with _task_store_lock:
                    for tid in task_ids:
                        t = _task_store["tasks"].get(tid)
                        if t and t["status"] == "pending":
                            # Check if blocked
                            open_blockers = [
                                b for b in t.get("blockedBy", [])
                                if b in _task_store["tasks"] and
                                _task_store["tasks"][b]["status"] != "completed"
                            ]
                            if not open_blockers:
                                t["status"] = "in_progress"
                                task_to_work = dict(t)
                                snapshot = _snapshot_task_store_locked()
                                break
                    else:
                        snapshot = None
                if snapshot is not None:
                    _persist_task_store(snapshot)

                if not task_to_work:
                    # Check if all done
                    with _task_store_lock:
                        all_done = all(
                            _task_store["tasks"].get(tid, {}).get("status") in ("completed", "deleted")
                            for tid in task_ids
                        )
                    if all_done:
                        break
                    time.sleep(1)
                    continue

                # Execute the task
                _tid = task_to_work["id"]
                with _print_lock:
                    _scroll_aware_print(
                        f"  {_ansi(chr(27)+'[38;5;141m')}[{name}] "
                        f"Starting task #{_tid}: {task_to_work['subject'][:60]}{C.RESET}")

                sub = SubAgentTool(self._config, self._client, self._registry, self._permissions)
                result = sub.execute({
                    "prompt": (
                        f"Complete this task:\n"
                        f"Subject: {task_to_work['subject']}\n"
                        f"Description: {task_to_work['description']}\n\n"
                        f"Working directory: {self._config.cwd}"
                    ),
                    "max_turns": 15,
                    "allow_writes": allow_writes,
                    "_agent_label": name,
                    "_structured_result": True,
                })

                # Mark task complete
                with _task_store_lock:
                    t = _task_store["tasks"].get(_tid)
                    if t:
                        t["status"] = "completed" if isinstance(result, dict) and result.get("ok", False) else "pending"
                    snapshot = _snapshot_task_store_locked()
                _persist_task_store(snapshot)

                self._results[f"{name}:#{_tid}"] = result
                with _print_lock:
                    _scroll_aware_print(
                        f"  {_ansi(chr(27)+'[38;5;46m')}[{name}] "
                        f"{'Completed' if isinstance(result, dict) and result.get('ok', False) else 'Needs retry'} task #{_tid}{C.RESET}")

        threads = []
        for i in range(num_teammates):
            name = f"Agent-{i+1}"
            t = threading.Thread(target=_teammate_worker, args=(name, i), daemon=True)
            threads.append(t)
            t.start()

        # Step 4: Wait with timeout
        team_start = time.time()
        while time.time() - team_start < self.MAX_TEAM_DURATION:
            alive = [t for t in threads if t.is_alive()]
            if not alive:
                break
            time.sleep(2)
            # Progress update
            with _task_store_lock:
                completed = sum(1 for tid in task_ids
                              if _task_store["tasks"].get(tid, {}).get("status") == "completed")
            elapsed = time.time() - team_start
            if int(elapsed) % 10 == 0 and int(elapsed) > 0:
                with _print_lock:
                    _scroll_aware_print(
                        f"  {C.DIM}Team progress: {completed}/{len(task_ids)} tasks, "
                        f"{elapsed:.0f}s elapsed{C.RESET}")

        self._stop_event.set()
        for t in threads:
            t.join(timeout=5)

        # Step 5: Compile results
        total_time = time.time() - team_start
        output_parts = [f"Team Results ({num_teammates} agents, {total_time:.1f}s)\n"]

        with _task_store_lock:
            for tid in task_ids:
                t = _task_store["tasks"].get(tid, {})
                status_icon = "[done]" if t.get("status") == "completed" else "[open]"
                output_parts.append(f"{status_icon} Task #{tid}: {t.get('subject', '?')} [{t.get('status', '?')}]")

        output_parts.append("")
        for key, result in self._results.items():
            output_parts.append(f"--- {key} ---")
            if isinstance(result, dict):
                result_text = result.get("result", "")
                if result.get("error"):
                    output_parts.append(f"| status: FAIL")
                    output_parts.append(f"| error: {result['error']}")
                else:
                    output_parts.append(f"| status: OK")
                    output_parts.append(f"| summary: {result.get('summary', '')}")
            else:
                result_text = str(result)
            if len(result_text) > 2000:
                result_text = result_text[:2000] + "\n...(truncated)"
            for line in result_text.split("\n"):
                output_parts.append(f"| {line}")
            output_parts.append(f"{'─' * 40}")

        return "\n".join(output_parts)


# ════════════════════════════════════════════════════════════════════════════════
# Channels — external message ingestion (webhook / Discord / Slack)
# ════════════════════════════════════════════════════════════════════════════════

class ChannelMessage:
    """A message received from an external channel."""

    def __init__(self, channel, sender_id, sender_name, content,
                 reply_target="", raw=None):
        self.id = uuid.uuid4().hex[:12]
        self.channel = channel          # "webhook" | "discord" | "slack"
        self.sender_id = sender_id      # platform-specific user ID
        self.sender_name = sender_name  # display name
        self.content = content          # message text (≤4000 chars)
        self.reply_target = reply_target  # where to send the reply
        self.raw = raw or {}
        self.received_at = time.time()

    def __repr__(self):
        return (f"<ChannelMessage channel={self.channel!r} "
                f"sender={self.sender_name!r} content={self.content[:40]!r}>")


class BaseChannelAdapter(ABC):
    """Base class for all channel adapters."""

    def __init__(self):
        self._queue = None           # injected by ChannelManager
        self._stop_event = threading.Event()

    @property
    def name(self):
        return "base"

    def start(self):
        """Start the adapter (launch polling thread etc.)."""

    def stop(self):
        """Stop the adapter cleanly."""
        self._stop_event.set()

    @abstractmethod
    def send(self, msg, content):
        """Send a reply back through this channel."""

    def _enqueue(self, ch_msg):
        if self._queue is not None:
            self._queue.put(ch_msg)


# ── WebhookAdapter ────────────────────────────────────────────────────────────

class WebhookAdapter(BaseChannelAdapter):
    """
    Receives messages via HTTP POST to /webhook.

    Expected JSON body:
      {
        "content":      "message text",
        "sender_id":    "user-id",        (optional, default: "webhook")
        "sender_name":  "Display Name",   (optional, default: "webhook")
        "callback_url": "http://..."      (optional, for reply delivery)
      }

    Optional request header for API key auth:
      Authorization: Bearer <api_key>
    """

    def __init__(self, api_key=""):
        super().__init__()
        self._api_key = api_key

    @staticmethod
    def _is_safe_callback_url(url):
        if not url:
            return True
        parsed = urllib.parse.urlparse(url)
        if parsed.scheme.lower() not in ("http", "https"):
            return False
        if parsed.username or "@" in (parsed.netloc or ""):
            return False
        hostname = parsed.hostname or ""
        if not hostname:
            return False
        return not WebFetchTool._is_private_ip(hostname)

    @property
    def name(self):
        return "webhook"

    def handle_request(self, headers, body):
        """
        Called by ChannelServer when POST /webhook arrives.
        Returns (status_code, response_body_str).
        """
        if not self._api_key:
            return 403, json.dumps({"error": "Webhook API key is required. Run /webhook:configure first."})
        auth = headers.get("authorization", "")
        if auth != f"Bearer {self._api_key}":
            return 403, json.dumps({"error": "Unauthorized"})

        try:
            data = json.loads(body.decode("utf-8", errors="replace"))
        except (json.JSONDecodeError, AttributeError):
            return 400, json.dumps({"error": "Invalid JSON"})

        content = str(data.get("content", "")).strip()
        if not content:
            return 400, json.dumps({"error": "Missing 'content' field"})

        sender_id = str(data.get("sender_id", "webhook"))[:128]
        sender_name = str(data.get("sender_name", "webhook"))[:128]
        callback_url = str(data.get("callback_url", ""))
        content = content[:4000]
        if callback_url and not self._is_safe_callback_url(callback_url):
            return 400, json.dumps({"error": "Invalid callback_url"})

        msg = ChannelMessage(
            channel="webhook",
            sender_id=sender_id,
            sender_name=sender_name,
            content=content,
            reply_target=callback_url,
            raw=data,
        )
        self._enqueue(msg)
        return 200, json.dumps({"ok": True, "id": msg.id})

    def send(self, msg, content):
        """POST reply to callback_url if provided."""
        url = msg.reply_target
        if not url:
            return
        if not self._is_safe_callback_url(url):
            return
        try:
            body = json.dumps(
                {"content": content, "in_reply_to": msg.id},
                ensure_ascii=False,
            ).encode("utf-8")
            req = urllib.request.Request(
                url,
                data=body,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            urllib.request.urlopen(req, timeout=10)
        except Exception:
            pass  # best-effort delivery


# ── DiscordAdapter ────────────────────────────────────────────────────────────

class DiscordAdapter(BaseChannelAdapter):
    """
    Polls Discord REST API for new messages every POLL_INTERVAL seconds.

    Receive: GET /api/v10/channels/{id}/messages?after={last_id}&limit=10
    Send:    POST /api/v10/channels/{id}/messages (auto-split at 1900 chars)

    Pairing flow:
      1. Unknown sender DMs the bot → bot replies with a 6-digit pairing code
      2. User runs /discord:pair <code> in eve-cli → sender added to allowlist

    Configuration (.eve-cli/channels/discord/.env):
      DISCORD_BOT_TOKEN=<token>
      DISCORD_CHANNEL_IDS=<id1>,<id2>   (comma-separated channel IDs to monitor)
    """

    BASE_URL = "https://discord.com/api/v10"
    POLL_INTERVAL = 3   # seconds between polls
    MAX_MSG_LEN = 1900  # Discord hard limit is 2000; leave margin

    _WATERMARK_FILE = os.path.join(
        os.path.expanduser("~"), ".config", "eve-cli", "discord_watermarks.json"
    )

    def __init__(self, token, channel_ids):
        super().__init__()
        self._token = token
        self._channel_ids = list(channel_ids)
        self._last_ids = self._load_watermarks()  # channel_id -> last processed message_id
        self._bot_user_id = None  # own ID, to skip self-messages
        self._allowlist = set()   # synced from ChannelManager
        self._pending_pairs = {}  # user_id -> pairing_code
        self._intent_warned = False  # warn once about missing MESSAGE_CONTENT intent
        self._thread = None

    # ── Watermark persistence ────────────────────────────────────────────────

    def _load_watermarks(self):
        """Load saved message watermarks from disk."""
        try:
            if os.path.isfile(self._WATERMARK_FILE):
                with open(self._WATERMARK_FILE, "r", encoding="utf-8") as f:
                    data = json.loads(f.read())
                if isinstance(data, dict):
                    return data
        except Exception:
            pass
        return {}

    def _save_watermarks(self):
        """Persist current watermarks to disk."""
        try:
            os.makedirs(os.path.dirname(self._WATERMARK_FILE), exist_ok=True)
            with open(self._WATERMARK_FILE, "w", encoding="utf-8") as f:
                f.write(json.dumps(self._last_ids, ensure_ascii=False))
        except Exception:
            pass

    @property
    def name(self):
        return "discord"

    def notify_allowed_senders(self, senders):
        """Called by ChannelManager when the allowlist changes."""
        self._allowlist = set(senders)

    def start(self):
        self._stop_event.clear()
        self._thread = threading.Thread(target=self._poll_loop, daemon=True)
        self._thread.start()

    # ── REST helpers ──────────────────────────────────────────────────────────

    def _api(self, method, path, data=None):
        """Make a Discord REST request. Returns (ok: bool, body: dict|list)."""
        url = f"{self.BASE_URL}{path}"
        headers = {
            "Authorization": f"Bot {self._token}",
            "Content-Type": "application/json",
            "User-Agent": "EvECLIChannels/1.0",
        }
        try:
            body = json.dumps(data, ensure_ascii=False).encode() if data else None
            req = urllib.request.Request(url, data=body, headers=headers, method=method)
            with urllib.request.urlopen(req, timeout=10) as resp:
                return True, json.loads(resp.read().decode("utf-8", errors="replace"))
        except urllib.error.HTTPError as e:
            try:
                return False, json.loads(e.read().decode("utf-8", errors="replace"))
            except Exception:
                return False, {"message": str(e)}
        except Exception as e:
            return False, {"message": str(e)}

    # ── Polling ───────────────────────────────────────────────────────────────

    def _poll_loop(self):
        # Fetch own user ID so we can skip self-messages
        ok, data = self._api("GET", "/users/@me")
        if ok:
            self._bot_user_id = data.get("id")

        # Initialize watermarks: skip all historical messages
        for ch_id in self._channel_ids:
            if ch_id not in self._last_ids:
                ok, msgs = self._api("GET", f"/channels/{ch_id}/messages?limit=1")
                if ok and msgs:
                    self._last_ids[ch_id] = msgs[0]["id"]
                # If API failed, do NOT set "0" — leave missing so _poll_channel skips it
        self._save_watermarks()

        while not self._stop_event.is_set():
            for ch_id in self._channel_ids:
                try:
                    self._poll_channel(ch_id)
                except Exception:
                    pass
            self._stop_event.wait(self.POLL_INTERVAL)

    def _poll_channel(self, channel_id):
        after = self._last_ids.get(channel_id)
        if not after:
            # Watermark not initialized — try to initialize now, skip polling this cycle
            ok, msgs = self._api("GET", f"/channels/{channel_id}/messages?limit=1")
            if ok and msgs:
                self._last_ids[channel_id] = msgs[0]["id"]
                self._save_watermarks()
            return
        ok, data = self._api("GET",
                             f"/channels/{channel_id}/messages?limit=10&after={after}")
        if not ok or not isinstance(data, list):
            return
        # Discord returns newest-first; reverse for chronological processing
        _watermark_advanced = False
        for msg in reversed(data):
            msg_id = msg.get("id", "")
            if not msg_id:
                continue
            self._last_ids[channel_id] = msg_id  # always advance watermark
            _watermark_advanced = True

            author = msg.get("author", {})
            author_id = author.get("id", "")
            # Skip own messages and non-default message types
            if author_id == self._bot_user_id or msg.get("type", 0) != 0:
                continue
            content = msg.get("content", "").strip()
            if not content:
                # Detect missing MESSAGE_CONTENT intent: allowed sender but empty content
                if author_id in self._allowlist and not self._intent_warned:
                    self._intent_warned = True
                    _scroll_aware_print(
                        f"  {C.YELLOW}[discord] メッセージ内容が空です。Bot の MESSAGE_CONTENT intent が"
                        f"無効の可能性があります。{C.RESET}\n"
                        f"  {C.DIM}Discord Developer Portal → Bot → Privileged Gateway Intents → "
                        f"MESSAGE CONTENT INTENT を有効にしてください。{C.RESET}"
                    )
                continue

            # Unknown sender → send pairing code
            if author_id not in self._allowlist:
                code = self._make_pair_code(author_id)
                self._send_raw(channel_id,
                               f"\U0001f510 Pairing code: **{code}**\n"
                               f"In eve-cli run: `/discord:pair {code}`")
                continue

            self._enqueue(ChannelMessage(
                channel="discord",
                sender_id=author_id,
                sender_name=author.get("username", author_id),
                content=content[:4000],
                reply_target=channel_id,
                raw=msg,
            ))
        # Persist watermarks after processing batch
        if _watermark_advanced:
            self._save_watermarks()

    # ── Pairing ───────────────────────────────────────────────────────────────

    def _make_pair_code(self, user_id):
        import random as _r
        code = str(_r.randint(100000, 999999))
        self._pending_pairs[user_id] = code
        return code

    def confirm_pair(self, code):
        """Return sender_id if code matches a pending pairing request."""
        for uid, stored in list(self._pending_pairs.items()):
            if stored == code:
                del self._pending_pairs[uid]
                return uid
        return None

    # ── Send ──────────────────────────────────────────────────────────────────

    def send(self, msg, content):
        if msg.reply_target:
            self._send_raw(msg.reply_target, content)

    def _send_raw(self, channel_id, content):
        for chunk in self._split(content):
            self._api("POST", f"/channels/{channel_id}/messages", {"content": chunk})
            time.sleep(0.3)  # rate-limit safety

    def _split(self, content):
        if len(content) <= self.MAX_MSG_LEN:
            return [content]
        chunks = []
        while content:
            if len(content) <= self.MAX_MSG_LEN:
                chunks.append(content)
                break
            split_at = content.rfind("\n", 0, self.MAX_MSG_LEN)
            if split_at <= 0:
                split_at = self.MAX_MSG_LEN
            chunks.append(content[:split_at])
            content = content[split_at:].lstrip("\n")
        return chunks


# ── SlackAdapter ──────────────────────────────────────────────────────────────

class SlackAdapter(BaseChannelAdapter):
    """
    Receives Slack Events API webhooks via ChannelServer POST /webhook/slack.
    Sends replies via Slack Web API chat.postMessage (thread replies).

    Security: HMAC-SHA256 signature verification on every incoming request.
    Unknown senders receive a DM telling them to contact the admin.

    Configuration (.eve-cli/channels/slack/.env):
      SLACK_BOT_TOKEN=xoxb-xxx
      SLACK_SIGNING_SECRET=xxx
    """

    SLACK_API = "https://slack.com/api"
    MAX_MSG_LEN = 2900  # Slack block text limit is 3000; leave margin

    def __init__(self, bot_token, signing_secret):
        super().__init__()
        self._token = bot_token
        _sec = signing_secret if isinstance(signing_secret, bytes) else signing_secret.encode("utf-8")
        self._secret = _sec
        self._allowlist = set()   # synced from ChannelManager

    @property
    def name(self):
        return "slack"

    def notify_allowed_senders(self, senders):
        self._allowlist = set(senders)

    def handle_webhook(self, headers, body):
        """
        Called by ChannelServer for POST /webhook/slack.
        Returns (status_code, response_body_str).
        """
        try:
            data = json.loads(body.decode("utf-8", errors="replace"))
        except Exception:
            return 400, json.dumps({"error": "Invalid JSON"})

        # URL verification handshake must be handled before signature check
        # (Slack sends this when you first configure the Events API endpoint)
        if data.get("type") == "url_verification":
            return 200, json.dumps({"challenge": data.get("challenge", "")})

        # Verify HMAC-SHA256 signature for all other events
        if self._secret and not self._verify(headers, body):
            return 403, json.dumps({"error": "Invalid signature"})

        # Process message events
        event = data.get("event", {})
        ev_type = event.get("type", "")
        if ev_type == "message" and not event.get("subtype"):
            user_id = event.get("user", "")
            text = event.get("text", "").strip()
            channel = event.get("channel", "")
            ts = event.get("ts", "")
            if user_id and text and channel:
                if user_id not in self._allowlist:
                    self._post(channel,
                               "\u26d4 Not authorized. "
                               "Ask an admin to run `/slack:allow` with your user ID.",
                               thread_ts=ts)
                else:
                    self._enqueue(ChannelMessage(
                        channel="slack",
                        sender_id=user_id,
                        sender_name=event.get("username", user_id),
                        content=text[:4000],
                        reply_target=f"{channel}:{ts}",
                        raw=event,
                    ))
        return 200, json.dumps({"ok": True})

    # ── Signature verification ────────────────────────────────────────────────

    def _verify(self, headers, body):
        ts = headers.get("x-slack-request-timestamp", "")
        sig = headers.get("x-slack-signature", "")
        if not ts or not sig:
            return False
        # Reject requests older than 5 minutes (replay attack prevention)
        try:
            if abs(time.time() - float(ts)) > 300:
                return False
        except (ValueError, TypeError):
            return False
        base = f"v0:{ts}:{body.decode('utf-8', errors='replace')}".encode("utf-8")
        expected = "v0=" + hmac.new(self._secret, base, hashlib.sha256).hexdigest()
        return hmac.compare_digest(expected, sig)

    # ── Send ──────────────────────────────────────────────────────────────────

    def send(self, msg, content):
        parts = msg.reply_target.split(":", 1) if msg.reply_target else ["", ""]
        channel = parts[0]
        thread_ts = parts[1] if len(parts) > 1 else None
        if not channel:
            return
        for chunk in self._split(content):
            self._post(channel, chunk, thread_ts=thread_ts)
            thread_ts = None  # subsequent chunks go to channel, not thread

    def _post(self, channel, text, thread_ts=None):
        payload = {"channel": channel, "text": text}
        if thread_ts:
            payload["thread_ts"] = thread_ts
        try:
            body = json.dumps(payload, ensure_ascii=False).encode("utf-8")
            req = urllib.request.Request(
                f"{self.SLACK_API}/chat.postMessage",
                data=body,
                headers={
                    "Authorization": f"Bearer {self._token}",
                    "Content-Type": "application/json",
                },
                method="POST",
            )
            urllib.request.urlopen(req, timeout=10)
        except Exception:
            pass

    def _split(self, content):
        if len(content) <= self.MAX_MSG_LEN:
            return [content]
        chunks = []
        while content:
            if len(content) <= self.MAX_MSG_LEN:
                chunks.append(content)
                break
            split_at = content.rfind("\n", 0, self.MAX_MSG_LEN)
            if split_at <= 0:
                split_at = self.MAX_MSG_LEN
            chunks.append(content[:split_at])
            content = content[split_at:].lstrip("\n")
        return chunks


# ── ChannelServer ─────────────────────────────────────────────────────────────

class _ChannelRequestHandler(http.server.BaseHTTPRequestHandler):
    """HTTP request handler for the channel webhook server."""

    _webhook_adapter = None  # injected by ChannelServer
    _slack_adapter = None    # injected by ChannelServer

    def log_message(self, fmt, *args):
        pass  # silence default access log

    def do_GET(self):
        if self.path == "/health":
            self._respond(200, b'{"status":"ok"}')
        else:
            self._respond(404, b'{"error":"Not Found"}')

    def do_POST(self):
        length = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(length) if length > 0 else b""
        hdrs = {k.lower(): v for k, v in self.headers.items()}
        if self.path in ("/webhook", "/webhook/"):
            if self._webhook_adapter is not None:
                status, resp = self._webhook_adapter.handle_request(hdrs, body)
                self._respond(status, resp.encode("utf-8"))
            else:
                self._respond(503, b'{"error":"Webhook adapter not configured"}')
        elif self.path in ("/webhook/slack", "/webhook/slack/"):
            if self._slack_adapter is not None:
                status, resp = self._slack_adapter.handle_webhook(hdrs, body)
                self._respond(status, resp.encode("utf-8"))
            else:
                self._respond(503, b'{"error":"Slack adapter not configured"}')
        else:
            self._respond(404, b'{"error":"Not Found"}')

    def _respond(self, status, body):
        self.send_response(status)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)


class ChannelServer(threading.Thread):
    """
    Lightweight HTTP server for receiving channel webhooks.
    Binds to 127.0.0.1 only — never exposed to external networks.
    """

    def __init__(self, port, webhook_adapter=None, slack_adapter=None):
        super().__init__(daemon=True)
        self._port = port
        self._webhook_adapter = webhook_adapter
        self._slack_adapter = slack_adapter
        self._server = None

    def run(self):
        webhook_adapter = self._webhook_adapter
        slack_adapter = self._slack_adapter

        class Handler(_ChannelRequestHandler):
            _webhook_adapter = webhook_adapter
            _slack_adapter = slack_adapter

        try:
            self._server = http.server.HTTPServer(("127.0.0.1", self._port), Handler)
            self._server.serve_forever()
        except OSError as e:
            _scroll_aware_print(
                f"{C.YELLOW}[channels] HTTP server failed on port {self._port}: {e}{C.RESET}"
            )

    def stop(self):
        if self._server:
            self._server.shutdown()


# ── ChannelManager ────────────────────────────────────────────────────────────

class ChannelManager:
    """
    Manages all channel adapters and provides a unified message queue.
    Handles sender allowlists and reply routing.
    """

    def __init__(self, config, adapters):
        self._config = config
        self._adapters = {a.name: a for a in adapters}
        self._queue = _queue_mod.Queue()
        self._server = None
        self._allowlists = {}  # channel_name -> set of sender_ids
        self._policy = {}      # channel_name -> "allowlist" | "open"
        self._load_allowlists()
        for adapter in adapters:
            adapter._queue = self._queue

    # ── Allowlist management ──────────────────────────────────────────────────

    def _channels_dir(self):
        return os.path.join(self._config.cwd, ".eve-cli", "channels")

    def _allowlist_path(self, channel_name):
        return os.path.join(self._channels_dir(), channel_name, "allowlist.json")

    def _load_allowlists(self):
        for name in self._adapters:
            path = self._allowlist_path(name)
            try:
                if os.path.isfile(path) and not os.path.islink(path):
                    with open(path, encoding="utf-8", errors="replace") as f:
                        data = json.load(f)
                    self._allowlists[name] = set(data.get("senders", []))
                    self._policy[name] = data.get("policy", "allowlist")
                else:
                    self._allowlists[name] = set()
                    self._policy[name] = "allowlist"
            except Exception:
                self._allowlists[name] = set()
                self._policy[name] = "allowlist"
        # Sync loaded allowlists to adapters that need them (Discord, Slack)
        self._sync_adapter_allowlists()

    def _sync_adapter_allowlists(self):
        """Push current allowlists into adapters that support notify_allowed_senders."""
        for name, adapter in self._adapters.items():
            if hasattr(adapter, "notify_allowed_senders"):
                adapter.notify_allowed_senders(self._allowlists.get(name, set()))

    def _save_allowlist(self, channel_name):
        try:
            path = _resolve_repo_storage_path(
                self._config.cwd, ".eve-cli", "channels", channel_name, "allowlist.json"
            )
            os.makedirs(os.path.dirname(path), exist_ok=True)
        except OSError:
            return
        data = {
            "senders": sorted(self._allowlists.get(channel_name, set())),
            "policy": self._policy.get(channel_name, "allowlist"),
        }
        try:
            with open(path, "w", encoding="utf-8") as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
        except OSError:
            pass
        # Keep adapter in sync
        adapter = self._adapters.get(channel_name)
        if adapter and hasattr(adapter, "notify_allowed_senders"):
            adapter.notify_allowed_senders(self._allowlists.get(channel_name, set()))

    def is_allowed(self, msg):
        """Return True if this sender is allowed to push messages."""
        policy = self._policy.get(msg.channel, "allowlist")
        if policy == "open":
            return True
        return msg.sender_id in self._allowlists.get(msg.channel, set())

    def get_adapter(self, channel_name):
        return self._adapters.get(channel_name)

    def add_sender(self, channel_name, sender_id):
        self._allowlists.setdefault(channel_name, set()).add(sender_id)
        self._save_allowlist(channel_name)

    def remove_sender(self, channel_name, sender_id):
        self._allowlists.get(channel_name, set()).discard(sender_id)
        self._save_allowlist(channel_name)

    def set_policy(self, channel_name, policy):
        if policy not in ("allowlist", "open"):
            raise ValueError(f"Invalid policy: {policy!r}")
        self._policy[channel_name] = policy
        self._save_allowlist(channel_name)

    def confirm_pair(self, channel_name, code):
        """
        Confirm a pairing code from /discord:pair or similar commands.
        Returns the sender_id on success, None on failure.
        """
        adapter = self._adapters.get(channel_name)
        if adapter and hasattr(adapter, "confirm_pair"):
            sender_id = adapter.confirm_pair(code)
            if sender_id:
                self.add_sender(channel_name, sender_id)
                return sender_id
        return None

    # ── Lifecycle ─────────────────────────────────────────────────────────────

    def start(self):
        webhook_adapter = self._adapters.get("webhook")
        slack_adapter = self._adapters.get("slack")
        self._server = ChannelServer(
            self._config.channels_port,
            webhook_adapter=webhook_adapter,
            slack_adapter=slack_adapter,
        )
        self._server.start()
        for adapter in self._adapters.values():
            adapter.start()

    def stop(self):
        for adapter in self._adapters.values():
            adapter.stop()
        if self._server:
            self._server.stop()

    # ── Message I/O ───────────────────────────────────────────────────────────

    def get_message(self):
        """Get next pending message (non-blocking). Returns None if empty."""
        try:
            return self._queue.get_nowait()
        except Exception:
            return None

    def send_reply(self, msg, content):
        adapter = self._adapters.get(msg.channel)
        if adapter:
            try:
                adapter.send(msg, content)
            except Exception:
                pass

    def ask_question(self, source_msg, question_text, timeout=300):
        """Send a question to the channel and wait for a response.

        Args:
            source_msg: The original ChannelMessage that triggered this interaction.
            question_text: Formatted question text to send to the channel.
            timeout: Max seconds to wait for a response (default 5 minutes).

        Returns:
            str: The user's answer text, or "(no response - timed out)" on timeout.
        """
        # Send question to the channel
        self.send_reply(source_msg, question_text)

        # Poll the queue for a response from the same sender on the same channel
        deadline = time.time() + timeout
        _stash = []  # messages from other senders/channels to re-queue
        try:
            while time.time() < deadline:
                try:
                    msg = self._queue.get(timeout=min(3.0, deadline - time.time()))
                except Exception:
                    continue
                # Check if this is a reply from the original sender
                if (msg.channel == source_msg.channel and
                        msg.sender_id == source_msg.sender_id):
                    return msg.content
                else:
                    _stash.append(msg)  # not for us, save for later
        finally:
            # Re-queue stashed messages so they aren't lost
            for m in _stash:
                self._queue.put(m)
        return "(no response - timed out)"

    def status(self):
        result = {}
        for name in self._adapters:
            result[name] = {
                "policy": self._policy.get(name, "allowlist"),
                "senders": sorted(self._allowlists.get(name, set())),
            }
        result["port"] = self._config.channels_port
        return result


def _build_channel_manager(config):
    """Create a ChannelManager from config.channels. Returns None if disabled."""
    if not config.channels:
        return None
    adapters = []
    for name in config.channels:
        if name == "webhook":
            api_key = _load_channel_env(config, "webhook").get("WEBHOOK_API_KEY", "")
            if not api_key:
                print(f"{C.YELLOW}[channels] Webhook: WEBHOOK_API_KEY not set. "
                      f"Run /webhook:configure <api_key>{C.RESET}")
            adapters.append(WebhookAdapter(api_key=api_key))
        elif name == "discord":
            env = _load_channel_env(config, "discord")
            token = env.get("DISCORD_BOT_TOKEN", "")
            ch_ids_raw = env.get("DISCORD_CHANNEL_IDS", "")
            ch_ids = [c.strip() for c in ch_ids_raw.split(",") if c.strip()]
            if not token:
                print(f"{C.YELLOW}[channels] Discord: DISCORD_BOT_TOKEN not set. "
                      f"Run /discord:configure <token> <channel_ids>{C.RESET}")
            elif not ch_ids:
                print(f"{C.YELLOW}[channels] Discord: DISCORD_CHANNEL_IDS not set. "
                      f"Run /discord:configure <token> <channel_ids>{C.RESET}")
            else:
                adapters.append(DiscordAdapter(token=token, channel_ids=ch_ids))
        elif name == "slack":
            env = _load_channel_env(config, "slack")
            token = env.get("SLACK_BOT_TOKEN", "")
            secret = env.get("SLACK_SIGNING_SECRET", "")
            if not token or not secret:
                print(f"{C.YELLOW}[channels] Slack: SLACK_BOT_TOKEN or SLACK_SIGNING_SECRET not set. "
                      f"Run /slack:configure <token> <signing_secret>{C.RESET}")
            else:
                adapters.append(SlackAdapter(bot_token=token, signing_secret=secret))
        else:
            print(f"{C.YELLOW}[channels] Unknown channel: {name!r} (skipped){C.RESET}")
    if not adapters:
        return None
    return ChannelManager(config, adapters)


def _load_channel_env(config, channel_name):
    """Load .eve-cli/channels/{name}/.env file. Returns dict of key->value."""
    env_path = os.path.join(config.cwd, ".eve-cli", "channels", channel_name, ".env")
    result = {}
    if not os.path.isfile(env_path) or os.path.islink(env_path):
        return result
    try:
        with open(env_path, encoding="utf-8", errors="replace") as f:
            for line in f:
                line = line.strip()
                if not line or line.startswith("#") or "=" not in line:
                    continue
                k, v = line.split("=", 1)
                result[k.strip()] = v.strip().strip("\"'")
    except OSError:
        pass
    return result


def _save_channel_env(config, channel_name, key, value):
    """Upsert a key=value entry in .eve-cli/channels/{name}/.env."""
    try:
        env_path = _resolve_repo_storage_path(config.cwd, ".eve-cli", "channels", channel_name, ".env")
        os.makedirs(os.path.dirname(env_path), exist_ok=True)
    except OSError:
        return
    existing = _load_channel_env(config, channel_name)
    existing[key] = value
    try:
        with open(env_path, "w", encoding="utf-8") as f:
            for k, v in existing.items():
                f.write(f"{k}={v}\n")
        os.chmod(env_path, 0o600)
    except OSError:
        pass


def _should_load_project_permissions(config, permissions_path):
    """Return True when a project permissions file is trusted for use."""
    if not os.path.isfile(permissions_path) or os.path.islink(permissions_path):
        return False
    if not getattr(config, "config_dir", None) or not getattr(config, "cwd", None):
        return False
    return _ensure_repo_scope_trusted(
        config,
        "permissions",
        "Project Permissions Trust Required",
        "Project permissions can change approval behavior and reduce confirmation prompts.",
        [permissions_path],
        preview_paths=[permissions_path],
    )


