# TUI — Terminal User Interface
# ════════════════════════════════════════════════════════════════════════════════

def _complete_at_paths(prefix):
    """Return readline completion candidates for @file references."""
    options = []
    try:
        if prefix.endswith(os.path.sep):
            dirn = prefix
            base = ""
        elif os.path.sep in prefix:
            dirn = os.path.dirname(prefix) + os.path.sep
            base = os.path.basename(prefix)
        else:
            dirn = "."
            base = prefix
        dirn_for_list = dirn.rstrip(os.path.sep) or "."
        entries = os.listdir(dirn_for_list)
        for entry in sorted(entries):
            if entry.startswith(base) and not entry.startswith("."):
                full_path = os.path.join(dirn_for_list, entry)
                option_path = entry if dirn == "." else dirn + entry
                suffix = os.path.sep if os.path.isdir(full_path) else ""
                options.append("@" + option_path + suffix)
    except OSError:
        pass
    return options


def _complete_general_paths(text):
    """Return readline completion candidates for plain file paths."""
    options = []
    try:
        if os.path.sep in text or text.startswith("~"):
            expanded = os.path.expanduser(text)
            dirn = os.path.dirname(expanded) or "."
            base = os.path.basename(expanded)
            prefix_dir = os.path.dirname(text)
        else:
            dirn = "."
            base = text
            prefix_dir = ""
        entries = os.listdir(dirn)
        for entry in sorted(entries):
            if entry.startswith(base) and not entry.startswith("."):
                full_path = os.path.join(dirn, entry)
                display = os.path.join(prefix_dir, entry) if prefix_dir else entry
                suffix = os.path.sep if os.path.isdir(full_path) else ""
                options.append(display + suffix)
    except OSError:
        pass
    return options


def _readline_completion_options(text, slash_commands):
    """Build completion candidates for the interactive prompt."""
    if text.startswith("/"):
        return [command for command in slash_commands if command.startswith(text)]
    if text.startswith("@"):
        return _complete_at_paths(text[1:])
    return _complete_general_paths(text)


def _ghostty_shift_enter_binding(env=None, readline_doc=None):
    """Return a targeted Shift+Enter binding for Ghostty terminals."""
    env = os.environ if env is None else env
    is_ghostty = (
        env.get("TERM_PROGRAM") == "ghostty"
        or "GHOSTTY_RESOURCES_DIR" in env
        or "GHOSTTY_BIN_DIR" in env
    )
    if not is_ghostty:
        return None

    if readline_doc is None:
        readline_doc = readline.__doc__ if HAS_READLINE else ""
    is_libedit = "libedit" in (readline_doc or "")
    if is_libedit:
        return r"bind -s '\e[27;2;13~' '\n'"
    return r'"\e[27;2;13~": "\n"'


def _strip_shift_enter_garbage(text):
    """Remove leaked Shift+Enter escape fragments from input lines."""
    import re
    text = re.sub(r'(?:\x1b\[)?27;2;13~', '', text)
    return re.sub(r'7;2;13~', '', text)


class TUI:
    """Terminal UI for input, streaming output, and tool result display."""

    # ANSI escape regex for stripping colors from tool output
    _ANSI_RE = re.compile(r'\033\[[0-9;]*[a-zA-Z]')


    def __init__(self, config):
        self.config = config
        self._spinner_stop = threading.Event()  # C3: thread-safe Event
        self._spinner_thread = None
        self.is_interactive = sys.stdin.isatty() and sys.stdout.isatty()
        self._is_cjk = self._detect_cjk_locale()
        self.scroll_region = ScrollRegion()
        self._typeahead_lock = threading.Lock()
        self._queued_inputs = collections.deque()
        self._typeahead_partial = ""
        self._typeahead_decoder = codecs.getincrementaldecoder("utf-8")("ignore")

        try:
            self._term_cols = shutil.get_terminal_size((80, 24)).columns
        except (ValueError, OSError):
            self._term_cols = 80

        # Setup readline history (Windows guard - C14)
        if HAS_READLINE:
            try:
                if os.path.isfile(config.history_file):
                    readline.read_history_file(config.history_file)
                readline.set_history_length(1000)
                # Tab-completion for slash commands and @files
                _slash_commands = [
                    "/help", "/exit", "/quit", "/q", "/clear", "/model", "/models",
                    "/status", "/doctor", "/tool-pool", "/command-graph", "/bootstrap-graph",
                    "/save", "/compact", "/yes", "/no", "/tokens", "/usage",
                    "/think", "/no-think", "/map",
                    "/commit", "/diff", "/git", "/plan", "/approve", "/act",
                    "/execute", "/undo", "/init", "/config", "/debug", "/debug-scroll",
                    "/checkpoint", "/rollback", "/autotest", "/gentest", "/watch", "/skills",
                    "/browser", "/fork", "/index", "/pr", "/gh",
                    "/team", "/memory", "/custom", "/cmd",
                    "/jobs", "/errors",
                ]
                def _completer(text, state):
                    try:
                        options = _readline_completion_options(text, _slash_commands)
                        return options[state] if state < len(options) else None
                    except Exception:
                        return None
                readline.set_completer(_completer)
                # Set completer delimiters: only space and newline (tab is completion trigger)
                # Keep @ as non-delimiter so "@path" is treated as single token
                readline.set_completer_delims(" \n")
                # Enable tab completion for libedit (macOS default Python)
                # libedit uses "bind" command instead of GNU readline syntax
                readline.parse_and_bind('bind ^I rl_complete')
                readline.parse_and_bind('bind ^N ed-next-history')  # Down arrow: history navigation
                readline.parse_and_bind('bind ^P ed-prev-history')  # Up arrow: history navigation
                shift_enter_binding = _ghostty_shift_enter_binding()
                if shift_enter_binding:
                    readline.parse_and_bind(shift_enter_binding)
            except Exception:
                pass

    def _scroll_print(self, *args, **kwargs):
        """Print within the scroll region (or normal print if inactive).
        When scroll region is active, acquires its lock to prevent text from
        being written while the cursor is in the footer area (during status updates).
        DECSTBM handles auto-scrolling — the cursor stays in the scroll region."""
        sr = self.scroll_region
        if sr._active:
            with sr._lock:
                print(*args, **kwargs)
                sys.stdout.flush()
        else:
            print(*args, **kwargs)

