def _show_model_list(models):
    """Display installed models with tier labels and colors."""
    _tier_colors = {"S": "196", "A": "208", "B": "226", "C": "46", "D": "51", "E": "250"}
    for m in sorted(models):
        tier, min_ram = Config.get_model_tier(m)
        if tier:
            tc = _tier_colors.get(tier, "250")
            _c = _ansi(chr(27) + "[38;5;%sm" % tc)
            ctx = Config.MODEL_CONTEXT_SIZES.get(m, "?")
            print(f"    {_c}[{tier}]{C.RESET} {m}  {C.DIM}(ctx: {ctx}, ~{min_ram}GB+ RAM){C.RESET}")
        else:
            print(f"    {C.DIM}[?]{C.RESET} {m}")


def _enter_plan_mode(agent, session):
    """Switch agent to Plan mode with plan file setup and LLM guidance."""
    if agent._plan_mode:
        print(f"{C.YELLOW}Already in plan mode.{C.RESET}")
        return
    agent._plan_mode = True
    # Ensure plans directory exists
    plans_dir = os.path.join(agent.config.cwd, ".eve-cli", "plans")
    os.makedirs(plans_dir, exist_ok=True)
    # Pre-set plan path with timestamp
    plan_name = time.strftime("plan-%Y%m%d-%H%M%S.md")
    agent._active_plan_path = os.path.join(plans_dir, plan_name)
    if session.runtime_state:
        session.runtime_state.update_runtime(
            plan_mode=True,
            active_plan_path=agent._active_plan_path,
            last_known_phase="planning",
            resume_hint="review active plan",
            updated_at=time.time(),
        )
        session.runtime_state.record_resume_event(
            "plan_mode_entered",
            f"Entered plan mode with {os.path.basename(agent._active_plan_path)}.",
        )
    # Inject system note to guide LLM
    session.add_system_note(
        "[Plan Mode] You are now in Plan mode. Your task is to explore the codebase, "
        "analyze the problem, and write a plan. Use Read, Glob, Grep, WebFetch, WebSearch "
        "for exploration. Write your plan to the file: " + agent._active_plan_path + "\n"
        "When your plan is complete, the user will use /approve to switch to Act mode."
    )
    # Banner
    _c226 = _ansi(chr(27) + '[38;5;226m')
    _c240 = _ansi(chr(27) + '[38;5;240m')
    _scroll_aware_print(f"\n  {_c226}━━ Plan Mode ━━━━━━━━━━━━━━━━━━━━━━{C.RESET}")
    _scroll_aware_print(f"  {_c226}Read-only exploration + plan writing.{C.RESET}")
    _scroll_aware_print(f"  {_c240}Write restricted to: .eve-cli/plans/{C.RESET}")
    _scroll_aware_print(f"  {_c240}Plan file: {plan_name}{C.RESET}")
    _scroll_aware_print(f"  {_c240}/approve → Act mode{C.RESET}")
    _scroll_aware_print(f"  {_c226}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
    # Update footer status to show PLAN mode
    if agent.tui.scroll_region._active:
        pct = min(int((session.get_token_estimate() / agent.config.context_window) * 100), 100)
        agent.tui.scroll_region.update_status(
            _build_footer_status(agent.config, pct, plan_mode=True)
        )


def _read_latest_plan(agent):
    """Read the active plan file content (max 8000 chars). Falls back to newest .md in plans/."""
    plan_path = agent._active_plan_path
    if plan_path and os.path.isfile(plan_path):
        try:
            with open(plan_path, "r", encoding="utf-8") as f:
                return f.read()[:8000]
        except Exception:
            pass
    # Fallback: find newest .md in plans/
    plans_dir = os.path.join(agent.config.cwd, ".eve-cli", "plans")
    if os.path.isdir(plans_dir):
        md_files = sorted(
            [os.path.join(plans_dir, f) for f in os.listdir(plans_dir) if f.endswith(".md")],
            key=lambda p: os.path.getmtime(p) if os.path.isfile(p) else 0,
            reverse=True,
        )
        if md_files:
            try:
                with open(md_files[0], "r", encoding="utf-8") as f:
                    return f.read()[:8000]
            except Exception:
                pass
    return ""


def _handle_suggest_help(agent, config, client, session):
    """
    現在のコンテキストからプロンプト候補を生成して表示する。
    ユーザーが選択した候補をプロンプト入力欄に返す。
    """
    import json
    import subprocess

    # --- 1. コンテキスト収集 ---
    suggest_parts = []

    # 直近の会話履歴（最大 5 メッセージ）
    recent_messages = session.messages[-5:] if session.messages else []
    if recent_messages:
        history_text = "\n".join([
            f"[{m.get('role','?')}]: {str(m.get('content',''))[:300]}"
            for m in recent_messages
        ])
        suggest_parts.append(f"## 直近の会話\n{history_text}")

    # 最新のエラー情報（あれば）
    last_error = getattr(agent, 'last_error', None)
    if last_error:
        suggest_parts.append(f"## 最新のエラー\n{str(last_error)[:500]}")

    # 変更されたファイル（git diff --name-only）
    try:
        result = subprocess.run(
            ['git', 'diff', '--name-only', 'HEAD'],
            capture_output=True, text=True, timeout=3,
            cwd=config.cwd
        )
        if result.stdout.strip():
            suggest_parts.append(f"## 変更中のファイル\n{result.stdout.strip()[:300]}")
    except Exception:
        pass

    # プロジェクト種別（package.json / requirements.txt 等）
    project_type = ""
    if os.path.isfile(os.path.join(config.cwd, "package.json")):
        project_type = "JavaScript/TypeScript (Node.js)"
    elif os.path.isfile(os.path.join(config.cwd, "requirements.txt")):
        project_type = "Python"
    elif os.path.isfile(os.path.join(config.cwd, "go.mod")):
        project_type = "Go"
    elif os.path.isfile(os.path.join(config.cwd, "Cargo.toml")):
        project_type = "Rust"
    if project_type:
        suggest_parts.append(f"## プロジェクト種別\n{project_type}")

    suggest_str = "\n\n".join(suggest_parts) if suggest_parts else "（コンテキストなし）"

    # --- 2. サイドカーモデルへリクエスト ---
    system_prompt = """あなたはプログラミング学習支援 AI です。
初心者エンジニアが「次に何を聞けばよいか」を提案してください。
以下のルールを守ってください：
- 必ず JSON 配列のみを返す（前置き・後置き不要）
- 提案は 5〜7 件
- 日本語で書く
- 学習に役立つ質問を含める（「なぜ？」「どうすれば？」「比較すると？」）
- 具体的なファイル名やエラー内容があれば質問に盛り込む

出力形式：
["質問 1", "質問 2", "質問 3", "質問 4", "質問 5"]
"""

    user_prompt = f"""以下のコンテキストを踏まえて、ユーザーが次に質問すべき候補を 5〜7 件提案してください。

{suggest_str}
"""

    print("\n💡 プロンプト候補を生成中...")

    try:
        suggestions = _call_sidecar_for_suggestions(
            agent, config, client, system_prompt, user_prompt
        )
    except Exception as e:
        suggestions = _fallback_suggest_help_suggestions(project_type=project_type, last_error=last_error)
        print("  AI候補を生成できなかったため、一般的な候補を表示します。")
        print(f"  理由: {e}")

    if not suggestions:
        print("  候補を生成できませんでした。")
        return None

    # --- 3. 候補を表示 ---
    print("\n📝 次に聞けること：\n")
    for i, suggestion in enumerate(suggestions, 1):
        print(f"  [{i}] {suggestion}")
    print(f"  [Enter] キャンセル\n")

    # --- 4. ユーザー選択を受け付ける ---
    try:
        choice = input("番号を入力してください > ").strip()
    except (KeyboardInterrupt, EOFError):
        print("\nキャンセルしました。")
        return None

    if not choice.isdigit():
        print("キャンセルしました。")
        return None

    idx = int(choice) - 1
    if 0 <= idx < len(suggestions):
        selected = suggestions[idx]
        print(f"\n✅ 選択：{selected}\n")
        return selected
    else:
        print("無効な番号です。キャンセルしました。")
        return None


def _call_sidecar_for_suggestions(agent, config, client, system_prompt, user_prompt):
    """
    サイドカーモデルを使ってプロンプト候補を生成する。
    既存の Ollama API 呼び出し機構を流用する。
    """
    import json

    sidecar_model = config.sidecar_model or os.environ.get('EVE_CLI_SIDECAR_MODEL', 'qwen3:8b')

    # Build messages
    messages = [
        {"role": "system", "content": system_prompt},
        {"role": "user", "content": user_prompt},
    ]

    # Build model-aware options (use _merge_chat_options if available)
    if hasattr(client, '_merge_chat_options'):
        _opts = client._merge_chat_options(sidecar_model, 0.7)
        _opts["num_predict"] = 512
    else:
        _opts = {"temperature": 0.7, "max_tokens": 512}

    # Call Ollama API via client
    try:
        resp = client.chat(
            model=sidecar_model,
            messages=messages,
            tools=None,
            stream=False,
            options=_opts,
        )
    except Exception as e:
        raise RuntimeError(t('errors.sidecar_call_failed', default=f"サイドカーモデル呼び出し失敗：{e}"))

    response_text = ""
    if isinstance(resp, dict):
        choices = resp.get("choices", [])
        if choices:
            response_text = choices[0].get("message", {}).get("content", "").strip()

    suggestions = _parse_suggest_help_response(response_text)

    # Convert to string list
    return [str(s).strip() for s in suggestions if s]


def _fallback_suggest_help_suggestions(project_type="", last_error=None):
    """Return safe default prompt suggestions when sidecar generation fails."""
    suggestions = []
    if last_error:
        suggestions.append(f"このエラーの原因を初心者向けに説明して: {str(last_error)[:80]}")
    if project_type:
        suggestions.append(f"この{project_type}プロジェクトの全体像を初心者向けに説明して")
    suggestions.extend([
        "今のリポジトリで最初に読むべきファイルと理由を教えて",
        "このプロジェクトの主要な処理の流れを初心者向けに説明して",
        "次に安全に確認できるコマンドを教えて",
        "今の状態から次に質問すると理解が進む内容を5つ教えて",
        "変更前に把握しておくべき注意点を教えて",
    ])
    deduped = []
    seen = set()
    for suggestion in suggestions:
        if suggestion and suggestion not in seen:
            deduped.append(suggestion)
            seen.add(suggestion)
    return deduped[:5]


def _parse_suggest_help_response(response_text):
    """Parse a JSON array from sidecar suggest-help output with clear errors."""
    import json

    cleaned = (response_text or "").strip()
    if not cleaned:
        raise RuntimeError(
            t('errors.sidecar_no_suggestions', default="サイドカーモデルから候補が返りませんでした。"
            " 起動直後で会話履歴・エラー・変更差分が少ないと、空の応答になることがあります。")
        )

    if cleaned.startswith('```'):
        lines = cleaned.split('\n')
        if len(lines) > 2:
            cleaned = '\n'.join(lines[1:-1]).strip()

    try:
        suggestions = json.loads(cleaned)
    except json.JSONDecodeError:
        start = cleaned.find('[')
        end = cleaned.rfind(']')
        if start != -1 and end > start:
            try:
                suggestions = json.loads(cleaned[start:end + 1])
            except json.JSONDecodeError:
                suggestions = None
        else:
            suggestions = None
        if suggestions is None:
            raise RuntimeError(
                t('errors.sidecar_invalid_json', default="サイドカーモデルの応答を候補一覧として読めませんでした。"
                " 空文字や説明文ではなく、JSON 配列が返る想定です。")
            )

    if not isinstance(suggestions, list):
        raise RuntimeError(t('errors.sidecar_not_array', default="サイドカーモデルの応答が JSON 配列ではありませんでした。"))
    return suggestions


def _exit_plan_mode(agent, session):
    """Switch agent from Plan mode to Act mode, injecting the plan into context."""
    if not agent._plan_mode:
        print(f"{C.YELLOW}Not in plan mode.{C.RESET}")
        return
    plan_content = _read_latest_plan(agent)
    plan_name = os.path.basename(agent._active_plan_path) if agent._active_plan_path else "(none)"
    agent._plan_mode = False
    # Non-invasive checkpoint: create stash ref without modifying working tree
    if agent.git_checkpoint._is_git_repo:
        agent.git_checkpoint.create("plan-to-act")
    # Inject plan into session context
    if plan_content:
        session.add_system_note(
            "[Act Mode] The following plan was created in Plan mode. Implement it step by step.\n\n"
            + plan_content
        )
    if session.runtime_state:
        session.runtime_state.update_runtime(
            plan_mode=False,
            active_plan_path=agent._active_plan_path,
            last_known_phase="acting",
            resume_hint="continue implementing the approved plan",
            updated_at=time.time(),
        )
        session.runtime_state.record_resume_event(
            "plan_mode_exited",
            f"Approved plan {plan_name} and returned to act mode.",
        )
    # Banner
    _c46 = _ansi(chr(27) + '[38;5;46m')
    _c240 = _ansi(chr(27) + '[38;5;240m')
    _scroll_aware_print(f"\n  {_c46}━━ Act Mode ━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}")
    _scroll_aware_print(f"  {_c46}All tools re-enabled. Implementing plan.{C.RESET}")
    if plan_content:
        _scroll_aware_print(f"  {_c240}Plan loaded: {plan_name} ({len(plan_content)} chars){C.RESET}")
    _scroll_aware_print(f"  {_c240}/plan → return to Plan mode{C.RESET}")
    _scroll_aware_print(f"  {_c240}/rollback → undo all changes since plan{C.RESET}")
    _scroll_aware_print(f"  {_c46}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
    # Update footer status to show ACT mode
    if agent.tui.scroll_region._active:
        pct = min(int((session.get_token_estimate() / agent.config.context_window) * 100), 100)
        agent.tui.scroll_region.update_status(
            _build_footer_status(agent.config, pct, plan_mode=False)
        )


def _build_footer_status(config, pct, plan_mode=False):
    """Build the footer status string with network indicator and mode display."""
    if config.network_status == "online":
        net = "\033[38;5;46m● ON\033[0m"
    else:
        net = "\033[38;5;208m○ OFF\033[0m"
    
    # Mode indicator with color
    if plan_mode:
        mode = "\033[38;5;226mⓅ PLAN\033[0m"
    else:
        mode = "\033[38;5;46mⒶ ACT\033[0m"
    
    return (f"\033[38;5;51m✦ Ready\033[0m "
            f"\033[38;5;240m│\033[0m {mode} "
            f"\033[38;5;240m│\033[0m {net} "
            f"\033[38;5;240m│ ctx:{pct}% │ {config.model}\033[0m")


def _merge_claude_md(existing, generated):
    """Merge generated CLAUDE.md into existing, preserving user content.

    Appends only sections (## headings) from *generated* that do not already
    appear in *existing*.  User-written content is never removed or reordered.
    """
    import re as _re
    _heading_re = _re.compile(r'^##\s+(.+)$', _re.MULTILINE)
    existing_headings = {m.group(1).strip().lower() for m in _heading_re.finditer(existing)}
    # Split generated into sections (## ...)
    gen_sections = _re.split(r'(?=^## )', generated, flags=_re.MULTILINE)
    appended = []
    for section in gen_sections:
        m = _heading_re.match(section)
        if m and m.group(1).strip().lower() not in existing_headings:
            appended.append(section.rstrip())
    if not appended:
        return existing
    merged = existing.rstrip() + "\n\n" + "\n\n".join(appended) + "\n"
    return merged


def _generate_project_claude_md(cwd):
    """Analyze codebase and generate a useful CLAUDE.md template."""
    proj_name = os.path.basename(cwd)
    language = None
    framework = None
    build_cmd = None
    test_cmd = None
    detections = {
        "package.json": ("JavaScript/TypeScript", None),
        "pyproject.toml": ("Python", None),
        "setup.py": ("Python", None),
        "requirements.txt": ("Python", None),
        "Cargo.toml": ("Rust", None),
        "go.mod": ("Go", None),
        "Gemfile": ("Ruby", None),
        "pom.xml": ("Java", "Maven"),
        "build.gradle": ("Java", "Gradle"),
    }
    for fname, (lang, fw) in detections.items():
        if os.path.isfile(os.path.join(cwd, fname)):
            if language is None:
                language = lang
            if fw and framework is None:
                framework = fw
    pkg_json_path = os.path.join(cwd, "package.json")
    if os.path.isfile(pkg_json_path):
        try:
            with open(pkg_json_path, encoding="utf-8", errors="replace") as f:
                pkg = json.load(f)
            if isinstance(pkg, dict):
                if pkg.get("name"):
                    proj_name = pkg["name"]
                scripts = pkg.get("scripts", {})
                if isinstance(scripts, dict):
                    if "build" in scripts:
                        build_cmd = "npm run build"
                    if "test" in scripts:
                        test_cmd = "npm run test"
                deps = {}
                deps.update(pkg.get("dependencies", {}))
                deps.update(pkg.get("devDependencies", {}))
                for fw_name in ["react", "vue", "angular", "next", "nuxt", "svelte", "express", "fastify", "nest"]:
                    if any(fw_name in k for k in deps):
                        framework = fw_name.capitalize()
                        break
        except Exception:
            pass
    if language == "Python":
        pyproj_path = os.path.join(cwd, "pyproject.toml")
        if os.path.isfile(pyproj_path):
            try:
                with open(pyproj_path, encoding="utf-8", errors="replace") as f:
                    pyproj_text = f.read()
                for fw_name in ["django", "flask", "fastapi", "pytest"]:
                    if fw_name in pyproj_text.lower():
                        if fw_name == "pytest":
                            test_cmd = "python -m pytest"
                        elif framework is None:
                            framework = fw_name.capitalize()
            except Exception:
                pass
        req_path = os.path.join(cwd, "requirements.txt")
        if os.path.isfile(req_path):
            try:
                with open(req_path, encoding="utf-8", errors="replace") as f:
                    req_text = f.read().lower()
                for fw_name in ["django", "flask", "fastapi", "pytest"]:
                    if fw_name in req_text:
                        if fw_name == "pytest":
                            test_cmd = test_cmd or "python -m pytest"
                        elif framework is None:
                            framework = fw_name.capitalize()
            except Exception:
                pass
        if test_cmd is None:
            test_cmd = "python -m pytest"
    if language == "Rust":
        build_cmd = "cargo build"
        test_cmd = "cargo test"
    if language == "Go":
        build_cmd = "go build ./..."
        test_cmd = "go test ./..."
    if language == "Ruby":
        if os.path.isfile(os.path.join(cwd, "Rakefile")):
            test_cmd = "bundle exec rake test"
    if os.path.isfile(os.path.join(cwd, "Makefile")):
        if build_cmd is None:
            build_cmd = "make"
        try:
            with open(os.path.join(cwd, "Makefile"), encoding="utf-8", errors="replace") as f:
                makefile_text = f.read()
            if "test:" in makefile_text and test_cmd is None:
                test_cmd = "make test"
        except Exception:
            pass
    has_docker = (os.path.isfile(os.path.join(cwd, "Dockerfile"))
                  or os.path.isfile(os.path.join(cwd, "docker-compose.yml"))
                  or os.path.isfile(os.path.join(cwd, "docker-compose.yaml")))
    git_remote = None
    git_branch = None
    try:
        r = subprocess.run(["git", "remote", "get-url", "origin"],
                           capture_output=True, cwd=cwd, timeout=5)
        if r.returncode == 0:
            git_remote = r.stdout.decode("utf-8", errors="replace").strip()
    except Exception:
        pass
    try:
        r = subprocess.run(["git", "branch", "--show-current"],
                           capture_output=True, cwd=cwd, timeout=5)
        if r.returncode == 0:
            git_branch = r.stdout.decode("utf-8", errors="replace").strip()
    except Exception:
        pass
    skip_dirs = {".git", "node_modules", "__pycache__", ".venv", "venv", ".tox",
                 ".mypy_cache", ".pytest_cache", "dist", "build", ".next", ".nuxt",
                 "target", ".idea", ".vscode"}
    dir_entries = []
    try:
        for entry in sorted(os.listdir(cwd)):
            if entry in skip_dirs:
                continue
            if entry.startswith(".") and entry not in (".github", ".eve-cli"):
                continue
            full = os.path.join(cwd, entry)
            if os.path.isdir(full):
                dir_entries.append(entry + "/")
            else:
                dir_entries.append(entry)
            if len(dir_entries) >= 20:
                break
    except Exception:
        pass
    lines = [f"# {proj_name}", ""]
    lines.append("## Project Overview")
    lines.append(f"- **Language**: {language or 'Unknown'}")
    if framework:
        lines.append(f"- **Framework**: {framework}")
    if has_docker:
        lines.append("- **Docker**: Yes")
    if git_remote:
        lines.append(f"- **Repository**: {git_remote}")
    if git_branch:
        lines.append(f"- **Main branch**: {git_branch}")
    if build_cmd:
        lines.append(f"- **Build**: `{build_cmd}`")
    if test_cmd:
        lines.append(f"- **Test**: `{test_cmd}`")
    lines.append("")
    if dir_entries:
        lines.append("## Directory Structure")
        lines.append("```")
        for e in dir_entries:
            lines.append(e)
        lines.append("```")
        lines.append("")
    lines.append("## Instructions for AI")
    lines.append("- Follow existing code style and conventions")
    lines.append("- Write tests for new features")
    lines.append("- Use absolute paths for file operations")
    lines.append("")
    lines.append("## Design Quality Rules")
    lines.append("")
    lines.append("### Before Writing Code")
    lines.append("- ALWAYS read the target file and related files (callers, tests) BEFORE editing")
    lines.append("- Identify existing patterns, naming conventions, and error handling style")
    lines.append("- For tasks touching 2+ files: state your plan before implementing")
    lines.append("")
    lines.append("### Implementation Standards")
    lines.append("- One function = one responsibility. Keep functions under 30 lines")
    lines.append("- Use clear, descriptive names: `validate_user_input()` not `proc(d)`")
    lines.append("- Do NOT write more than 50 lines at once. Build incrementally:")
    lines.append("  skeleton → flesh out → edge cases, verifying at each step")
    lines.append("- Before implementing, list 3+ edge cases that could break the code")
    lines.append("  (empty input, None, boundary values, Unicode, large data)")
    lines.append("")
    lines.append("### After Writing Code")
    lines.append("- Run syntax check / linter before reporting completion")
    lines.append("- Run tests if available; write tests for new features")
    lines.append("- Re-read modified files to confirm correctness")
    lines.append("")
    return "\n".join(lines)


def _run_gh_command(args, cwd=None, timeout=30):
    """Run a gh CLI command and return (success, stdout, stderr)."""
    if not shutil.which("gh"):
        return False, "", "gh CLI not found. Install: https://cli.github.com/"
    try:
        proc = subprocess.run(
            ["gh"] + args,
            capture_output=True, text=True, timeout=timeout,
            cwd=cwd or os.getcwd(),
        )
        return proc.returncode == 0, proc.stdout.strip(), proc.stderr.strip()
    except subprocess.TimeoutExpired:
        return False, "", "Command timed out"
    except Exception as e:
        return False, "", str(e)


def main():
    # Handle extension subcommands early (before full config load)
    if len(sys.argv) > 1 and sys.argv[1] in ("install", "uninstall", "extensions"):
        config = Config()
        # Minimal load: just paths, no model detection
        config._ensure_dirs()
        sys.exit(_handle_extension_command(sys.argv[1:], config))

    # Parse config
    config = Config().load()

    # MCP server mode: early dispatch (no Ollama, no TUI needed)
    if config.mcp_server:
        _run_mcp_server(config)
        sys.exit(0)

    # Validate loop mode arguments
    if config.loop_mode and not config.prompt:
        print(f"{C.RED}{t('errors.loop_requires_prompt', default='Error: --loop can only be used with -p/--prompt')}{C.RESET}")
        sys.exit(1)
    if config.max_loop_iterations < 1:
        print(f"{C.RED}{t('errors.invalid_max_loop_iterations', default='Error: --max-loop-iterations must be >= 1')}{C.RESET}")
        sys.exit(1)

    # Handle --list-sessions
    if config.list_sessions:
        sessions = Session.list_sessions(config)
        if not sessions:
            print("No saved sessions.")
            return
        print(f"\n{'ID':<20} {'Modified':<18} {'Messages':<10} {'Size':<10}")
        print("─" * 60)
        for s in sessions:
            print(f"{s['id']:<20} {s['modified']:<18} {s['messages']:<10} {s['size']:<10}")
        return

    # Handle --rag-index (index files and exit)
    if config.rag_index:
        print(f"\n{C.CYAN}RAG Indexing: {config.rag_index}{C.RESET}")
        print(f"{C.DIM}Embedding model: {config.rag_model}{C.RESET}")
        print(f"{C.DIM}Ollama: {config.ollama_host}{C.RESET}\n")
        try:
            rag = RAGEngine(config)
            rag.index_path(config.rag_index)
        except Exception as e:
            print(f"{C.RED}RAG indexing failed: {e}{C.RESET}")
            if config.debug:
                traceback.print_exc()
            sys.exit(1)
        return

    # Suppress colors and banner for non-text output formats (json, stream-json)
    if config.output_format != "text":
        C.disable()

    # Show banner immediately so user sees output while connecting
    tui = TUI(config)
    if config.headless:
        tui.is_interactive = False  # suppress spinner/TUI in headless
    if not config.prompt:
        tui.banner(config, model_ok=True)  # skip banner in one-shot mode (-p)

    # Check Ollama connection
    client = OllamaClient(config)
    ok, models = client.check_connection()
    if not ok:
        if config.uses_local_ollama():
            print(f"\n{C.RED}Ollama (the local AI engine) is not running.{C.RESET}")
            if platform.system() == "Darwin":
                print(f"{C.DIM}Look for the llama icon in your menu bar, or open the Ollama app.{C.RESET}")
            else:
                print(f"{C.DIM}Start it by running this in another terminal:  ollama serve{C.RESET}")
        else:
            print(f"\n{C.RED}Could not connect to the configured Ollama endpoint.{C.RESET}")
            print(f"{C.DIM}Endpoint: {config.ollama_host}{C.RESET}")
            print(f"{C.DIM}Check OLLAMA_HOST / OLLAMA_API_KEY, or use https://ollama.com/api for Ollama Cloud.{C.RESET}")
        # Try to auto-start Ollama on macOS and Linux for local hosts only
        if config.uses_local_ollama() and shutil.which("ollama"):
            try:
                ans = "y" if config.yes_mode else input(
                    f"{_ansi(chr(27)+'[38;5;51m')}Try to start Ollama automatically? [Y/n]: {C.RESET}"
                ).strip().lower()
                if ans in ("", "y", "yes"):
                    if platform.system() == "Darwin":
                        # Try macOS app first, fall back to CLI
                        try:
                            subprocess.Popen(
                                ["open", "-a", "Ollama"],
                                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                            )
                        except Exception:
                            subprocess.Popen(
                                ["ollama", "serve"],
                                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                                start_new_session=True,
                            )
                    else:
                        subprocess.Popen(
                            ["ollama", "serve"],
                            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                            start_new_session=True,
                        )
                    print(f"{_ansi(chr(27)+'[38;5;51m')}Starting Ollama... waiting up to 10s{C.RESET}")
                    for _wait in range(10):
                        time.sleep(1)
                        ok, models = client.check_connection()
                        if ok:
                            print(f"{C.GREEN}Ollama started successfully!{C.RESET}")
                            break
            except (EOFError, KeyboardInterrupt):
                print()
            except Exception:
                pass
        if not ok:
            sys.exit(1)

    model_ok = client.check_model(config.model, available_models=models)

    if not model_ok:
        if config.uses_local_ollama():
            print(f"\n{C.YELLOW}The AI model '{config.model}' hasn't been downloaded yet.{C.RESET}")
            if models:
                print(f"{C.DIM}Models already downloaded: {', '.join(models)}{C.RESET}")
            else:
                print(f"{C.DIM}No models downloaded yet.{C.RESET}")
            do_pull = False
            if config.yes_mode:
                do_pull = True
            else:
                try:
                    ans = input(f"{C.CYAN}Download '{config.model}' now? (may be several GB) [Y/n]: {C.RESET}").strip().lower()
                    do_pull = ans in ("", "y", "yes")
                except (EOFError, KeyboardInterrupt):
                    print()
            if do_pull:
                print(f"{C.CYAN}Downloading {config.model}... (this may take a few minutes){C.RESET}")
                if client.pull_model(config.model):
                    print(f"{C.GREEN}Download complete: {config.model}{C.RESET}")
                    model_ok = True
                else:
                    print(f"{C.RED}Download failed. Try manually:  ollama pull {config.model}{C.RESET}")
                    sys.exit(1)
            else:
                print(f"{C.DIM}Skipping download. The AI may not work until the model is downloaded.{C.RESET}")
        else:
            print(f"\n{C.YELLOW}The AI model '{config.model}' is not available on the configured Ollama endpoint.{C.RESET}")
            print(f"{C.DIM}Endpoint: {config.ollama_host}{C.RESET}")
            print(f"{C.DIM}Check the model name, your Ollama Cloud access, and OLLAMA_API_KEY.{C.RESET}")
            sys.exit(1)

    # Setup components
    system_prompt = _build_runtime_system_prompt(config)

    # RAG: inject local context into system prompt (query mode)
    _rag_engine = None
    if config.rag:
        try:
            _rag_engine = RAGEngine(config)
            stats = _rag_engine.get_stats()
            if stats["chunks"] > 0:
                print(f"{C.CYAN}RAG enabled:{C.RESET} {stats['files']} files, "
                      f"{stats['chunks']} chunks indexed "
                      f"({stats['db_size'] // 1024} KB)")
            else:
                rag_path = config.rag_path or config.cwd
                print(f"{C.YELLOW}RAG: No index found. Run indexing first:{C.RESET}")
                print(f"{C.DIM}  python3 eve-coder.py --rag-index {rag_path}{C.RESET}")
        except Exception as e:
            print(f"{C.YELLOW}RAG initialization warning: {e}{C.RESET}")
            _rag_engine = None

    session = Session(config, system_prompt)
    session.set_client(client)  # enable sidecar model for context compaction
    registry = ToolRegistry().register_defaults()
    # Replace BashTool with sandbox-aware instance if --sandbox is set
    if config.sandbox:
        registry.register(BashTool(cwd=config.cwd, config=config))
    permissions = PermissionMgr(config)
    # Wire auto-mode sidecar references
    if config.auto_mode and client:
        permissions._sidecar_client = client
        permissions._sidecar_model = config.sidecar_model or config.model
    registry.register(SubAgentTool(config, client, registry, permissions, tui))
    coordinator = MultiAgentCoordinator(config, client, registry, permissions, tui)
    registry.register(ParallelAgentTool(coordinator))

    # Initialize MCP servers
    try:
        _mcp_clients = _init_mcp_clients(config, registry, permissions)
    except RuntimeError as e:
        print(f"{C.RED}{e}{C.RESET}", file=sys.stderr)
        sys.exit(1)

    # Code Intelligence (lightweight symbol indexing) — used by Agent and /reindex command
    _code_intel = CodeIntelligence(config.cwd)

    # Initialize hooks system
    hook_mgr = HookManager(config)
    if hook_mgr.has_hooks and config.debug:
        print(f"{C.DIM}[debug] Loaded {len(hook_mgr._hooks)} hooks{C.RESET}", file=sys.stderr)
    notifier = NotificationManager(config)
    global _active_notifier
    _active_notifier = notifier

    agent = Agent(config, client, registry, permissions, session, tui,
                  rag_engine=_rag_engine, hook_mgr=hook_mgr, code_intel=_code_intel)

    # Initialize Channels (if --channels flag was given)
    channel_manager = _build_channel_manager(config)
    if channel_manager:
        channel_manager.start()
        _c51 = _ansi(chr(27) + '[38;5;51m')
        _c240 = _ansi(chr(27) + '[38;5;240m')
        _ch_names = ", ".join(config.channels)
        print(f"  {_c51}⚡ Channels enabled:{C.RESET} {_ch_names}")
        if "webhook" in config.channels:
            print(f"  {_c240}Webhook listening on http://127.0.0.1:{config.channels_port}/webhook{C.RESET}")
        print()
        atexit.register(channel_manager.stop)
    agent.channel_manager = channel_manager
    if _kairos_settings(config).get("enabled"):
        agent._init_kairos()
        if agent.kairos:
            agent.kairos.start()

    # Handle Ctrl+C gracefully
    def signal_handler(sig, frame):
        agent.interrupt()
        raise KeyboardInterrupt
    signal.signal(signal.SIGINT, signal_handler)

    # Handle terminal resize — update scroll region
    if hasattr(signal, 'SIGWINCH'):
        signal.signal(signal.SIGWINCH, lambda s, f: tui.scroll_region.resize())

    # Helper: show last user message from session for "welcome back"
    def _show_resume_info(label, msgs, pct, messages_list, runtime_summary=None):
        print(f"\n  {_ansi(chr(27)+'[38;5;51m')}✦ Welcome back! Resumed {label}{C.RESET}")
        # Find last user message for context
        last_user_msg = ""
        for m in reversed(messages_list):
            if m.get("role") == "user" and isinstance(m.get("content"), str):
                last_user_msg = m["content"].strip()[:80]
                break
        info = f"  {msgs} messages, {pct}% context used"
        if last_user_msg:
            info += f' | last: "{last_user_msg}"'
        print(f"  {_ansi(chr(27)+'[38;5;240m')}{info}{C.RESET}\n")
        if runtime_summary:
            phase = runtime_summary.get("last_known_phase") or "unknown"
            plan_path = runtime_summary.get("active_plan_path")
            latest_plan = os.path.basename(plan_path) if plan_path else None
            verifier = runtime_summary.get("latest_verifier") or {}
            lines = [f"  {_ansi(chr(27)+'[38;5;240m')}phase: {phase}{C.RESET}"]
            if latest_plan:
                lines.append(f"  {_ansi(chr(27)+'[38;5;240m')}active plan: {latest_plan}{C.RESET}")
            if runtime_summary.get("pending_tasks"):
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}pending tasks: {runtime_summary['pending_tasks']}{C.RESET}"
                )
            if runtime_summary.get("running_jobs") or runtime_summary.get("orphaned_jobs"):
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}jobs: running {runtime_summary.get('running_jobs', 0)}, "
                    f"orphaned {runtime_summary.get('orphaned_jobs', 0)}{C.RESET}"
                )
            if runtime_summary.get("latest_checkpoint"):
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}latest checkpoint: {runtime_summary['latest_checkpoint']}{C.RESET}"
                )
            if verifier:
                summary = verifier.get("summary", "") or verifier.get("status", "")
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}last verifier: {verifier.get('status', 'unknown')} — "
                    f"{summary[:80]}{C.RESET}"
                )
            recent_events = runtime_summary.get("recent_events") or []
            if recent_events:
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}timeline: {recent_events[-1].get('message', '')[:80]}{C.RESET}"
                )
            if runtime_summary.get("resume_hint"):
                lines.append(
                    f"  {_ansi(chr(27)+'[38;5;240m')}next: {runtime_summary['resume_hint']}{C.RESET}"
                )
            if len(lines) > 1:
                print("\n".join(lines) + "\n")

    # Resume session if requested
    if config.resume:
        if config.session_id:
            if session.load(config.session_id):
                msgs = len(session.messages)
                pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
                _show_resume_info(
                    f"session: {config.session_id}", msgs, pct, session.messages, session.get_resume_summary()
                )
            else:
                print(f"{C.RED}No saved session found with ID '{config.session_id}'.{C.RESET}")
                print(f"{C.DIM}List sessions: python3 eve-coder.py --list-sessions{C.RESET}")
                return
        else:
            # First try to find a session for the current working directory
            project_sid = Session.get_project_session(config)
            resumed = False
            if project_sid:
                if session.load(project_sid):
                    msgs = len(session.messages)
                    pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
                    _show_resume_info(
                        f"project session: {project_sid}", msgs, pct, session.messages, session.get_resume_summary()
                    )
                    resumed = True
            if not resumed:
                # Fall back to latest session
                sessions = Session.list_sessions(config)
                if sessions:
                    latest = sessions[0]["id"]
                    if session.load(latest):
                        msgs = len(session.messages)
                        pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
                        _show_resume_info(latest, msgs, pct, session.messages, session.get_resume_summary())
                    else:
                        print(f"{C.YELLOW}Could not resume. Starting new session.{C.RESET}")

    # First-run onboarding hint for new users
    if not config.resume and not config.prompt:
        first_run_marker = os.path.join(config.state_dir, ".first_run_done")
        if not os.path.exists(first_run_marker):
            _hint_color = _ansi(chr(27)+'[38;5;51m')
            print(f"  {_hint_color}First time? Try typing: \"create a hello world in Python\"{C.RESET}")
            print(f"  {_ansi(chr(27)+'[38;5;240m')}Type /help for commands, or just ask anything in natural language.{C.RESET}\n")
            try:
                open(first_run_marker, "w").close()
            except OSError:
                pass

    # Fire SessionStart hook
    if hook_mgr.has_hooks:
        hook_mgr.fire("SessionStart", {
            "model": config.model,
            "cwd": config.cwd,
            "session_id": session.session_id,
        })

    # One-shot mode
    if config.prompt:
        # Build system prompt once (shared across all loop iterations)
        system_prompt = _build_runtime_system_prompt(config)
        exit_code = 0  # Track exit code for CI/CD

        # Create headless output collector for structured CI/CD output
        _output_collector = None
        if config.headless and config.output_format in ("json", "stream-json"):
            _output_collector = HeadlessOutputCollector(
                output_format=config.output_format,
                model=config.model,
                session_id="",  # will be set after session creation
            )

        if config.loop_mode:
            # Loop mode: re-run until done_string is detected or max iterations/time reached
            loop_start_time = time.time()
            loop_i = 0
            loop_success = False
            # --carry-session: reuse session across iterations
            _carry_session = None
            while loop_i < config.max_loop_iterations:
                loop_i += 1

                # Check time-based limit
                if config.max_loop_hours is not None:
                    elapsed_hours = (time.time() - loop_start_time) / 3600.0
                    if elapsed_hours >= config.max_loop_hours:
                        print(f"\n  Loop ended: reached max time ({config.max_loop_hours:.1f} hours).")
                        exit_code = 2  # Timeout
                        break
                    remaining_hours = config.max_loop_hours - elapsed_hours
                    print(f"\n{'='*60}")
                    print(f"  Loop iteration {loop_i}/{config.max_loop_iterations} "
                          f"(time remaining: {remaining_hours:.2f}h)")
                else:
                    print(f"\n{'='*60}")
                    print(f"  Loop iteration {loop_i}/{config.max_loop_iterations} "
                          f"(remaining: {config.max_loop_iterations - loop_i})")
                print(f"{'='*60}")

                # --carry-session: reuse session (history carryover) or create fresh
                if config.carry_session and _carry_session is not None:
                    session = _carry_session
                else:
                    session = Session(config, system_prompt)
                if _output_collector:
                    _output_collector._session_id = session.session_id
                agent = Agent(config, client, registry, permissions, session, tui,
                              output_collector=_output_collector)
                try:
                    agent.run(config.prompt)
                except Exception as e:
                    print(f"\n{C.RED}Loop iteration failed: {e}{C.RESET}")
                    exit_code = 1  # Error
                    if config.output_format in ("json", "stream-json"):
                        _output = {
                            "role": "error",
                            "error": str(e),
                            "model": config.model,
                            "session_id": session.session_id,
                        }
                        print(json.dumps(_output, ensure_ascii=False))
                    sys.exit(exit_code)

                # Save reference for --carry-session
                if config.carry_session:
                    _carry_session = session

                last_output = agent.get_last_output()
                if config.done_string in last_output:
                    print(f"\n  Loop complete: '{config.done_string}' detected.")
                    loop_success = True
                    break
            else:
                print(f"\n  Loop ended: reached max iterations ({config.max_loop_iterations}).")
                exit_code = 3  # Max iterations reached without success

            # Set success if loop completed normally
            if loop_success and exit_code == 0:
                exit_code = 0
        else:
            # Standard one-shot mode
            session = Session(config, system_prompt)
            if _output_collector:
                _output_collector._session_id = session.session_id
            agent = Agent(config, client, registry, permissions, session, tui,
                          output_collector=_output_collector)
            try:
                agent.run(config.prompt)
            except Exception as e:
                print(f"\n{C.RED}Execution failed: {e}{C.RESET}")
                exit_code = 1
                if config.output_format in ("json", "stream-json"):
                    _output = {
                        "role": "error",
                        "error": str(e),
                        "model": config.model,
                    }
                    print(json.dumps(_output, ensure_ascii=False))
                sys.exit(exit_code)

        session.save()
        if config.output_format in ("json", "stream-json"):
            if _output_collector:
                # Use headless collector's structured summary
                _output = _output_collector.get_summary()
                _output["exit_code"] = exit_code
            else:
                # Extract last assistant message from session
                _last_content = ""
                for _msg in reversed(session.messages):
                    if _msg.get("role") == "assistant":
                        _last_content = _msg.get("content", "")
                        break
                _output = {
                    "role": "assistant",
                    "content": _last_content,
                    "model": config.model,
                    "session_id": session.session_id,
                    "exit_code": exit_code,
                }

            # --output-schema: validate and extract structured output
            if config.output_schema:
                _raw_content = _output.get("content", "")
                _parsed = _extract_json_from_response(_raw_content)
                _schema_valid = False
                if _parsed is not None:
                    _valid, _errs = _validate_against_schema(_parsed, config.output_schema)
                    if _valid:
                        _schema_valid = True
                        _output["structured_output"] = _parsed
                    else:
                        # Retry once: ask agent to fix the output
                        _fix_prompt = (
                            f"Your previous response did not match the required JSON schema.\n"
                            f"Errors: {'; '.join(_errs)}\n"
                            f"Schema: {json.dumps(config.output_schema, ensure_ascii=False)}\n"
                            f"Please output ONLY a corrected JSON object."
                        )
                        try:
                            session.add_user_message(_fix_prompt)
                            agent.run(_fix_prompt)
                            _retry_content = ""
                            for _msg in reversed(session.messages):
                                if _msg.get("role") == "assistant":
                                    _retry_content = _msg.get("content", "")
                                    break
                            _retry_parsed = _extract_json_from_response(_retry_content)
                            if _retry_parsed is not None:
                                _v2, _e2 = _validate_against_schema(_retry_parsed, config.output_schema)
                                if _v2:
                                    _schema_valid = True
                                    _output["structured_output"] = _retry_parsed
                                    _output["content"] = _retry_content
                        except Exception:
                            pass
                else:
                    # No JSON found at all — try retry
                    _fix_prompt = (
                        f"Your response was not valid JSON.\n"
                        f"Schema: {json.dumps(config.output_schema, ensure_ascii=False)}\n"
                        f"Please output ONLY a valid JSON object matching the schema."
                    )
                    try:
                        session.add_user_message(_fix_prompt)
                        agent.run(_fix_prompt)
                        _retry_content = ""
                        for _msg in reversed(session.messages):
                            if _msg.get("role") == "assistant":
                                _retry_content = _msg.get("content", "")
                                break
                        _retry_parsed = _extract_json_from_response(_retry_content)
                        if _retry_parsed is not None:
                            _v2, _e2 = _validate_against_schema(_retry_parsed, config.output_schema)
                            if _v2:
                                _schema_valid = True
                                _output["structured_output"] = _retry_parsed
                                _output["content"] = _retry_content
                    except Exception:
                        pass
                _output["schema_valid"] = _schema_valid

            print(json.dumps(_output, ensure_ascii=False))
        sys.exit(exit_code)

    # Interactive mode
    _last_ctrl_c = [0.0]  # mutable container for closure
    _session_start_time = time.time()
    _session_start_msgs = len(session.messages)

    # Scroll region: activate for the entire interactive session
    global _active_scroll_region, _active_tui
    _active_tui = tui
    _scroll_mode = tui.scroll_region.supported()
    if _scroll_mode:
        _active_scroll_region = tui.scroll_region
        # Store status BEFORE setup() so footer includes it in initial draw
        pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
        tui.scroll_region.update_status(
            _build_footer_status(config, pct, plan_mode=agent._plan_mode)
        )
        tui.scroll_region.update_hint("")
        tui.scroll_region.setup()

    while True:
        try:
            # ── Channel message polling (non-blocking) ────────────────────────
            if channel_manager:
                _ch_msg = channel_manager.get_message()
                if _ch_msg:
                    if not channel_manager.is_allowed(_ch_msg):
                        _scroll_aware_print(
                            f"  {C.YELLOW}[channels] Rejected unauthorized sender "
                            f"'{_ch_msg.sender_id}' on {_ch_msg.channel}{C.RESET}"
                        )
                    else:
                        _ch_color = _ansi(chr(27) + '[38;5;198m')
                        _scroll_aware_print(
                            f"\n  {_ch_color}⚡ [{_ch_msg.channel.upper()}:{_ch_msg.sender_name}]{C.RESET} "
                            f"{_ch_msg.content[:120]}\n"
                        )
                        _ch_input = (f"[Channel:{_ch_msg.channel.upper()} from {_ch_msg.sender_name}] "
                                     f"{_ch_msg.content}")
                        # Set channel context so AskUserQuestion tools can route I/O through channels
                        global _active_channel_context
                        _active_channel_context = {
                            "channel_manager": channel_manager,
                            "source_msg": _ch_msg,
                        }
                        try:
                            agent.run(_ch_input)
                            _ch_reply = agent.get_last_output()
                            channel_manager.send_reply(_ch_msg, _ch_reply)
                        finally:
                            _active_channel_context = None
                    continue

            # ── Non-blocking stdin wait when channels are active ──────────────
            # Without this, input() blocks indefinitely and channel messages
            # are never processed while waiting for user input.
            if channel_manager and HAS_TERMIOS and sys.stdin.isatty():
                _ch_ready, _, _ = _select_mod.select([sys.stdin], [], [], 0.3)
                if not _ch_ready:
                    continue  # no user input yet; loop back to poll channels

            user_input = tui.get_multiline_input(
                session=session, plan_mode=agent._plan_mode,
            )

            if user_input is None:
                continue
            user_input = user_input.strip()
            if not user_input:
                continue

            # Handle exit keywords (user may type "exit", "exit;", "quit", "bye")
            _exit_words = {"exit", "exit;", "quit", "quit;", "bye", "bye;"}
            if user_input.strip().lower() in _exit_words:
                session.save()
                _elapsed = int(time.time() - _session_start_time)
                _mins, _secs = divmod(_elapsed, 60)
                _new_msgs = len(session.messages) - _session_start_msgs
                _dur = f"{_mins}m {_secs}s" if _mins else f"{_secs}s"
                print(f"\n  {_ansi(chr(27)+'[38;5;51m')}✦ Session saved. Duration: {_dur}, {_new_msgs} new messages.{C.RESET}")
                print(f"  {_ansi(chr(27)+'[38;5;240m')}Resume anytime: eve-cli --resume{C.RESET}\n")
                break

            # Handle commands (only /word style, not absolute paths like /Users/...)
            _first_word = user_input.split()[0] if user_input.strip() else ""
            _is_slash_cmd = (user_input.startswith("/") and
                             len(_first_word) > 1 and
                             _first_word[1:2].isalpha() and
                             "/" not in _first_word[1:])
            if _is_slash_cmd:
                cmd = _first_word.lower()
                if cmd in ("/exit", "/quit", "/q"):
                    session.save()
                    msgs = len(session.messages)
                    tokens = session.get_token_estimate()
                    print(f"\n  {_ansi(chr(27)+'[38;5;51m')}✦ Session saved ({msgs} messages, ~{tokens:,} tokens){C.RESET}")
                    print(f"  {_ansi(chr(27)+'[38;5;240m')}Resume anytime: python3 eve-coder.py --resume{C.RESET}\n")
                    break
                elif cmd == "/help":
                    tui.show_help()
                    continue
                elif cmd == "/clear":
                    session.save()
                    old_sid = session.session_id
                    session.messages.clear()
                    session._token_estimate = 0
                    session.session_id = (
                        datetime.now().strftime("%Y%m%d_%H%M%S") + "_" + uuid.uuid4().hex[:6]
                    )
                    print(f"{C.GREEN}{t('slash.cleared', default='Conversation cleared.')}{C.RESET}")
                    print(f"{C.DIM}{t('slash.session_saved', default=f'Previous session saved as: {old_sid}')}{C.RESET}")
                    continue
                elif cmd == "/suggest-help":
                    _selected = _handle_suggest_help(agent, config, client, session)
                    if _selected:
                        user_input = _selected
                        # Fall through to normal agent processing
                    else:
                        continue
                elif cmd == "/status":
                    tui.show_status(session, config, agent=agent)
                    continue
                elif cmd == "/kairos":
                    # KAIROS supervisor command handler
                    _kairos_args = user_input.split()[1:]
                    if not _kairos_args:
                        print(f"\n{C.BOLD}KAIROS commands:{C.RESET}")
                        print("  /kairos on                          - Start proactive supervisor")
                        print("  /kairos off                         - Stop supervisor")
                        print("  /kairos status                      - Show current status")
                        print("  /kairos pause <minutes>             - Pause heartbeat execution")
                        print("  /kairos resume                      - Resume heartbeat execution")
                        print("  /kairos log [--date YYYY-MM-DD]     - Show audit log")
                        print("  /kairos approvals                   - Show pending approvals")
                        print("  /kairos watch pr add <repo> <num>   - Add PR subscription")
                        print("  /kairos watch pr list               - List PR subscriptions")
                        print("  /kairos dream now                   - Run autoDream immediately")
                        print("  /kairos reset                       - Reset state to defaults")
                        print()
                        continue
                    
                    _kairos_cmd = _kairos_args[0].lower()

                    def _ensure_kairos():
                        if agent.kairos is None:
                            agent._init_kairos()
                        return agent.kairos
                    
                    if _kairos_cmd == "on":
                        # Initialize and start KAIROS
                        if _ensure_kairos():
                            agent.kairos.start()
                            mode = agent.kairos.get_status().get('mode', 'observe')
                            interval = agent.kairos.scheduler.interval
                            print(f"\n{C.GREEN}KAIROS started (mode: {mode}, heartbeat: {interval}s){C.RESET}")
                            print(f"{C.DIM}Audit log: {_get_kairos_state_dir(config)}/audit/{C.RESET}\n")
                        else:
                            print(f"{C.RED}Failed to initialize KAIROS{C.RESET}\n")
                    
                    elif _kairos_cmd == "off":
                        if agent.kairos:
                            agent.kairos.stop()
                            print(f"\n{C.YELLOW}KAIROS stopped{C.RESET}\n")
                        else:
                            print(f"{C.DIM}KAIROS is not running{C.RESET}\n")
                    
                    elif _kairos_cmd == "status":
                        if _ensure_kairos():
                            status = agent.kairos.get_status()
                            print(f"\n{C.BOLD}KAIROS Status:{C.RESET}")
                            print(f"  enabled: {status.get('enabled', False)}")
                            print(f"  mode: {status.get('mode', 'observe')}")
                            print(f"  state: {status.get('state', 'unknown')}")
                            print(f"  running: {status.get('running', False)}")
                            print(f"  paused: {status.get('paused', False)}")
                            print(f"  last heartbeat: {status.get('last_heartbeat') or 'never'}")
                            print(f"  next heartbeat: {status.get('next_heartbeat') or 'unknown'}")
                            print(f"  heartbeat cursor: {status.get('heartbeat_cursor') or 'none'}")
                            print(f"  active watchers: {len(status.get('active_watchers', []))}")
                            print(f"  queued approvals: {status.get('approval_queue_size', 0)}")
                            print(f"  last action: {status.get('last_action') or 'never'}")
                            print(f"  last dream: {status.get('last_dream') or 'never'}")
                            print(f"  last error: {status.get('last_error') or '(none)'}")
                            print()
                        else:
                            print(f"{C.DIM}KAIROS is not initialized{C.RESET}\n")

                    elif _kairos_cmd == "pause":
                        if len(_kairos_args) < 2:
                            print(f"{C.YELLOW}Usage: /kairos pause <minutes>{C.RESET}\n")
                        elif _ensure_kairos():
                            try:
                                _pause_minutes = int(_kairos_args[1])
                                pause_until = agent.kairos.pause(_pause_minutes)
                                print(f"\n{C.YELLOW}KAIROS paused until {pause_until.isoformat()}{C.RESET}\n")
                            except ValueError:
                                print(f"{C.RED}Minutes must be an integer{C.RESET}\n")

                    elif _kairos_cmd == "resume":
                        if _ensure_kairos():
                            agent.kairos.resume()
                            print(f"\n{C.GREEN}KAIROS resumed{C.RESET}\n")
                    
                    elif _kairos_cmd == "log":
                        _log_date = datetime.now().strftime('%Y-%m-%d')
                        if len(_kairos_args) >= 3 and _kairos_args[1] == "--date":
                            _log_date = _kairos_args[2]
                        elif len(_kairos_args) >= 2:
                            _log_date = _kairos_args[1]
                        if _ensure_kairos():
                            entries = agent.kairos.audit_log.read_date(_log_date)
                            if entries:
                                print(f"\n{C.BOLD}KAIROS Audit Log ({_log_date}):{C.RESET}")
                                for entry in entries[-20:]:  # Show last 20 entries
                                    _ts = entry.get('_timestamp', entry.get('timestamp', '?'))[:19]
                                    _evt = entry.get('event', '?')
                                    _dec = entry.get('decision', '?')
                                    _hb = entry.get('heartbeat_id', '')[:20]
                                    print(f"  [{_ts}] {_evt:20s} {_dec:12s} {_hb}")
                                print()
                            else:
                                print(f"{C.DIM}No log entries for {_log_date}{C.RESET}\n")
                        else:
                            print(f"{C.DIM}KAIROS is not initialized{C.RESET}\n")

                    elif _kairos_cmd == "approvals":
                        if _ensure_kairos():
                            pending = agent.kairos.approval_queue.get_pending()
                            if not pending:
                                print(f"{C.DIM}No pending approvals{C.RESET}\n")
                            else:
                                print(f"\n{C.BOLD}Pending Approvals:{C.RESET}")
                                for item in pending:
                                    decision = item.get("decision", {})
                                    print(f"  {item.get('approval_id')}  {decision.get('decision', 'plan'):12s}  {decision.get('reason', '')}")
                                print()

                    elif _kairos_cmd == "watch" and len(_kairos_args) >= 3 and _kairos_args[1].lower() == "pr":
                        if _kairos_args[2].lower() == "add" and len(_kairos_args) >= 5:
                            if _ensure_kairos() and agent.kairos.add_pr_subscription(_kairos_args[3], _kairos_args[4]):
                                print(f"\n{C.GREEN}Watching PR {_kairos_args[3]}#{_kairos_args[4]}{C.RESET}\n")
                            else:
                                print(f"{C.RED}Failed to add PR subscription{C.RESET}\n")
                        elif _kairos_args[2].lower() == "list":
                            if _ensure_kairos():
                                subs = agent.kairos.list_pr_subscriptions()
                                if not subs:
                                    print(f"{C.DIM}No PR subscriptions configured{C.RESET}\n")
                                else:
                                    print(f"\n{C.BOLD}PR Subscriptions:{C.RESET}")
                                    for sub in subs:
                                        print(f"  {sub.get('repo')}#{sub.get('pr_number')}  events={','.join(sub.get('events', []))}")
                                    print()
                        else:
                            print(f"{C.YELLOW}Usage: /kairos watch pr add <repo> <num> | /kairos watch pr list{C.RESET}\n")

                    elif _kairos_cmd == "dream" and len(_kairos_args) >= 2 and _kairos_args[1].lower() == "now":
                        if _ensure_kairos() and agent.kairos.dream_worker:
                            result = agent.kairos.dream_worker.run_now()
                            agent.kairos.state_store.set("last_dream", datetime.now().strftime("%Y-%m-%d"))
                            agent.kairos.state_store.save()
                            print(f"\n{C.GREEN}autoDream completed{C.RESET}")
                            print(f"  learnings: {result.get('learnings_count', 0)}")
                            print(f"  report: {result.get('report_path')}")
                            print()
                    
                    elif _kairos_cmd == "reset":
                        if _ensure_kairos():
                            agent.kairos.state_store.reset()
                            print(f"\n{C.YELLOW}KAIROS state reset to defaults{C.RESET}\n")
                        else:
                            print(f"{C.DIM}KAIROS is not initialized{C.RESET}\n")
                    
                    else:
                        print(f"{C.RED}Unknown KAIROS command: {_kairos_cmd}{C.RESET}")
                        print("Use /kairos for available commands.\n")
                    
                    continue
                elif cmd == "/doctor":
                    print()
                    for _line in _build_doctor_lines(config, client, registry, permissions, session, agent, hook_mgr, channel_manager, _mcp_clients):
                        print(f"  {_line}")
                    print()
                    continue
                elif cmd == "/tool-pool":
                    print()
                    for _line in _build_tool_pool_lines(registry, permissions, allowed_names=agent._get_allowed_tool_names()):
                        print(f"  {_line}")
                    print()
                    continue
                elif cmd == "/command-graph":
                    _parts = user_input.split(None, 1)
                    _prompt_text = _parts[1].strip() if len(_parts) > 1 else ""
                    print()
                    for _line in _build_command_graph_lines(config, agent, registry, prompt_text=_prompt_text):
                        print(f"  {_line}")
                    print()
                    continue
                elif cmd == "/bootstrap-graph":
                    print()
                    for _line in _build_bootstrap_graph_lines(config, client, registry, permissions, hook_mgr, channel_manager, _mcp_clients):
                        print(f"  {_line}")
                    print()
                    continue
                elif cmd == "/jobs":
                    # Show recent background jobs with output history
                    _rt = _get_active_runtime_state()
                    if _rt is None:
                        print(f"{C.YELLOW}No runtime state available.{C.RESET}")
                        continue
                    _jobs = _rt.list_jobs()
                    if not _jobs:
                        print(f"{C.DIM}No background jobs recorded in this session.{C.RESET}")
                        continue
                    _job_limit = 15
                    print(f"\n{C.BOLD}━━━ Background Jobs (recent {min(len(_jobs), _job_limit)}/{len(_jobs)}) ━━━{C.RESET}")
                    for _j in _jobs[:_job_limit]:
                        _jid = _j.get("job_id", "?")
                        _jstate = _j.get("state", "?")
                        _jcmd = (_j.get("command_or_prompt") or "")[:80]
                        _jdur = ""
                        if _j.get("started_at") and _j.get("finished_at"):
                            _jdur = f" ({int(_j['finished_at'] - _j['started_at'])}s)"
                        elif _j.get("started_at"):
                            _jdur = f" ({int(time.time() - _j['started_at'])}s, running)"
                        _state_color = C.GREEN if _jstate == "finished" else (C.RED if _jstate in ("failed", "orphaned") else C.YELLOW)
                        print(f"  {_state_color}{_jstate:10s}{C.RESET} {_jid:8s}{_jdur}  {C.DIM}{_jcmd}{C.RESET}")
                        # Show truncated output for failed jobs
                        if _jstate in ("failed", "orphaned"):
                            _jerr = (_j.get("error_summary") or _j.get("result_summary") or "")[:120]
                            if _jerr:
                                print(f"             {C.RED}{_jerr}{C.RESET}")
                    print()
                    continue
                elif cmd == "/errors":
                    # Aggregated error summary from recent jobs
                    _rt = _get_active_runtime_state()
                    if _rt is None:
                        print(f"{C.YELLOW}No runtime state available.{C.RESET}")
                        continue
                    _jobs = _rt.list_jobs()
                    _failed = [j for j in _jobs if j.get("state") in ("failed", "orphaned")]
                    if not _failed:
                        print(f"{C.GREEN}No failed jobs in this session. All clear!{C.RESET}")
                        continue
                    print(f"\n{C.BOLD}{C.RED}━━━ Error Summary ({len(_failed)} failed job{'s' if len(_failed) != 1 else ''}) ━━━{C.RESET}")
                    # Group errors by common patterns
                    _err_groups = {}
                    for _j in _failed:
                        _jerr = _j.get("error_summary") or _j.get("result_summary") or "(no output)"
                        # Extract first meaningful error line for grouping
                        _err_key = ""
                        for _line in _jerr.split("\n"):
                            _line = _line.strip()
                            if _line and not _line.startswith("(") and len(_line) > 5:
                                _err_key = _line[:100]
                                break
                        if not _err_key:
                            _err_key = _jerr[:100]
                        _err_groups.setdefault(_err_key, []).append(_j)
                    for _err_key, _group in _err_groups.items():
                        _cnt = len(_group)
                        _cnt_str = f" (x{_cnt})" if _cnt > 1 else ""
                        print(f"\n  {C.RED}✗{_cnt_str}{C.RESET} {_err_key}")
                        for _gj in _group[:3]:  # Show max 3 jobs per error group
                            _gjcmd = (_gj.get("command_or_prompt") or "")[:60]
                            print(f"    {C.DIM}→ {_gj.get('job_id', '?')}: {_gjcmd}{C.RESET}")
                    print()
                    continue
                elif cmd == "/debug-scroll":
                    # TUI 機能強化：スクロール領域診断
                    print(f"\n{C.BOLD}━━━ スクロール領域診断 ━━━{C.RESET}")
                    print(f"  VIBE_DEBUG_TUI: {VIBE_DEBUG_TUI}")
                    print(f"  VIBE_NO_SCROLL: {VIBE_NO_SCROLL}")
                    if VIBE_DEBUG_TUI:
                        print(f"  デバッグログ：{VIBE_DEBUG_TUI_LOG}")
                    if agent.tui._scroll_region:
                        sr = agent.tui._scroll_region
                        print(f"  スクロール領域：{sr.top}-{sr.bottom} 行")
                        print(f"  状態：{'active' if sr._active else 'inactive'}")
                    else:
                        print(f"  スクロール領域：未初期化")
                    print(f"  使い方：VIBE_NO_SCROLL=1 eve-coder.py（無効化）")
                    print(f"          VIBE_DEBUG_TUI=1 eve-coder.py（デバッグ）")
                    print()
                    continue
                elif cmd == "/save":
                    session.save()
                    sessions_dir = os.path.join(config.state_dir, "sessions")
                    filepath = os.path.join(sessions_dir, f"{session.session_id}.jsonl")
                    print(f"{C.GREEN}{t('slash.session_saved', default=f'Session saved: {session.session_id}')}{C.RESET}")
                    print(f"{C.DIM}  {filepath}{C.RESET}")
                    continue
                elif cmd == "/fork":
                    fork_id = session.fork()
                    if fork_id:
                        # Option: rename the fork if a name was provided
                        parts = user_input.split(None, 1)
                        _fork_name = parts[1].strip() if len(parts) > 1 else ""
                        if _fork_name:
                            fork_id_named = re.sub(r'[^A-Za-z0-9_\-]', '', _fork_name)[:64]
                            # Rename the fork
                            src = os.path.join(config.sessions_dir, f"{fork_id}.jsonl")
                            dst = os.path.join(config.sessions_dir, f"{fork_id_named}.jsonl")
                            try:
                                os.rename(src, dst)
                                fork_id = fork_id_named
                            except OSError:
                                pass

                        old_id = session.session_id
                        session.session_id = fork_id
                        print(f"{C.GREEN}{t('slash.session_forked', default=f'Session forked: {old_id} → {fork_id}')}{C.RESET}")
                        print(f"{C.DIM}{t('slash.fork_preserved', default='Original session preserved. You are now on the fork.')}{C.RESET}")
                        print(f"{C.DIM}{t('slash.fork_switch_back', default=f'Switch back: /resume {old_id}')}{C.RESET}")
                    else:
                        print(f"{C.RED}{t('slash.fork_failed', default='Failed to fork session.')}{C.RESET}")
                    continue
                elif cmd == "/compact":
                    before = session.get_token_estimate()
                    session.compact_if_needed(force=True)
                    after = session.get_token_estimate()
                    if after < before:
                        print(f"{C.GREEN}{t('slash.compacted', default=f'Compacted: {before} -> {after} tokens')}{C.RESET}")
                    else:
                        print(f"{C.DIM}{t('slash.already_compact', default=f'Already compact ({after} tokens, {len(session.messages)} messages)')}{C.RESET}")
                    continue
                elif cmd == "/model" or cmd == "/models":
                    parts = user_input.split(maxsplit=1)
                    if len(parts) > 1 and cmd == "/model":
                        new_model = parts[1].strip()
                        # M5: Validate model name against safe regex
                        _SAFE_MODEL_RE = re.compile(r'^[a-zA-Z0-9_.:\-/]+$')
                        if not _SAFE_MODEL_RE.match(new_model):
                            print(f"{C.RED}Invalid model name: {new_model!r}{C.RESET}")
                            continue
                        # M4: Fetch fresh model list instead of using stale startup list
                        _ok, fresh_models = client.check_connection()
                        if client.check_model(new_model, available_models=fresh_models if _ok else None):
                            config.model = new_model
                            config._apply_context_window(new_model)
                            config._apply_max_tokens(new_model)
                            _tier, _ = Config.get_model_tier(new_model)
                            _tier_str = f" (Tier {_tier})" if _tier else ""
                            print(f"{C.GREEN}Switched to model: {new_model}{_tier_str}{C.RESET}")
                            print(f"{C.DIM}Context window: {config.context_window} tokens{C.RESET}")
                        else:
                            avail = fresh_models if _ok else []
                            print(f"{C.YELLOW}Model '{new_model}' is not downloaded yet.{C.RESET}")
                            if avail:
                                _show_model_list(avail)
                            print(f"{C.DIM}Download it:  ollama pull {new_model}{C.RESET}")
                    else:
                        _ok, fresh_models = client.check_connection()
                        avail = fresh_models if _ok else []
                        _tier, _ = Config.get_model_tier(config.model)
                        _tier_str = f" (Tier {_tier})" if _tier else ""
                        print(f"\n  {C.BOLD}Current model:{C.RESET} {_ansi(chr(27)+'[38;5;51m')}{config.model}{_tier_str}{C.RESET}")
                        print(f"  {C.DIM}Context window: {config.context_window} tokens{C.RESET}")
                        if config.sidecar_model:
                            print(f"  {C.DIM}Sidecar (compaction): {config.sidecar_model}{C.RESET}")
                        if avail:
                            print(f"\n  {C.BOLD}Installed models:{C.RESET}")
                            _show_model_list(avail)
                        print(f"\n  {C.DIM}Switch: /model <name>  |  Download: ollama pull <name>{C.RESET}")
                        _tier_legend = (f"  {C.DIM}Tiers: "
                                        f"{_ansi(chr(27)+'[38;5;196m')}S{C.RESET}{C.DIM}=Frontier "
                                        f"{_ansi(chr(27)+'[38;5;208m')}A{C.RESET}{C.DIM}=Expert "
                                        f"{_ansi(chr(27)+'[38;5;226m')}B{C.RESET}{C.DIM}=Advanced "
                                        f"{_ansi(chr(27)+'[38;5;46m')}C{C.RESET}{C.DIM}=Solid "
                                        f"{_ansi(chr(27)+'[38;5;51m')}D{C.RESET}{C.DIM}=Light "
                                        f"{C.WHITE}E{C.RESET}{C.DIM}=Minimal{C.RESET}")
                        print(_tier_legend)
                    continue
                elif cmd == "/yes":
                    config.yes_mode = True
                    permissions.yes_mode = True
                    print(f"{C.GREEN}{t('slash.yes_enabled', default='Auto-approve enabled for this session.')}{C.RESET}")
                    continue
                elif cmd == "/no":
                    config.yes_mode = False
                    permissions.yes_mode = False
                    print(f"{C.GREEN}{t('slash.no_disabled', default='Auto-approve disabled. Tool calls will require confirmation.')}{C.RESET}")
                    continue
                elif cmd == "/think":
                    config.think_mode = True
                    client.think_mode = True
                    print(f"{C.GREEN}Thinking mode enabled. The model will use extended reasoning (<think> blocks).{C.RESET}")
                    continue
                elif cmd == "/no-think":
                    config.think_mode = False
                    client.think_mode = False
                    print(f"{C.GREEN}Thinking mode disabled. The model will respond without extended reasoning.{C.RESET}")
                    continue
                elif cmd == "/tokens":
                    tokens = session.get_token_estimate()
                    msgs = len(session.messages)
                    pct = min(int((tokens / config.context_window) * 100), 100)
                    bar_len = 30
                    filled = int(bar_len * pct / 100)
                    _c51 = _ansi("\033[38;5;51m")
                    _c87 = _ansi("\033[38;5;87m")
                    _c240 = _ansi("\033[38;5;240m")
                    bar_color = _ansi("\033[38;5;46m") if pct < 50 else _ansi("\033[38;5;226m") if pct < 80 else _ansi("\033[38;5;196m")
                    bar = bar_color + "█" * filled + _c240 + "░" * (bar_len - filled) + C.RESET
                    print(f"\n  {_c51}━━ トークン使用量 ━━━━━━━━━━━━━━━━━━━━{C.RESET}")
                    print(f"  [{bar}] {pct}%")
                    print(f"  {_c87}~{tokens:,}{C.RESET} / {_c240}{config.context_window:,} tokens{C.RESET}")
                    print(f"  {_c87}{msgs}{C.RESET} {_c240}{t('slash.tokens_messages', default='messages in session')}{C.RESET}")
                    if pct >= 80:
                        print(f"  {_ansi(chr(27)+'[38;5;196m')}⚠ {t('slash.tokens_warning', default='Context almost full! Use /compact or /clear')}{C.RESET}")
                    print(f"  {_c51}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    continue
                elif cmd == "/usage":
                    _usage_engine = getattr(agent, "_evolution", None) or EvolutionEngine(config.config_dir)
                    print()
                    for _line in _build_usage_report_lines(config, _usage_engine, session=session):
                        print(f"  {_line}")
                    print()
                    continue
                # ── Git commands ──────────────────────────────────────
                elif cmd == "/commit":
                    try:
                        # 1. Check git status
                        st = subprocess.run(
                            ["git", "status", "--porcelain"],
                            capture_output=True, text=True, timeout=10
                        )
                        if st.returncode != 0:
                            print(f"{C.RED}Not a git repository or git error.{C.RESET}")
                            continue

                        # 2. Check staged files
                        staged = subprocess.run(
                            ["git", "diff", "--cached", "--stat"],
                            capture_output=True, text=True, timeout=10
                        )
                        has_staged = bool(staged.stdout.strip())

                        if not has_staged:
                            # Nothing staged — offer to stage everything
                            if not st.stdout.strip():
                                print(f"{C.GREEN}{t('slash.commit_clean', default='Nothing to commit, working tree clean.')}{C.RESET}")
                                continue
                            if config.yes_mode:
                                do_add = True
                            else:
                                print(f"{C.YELLOW}{t('slash.commit_stage_prompt', default='Nothing staged. Stage tracked file changes with git add -u?')}{C.RESET}")
                                print(f"{C.DIM}{st.stdout.strip()}{C.RESET}")
                                ans = input(f"{C.CYAN}[y/N]{C.RESET} ").strip().lower()
                                do_add = ans in ("y", "yes")
                            if do_add:
                                subprocess.run(["git", "add", "-u"], timeout=10)
                                print(f"{C.GREEN}{t('slash.commit_staged', default='Staged tracked file changes.')}{C.RESET}")
                                # M8: Check for untracked files and inform user
                                untracked = subprocess.run(
                                    ["git", "ls-files", "--others", "--exclude-standard"],
                                    capture_output=True, text=True, timeout=10
                                )
                                if untracked.stdout.strip():
                                    files = untracked.stdout.strip().split("\n")
                                    print(f"{C.YELLOW}{t('slash.commit_untracked', default='{len} untracked file(s) not staged:')}{C.RESET}")
                                    for f in files[:10]:
                                        print(f"  {C.DIM}{f}{C.RESET}")
                                    if len(files) > 10:
                                        print(f"  {C.DIM}... and {len(files)-10} more{C.RESET}")
                            else:
                                print(f"{C.YELLOW}{t('slash.commit_aborted', default='Aborted. Stage files manually and retry.')}{C.RESET}")
                                continue

                        # 3. Get diff for commit message generation
                        diff_result = subprocess.run(
                            ["git", "diff", "--cached"],
                            capture_output=True, text=True, timeout=10
                        )
                        diff_text = diff_result.stdout.strip()
                        if not diff_text:
                            print(f"{C.YELLOW}No diff to commit.{C.RESET}")
                            continue

                        # Truncate diff if too large (keep first 4000 chars)
                        if len(diff_text) > 4000:
                            diff_text = diff_text[:4000] + "\n... (truncated)"

                        # 4. Get recent commit messages for style reference
                        log_result = subprocess.run(
                            ["git", "log", "--oneline", "-5"],
                            capture_output=True, text=True, timeout=10
                        )
                        recent_commits = log_result.stdout.strip() if log_result.returncode == 0 else ""

                        # 5. Generate commit message via LLM
                        tui.start_spinner("Generating commit message")
                        gen_messages = [
                            {"role": "system", "content": (
                                "You are a commit message generator. Given a git diff and recent commit history, "
                                "write a concise conventional commit message that matches the project's style.\n"
                                "Format: <type>(<scope>): <description>\n"
                                "Types: feat, fix, refactor, docs, style, test, chore, perf\n"
                                "Rules:\n"
                                "- First line under 72 characters\n"
                                "- Match the language/style of recent commits (Japanese OK if project uses it)\n"
                                "- Add bullet points for multiple changes\n"
                                "- Output ONLY the commit message, nothing else"
                            )},
                            {"role": "user", "content": (
                                f"Recent commits:\n{recent_commits}\n\n"
                                f"Diff to commit:\n{diff_text}"
                            )},
                        ]
                        try:
                            resp = client.chat(
                                model=config.model,
                                messages=gen_messages,
                                tools=None,
                                stream=False,
                            )
                        finally:
                            tui.stop_spinner()

                        # Extract message from response
                        commit_msg = ""
                        if isinstance(resp, dict):
                            choices = resp.get("choices", [])
                            if choices:
                                commit_msg = choices[0].get("message", {}).get("content", "").strip()
                        # Strip thinking traces (Qwen <think> and Gemma 4 <|channel>thought)
                        commit_msg = _strip_thinking_tags(commit_msg)
                        if not commit_msg:
                            # Fallback: auto-generate from file names
                            fb_files = subprocess.run(
                                ["git", "diff", "--cached", "--name-only"],
                                capture_output=True, text=True, timeout=10
                            )
                            file_list = [f for f in fb_files.stdout.strip().split("\n") if f][:5]
                            if file_list:
                                commit_msg = f"chore: update {', '.join(file_list)}"
                            else:
                                print(f"{C.RED}{t('slash.commit_gen_failed', default='Failed to generate commit message.')}{C.RESET}")
                                continue

                        # 6. Show message and confirm
                        print(f"\n{C.CYAN}{t('slash.commit_proposed', default='Proposed commit message:')}{C.RESET}")
                        print(f"{C.BOLD}{commit_msg}{C.RESET}\n")

                        if not config.yes_mode:
                            ans = input(f"{C.CYAN}{t('slash.commit_confirm', default='Commit with this message? [Y/n/e(dit)]')}{C.RESET} ").strip().lower()
                            if ans == "e":
                                print(f"{C.DIM}Enter new message (end with empty line):{C.RESET}")
                                lines = []
                                while True:
                                    try:
                                        l = input()
                                        if l == "":
                                            break
                                        lines.append(l)
                                    except (EOFError, KeyboardInterrupt):
                                        break
                                if lines:
                                    commit_msg = "\n".join(lines)
                                else:
                                    print(f"{C.YELLOW}Empty message, aborted.{C.RESET}")
                                    continue
                            elif ans not in ("", "y", "yes"):
                                print(f"{C.YELLOW}Commit aborted.{C.RESET}")
                                continue

                        # 7. Commit
                        result = subprocess.run(
                            ["git", "commit", "-m", commit_msg],
                            capture_output=True, text=True, timeout=30
                        )
                        if result.returncode == 0:
                            print(f"{C.GREEN}{result.stdout.strip()}{C.RESET}")
                        else:
                            print(f"{C.RED}Commit failed:{C.RESET}")
                            print(result.stderr.strip())
                    except subprocess.TimeoutExpired:
                        tui.stop_spinner()
                        print(f"{C.RED}Git command timed out.{C.RESET}")
                    except FileNotFoundError:
                        tui.stop_spinner()
                        print(f"{C.RED}git not found. Is git installed?{C.RESET}")
                    except Exception as e:
                        tui.stop_spinner()
                        print(f"{C.RED}Error: {e}{C.RESET}")
                    continue

                elif cmd == "/diff":
                    try:
                        result = subprocess.run(
                            ["git", "diff", "--color=always"],
                            capture_output=True, text=True, timeout=10
                        )
                        if result.returncode != 0:
                            print(f"{C.RED}{t('errors.git_diff_failed', default='Not a git repository or git error.')}{C.RESET}")
                        elif result.stdout.strip():
                            print(result.stdout)
                        else:
                            # Try staged diff
                            staged = subprocess.run(
                                ["git", "diff", "--cached", "--color=always"],
                                capture_output=True, text=True, timeout=10
                            )
                            if staged.stdout.strip():
                                print(f"{C.CYAN}{t('slash.diff_staged', default='(staged changes)')}{C.RESET}")
                                print(staged.stdout)
                            else:
                                print(f"{C.GREEN}{t('slash.diff_no_changes', default='No changes.')}{C.RESET}")
                    except FileNotFoundError:
                        print(f"{C.RED}{t('slash.git_not_found', default='git not found. Is git installed?')}{C.RESET}")
                    except Exception as e:
                        print(f"{C.RED}{t('errors.git_command_failed', default=f'Error: {e}')}{C.RESET}")
                    continue

                elif cmd == "/git":
                    git_args = user_input.split(maxsplit=1)
                    if len(git_args) < 2:
                        print(f"{C.YELLOW}{t('slash.git_usage', default='Usage: /git <command> (e.g. /git log --oneline -10)')}{C.RESET}")
                        continue
                    try:
                        # Split the git arguments properly
                        import shlex
                        args = shlex.split(git_args[1])
                        # Safety: reject dangerous git config-based command execution
                        # Use startswith to catch --upload-pack=evil, --config=x, etc.
                        _git_dangerous_exact = {"-c"}
                        _git_dangerous_prefixes = ("--exec-path", "--upload-pack", "--receive-pack",
                                                   "--config", "--config-env", "-c=",
                                                   "--git-dir", "--work-tree")
                        if any(a.lower() in _git_dangerous_exact or
                               a.lower().startswith(_git_dangerous_prefixes)
                               for a in args):
                            print(f"{C.RED}Blocked: /git does not allow -c, --config, or exec options for safety.{C.RESET}")
                            print(f"{C.DIM}Use BashTool via the agent for advanced git operations.{C.RESET}")
                            continue
                        result = subprocess.run(
                            ["git"] + args,
                            capture_output=True, text=True, timeout=30
                        )
                        if result.stdout:
                            print(result.stdout, end="")
                        if result.stderr:
                            print(f"{C.YELLOW}{result.stderr}{C.RESET}", end="")
                        if result.returncode != 0 and not result.stderr:
                            print(f"{C.RED}git exited with code {result.returncode}{C.RESET}")
                    except FileNotFoundError:
                        print(f"{C.RED}git not found. Is git installed?{C.RESET}")
                    except Exception as e:
                        print(f"{C.RED}{t('errors.git_command_failed', default=f'Error: {e}')}{C.RESET}")
                    continue

                # ── GitHub commands ───────────────────────────────────
                elif cmd == "/pr":
                    parts = user_input.split(maxsplit=1)
                    sub = parts[1].strip().lower() if len(parts) > 1 else "list"

                    if sub == "list":
                        ok, out, err = _run_gh_command(["pr", "list"], cwd=config.cwd)
                        print(out if ok else f"{C.RED}{err}{C.RESET}")

                    elif sub == "create":
                        try:
                            # Get branch info
                            branch_result = subprocess.run(
                                ["git", "rev-parse", "--abbrev-ref", "HEAD"],
                                capture_output=True, text=True, cwd=config.cwd, timeout=10)
                            branch = branch_result.stdout.strip() if branch_result.returncode == 0 else "unknown"

                            # Get commit log
                            log_result = subprocess.run(
                                ["git", "log", "--oneline", "origin/main..HEAD"],
                                capture_output=True, text=True, cwd=config.cwd, timeout=10)
                            log_output = log_result.stdout.strip() if log_result.returncode == 0 else ""

                            # Get diff stat
                            diff_result = subprocess.run(
                                ["git", "diff", "--stat", "origin/main..HEAD"],
                                capture_output=True, text=True, cwd=config.cwd, timeout=10)
                            diff_stat = diff_result.stdout.strip() if diff_result.returncode == 0 else ""

                            if not log_output:
                                print(f"{C.YELLOW}No commits ahead of origin/main.{C.RESET}")
                                continue

                            # Use agent to generate PR title and body
                            pr_prompt = (
                                f"Based on these commits, generate a PR title and description.\n\n"
                                f"Branch: {branch}\n"
                                f"Commits:\n{log_output}\n\n"
                                f"Diff stat:\n{diff_stat}\n\n"
                                f"Format your response EXACTLY as:\n"
                                f"TITLE: <one line title>\n"
                                f"BODY:\n<markdown body with ## Summary and ## Changes sections>"
                            )
                            session.add_user_message(pr_prompt)
                            agent.run(pr_prompt)

                            # After agent responds, ask user to confirm and create
                            confirm = input(f"\n{C.CYAN}Create this PR? [Y/n]: {C.RESET}").strip().lower()
                            if confirm in ("", "y", "yes"):
                                # Extract title and body from last assistant message
                                last_msg = ""
                                for m in reversed(session.messages):
                                    if m.get("role") == "assistant" and m.get("content"):
                                        last_msg = m["content"]
                                        break
                                title = branch  # fallback
                                body = last_msg
                                # Try to extract TITLE: line
                                for line in last_msg.split("\n"):
                                    if line.strip().startswith("TITLE:"):
                                        title = line.split("TITLE:", 1)[1].strip()
                                        break
                                # Extract BODY: section
                                if "BODY:" in last_msg:
                                    body = last_msg.split("BODY:", 1)[1].strip()

                                # Push first
                                print(f"{C.DIM}Pushing to origin/{branch}...{C.RESET}")
                                push_result = subprocess.run(
                                    ["git", "push", "-u", "origin", branch],
                                    capture_output=True, text=True, cwd=config.cwd, timeout=60)
                                if push_result.returncode != 0:
                                    print(f"{C.YELLOW}Push warning: {push_result.stderr}{C.RESET}")

                                ok, out, err = _run_gh_command(
                                    ["pr", "create", "--title", title, "--body", body],
                                    cwd=config.cwd, timeout=30)
                                if ok:
                                    print(f"{C.GREEN}PR created: {out}{C.RESET}")
                                else:
                                    print(f"{C.RED}Failed to create PR: {err}{C.RESET}")
                            else:
                                print(f"{C.DIM}PR creation cancelled.{C.RESET}")
                        except (EOFError, KeyboardInterrupt):
                            print(f"\n{C.DIM}Cancelled.{C.RESET}")
                        except Exception as e:
                            print(f"{C.RED}Error: {e}{C.RESET}")

                    elif sub.startswith("view"):
                        pr_num = sub.split(None, 1)[1] if len(sub.split()) > 1 else ""
                        args = ["pr", "view"]
                        if pr_num:
                            args.append(pr_num)
                        ok, out, err = _run_gh_command(args, cwd=config.cwd)
                        print(out if ok else f"{C.RED}{err}{C.RESET}")

                    elif sub.startswith("checks"):
                        pr_num = sub.split(None, 1)[1] if len(sub.split()) > 1 else ""
                        args = ["pr", "checks"]
                        if pr_num:
                            args.append(pr_num)
                        ok, out, err = _run_gh_command(args, cwd=config.cwd)
                        print(out if ok else f"{C.RED}{err}{C.RESET}")

                    elif sub.startswith("diff"):
                        pr_num = sub.split(None, 1)[1] if len(sub.split()) > 1 else ""
                        args = ["pr", "diff"]
                        if pr_num:
                            args.append(pr_num)
                        ok, out, err = _run_gh_command(args, cwd=config.cwd)
                        print(out if ok else f"{C.RED}{err}{C.RESET}")

                    elif sub.startswith("merge"):
                        pr_num = sub.split(None, 1)[1] if len(sub.split()) > 1 else ""
                        args = ["pr", "merge"]
                        if pr_num:
                            args.append(pr_num)
                        try:
                            confirm = input(f"{C.CYAN}Merge this PR? [y/N]: {C.RESET}").strip().lower()
                            if confirm in ("y", "yes"):
                                ok, out, err = _run_gh_command(args, cwd=config.cwd, timeout=30)
                                if ok:
                                    print(f"{C.GREEN}{out}{C.RESET}")
                                else:
                                    print(f"{C.RED}{err}{C.RESET}")
                            else:
                                print(f"{C.DIM}Merge cancelled.{C.RESET}")
                        except (EOFError, KeyboardInterrupt):
                            print(f"\n{C.DIM}Cancelled.{C.RESET}")

                    else:
                        print(f"{C.YELLOW}{t('slash.pr_usage', default='Usage: /pr [list|create|view|checks|diff|merge] [number]')}{C.RESET}")
                    continue

                elif cmd == "/review":
                    # Code review command: /review [target]
                    # target: (empty)=uncommitted, --staged, HEAD~N, PR number
                    parts = user_input.split(maxsplit=1)
                    review_target = parts[1].strip() if len(parts) > 1 else None
                    _run_code_review(config, agent, session, tui, review_target)
                    continue

                elif cmd == "/issue":
                    # Issue → PR automation: /issue <number>
                    parts = user_input.split(maxsplit=1)
                    issue_arg = parts[1].strip() if len(parts) > 1 else ""
                    if not issue_arg or not issue_arg.split()[0].isdigit():
                        print(f"  {C.CYAN}/issue <number>{C.RESET} — Fetch GitHub issue, implement, self-review, and create PR")
                        print(f"  {C.DIM}Example: /issue 42{C.RESET}")
                        continue
                    issue_num = int(issue_arg.split()[0])
                    _issue_to_pr(config, agent, session, tui, issue_num)
                    continue

                elif cmd == "/evolve":
                    # Evolution engine stats and insights
                    _evo = EvolutionEngine(config.config_dir)
                    _evo_parts = user_input.split(None, 1)
                    _evo_sub = _evo_parts[1].strip() if len(_evo_parts) > 1 else ""
                    if _evo_sub == "reset":
                        _evo.reset()
                        print(f"  {C.GREEN}Evolution data cleared.{C.RESET}")
                    elif _evo_sub == "insights":
                        _insights = _evo._data.get("insights", [])
                        if not _insights:
                            print(f"  {C.DIM}No insights yet. Insights are generated every {_evo.INSIGHT_INTERVAL} sessions.{C.RESET}")
                        else:
                            print(f"\n  {C.CYAN}Learned Insights:{C.RESET}")
                            for _ins in sorted(_insights, key=lambda x: x.get("confidence", 0), reverse=True):
                                _conf = _ins.get("confidence", 0)
                                _bar = "█" * int(_conf * 10) + "░" * (10 - int(_conf * 10))
                                print(f"  {_bar} {_conf:.0%}  {_ins.get('text', '')}  {C.DIM}({_ins.get('created', '')}){C.RESET}")
                        print()
                    else:
                        _d = _evo._data
                        print(f"\n  {C.CYAN}Evolution Stats:{C.RESET}")
                        print(f"  Sessions: {_d.get('total_sessions', 0)}  |  Tool calls: {_d.get('total_tool_calls', 0)}")
                        _ts = _d.get("tool_stats", {})
                        if _ts:
                            print(f"\n  {'Tool':<18} {'OK':>6} {'Fail':>6} {'Avg':>8}")
                            print(f"  {'─'*18} {'─'*6} {'─'*6} {'─'*8}")
                            for _tn, _s in sorted(_ts.items(), key=lambda x: x[1].get("success", 0), reverse=True)[:8]:
                                print(f"  {_tn:<18} {_s.get('success',0):>6} {_s.get('fail',0):>6} {_s.get('avg_time',0):>7.1f}s")
                        _wp = _d.get("workflow_patterns", [])[:5]
                        if _wp:
                            print(f"\n  {C.CYAN}Common Patterns:{C.RESET}")
                            for _p in _wp:
                                print(f"  {' → '.join(_p.get('sequence',[]))} (x{_p.get('count',0)})")
                        _ins = _d.get("insights", [])
                        if _ins:
                            print(f"\n  {C.CYAN}Active Insights:{C.RESET} {len(_ins)} (use /evolve insights for details)")
                        print()
                    continue

                elif cmd == "/mcp":
                    # MCP server management: /mcp [list|add|remove|reload]
                    parts = user_input.split()
                    sub = parts[1] if len(parts) > 1 else "list"
                    if sub == "list":
                        srv_configs = _load_mcp_servers(config)
                        if not srv_configs:
                            print(f"  {C.DIM}No MCP servers configured.{C.RESET}")
                            print(f"  {C.DIM}Add one: /mcp add <name> <command> [args...]{C.RESET}")
                        else:
                            print(f"\n  {'Name':<20} {'Command':<25} {'Status'}")
                            print(f"  {'─'*20} {'─'*25} {'─'*10}")
                            for name, srv in srv_configs.items():
                                cmd_str = srv.get("command", "?")
                                args_str = " ".join(srv.get("args", []))[:30]
                                alive = any(c.name == name and c._proc and c._proc.poll() is None for c in _mcp_clients)
                                status = f"{C.GREEN}running{C.RESET}" if alive else f"{C.DIM}stopped{C.RESET}"
                                print(f"  {name:<20} {cmd_str} {args_str:<20} {status}")
                        print()
                    elif sub == "add" and len(parts) >= 4:
                        _is_project = "--project" in parts
                        _add_parts = [p for p in parts[2:] if p != "--project"]
                        _srv_name = _add_parts[0]
                        _srv_cmd = _add_parts[1]
                        _srv_args = _add_parts[2:] if len(_add_parts) > 2 else []
                        if _is_project:
                            _mcp_path = os.path.join(config.cwd, ".eve-cli", "mcp.json")
                        else:
                            _mcp_path = os.path.join(config.config_dir, "mcp.json")
                        try:
                            _existing = {}
                            if os.path.isfile(_mcp_path):
                                with open(_mcp_path, encoding="utf-8") as f:
                                    _existing = json.load(f)
                            _servers = _existing.setdefault("mcpServers", {})
                            _servers[_srv_name] = {"command": _srv_cmd, "args": _srv_args}
                            _save_mcp_config(_mcp_path, _existing)
                            scope = "project" if _is_project else "global"
                            print(f"  {C.GREEN}Added MCP server '{_srv_name}' ({scope}). Use /mcp reload to activate.{C.RESET}")
                        except Exception as e:
                            print(f"  {C.RED}Error saving MCP config: {e}{C.RESET}")
                    elif sub == "remove" and len(parts) >= 3:
                        _srv_name = parts[2]
                        _removed = False
                        for _mcp_path in [os.path.join(config.config_dir, "mcp.json"),
                                          os.path.join(config.cwd, ".eve-cli", "mcp.json")]:
                            if not os.path.isfile(_mcp_path):
                                continue
                            try:
                                with open(_mcp_path, encoding="utf-8") as f:
                                    _existing = json.load(f)
                                if _srv_name in _existing.get("mcpServers", {}):
                                    del _existing["mcpServers"][_srv_name]
                                    _save_mcp_config(_mcp_path, _existing)
                                    _removed = True
                                    break
                            except Exception:
                                pass
                        # Stop running client
                        for c in _mcp_clients:
                            if c.name == _srv_name and c._proc:
                                try:
                                    c._proc.terminate()
                                except Exception:
                                    pass
                        if _removed:
                            print(f"  {C.GREEN}Removed MCP server '{_srv_name}'. Use /mcp reload to apply.{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}MCP server '{_srv_name}' not found in config.{C.RESET}")
                    elif sub == "reload":
                        # Stop all existing clients
                        for c in _mcp_clients:
                            if c._proc:
                                try:
                                    c._proc.terminate()
                                except Exception:
                                    pass
                        _mcp_clients.clear()
                        # Re-initialize
                        _mcp_clients.extend(_init_mcp_clients(config, registry, permissions))
                        print(f"  {C.GREEN}MCP servers reloaded: {len(_mcp_clients)} active.{C.RESET}")
                    else:
                        print(f"  {C.CYAN}/mcp{C.RESET}                List configured MCP servers")
                        print(f"  {C.CYAN}/mcp add{C.RESET} <name> <cmd> [args...]  Add MCP server")
                        print(f"  {C.CYAN}/mcp add --project{C.RESET} <name> <cmd>  Add to project config")
                        print(f"  {C.CYAN}/mcp remove{C.RESET} <name>  Remove MCP server")
                        print(f"  {C.CYAN}/mcp reload{C.RESET}        Restart all MCP servers")
                    continue

                elif cmd == "/gh":
                    parts = user_input.split(None, 1)
                    gh_args = parts[1] if len(parts) > 1 else ""
                    if not gh_args:
                        print(f"  {C.CYAN}/gh <command>{C.RESET} — Run any gh CLI command")
                        print(f"  {C.DIM}Examples: /gh issue list, /gh repo view, /gh run list{C.RESET}")
                        continue
                    # Security: block dangerous commands
                    _blocked = {"auth", "ssh-key", "gpg-key", "secret"}
                    import shlex as _shlex_gh
                    try:
                        _gh_parsed = _shlex_gh.split(gh_args)
                    except ValueError:
                        _gh_parsed = gh_args.split()
                    first_arg = _gh_parsed[0] if _gh_parsed else ""
                    if first_arg in _blocked:
                        print(f"{C.RED}Blocked: /gh {first_arg} is not allowed for security.{C.RESET}")
                        continue
                    ok, out, err = _run_gh_command(_gh_parsed, cwd=config.cwd, timeout=30)
                    if ok:
                        print(out)
                    else:
                        print(f"{C.RED}{err}{C.RESET}")
                        if "not logged in" in err.lower() or "auth" in err.lower():
                            print(f"{C.DIM}Run: gh auth login{C.RESET}")
                    continue

                # ── Plan mode commands ────────────────────────────────
                elif cmd == "/plan":
                    parts = user_input.split(maxsplit=1)
                    subcmd = parts[1].strip().lower() if len(parts) > 1 else ""
                    if subcmd == "list":
                        # List recent plan files
                        plans_dir = os.path.join(config.cwd, ".eve-cli", "plans")
                        if not os.path.isdir(plans_dir):
                            print(f"{C.DIM}  No plans yet.{C.RESET}")
                        else:
                            md_files = sorted(
                                [f for f in os.listdir(plans_dir) if f.endswith(".md")],
                                key=lambda f: os.path.getmtime(os.path.join(plans_dir, f))
                                    if os.path.isfile(os.path.join(plans_dir, f)) else 0,
                                reverse=True,
                            )[:10]
                            if not md_files:
                                print(f"{C.DIM}  {t('slash.plan_none', default='No plans yet.')}{C.RESET}")
                            else:
                                _c226 = _ansi(chr(27) + '[38;5;226m')
                                _c240 = _ansi(chr(27) + '[38;5;240m')
                                print(f"\n  {_c226}━━ {t('slash.plan_list_title', default='Plans (newest first)')} ━━{C.RESET}")
                                for pf in md_files:
                                    fp = os.path.join(plans_dir, pf)
                                    try:
                                        sz = os.path.getsize(fp)
                                    except OSError:
                                        sz = 0
                                    sz_str = f"{sz:,}B" if sz < 1024 else f"{sz/1024:.1f}KB"
                                    try:
                                        active = " ◀" if (agent._active_plan_path
                                                           and os.path.exists(fp)
                                                           and os.path.exists(agent._active_plan_path)
                                                           and os.path.samefile(fp, agent._active_plan_path)) else ""
                                    except (OSError, ValueError):
                                        active = ""
                                    print(f"  {_c240}{pf}  ({sz_str}){active}{C.RESET}")
                                print()
                    else:
                        _enter_plan_mode(agent, session)
                    continue

                elif cmd in ("/execute", "/plan-execute", "/approve", "/act"):
                    if not agent._plan_mode:
                        print(f"{C.YELLOW}Not in plan mode. Use /plan first.{C.RESET}")
                    else:
                        _exit_plan_mode(agent, session)
                    continue

                # ── Learn mode commands ────────────────────────────────
                elif cmd == "/learn":
                    parts = user_input.split()
                    if len(parts) == 1:
                        # Toggle learn mode
                        config.learn_mode = not config.learn_mode
                        status = "ON" if config.learn_mode else "OFF"
                        print(f"{C.CYAN}Learn mode: {status}{C.RESET}")
                        if config.learn_mode:
                            print(f"{C.DIM}  Level: {config.learn_level} (use /learn level <1-5> to change){C.RESET}")
                    elif len(parts) >= 2:
                        subcmd = parts[1].lower()
                        if subcmd == "on":
                            config.learn_mode = True
                            print(f"{C.GREEN}Learn mode: ON{C.RESET}")
                        elif subcmd == "off":
                            config.learn_mode = False
                            print(f"{C.GREEN}Learn mode: OFF{C.RESET}")
                        elif subcmd == "level" and len(parts) >= 3:
                            try:
                                level = int(parts[2])
                                if 1 <= level <= 5:
                                    config.learn_level = level
                                    print(f"{C.GREEN}Learn level set to: {level}{C.RESET}")
                                else:
                                    print(f"{C.YELLOW}Level must be 1-5.{C.RESET}")
                            except ValueError:
                                print(f"{C.YELLOW}Invalid level. Use /learn level <1-5>{C.RESET}")
                        elif subcmd == "auto":
                            if len(parts) >= 3:
                                val = parts[2].lower()
                                if val in ("on", "true", "1"):
                                    config.learn_auto_explain = True
                                    print(f"{C.GREEN}Auto-explain: ON{C.RESET}")
                                elif val in ("off", "false", "0"):
                                    config.learn_auto_explain = False
                                    print(f"{C.GREEN}Auto-explain: OFF{C.RESET}")
                                else:
                                    print(f"{C.YELLOW}Use /learn auto on|off{C.RESET}")
                            else:
                                status = "ON" if config.learn_auto_explain else "OFF"
                                print(f"{C.DIM}Auto-explain: {status}{C.RESET}")
                        else:
                            print(f"{C.DIM}{t('slash.learn_usage', default='Usage: /learn [on|off|level <1-5>|auto on|off]')}{C.RESET}")
                    continue
                # ── UI Theme ────────────────────────────────────────
                elif cmd == "/theme":
                    parts = user_input.split()
                    if len(parts) == 1:
                        # Show current theme and available themes
                        print(f"{C.BOLD}━━━ UI テーマ ━━━{C.RESET}")
                        print(f"  現在のテーマ：{config.ui_theme}")
                        print(f"  利用可能なテーマ:")
                        themes_info = {
                            "normal": ("standard", "▶"),
                            "gal": ("vivid", "✨"),
                            "dandy": ("elegant", "🎩"),
                            "bushi": ("warrior", "⚔️")
                        }
                        for name, (style, icon) in themes_info.items():
                            marker = "✓" if name == config.ui_theme else " "
                            print(f"  {marker} {name:8} - {style} ({icon})")
                        print(f"  使い方：/theme <theme_name>")
                        print(f"  例：/theme gal")
                    else:
                        theme_name = parts[1].lower()
                        if theme_name in ("normal", "gal", "dandy", "bushi"):
                            config.ui_theme = theme_name
                            C.apply_theme(theme_name)
                            print(f"{C.GREEN}テーマを '{theme_name}' に変更しました。{C.RESET}")
                            # Save to project config file (.eve-cli/config)
                            try:
                                project_config_path = os.path.join(os.getcwd(), ".eve-cli", "config")
                                if os.path.exists(project_config_path):
                                    with open(project_config_path, "r", encoding="utf-8") as f:
                                        lines = f.readlines()
                                    updated = False
                                    for i, line in enumerate(lines):
                                        if line.startswith("UI_THEME="):
                                            lines[i] = "UI_THEME=" + theme_name + "\n"
                                            updated = True
                                            break
                                    if not updated:
                                        lines.append("UI_THEME=" + theme_name + "\n")
                                    with open(project_config_path, "w", encoding="utf-8") as f:
                                        f.writelines(lines)
                                else:
                                    # Create project config file if it doesn't exist
                                    os.makedirs(os.path.dirname(project_config_path), exist_ok=True)
                                    with open(project_config_path, "w", encoding="utf-8") as f:
                                        f.write("UI_THEME=" + theme_name + "\n")
                            except (OSError, IOError):
                                pass  # Project config file write failed — skip silently
                            # Also save to global config file (~/.config/eve-cli/config)
                            try:
                                config_path = os.path.join(config.config_dir, "config")
                                if os.path.exists(config_path):
                                    with open(config_path, "r", encoding="utf-8") as f:
                                        lines = f.readlines()
                                    updated = False
                                    for i, line in enumerate(lines):
                                        if line.startswith("UI_THEME="):
                                            lines[i] = "UI_THEME=" + theme_name + "\n"
                                            updated = True
                                            break
                                    if not updated:
                                        lines.append("UI_THEME=" + theme_name + "\n")
                                    with open(config_path, "w", encoding="utf-8") as f:
                                        f.writelines(lines)
                                else:
                                    # Create config file if it doesn't exist
                                    os.makedirs(os.path.dirname(config_path), exist_ok=True)
                                    with open(config_path, "w", encoding="utf-8") as f:
                                        f.write("UI_THEME=" + theme_name + "\n")
                            except (OSError, IOError):
                                pass  # Config file write failed — skip silently
                        else:
                            print(f"{C.YELLOW}未知のテーマ：{theme_name}{C.RESET}")
                            print(f"  利用可能なテーマ：normal, gal, dandy, bushi")
                    continue

                # ── Git checkpoint & rollback ────────────────────────
                elif cmd == "/checkpoint":
                    parts = user_input.split(maxsplit=1)
                    subcmd = parts[1].strip().lower() if len(parts) > 1 else ""
                    if subcmd == "list":
                        checkpoints = agent.git_checkpoint.list_checkpoints()
                        if not checkpoints:
                            print(f"{C.DIM}{t('slash.checkpoint_none', default='No checkpoints available.')}{C.RESET}")
                        else:
                            _c226 = _ansi(chr(27) + '[38;5;226m')
                            _c240 = _ansi(chr(27) + '[38;5;240m')
                            print(f"\n  {_c226}━━ {t('slash.checkpoint_list_title', default='Checkpoints')} ━━━━━━━━━━━━━━━━━━━{C.RESET}")
                            for cp in checkpoints:
                                ts = datetime.fromtimestamp(cp["timestamp"]).strftime("%H:%M:%S")
                                print(f"  {cp['label']}  {_c240}({ts}) {cp['summary']}{C.RESET}")
                            print(f"  {_c226}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    elif not agent.git_checkpoint._is_git_repo:
                        print(f"{C.YELLOW}{t('slash.checkpoint_not_git', default='Not a git repository. Initialize with: git init')}{C.RESET}")
                    else:
                        if agent.git_checkpoint.create("manual"):
                            print(f"{C.GREEN}{t('slash.checkpoint_saved', default='Checkpoint saved. Use /rollback to restore.')}{C.RESET}")
                        else:
                            print(f"{C.YELLOW}{t('slash.checkpoint_no_changes', default='No changes to checkpoint.')}{C.RESET}")
                    continue

                elif cmd == "/rollback":
                    ok, msg = agent.git_checkpoint.rollback()
                    if ok:
                        print(f"{C.GREEN}{msg}{C.RESET}")
                    else:
                        print(f"{C.YELLOW}{msg}{C.RESET}")
                    continue

                # ── Generate tests ───────────────────────────────────
                elif cmd == "/gentest":
                    if not args:
                        print(f"{C.YELLOW}{t('slash.gentest_usage', default='Usage: /gentest <file.py>')}{C.RESET}")
                        continue
                    target_file = args.strip()
                    if not os.path.isabs(target_file):
                        target_file = os.path.join(config.cwd, target_file)
                    if not os.path.isfile(target_file):
                        print(f"{C.RED}File not found: {target_file}{C.RESET}")
                        continue
                    try:
                        with open(target_file, "r", encoding="utf-8", errors="replace") as f:
                            source_code = f.read(10000)
                    except OSError as e:
                        print(f"{C.RED}Cannot read file: {e}{C.RESET}")
                        continue
                    test_style = ""
                    tests_dir = os.path.join(config.cwd, "tests")
                    if os.path.isdir(tests_dir):
                        for fname in os.listdir(tests_dir):
                            if fname.startswith("test_") and fname.endswith(".py"):
                                try:
                                    with open(os.path.join(tests_dir, fname), "r", encoding="utf-8", errors="replace") as f:
                                        test_style = f.read(3000)
                                    break
                                except OSError:
                                    pass
                    basename = os.path.basename(target_file)
                    test_filename = f"test_{basename}"
                    test_path = os.path.join(config.cwd, "tests", test_filename)
                    style_ref = ""
                    if test_style:
                        style_ref = f"\n\nExisting test style reference:\n```python\n{test_style}\n```\nMatch this style."
                    gen_messages = [
                        {"role": "system", "content": (
                            "You are a test generator. Given a Python source file, generate comprehensive "
                            "unit tests using unittest. Include edge cases and error cases. "
                            "Output ONLY the Python test code, nothing else. No markdown fences."
                            f"{style_ref}"
                        )},
                        {"role": "user", "content": f"Generate tests for this file ({basename}):\n\n```python\n{source_code}\n```"},
                    ]
                    tui.start_spinner("Generating tests")
                    try:
                        resp = client.chat(
                            model=config.model,
                            messages=gen_messages,
                            tools=None,
                            stream=False,
                        )
                    finally:
                        tui.stop_spinner()
                    test_code = ""
                    if isinstance(resp, dict):
                        choices = resp.get("choices", [])
                        if choices:
                            test_code = choices[0].get("message", {}).get("content", "").strip()
                    test_code = re.sub(r'<think>.*?</think>\s*', '', test_code, flags=re.DOTALL)
                    test_code = re.sub(r'^```python\s*\n?', '', test_code)
                    test_code = re.sub(r'\n?```\s*$', '', test_code)
                    if not test_code:
                        print(f"{C.RED}Failed to generate tests.{C.RESET}")
                        continue
                    os.makedirs(os.path.join(config.cwd, "tests"), exist_ok=True)
                    init_file = os.path.join(config.cwd, "tests", "__init__.py")
                    if not os.path.exists(init_file):
                        open(init_file, "w").close()
                    if os.path.exists(test_path):
                        print(f"{C.YELLOW}Test file already exists: {test_path}{C.RESET}")
                        print(f"{C.DIM}Preview:{C.RESET}")
                        for ln in test_code.split("\n")[:20]:
                            print(f"  {C.DIM}{ln}{C.RESET}")
                        if test_code.count("\n") > 20:
                            print(f"  {C.DIM}... ({test_code.count(chr(10))+1} lines total){C.RESET}")
                        if not config.yes_mode:
                            ans = input(f"{C.CYAN}Overwrite? [y/N] {C.RESET}").strip().lower()
                            if ans not in ("y", "yes"):
                                continue
                    with open(test_path, "w", encoding="utf-8") as f:
                        f.write(test_code)
                    print(f"{C.GREEN}Generated: {test_path}{C.RESET}")
                    print(f"{C.DIM}({test_code.count(chr(10))+1} lines, run with: python3 -m unittest tests.{test_filename[:-3]}){C.RESET}")
                    try:
                        result = subprocess.run(
                            ["python3", "-m", "py_compile", test_path],
                            capture_output=True, text=True, timeout=10
                        )
                        if result.returncode != 0:
                            print(f"{C.YELLOW}{t('warnings.test_syntax_error', default='Warning: Generated test has syntax errors:')}{C.RESET}")
                            print(f"{C.DIM}{result.stderr}{C.RESET}")
                    except (subprocess.TimeoutExpired, OSError):
                        pass
                    continue

                # ── Auto test toggle ─────────────────────────────────
                elif cmd == "/autotest":
                    agent.auto_test.enabled = not agent.auto_test.enabled
                    if session.runtime_state:
                        session.runtime_state.update_runtime(
                            autotest_enabled=agent.auto_test.enabled,
                            updated_at=time.time(),
                        )
                    state = f"{C.GREEN}ON{C.RESET}" if agent.auto_test.enabled else f"{C.RED}OFF{C.RESET}"
                    print(f"  Auto-test: {state}")
                    if agent.auto_test.enabled:
                        desc = agent.auto_test.describe()
                        print(f"  {C.DIM}Syntax command: {desc['lint']}{C.RESET}")
                        if agent.auto_test.test_cmd:
                            print(f"  {C.DIM}Test command: {desc['test']}{C.RESET}")
                        else:
                            print(f"  {C.DIM}No test command detected. Only syntax checks will run.{C.RESET}")
                    continue

                elif cmd == "/map":
                    _ci = agent.code_intel if hasattr(agent, 'code_intel') else None
                    if not _ci:
                        _ci = CodeIntelligence(config.cwd)
                    _n = _ci.build_index()
                    _map_text = _ci.repo_map()
                    _map_lines = _map_text.count("\n")
                    print(f"\n{_map_text}")
                    print(f"{C.DIM}{_n} symbols indexed, {_map_lines} lines{C.RESET}")
                    # Inject into session so LLM has context
                    session.add_system_note(f"[Repo Map]\n{_map_text}")
                    print(f"{C.GREEN}Repo map injected into context.{C.RESET}")
                    continue

                # ── File watcher toggle ───────────────────────────────
                elif cmd == "/watch":
                    if agent.file_watcher.enabled:
                        agent.file_watcher.stop()
                        if session.runtime_state:
                            session.runtime_state.update_runtime(
                                watcher_enabled=False,
                                updated_at=time.time(),
                            )
                        print(f"  File watcher: {C.RED}OFF{C.RESET}")
                    else:
                        agent.file_watcher.start()
                        if session.runtime_state:
                            session.runtime_state.update_runtime(
                                watcher_enabled=True,
                                updated_at=time.time(),
                            )
                        n = len(agent.file_watcher._snapshots)
                        print(f"  File watcher: {C.GREEN}ON{C.RESET}")
                        print(f"  {C.DIM}Tracking {n} files. External changes will be reported to the AI.{C.RESET}")
                    continue

                # ── Skills list ───────────────────────────────────────
                elif cmd == "/skills":
                    loaded_skills = _load_skills(config)
                    if loaded_skills:
                        _c51s = _ansi("\033[38;5;51m")
                        _c87s = _ansi("\033[38;5;87m")
                        print(f"\n  {_c51s}━━ Loaded Skills ━━━━━━━━━━━━━━━━━━{C.RESET}")
                        for sname in sorted(loaded_skills.keys()):
                            _sc = loaded_skills[sname]["content"]
                            lines = len(_sc.split('\n'))
                            _has_args = "$ARGUMENTS" in _sc or "$0" in _sc
                            _args_tag = f" {C.DIM}(accepts args){C.RESET}" if _has_args else ""
                            print(f"  {_c87s}{sname}{C.RESET}  ({lines} lines){_args_tag}")
                        print(f"  {_c51s}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    else:
                        print(f"{C.YELLOW}No skills loaded.{C.RESET}")
                        print(f"{C.DIM}Place .md files in ~/.config/eve-cli/skills/ or .eve-cli/skills/{C.RESET}")
                    continue

                elif cmd == "/hooks":
                    _c51h = _ansi("\033[38;5;51m")
                    _c87h = _ansi("\033[38;5;87m")
                    print(f"\n  {_c51h}━━ Hooks ━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}")
                    if hook_mgr.has_hooks:
                        print(hook_mgr.list_hooks())
                    else:
                        print(f"  {C.DIM}No hooks loaded.{C.RESET}")
                        print(f"  {C.DIM}Place hooks.json in ~/.config/eve-cli/ or .eve-cli/{C.RESET}")
                    print(f"  {_c51h}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    continue

                elif cmd == "/undo":
                    if not _undo_stack:
                        print(f"{C.YELLOW}Nothing to undo.{C.RESET}")
                    else:
                        path, old_content = _undo_stack.pop()
                        try:
                            dir_name = os.path.dirname(path)
                            fd, tmp_path = tempfile.mkstemp(dir=dir_name, suffix=".tmp")
                            try:
                                with os.fdopen(fd, "w", encoding="utf-8") as uf:
                                    uf.write(old_content)
                                os.replace(tmp_path, path)
                            except Exception:
                                try:
                                    os.unlink(tmp_path)
                                except OSError:
                                    pass
                                raise
                            print(f"{C.GREEN}Reverted: {path}{C.RESET}")
                        except Exception as e:
                            print(f"{C.RED}Undo failed: {e}{C.RESET}")
                    continue

                elif cmd == "/image":
                    parts = user_input.split(None, 1)
                    if len(parts) > 1:
                        # /image <path> — attach specific file
                        img_path = parts[1].strip().strip("'\"")
                        if img_path.startswith("file://"):
                            img_path = urllib.parse.unquote(img_path[7:])
                        result, err = _read_image_as_base64(img_path)
                        if err:
                            print(f"{C.RED}{err}{C.RESET}")
                            continue
                        b64_data, media_type = result
                        if not hasattr(session, '_pending_images'):
                            session._pending_images = []
                        session._pending_images.append((b64_data, media_type))
                        fname = os.path.basename(img_path)
                        print(f"  {C.GREEN}📎 Image attached: {fname}{C.RESET}")
                        print(f"  {C.DIM}Type your message and press Enter to send with image.{C.RESET}")
                    else:
                        # /image — paste from clipboard
                        print(f"  {C.DIM}Checking clipboard for image...{C.RESET}")
                        tmp_path = _clipboard_image_to_file()
                        if tmp_path:
                            result, err = _read_image_as_base64(tmp_path)
                            if err:
                                print(f"{C.RED}{err}{C.RESET}")
                                try:
                                    os.unlink(tmp_path)
                                except OSError:
                                    pass
                                continue
                            b64_data, media_type = result
                            if not hasattr(session, '_pending_images'):
                                session._pending_images = []
                            session._pending_images.append((b64_data, media_type))
                            print(f"  {C.GREEN}📎 Clipboard image attached{C.RESET}")
                            print(f"  {C.DIM}Type your message and press Enter to send with image.{C.RESET}")
                            try:
                                os.unlink(tmp_path)
                            except OSError:
                                pass
                        else:
                            print(f"{C.YELLOW}No image found in clipboard.{C.RESET}")
                            print(f"{C.DIM}{t('slash.image_usage', default='Usage: /image <path>  or  copy an image to clipboard first')}{C.RESET}")
                    continue

                elif cmd == "/init":
                    _init_cwd = os.getcwd()
                    _root_claude = os.path.join(_init_cwd, "CLAUDE.md")
                    _eve_dir = os.path.join(_init_cwd, ".eve-cli")
                    _eve_claude = os.path.join(_eve_dir, "CLAUDE.md")
                    # Determine target and existing content
                    _existing_path = None
                    _existing_content = ""
                    if os.path.exists(_root_claude):
                        _existing_path = _root_claude
                    elif os.path.exists(_eve_claude):
                        _existing_path = _eve_claude
                    if _existing_path:
                        try:
                            with open(_existing_path, encoding="utf-8", errors="replace") as f:
                                _existing_content = f.read()
                        except Exception:
                            pass
                    _new_content = _generate_project_claude_md(_init_cwd)
                    if _existing_content:
                        # Merge: keep existing content, append missing sections
                        _merged = _merge_claude_md(_existing_content, _new_content)
                        if _merged == _existing_content:
                            print(f"{C.GREEN}CLAUDE.md is up to date: {_existing_path}{C.RESET}")
                        else:
                            try:
                                with open(_existing_path, "w", encoding="utf-8") as f:
                                    f.write(_merged)
                                print(f"{C.GREEN}Updated {_existing_path}{C.RESET}")
                                print(f"{C.DIM}Existing content preserved. Missing sections added.{C.RESET}")
                            except Exception as e:
                                print(f"{C.RED}Failed to update CLAUDE.md: {e}{C.RESET}")
                    else:
                        try:
                            os.makedirs(_eve_dir, exist_ok=True)
                            with open(_eve_claude, "w", encoding="utf-8") as f:
                                f.write(_new_content)
                            print(f"{C.GREEN}Created {_eve_claude}{C.RESET}")
                            print(f"{C.DIM}Detected project info has been included.{C.RESET}")
                            print(f"{C.DIM}Edit this file to customize AI behavior for your project.{C.RESET}")
                        except Exception as e:
                            print(f"{C.RED}Failed to create CLAUDE.md: {e}{C.RESET}")
                    continue

                elif cmd == "/config":
                    _c51x = _ansi("\033[38;5;51m")
                    _c87x = _ansi("\033[38;5;87m")
                    _c240x = _ansi("\033[38;5;240m")
                    _c28x = _ansi("\033[38;5;28m")  # green for input prompt
                    
                    # Check if user wants to change model
                    parts = user_input.split(None, 1)
                    if len(parts) > 1 and parts[0] == "/config":
                        new_model = parts[1].strip()
                        if new_model:
                            # Validate model name (same validation as Config._validate_ollama_host)
                            _SAFE_MODEL_RE = re.compile(r'^[a-zA-Z0-9_.:\-/]+$')
                            if _SAFE_MODEL_RE.match(new_model):
                                _ok, fresh_models = client.check_connection()
                                if client.check_model(new_model, available_models=fresh_models if _ok else None):
                                    config.model = new_model
                                    if not config._cli_context_window_set:
                                        config.context_window = Config.DEFAULT_CONTEXT_WINDOW
                                    config._apply_context_window(new_model)
                                    if not config._cli_max_tokens_set:
                                        config.max_tokens = Config.DEFAULT_MAX_TOKENS
                                    config._apply_max_tokens(new_model)
                                    client.refresh_from_config(config)
                                    session.system_prompt = _build_runtime_system_prompt(config)
                                    # Update footer mode display
                                    if agent.tui.scroll_region._active:
                                        agent.tui.scroll_region.update_mode_display(f"Model: {new_model}")
                                    print(f"\n  {C.GREEN}Model changed to: {new_model}{C.RESET}")
                                    print(f"  {_c240x}To make this permanent, add MODEL={new_model} to {config.config_file}{C.RESET}\n")
                                else:
                                    print(f"\n  {C.YELLOW}Model '{new_model}' is not downloaded yet.{C.RESET}")
                                    if _ok and fresh_models:
                                        _show_model_list(fresh_models)
                                    print(f"  {_c240x}Download it first: ollama pull {new_model}{C.RESET}\n")
                            else:
                                print(f"\n  {C.RED}Invalid model name. Use only alphanumeric, dots, colons, hyphens, underscores, and slashes.{C.RESET}\n")
                            continue
                    
                    print(f"\n  {_c51x}━━ Configuration ━━━━━━━━━━━━━━━━━━{C.RESET}")
                    print(f"  {_c87x}Model{C.RESET}         {config.model}")
                    print(f"  {_c87x}Sidecar{C.RESET}       {config.sidecar_model or '(none)'}")
                    print(f"  {_c87x}Host{C.RESET}          {config.ollama_host}")
                    print(f"  {_c87x}Temperature{C.RESET}   {config.temperature}")
                    print(f"  {_c87x}Max tokens{C.RESET}    {config.max_tokens}")
                    print(f"  {_c87x}Context{C.RESET}       {config.context_window}")
                    print(f"  {_c87x}Prompt $/M{C.RESET}    {config.prompt_cost_per_mtok}")
                    print(f"  {_c87x}Output $/M{C.RESET}    {config.completion_cost_per_mtok}")
                    print(f"  {_c87x}Plan think{C.RESET}    {config.plan_mode_reasoning_effort or '(default)'}")
                    print(f"  {_c87x}Shell env{C.RESET}     {config.shell_env_policy}")
                    print(f"  {_c87x}Hook env{C.RESET}      {config.hook_env_policy}")
                    print(f"  {_c87x}Notify{C.RESET}        {config.notify_command or '(disabled)'}")
                    print(f"  {_c87x}Auto-approve{C.RESET}  {'ON' if config.yes_mode else 'OFF'}")
                    print(f"  {_c87x}Debug{C.RESET}         {'ON' if config.debug else 'OFF'}")
                    print(f"\n  {_c240x}Config: {config.config_file}{C.RESET}")
                    print(f"  {_c240x}Format: KEY=VALUE (MODEL=qwen3:8b){C.RESET}")
                    print(f"  {_c240x}Change model: /config <model_name>{C.RESET}")
                    print(f"  {_c51x}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    continue

                elif cmd == "/browser":
                    parts = user_input.split(None, 1)
                    sub = parts[1].strip().lower() if len(parts) > 1 else ""
                    if sub == "setup":
                        # Setup Playwright MCP
                        _c51b = _ansi("\033[38;5;51m")
                        _c240b = _ansi("\033[38;5;240m")
                        print(f"\n  {_c51b}━━ Browser Setup (Playwright MCP) ━━{C.RESET}")
                        # Check Node.js
                        _has_node = subprocess.run(
                            ["node", "--version"], capture_output=True, timeout=5
                        ).returncode == 0 if subprocess.run(["which", "node"], capture_output=True).returncode == 0 else False
                        if not _has_node:
                            print(f"  {C.RED}Node.js が見つかりません。{C.RESET}")
                            print(f"  {_c240b}インストール: brew install node  または  https://nodejs.org/{C.RESET}")
                            print(f"  {_c51b}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                            continue
                        # Check npx
                        _has_npx = subprocess.run(["which", "npx"], capture_output=True).returncode == 0
                        if not _has_npx:
                            print(f"  {C.RED}npx が見つかりません。Node.js を再インストールしてください。{C.RESET}")
                            continue
                        # Write MCP config
                        _mcp_dir = os.path.join(config.config_dir)
                        os.makedirs(_mcp_dir, exist_ok=True)
                        _mcp_path = os.path.join(_mcp_dir, "mcp.json")
                        _mcp_data = {
                            "mcpServers": {
                                "playwright": {
                                    "command": "npx",
                                    "args": ["@playwright/mcp@latest"]
                                }
                            }
                        }
                        # Merge with existing config if present
                        if os.path.isfile(_mcp_path) and not os.path.islink(_mcp_path):
                            try:
                                with open(_mcp_path, encoding="utf-8") as _mf:
                                    _existing = json.load(_mf)
                                if isinstance(_existing, dict) and "mcpServers" in _existing:
                                    _existing["mcpServers"]["playwright"] = _mcp_data["mcpServers"]["playwright"]
                                    _mcp_data = _existing
                            except Exception:
                                pass
                        try:
                            with open(_mcp_path, "w", encoding="utf-8") as _mf:
                                json.dump(_mcp_data, _mf, indent=2, ensure_ascii=False)
                            print(f"  {C.GREEN}MCP設定を書き込みました: {_mcp_path}{C.RESET}")
                        except Exception as e:
                            print(f"  {C.RED}設定の書き込みに失敗: {e}{C.RESET}")
                            continue
                        # Test Playwright MCP launch
                        print(f"  {_c240b}Playwright MCP の動作確認中...{C.RESET}")
                        try:
                            _test_proc = subprocess.run(
                                ["npx", "@playwright/mcp@latest", "--help"],
                                capture_output=True, timeout=30
                            )
                            if _test_proc.returncode == 0:
                                print(f"  {C.GREEN}Playwright MCP は利用可能です。{C.RESET}")
                            else:
                                print(f"  {C.YELLOW}Playwright MCP のインストール中にエラーが発生しました。{C.RESET}")
                                print(f"  {_c240b}手動実行: npx @playwright/mcp@latest --help{C.RESET}")
                        except Exception:
                            print(f"  {C.YELLOW}確認がタイムアウトしました（初回ダウンロード中の可能性あり）。{C.RESET}")
                        # Auto-install Playwright browsers (chromium)
                        print(f"  {_c240b}Chromium ブラウザをインストール中...{C.RESET}")
                        try:
                            _install_proc = subprocess.run(
                                ["npx", "playwright", "install", "chromium"],
                                capture_output=True, timeout=120
                            )
                            if _install_proc.returncode == 0:
                                print(f"  {C.GREEN}Chromium のインストールが完了しました。{C.RESET}")
                            else:
                                _stderr_out = _install_proc.stderr.decode("utf-8", errors="replace").strip()[:200]
                                print(f"  {C.YELLOW}Chromium のインストールに失敗しました。{C.RESET}")
                                if _stderr_out:
                                    print(f"  {_c240b}{_stderr_out}{C.RESET}")
                                print(f"  {_c240b}手動実行: npx playwright install chromium{C.RESET}")
                        except Exception:
                            print(f"  {C.YELLOW}Chromium インストールがタイムアウトしました。{C.RESET}")
                            print(f"  {_c240b}手動実行: npx playwright install chromium{C.RESET}")
                        # Hot-reload: start MCP server and register tools immediately
                        _hot_reload_count = 0
                        print(f"  {_c240b}MCP ツールをホットリロード中...{C.RESET}")
                        try:
                            _pw_mcp = MCPClient(
                                name="playwright",
                                command="npx",
                                args=["@playwright/mcp@latest"],
                            )
                            _pw_mcp.start()
                            _pw_mcp.initialize()
                            _pw_tools_list = _pw_mcp.list_tools()
                            for _tool_schema in _pw_tools_list:
                                _mcp_tool = MCPTool(_pw_mcp, _tool_schema)
                                registry.register(_mcp_tool)
                                permissions.ASK_TOOLS.add(_mcp_tool.name)
                                _hot_reload_count += 1
                            _mcp_clients.append(_pw_mcp)
                            print(f"  {C.GREEN}ホットリロード完了: {_hot_reload_count} ツールを登録しました。{C.RESET}")
                        except Exception as _hr_e:
                            print(f"  {C.YELLOW}ホットリロードに失敗しました: {_hr_e}{C.RESET}")
                            print(f"  {_c240b}eve-cli を再起動するとツールが利用可能になります。{C.RESET}")
                        print(f"\n  {C.GREEN}セットアップ完了!{C.RESET}")
                        if _hot_reload_count > 0:
                            print(f"  {_c240b}ブラウザ操作ツール ({_hot_reload_count} tools) が利用可能です。{C.RESET}")
                        else:
                            print(f"  {_c240b}eve-cli を再起動すると、ブラウザ操作ツールが使えるようになります。{C.RESET}")
                        print(f"  {_c240b}例: 「https://example.com を開いてスクリーンショットを撮って」{C.RESET}")
                        print(f"  {_c51b}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    elif sub == "status":
                        _c51b = _ansi("\033[38;5;51m")
                        _c240b = _ansi("\033[38;5;240m")
                        print(f"\n  {_c51b}━━ Browser Status ━━━━━━━━━━━━━━━━━{C.RESET}")
                        # Check if playwright MCP tools are registered
                        _pw_tools = [t for t in registry.list_tools() if "browser" in t.lower() or "playwright" in t.lower() or "navigate" in t.lower() or "screenshot" in t.lower() or "click" in t.lower()]
                        if _pw_tools:
                            print(f"  {C.GREEN}Playwright MCP: 接続済み ({len(_pw_tools)} tools){C.RESET}")
                            for _t in _pw_tools[:10]:
                                print(f"    {_c240b}- {_t}{C.RESET}")
                            if len(_pw_tools) > 10:
                                print(f"    {_c240b}  ... +{len(_pw_tools)-10} more{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}Playwright MCP: 未接続{C.RESET}")
                            print(f"  {_c240b}/browser setup でセットアップしてください{C.RESET}")
                        print(f"  {_c51b}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    else:
                        print(f"  {C.CYAN}/browser setup{C.RESET}   — Playwright MCP をセットアップ")
                        print(f"  {C.CYAN}/browser status{C.RESET}  — ブラウザツールの接続状態を確認")
                        print(f"  {C.DIM}")
                        print(f"  セットアップ後、eve-cli を再起動するとブラウザ操作が可能になります。")
                        print(f"  例: 「https://example.com を開いてページの内容を教えて」")
                        print(f"  例: 「Google で EvE CLI を検索して結果を教えて」{C.RESET}")
                    continue

                elif cmd == "/index":
                    parts = user_input.split(None, 2)
                    sub = parts[1].lower() if len(parts) > 1 else ""
                    _c51b = _ansi("\033[38;5;51m")
                    _c240b = _ansi("\033[38;5;240m")
                    _c198b = _ansi("\033[38;5;198m")
                    if sub == "build":
                        print(f"\n  {_c51b}Building symbol index...{C.RESET}")
                        _t0 = time.time()
                        _n_syms = _code_intel.build_index()
                        _elapsed_ms = int((time.time() - _t0) * 1000)
                        print(f"  {C.GREEN}Indexed {_code_intel.symbol_count} symbols "
                              f"({_n_syms} unique names) in {_elapsed_ms}ms{C.RESET}")
                        # Also build RAG index if available
                        if _rag_engine is not None:
                            try:
                                rag_path = config.rag_path or config.cwd
                                print(f"  {_c51b}Building RAG index for {rag_path}...{C.RESET}")
                                _rag_engine.index_directory(rag_path)
                                _rstats = _rag_engine.get_stats()
                                print(f"  {C.GREEN}RAG: {_rstats['files']} files, "
                                      f"{_rstats['chunks']} chunks{C.RESET}")
                            except Exception as _re:
                                print(f"  {C.YELLOW}RAG index error: {_re}{C.RESET}")
                    elif sub == "search":
                        _query = parts[2] if len(parts) > 2 else ""
                        if not _query:
                            print(f"  {C.YELLOW}{t('slash.index_search_usage', default='Usage: /index search <query>')}{C.RESET}")
                        else:
                            if _code_intel.symbol_count == 0:
                                print(f"  {_c240b}Index empty. Building...{C.RESET}")
                                _code_intel.build_index()
                            _results = _code_intel.search_symbols(_query)
                            if _results:
                                print(f"\n  {_c51b}━━ Symbol Search: '{_query}' ({len(_results)} results) ━━{C.RESET}")
                                for r in _results:
                                    _kind_c = C.CYAN if r["kind"] in ("class", "struct", "interface", "trait") else C.GREEN
                                    print(f"    {_kind_c}{r['kind']:10}{C.RESET} "
                                          f"{_c198b}{r['name']}{C.RESET}  "
                                          f"{_c240b}{r['file']}:{r['line']}{C.RESET}")
                                print()
                            else:
                                print(f"  {C.YELLOW}No symbols matching '{_query}'{C.RESET}")
                    elif sub == "def":
                        _sym = parts[2] if len(parts) > 2 else ""
                        if not _sym:
                            print(f"  {C.YELLOW}{t('slash.index_def_usage', default='Usage: /index def <symbol>')}{C.RESET}")
                        else:
                            if _code_intel.symbol_count == 0:
                                print(f"  {_c240b}Index empty. Building...{C.RESET}")
                                _code_intel.build_index()
                            _defs = _code_intel.find_definition(_sym)
                            if _defs:
                                print(f"\n  {_c51b}━━ Definitions of '{_sym}' ({len(_defs)} found) ━━{C.RESET}")
                                for d in _defs:
                                    _kind_c = C.CYAN if d["kind"] in ("class", "struct", "interface", "trait") else C.GREEN
                                    print(f"    {_kind_c}{d['kind']:10}{C.RESET} "
                                          f"{_c240b}{d['file']}:{d['line']}{C.RESET}")
                                print()
                            else:
                                print(f"  {C.YELLOW}No definitions found for '{_sym}'{C.RESET}")
                    elif sub == "refs":
                        _sym = parts[2] if len(parts) > 2 else ""
                        if not _sym:
                            print(f"  {C.YELLOW}{t('slash.index_refs_usage', default='Usage: /index refs <symbol>')}{C.RESET}")
                        else:
                            print(f"  {_c240b}Searching references...{C.RESET}")
                            _refs = _code_intel.find_references(_sym)
                            if _refs:
                                print(f"\n  {_c51b}━━ References to '{_sym}' ({len(_refs)} found) ━━{C.RESET}")
                                for r in _refs:
                                    print(f"    {_c240b}{r['file']}:{r['line']}{C.RESET}  {r['text']}")
                                print()
                            else:
                                print(f"  {C.YELLOW}No references found for '{_sym}'{C.RESET}")
                    elif sub == "status":
                        print(f"\n  {_c51b}━━ Index Status ━━━━━━━━━━━━━━━━━━━{C.RESET}")
                        print(f"  Symbols: {_code_intel.symbol_count} "
                              f"({len(_code_intel._index)} unique names)")
                        print(f"  CWD: {_code_intel.cwd}")
                        if _rag_engine is not None:
                            _rstats = _rag_engine.get_stats()
                            print(f"  RAG: {_rstats['files']} files, "
                                  f"{_rstats['chunks']} chunks "
                                  f"({_rstats['db_size'] // 1024} KB)")
                        print(f"  {_c51b}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                    else:
                        print(f"  {C.CYAN}/index build{C.RESET}            Build symbol index")
                        print(f"  {C.CYAN}/index search{C.RESET} <query>  Search symbols by name")
                        print(f"  {C.CYAN}/index def{C.RESET} <symbol>    Find definitions (go-to-definition)")
                        print(f"  {C.CYAN}/index refs{C.RESET} <symbol>   Find references")
                        print(f"  {C.CYAN}/index status{C.RESET}          Show index statistics")
                    continue

                elif cmd == "/debug":
                    _parts = user_input.split(None, 1)
                    _debug_sub = _parts[1].strip().lower() if len(_parts) > 1 else ""
                    if _debug_sub == "setup":
                        print()
                        for _line in _build_doctor_lines(config, client, registry, permissions, session, agent, hook_mgr, channel_manager, _mcp_clients):
                            print(f"  {_line}")
                        print()
                    elif _debug_sub == "route":
                        print()
                        for _line in _build_command_graph_lines(config, agent, registry):
                            print(f"  {_line}")
                        print()
                    else:
                        config.debug = not config.debug
                        state_str = f"{C.GREEN}ON{C.RESET}" if config.debug else f"{C.RED}OFF{C.RESET}"
                        print(f"  Debug mode: {state_str}")
                    continue

                elif cmd == "/debug-scroll":
                    _debug_scroll_region(tui)
                    continue

                elif cmd == "/memory":
                    memory = Memory(config.config_dir)
                    _mem_parts = user_input.split(None, 1)
                    args = _mem_parts[1].strip() if len(_mem_parts) > 1 else ""
                    if not args:
                        entries = memory.list_all()
                        if not entries:
                            print(f"{C.DIM}No memories stored. Use /memory add <text> to add.{C.RESET}")
                        else:
                            print(f"\n  {_ansi(chr(27)+'[38;5;51m')}━━ Memory ({len(entries)} entries) ━━{C.RESET}")
                            for i, e in enumerate(entries):
                                cat = e.get("category", "general")
                                print(f"  {_ansi(chr(27)+'[38;5;240m')}[{i}]{C.RESET} {_ansi(chr(27)+'[38;5;87m')}({cat}){C.RESET} {e.get('content', '')}")
                            print()
                    elif args.startswith("add "):
                        text = args[4:].strip()
                        if text:
                            cat_match = re.match(r'\[(\w+)\]\s*(.*)', text)
                            if cat_match:
                                memory.add(cat_match.group(2), cat_match.group(1))
                            else:
                                memory.add(text)
                            print(f"{C.GREEN}Memory added.{C.RESET}")
                        else:
                            print(f"{C.YELLOW}{t('slash.memory_add_usage', default='Usage: /memory add <text>')}{C.RESET}")
                    elif args.startswith("remove ") or args.startswith("rm "):
                        idx_str = args.split(None, 1)[1] if len(args.split()) > 1 else ""
                        try:
                            idx = int(idx_str)
                            if memory.remove(idx):
                                print(f"{C.GREEN}Memory #{idx} removed.{C.RESET}")
                            else:
                                print(f"{C.RED}Invalid index.{C.RESET}")
                        except ValueError:
                            print(f"{C.YELLOW}{t('slash.memory_remove_usage', default='Usage: /memory remove <index>')}{C.RESET}")
                    elif args.startswith("search "):
                        query = args[7:].strip()
                        results = memory.search(query)
                        if results:
                            for e in results:
                                print(f"  {_ansi(chr(27)+'[38;5;87m')}({e.get('category', 'general')}){C.RESET} {e.get('content', '')}")
                        else:
                            print(f"{C.DIM}No matching memories.{C.RESET}")
                    elif args == "clear":
                        memory._entries.clear()
                        memory._save()
                        print(f"{C.GREEN}All memories cleared.{C.RESET}")
                    continue

                # ── Custom Commands ───────────────────────────────────
                elif cmd in ("/custom", "/cmd"):
                    config.load_custom_commands(prompt_if_needed=True)
                    parts = user_input.split(None, 1)
                    if len(parts) < 2:
                        print(f"{C.YELLOW}{t('slash.custom_usage', default='Usage: /custom <name> [args]')}{C.RESET}")
                        print(f"{C.DIM}  Lists available custom commands if no name given.{C.RESET}")
                        continue
                    cmd_name = parts[1].split()[0].lower() if parts[1] else ""
                    cmd_args = parts[1][len(cmd_name):].strip() if cmd_name else ""
                    
                    # List available commands if no name given or if name is "list"
                    if not cmd_name or cmd_name == "list":
                        _c51c = _ansi("\033[38;5;51m")
                        _c87c = _ansi("\033[38;5;87m")
                        with _custom_commands_lock:
                            if _custom_commands:
                                print(f"\n  {_c51c}━━ Custom Commands ━━━━━━━━━━━━━━━━━━{C.RESET}")
                                for cname in sorted(_custom_commands.keys()):
                                    cinfo = _custom_commands[cname]
                                    desc = cinfo.get("description", "")
                                    _arg_hint = (cinfo.get("frontmatter") or {}).get("argument-hint", "")
                                    _hint_str = f" {_arg_hint}" if _arg_hint else ""
                                    desc_str = f" {C.DIM}- {desc}{C.RESET}" if desc else ""
                                    print(f"  {_c87c}/{cname}{_hint_str}{C.RESET}{desc_str}")
                                print(f"  {_c51c}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━{C.RESET}\n")
                            else:
                                print(f"{C.YELLOW}No custom commands found.{C.RESET}")
                                print(f"{C.DIM}Create .md files in .eve-cli/commands/ or ~/.eve-cli/commands/{C.RESET}")
                                print(f"{C.DIM}Example: .eve-cli/commands/review.md{C.RESET}")
                                print(f"""{C.DIM}---
description: Code review checklist
---
Review this code for:
1. Security issues
2. Performance problems
3. Code style{C.RESET}""")
                        continue
                    
                    # Execute the custom command
                    with _custom_commands_lock:
                        if cmd_name not in _custom_commands:
                            print(f"{C.RED}Unknown custom command: {cmd_name}{C.RESET}")
                            print(f"{C.DIM}Use /custom list to see available commands.{C.RESET}")
                            continue
                        cmd_info = _custom_commands[cmd_name]
                    
                    # Build the prompt from command body with argument substitution
                    cmd_body = cmd_info.get("body", "")
                    # Substitute $ARGUMENTS, $0, $1, etc.
                    cmd_body = cmd_body.replace("$ARGUMENTS", cmd_args)
                    cmd_body = cmd_body.replace("$0", cmd_name)
                    # Simple $1, $2 substitution
                    _arg_list = cmd_args.split()
                    for i, arg_val in enumerate(_arg_list, start=1):
                        cmd_body = cmd_body.replace(f"${i}", arg_val)

                    # Allow shell expansion only for user-owned global command files.
                    cmd_body, shell_expand_error = _expand_shell_injections(
                        cmd_body,
                        cwd=config.cwd,
                        allow_commands=_path_within_root(cmd_info.get("path"), config.config_dir),
                        source_name=f"custom command '{cmd_name}'",
                    )
                    if shell_expand_error:
                        print(f"{C.RED}{shell_expand_error}{C.RESET}")
                        continue

                    # Get allowed tools from frontmatter if specified
                    _allowed_tools = None
                    _frontmatter = cmd_info.get("frontmatter", {})
                    if "allowed-tools" in _frontmatter:
                        _allowed_tools, invalid_tools = _resolve_allowed_tool_names(
                            registry, _frontmatter["allowed-tools"]
                        )
                        if invalid_tools:
                            print(f"{C.YELLOW}Ignoring unknown tools in {cmd_name}: "
                                  f"{', '.join(invalid_tools)}{C.RESET}")
                        if not _allowed_tools:
                            print(f"{C.RED}Custom command '{cmd_name}' did not resolve any allowed tools.{C.RESET}")
                            continue
                    
                    # Inject the custom command prompt
                    user_input = cmd_body
                    print(f"{C.DIM}Running custom command: {cmd_name}{C.RESET}")
                    if cmd_args:
                        print(f"{C.DIM}Arguments: {cmd_args}{C.RESET}")
                    # Fall through to normal agent processing with the injected prompt
                    # But restrict tools if allowed-tools was specified
                    if _allowed_tools is not None:
                        # Temporarily override available tools
                        _orig_tools = agent.allowed_tool_names
                        agent.allowed_tool_names = set(_allowed_tools)
                        # Will restore after agent.run
                        # Store in session for restoration
                        session._custom_command_tools_override = _orig_tools

                # ── Channel commands ──────────────────────────────────
                elif cmd == "/channels":
                    _parts = user_input.split(None, 1)
                    _sub = _parts[1].strip().lower() if len(_parts) > 1 else ""
                    _c51 = _ansi(chr(27) + '[38;5;51m')
                    _c87 = _ansi(chr(27) + '[38;5;87m')
                    _c240 = _ansi(chr(27) + '[38;5;240m')
                    if _sub == "stop":
                        if channel_manager:
                            channel_manager.stop()
                            channel_manager = None
                            print(f"  {C.GREEN}Channels stopped.{C.RESET}")
                        else:
                            print(f"  {C.DIM}Channels are not running.{C.RESET}")
                    elif _sub.startswith("allow "):
                        # /channels allow <channel_name> <sender_id>
                        _allow_parts = _sub.split(None, 2)
                        if len(_allow_parts) == 3:
                            _ch_n, _sid = _allow_parts[1], _allow_parts[2]
                            if channel_manager:
                                channel_manager.add_sender(_ch_n, _sid)
                                print(f"  {C.GREEN}Added '{_sid}' to {_ch_n} allowlist.{C.RESET}")
                            else:
                                print(f"  {C.YELLOW}Channels not running. Start with --channels.{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}Usage: /channels allow <channel_name> <sender_id>{C.RESET}")
                    elif _sub.startswith("deny "):
                        _deny_parts = _sub.split(None, 2)
                        if len(_deny_parts) == 3:
                            _ch_n, _sid = _deny_parts[1], _deny_parts[2]
                            if channel_manager:
                                channel_manager.remove_sender(_ch_n, _sid)
                                print(f"  {C.GREEN}Removed '{_sid}' from {_ch_n} allowlist.{C.RESET}")
                            else:
                                print(f"  {C.YELLOW}Channels not running.{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}Usage: /channels deny <channel_name> <sender_id>{C.RESET}")
                    else:
                        # Default: show status
                        if channel_manager:
                            st = channel_manager.status()
                            port = st.pop("port", config.channels_port)
                            print(f"\n  {_c51}⚡ Channels Status{C.RESET}")
                            print(f"  {_c240}HTTP server: http://127.0.0.1:{port}{C.RESET}")
                            for _ch_n, _info in st.items():
                                _policy = _info["policy"]
                                _senders = _info["senders"]
                                _s_str = (f"{len(_senders)} senders"
                                          if _senders else "no senders (all blocked)")
                                print(f"  {_c87}{_ch_n}{C.RESET}  policy={_policy}  {_s_str}")
                                for _s in _senders[:5]:
                                    print(f"    {_c240}- {_s}{C.RESET}")
                                if len(_senders) > 5:
                                    print(f"    {_c240}  ... +{len(_senders)-5} more{C.RESET}")
                            print(f"\n  {_c240}/channels allow <name> <sender_id>  — add to allowlist")
                            print(f"  /channels deny  <name> <sender_id>  — remove from allowlist")
                            print(f"  /channels stop                       — stop all channels{C.RESET}\n")
                        else:
                            print(f"  {C.DIM}Channels not running. Start with: eve-cli --channels webhook{C.RESET}")
                            print(f"  {_c240}Available channels: webhook, discord (Phase 2), slack (Phase 3){C.RESET}")
                    continue

                elif cmd == "/webhook:configure":
                    _parts = user_input.split(None, 1)
                    _api_key = _parts[1].strip() if len(_parts) > 1 else ""
                    _save_channel_env(config, "webhook", "WEBHOOK_API_KEY", _api_key)
                    if _api_key:
                        print(f"  {C.GREEN}Webhook API key saved to .eve-cli/channels/webhook/.env{C.RESET}")
                        print(f"  {C.DIM}Restart with --channels webhook to apply.{C.RESET}")
                    else:
                        print(f"  {C.GREEN}Webhook API key cleared (no auth required).{C.RESET}")
                    continue

                elif cmd == "/discord:configure":
                    # /discord:configure <bot_token> [channel_id1,channel_id2,...]
                    _parts = user_input.split(None, 2)
                    if len(_parts) < 2:
                        print(f"  {C.YELLOW}Usage: /discord:configure <bot_token> [channel_ids]{C.RESET}")
                        print(f"  {C.DIM}channel_ids: comma-separated Discord channel IDs to monitor{C.RESET}")
                        continue
                    _tok = _parts[1].strip()
                    _cids = _parts[2].strip() if len(_parts) > 2 else ""
                    _save_channel_env(config, "discord", "DISCORD_BOT_TOKEN", _tok)
                    if _cids:
                        _save_channel_env(config, "discord", "DISCORD_CHANNEL_IDS", _cids)
                    print(f"  {C.GREEN}Discord bot token saved.{C.RESET}")
                    if _cids:
                        print(f"  {C.GREEN}Channel IDs: {_cids}{C.RESET}")
                    # Auto-start Discord adapter in the current session
                    # (Discord uses REST polling so no HTTP server restart needed)
                    if "discord" in config.channels:
                        _d_env2 = _load_channel_env(config, "discord")
                        _d_tok2 = _d_env2.get("DISCORD_BOT_TOKEN", "")
                        _d_cids2 = [c.strip() for c in _d_env2.get("DISCORD_CHANNEL_IDS", "").split(",") if c.strip()]
                        if _d_tok2 and _d_cids2:
                            if channel_manager is None:
                                channel_manager = _build_channel_manager(config)
                                if channel_manager:
                                    channel_manager.start()
                                    atexit.register(channel_manager.stop)
                                    print(f"  {C.GREEN}⚡ Discord adapter started.{C.RESET}")
                                    print(f"  {C.DIM}Send a message from Discord to receive a pairing code.{C.RESET}")
                            elif "discord" not in channel_manager._adapters:
                                _d_adapter2 = DiscordAdapter(token=_d_tok2, channel_ids=_d_cids2)
                                _d_adapter2._queue = channel_manager._queue
                                channel_manager._adapters["discord"] = _d_adapter2
                                channel_manager._allowlists.setdefault("discord", set())
                                channel_manager._policy.setdefault("discord", "allowlist")
                                channel_manager._sync_adapter_allowlists()
                                _d_adapter2.start()
                                print(f"  {C.GREEN}⚡ Discord adapter started.{C.RESET}")
                                print(f"  {C.DIM}Send a message from Discord to receive a pairing code.{C.RESET}")
                            else:
                                print(f"  {C.DIM}Discord adapter is already running.{C.RESET}")
                        else:
                            if not _d_cids2:
                                print(f"  {C.DIM}Also specify channel IDs: /discord:configure <token> <channel_ids>{C.RESET}")
                    else:
                        print(f"  {C.DIM}Run: eve-cli --channels discord to activate.{C.RESET}")
                    continue

                elif cmd == "/discord:pair":
                    _parts = user_input.split(None, 1)
                    _code = _parts[1].strip() if len(_parts) > 1 else ""
                    if not _code:
                        print(f"  {C.YELLOW}Usage: /discord:pair <6-digit-code>{C.RESET}")
                        continue
                    if channel_manager:
                        _sid = channel_manager.confirm_pair("discord", _code)
                        if _sid:
                            print(f"  {C.GREEN}Discord pairing confirmed! Sender '{_sid}' added to allowlist.{C.RESET}")
                        else:
                            print(f"  {C.RED}Invalid or expired pairing code: {_code}{C.RESET}")
                            print(f"  {C.DIM}DM your bot again to receive a new code.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Channels not running. Start with --channels discord.{C.RESET}")
                    continue

                elif cmd == "/discord:status":
                    # Diagnose Discord connection: verify token + channel access
                    _d_adapter_s = (channel_manager._adapters.get("discord")
                                    if channel_manager else None)
                    if not _d_adapter_s:
                        print(f"  {C.YELLOW}Discord adapter not running.{C.RESET}")
                        print(f"  {C.DIM}Run: eve-cli --channels discord  then  /discord:configure{C.RESET}")
                        continue
                    # Test token
                    _ok_me, _me = _d_adapter_s._api("GET", "/users/@me")
                    if _ok_me:
                        print(f"  {C.GREEN}Bot token: OK  (user: {_me.get('username')}#{_me.get('discriminator','0')}  id: {_me.get('id')}){C.RESET}")
                    else:
                        print(f"  {C.RED}Bot token: INVALID  {_me.get('message', _me)}{C.RESET}")
                        print(f"  {C.DIM}Re-run: /discord:configure <correct_token> <channel_ids>{C.RESET}")
                        continue
                    # Test each channel
                    for _ch_id_s in _d_adapter_s._channel_ids:
                        _ok_ch, _ch = _d_adapter_s._api("GET", f"/channels/{_ch_id_s}")
                        if _ok_ch:
                            _ch_name = _ch.get("name") or f"DM/{_ch_id_s}"
                            _watermark = _d_adapter_s._last_ids.get(_ch_id_s, "未初期化")
                            print(f"  {C.GREEN}Channel {_ch_id_s} ({_ch_name}): OK  watermark={_watermark}{C.RESET}")
                        else:
                            _err_msg = _ch.get('message', str(_ch))
                            print(f"  {C.RED}Channel {_ch_id_s}: ERROR  {_err_msg}{C.RESET}")
                            if "Missing Access" in str(_err_msg) or "403" in str(_err_msg):
                                print(f"  {C.DIM}→ ボットがこのチャンネルへのアクセス権を持っていません。{C.RESET}")
                                print(f"  {C.DIM}  サーバーでボットに「チャンネルを見る」「メッセージを読む」権限を付与してください。{C.RESET}")
                            elif "Unknown Channel" in str(_err_msg):
                                print(f"  {C.DIM}→ チャンネル ID が間違っています。{C.RESET}")
                    # MESSAGE_CONTENT intent check
                    print(f"\n  {_ansi(chr(27)+'[38;5;87m')}MESSAGE_CONTENT Intent:{C.RESET}")
                    print(f"  {C.DIM}メンションなしのメッセージに応答するには、Discord Developer Portal で{C.RESET}")
                    print(f"  {C.DIM}Bot → Privileged Gateway Intents → MESSAGE CONTENT INTENT を有効にしてください。{C.RESET}")
                    print(f"  {C.DIM}https://discord.com/developers/applications{C.RESET}")
                    continue

                elif cmd == "/discord:access":
                    _parts = user_input.split(None, 2)
                    _sub = _parts[1].strip().lower() if len(_parts) > 1 else ""
                    _val = _parts[2].strip().lower() if len(_parts) > 2 else ""
                    if _sub == "policy" and _val in ("allowlist", "open"):
                        if channel_manager:
                            channel_manager.set_policy("discord", _val)
                            print(f"  {C.GREEN}Discord access policy: {_val}{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}Channels not running.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Usage: /discord:access policy <allowlist|open>{C.RESET}")
                    continue

                elif cmd == "/slack:configure":
                    # /slack:configure <bot_token> <signing_secret>
                    _parts = user_input.split(None, 2)
                    if len(_parts) < 3:
                        print(f"  {C.YELLOW}Usage: /slack:configure <bot_token> <signing_secret>{C.RESET}")
                        print(f"  {C.DIM}bot_token: xoxb-xxx from Slack app settings{C.RESET}")
                        print(f"  {C.DIM}signing_secret: from Slack app Basic Information page{C.RESET}")
                        continue
                    _tok = _parts[1].strip()
                    _sec = _parts[2].strip()
                    _save_channel_env(config, "slack", "SLACK_BOT_TOKEN", _tok)
                    _save_channel_env(config, "slack", "SLACK_SIGNING_SECRET", _sec)
                    print(f"  {C.GREEN}Slack credentials saved to .eve-cli/channels/slack/.env{C.RESET}")
                    print(f"  {C.DIM}Set Events API Request URL to: http://your-host:{config.channels_port}/webhook/slack{C.RESET}")
                    print(f"  {C.DIM}Restart with --channels slack to activate.{C.RESET}")
                    continue

                elif cmd == "/slack:allow":
                    _parts = user_input.split(None, 1)
                    _sid = _parts[1].strip() if len(_parts) > 1 else ""
                    if not _sid:
                        print(f"  {C.YELLOW}Usage: /slack:allow <slack_user_id>{C.RESET}")
                        print(f"  {C.DIM}Slack user IDs look like: U01AB2CD3EF{C.RESET}")
                        continue
                    if channel_manager:
                        channel_manager.add_sender("slack", _sid)
                        print(f"  {C.GREEN}'{_sid}' added to Slack allowlist.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Channels not running. Start with --channels slack.{C.RESET}")
                    continue

                elif cmd == "/slack:access":
                    _parts = user_input.split(None, 2)
                    _sub = _parts[1].strip().lower() if len(_parts) > 1 else ""
                    _val = _parts[2].strip().lower() if len(_parts) > 2 else ""
                    if _sub == "policy" and _val in ("allowlist", "open"):
                        if channel_manager:
                            channel_manager.set_policy("slack", _val)
                            print(f"  {C.GREEN}Slack access policy: {_val}{C.RESET}")
                        else:
                            print(f"  {C.YELLOW}Channels not running.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Usage: /slack:access policy <allowlist|open>{C.RESET}")
                    continue

                elif cmd == "/webhook:allow":
                    _parts = user_input.split(None, 1)
                    _sid = _parts[1].strip() if len(_parts) > 1 else ""
                    if not _sid:
                        print(f"  {C.YELLOW}Usage: /webhook:allow <sender_id>{C.RESET}")
                        continue
                    if channel_manager:
                        channel_manager.add_sender("webhook", _sid)
                        print(f"  {C.GREEN}Added '{_sid}' to webhook allowlist.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Channels not running. Start with --channels webhook.{C.RESET}")
                    continue

                elif cmd == "/webhook:open":
                    if channel_manager and "webhook" in channel_manager._adapters:
                        channel_manager.set_policy("webhook", "open")
                        print(f"  {C.YELLOW}Webhook policy set to OPEN — all senders accepted.{C.RESET}")
                        print(f"  {C.DIM}Use /webhook:allowlist to restrict access.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Channels not running. Start with --channels webhook.{C.RESET}")
                    continue

                elif cmd == "/webhook:allowlist":
                    if channel_manager and "webhook" in channel_manager._adapters:
                        channel_manager.set_policy("webhook", "allowlist")
                        print(f"  {C.GREEN}Webhook policy set to allowlist.{C.RESET}")
                    else:
                        print(f"  {C.YELLOW}Channels not running. Start with --channels webhook.{C.RESET}")
                    continue

                elif cmd == "/team":
                    parts = user_input.split(None, 1)
                    team_args = parts[1].strip() if len(parts) > 1 else ""

                    if not team_args:
                        max_agents = _get_team_max_agents()
                        print(f"  {C.CYAN}{t('slash.team_usage', default='Usage: /team <goal>')}{C.RESET}")
                        print(f"  {C.DIM}Decomposes a goal into tasks and runs multiple agents in parallel.{C.RESET}")
                        print(f"  {C.DIM}Options: /team -n <N> <goal>  (set number of agents, default 2, max {max_agents}){C.RESET}")
                        print(f"  {C.DIM}         /team -w <goal>     (allow write operations){C.RESET}")
                        print(f"  {C.DIM}Note: Max agents is dynamically calculated based on system specs.{C.RESET}")
                        print(f"  {C.DIM}      Override with SUBAGENT_MAX_PARALLEL or TEAM_MAX_AGENTS env vars.{C.RESET}")
                        continue

                    # Parse options
                    _team_n = 2
                    _team_writes = False
                    _goal_parts = team_args.split()
                    _goal_start = 0
                    i = 0
                    while i < len(_goal_parts):
                        if _goal_parts[i] == "-n" and i + 1 < len(_goal_parts):
                            try:
                                _team_n = int(_goal_parts[i + 1])
                            except ValueError:
                                pass
                            i += 2
                            _goal_start = i
                        elif _goal_parts[i] == "-w":
                            _team_writes = True
                            i += 1
                            _goal_start = i
                        else:
                            break

                    _goal = " ".join(_goal_parts[_goal_start:])
                    if not _goal:
                        print(f"{C.YELLOW}Please provide a goal for the team.{C.RESET}")
                        continue

                    team = AgentTeam(config, client, registry, permissions)
                    team_result = team.run(_goal, num_teammates=_team_n, allow_writes=_team_writes)

                    session.add_user_message(f"/team {team_args}")
                    session.add_assistant_message(team_result)

                    # Display result
                    _scroll_aware_print(f"\n{C.BBLUE}assistant{C.RESET}: ", end="")
                    tui._render_markdown(team_result)
                    _scroll_aware_print()
                    continue

                else:
                    # Check if it's a skill invocation: /skill-name args
                    _skill_name = _first_word[1:]  # remove leading /
                    _loaded_skills = _load_skills(config)
                    if _skill_name in _loaded_skills:
                        _skill_args = user_input[len(_first_word):].strip()
                        _skill_info = _loaded_skills[_skill_name]
                        _skill_content = _expand_skill_variables(
                            _skill_info["content"], _skill_args,
                            skill_dir=_skill_info["skill_dir"],
                            cwd=config.cwd)
                        # Allow shell expansion only for user-owned global/extension skill files.
                        _skill_content, shell_expand_error = _expand_shell_injections(
                            _skill_content,
                            cwd=config.cwd,
                            allow_commands=_path_within_root(_skill_info.get("path"), config.config_dir),
                            source_name=f"skill '{_skill_name}'",
                        )
                        if shell_expand_error:
                            print(f"{C.RED}{shell_expand_error}{C.RESET}")
                            continue
                        # Inject as user message and fall through to normal agent processing
                        user_input = _skill_content
                    else:
                        # "Did you mean?" for typo'd slash commands
                        _all_cmds = ["/help", "/exit", "/quit", "/clear", "/model", "/models",
                                     "/status", "/doctor", "/tool-pool", "/command-graph", "/bootstrap-graph",
                                     "/save", "/compact", "/yes", "/no",
                                     "/tokens", "/usage", "/think", "/no-think", "/map",
                                     "/commit", "/diff", "/git", "/plan",
                                     "/approve", "/act", "/execute", "/undo", "/init",
                                     "/config", "/debug", "/debug-scroll", "/checkpoint",
                                     "/rollback", "/autotest", "/gentest", "/skills", "/hooks",
                                     "/image", "/browser", "/fork", "/index",
                                     "/pr", "/gh", "/team", "/memory",
                                     "/jobs", "/errors",
                                     "/channels", "/webhook:configure", "/webhook:allow",
                                     "/webhook:open", "/webhook:allowlist",
                                     "/discord:configure", "/discord:pair", "/discord:access", "/discord:status",
                                     "/slack:configure", "/slack:allow", "/slack:access"]
                        _close = [c for c in _all_cmds if c.startswith(cmd[:3])] if len(cmd) >= 3 else []
                        if not _close:
                            _close = [c for c in _all_cmds if cmd[1:] in c] if len(cmd) > 1 else []
                        if _close:
                            print(f"{C.YELLOW}Unknown command '{cmd}'. Did you mean: {', '.join(_close[:3])}?{C.RESET}")
                        else:
                            print(f"{C.YELLOW}Unknown command. Type /help for available commands.{C.RESET}")
                        continue

            # Expand @file references: @path/to/file → inject file contents
            if "@" in user_input:
                _at_pattern = re.compile(r'(?<!\w)@((?:[^\s@]|\\ )+)')
                _at_files_found = []
                def _at_replace(m):
                    fpath = m.group(1).replace("\\ ", " ")
                    expanded = os.path.expanduser(fpath)
                    if not os.path.isabs(expanded):
                        expanded = os.path.join(os.getcwd(), expanded)
                    if os.path.isfile(expanded):
                        try:
                            with open(expanded, "rb") as _bf:
                                sample = _bf.read(8192)
                            if b"\x00" in sample:
                                return m.group(0)  # skip binary files
                            with open(expanded, "r", encoding="utf-8", errors="replace") as _rf:
                                content = _rf.read(100_000)  # 100KB cap
                            _at_files_found.append(os.path.basename(expanded))
                            truncated = " (truncated)" if len(content) >= 100_000 else ""
                            return f"\n<file path=\"{expanded}\">\n{content}\n</file>{truncated}\n"
                        except Exception:
                            return m.group(0)
                    return m.group(0)  # not a file, keep as-is
                user_input = _at_pattern.sub(_at_replace, user_input)
                if _at_files_found:
                    _names = ", ".join(_at_files_found)
                    print(f"  {C.DIM}📎 Attached: {_names}{C.RESET}")

            # Detect dragged-and-dropped image paths in user input
            cleaned_input, dropped_images = _extract_image_paths(user_input)
            _images_for_msg = []
            for img_path in dropped_images:
                result, err = _read_image_as_base64(img_path)
                if err:
                    print(f"{C.YELLOW}Image skipped: {err}{C.RESET}")
                else:
                    _images_for_msg.append(result)
                    print(f"  {C.GREEN}📎 {os.path.basename(img_path)}{C.RESET}")

            # Add pending images from /image command
            if hasattr(session, '_pending_images') and session._pending_images:
                _images_for_msg.extend(session._pending_images)
                session._pending_images = []

            # Build multimodal message if images are present
            if _images_for_msg:
                text = cleaned_input if dropped_images else user_input
                if not text.strip():
                    text = "この画像について説明してください。"
                user_input = text
                # Check if model supports vision
                _model_name = config.model or ""
                if not hasattr(session, '_vision_warned'):
                    session._vision_warned = False
                if not session._vision_warned and _model_name:
                    _has_vision = client.check_vision_support(_model_name)
                    if not _has_vision:
                        print(f"  {C.YELLOW}⚠️  モデル '{_model_name}' はビジョン(画像認識)非対応の可能性があります。{C.RESET}")
                        print(f"  {C.DIM}ビジョン対応モデル例: llava, llama3.2-vision, gemma3, gemma4 等{C.RESET}")
                        session._vision_warned = True
                # Temporarily override add_user_message to send multimodal content
                content = _build_multimodal_content(text, _images_for_msg)
                n_imgs = len(_images_for_msg)
                print(f"  {C.DIM}Sending with {n_imgs} image{'s' if n_imgs > 1 else ''}...{C.RESET}")
                session.messages.append({"role": "user", "content": content})
                session._token_estimate += session._estimate_tokens(text) + n_imgs * 1000
                session._enforce_max_messages()
                # Run agent without adding user message again
                agent._run_without_add(user_input)
            else:
                # Run agent normally
                agent.run(user_input)
            # Restore tools if custom command had tool restrictions
            if hasattr(session, '_custom_command_tools_override'):
                agent.allowed_tool_names = session._custom_command_tools_override
                del session._custom_command_tools_override
            # Auto-save after each interaction (user's work is never lost)
            session.save()
            # Update scroll region status back to "Ready"
            if _scroll_mode and tui.scroll_region._active:
                pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
                tui.scroll_region.update_status(
                    _build_footer_status(config, pct, plan_mode=agent._plan_mode)
                )
                tui.scroll_region.update_hint("")

        except KeyboardInterrupt:
            now = time.time()
            if now - _last_ctrl_c[0] < 1.5:
                # Double Ctrl+C within 1.5s → exit
                if _scroll_mode and tui.scroll_region._active:
                    tui.scroll_region.teardown()
                    _active_scroll_region = None
                session.save()
                _elapsed = int(time.time() - _session_start_time)
                _mins, _secs = divmod(_elapsed, 60)
                _dur = f"{_mins}m {_secs}s" if _mins else f"{_secs}s"
                print(f"\n  {_ansi(chr(27)+'[38;5;51m')}✦ Session saved ({_dur}). Goodbye! ✦{C.RESET}")
                break
            _last_ctrl_c[0] = now
            tui._scroll_print(f"\n{C.DIM}(Ctrl+C again within 1.5s to exit, or type /exit){C.RESET}")
            # Restore "Ready" status after interrupt
            if _scroll_mode and tui.scroll_region._active:
                pct = min(int((session.get_token_estimate() / config.context_window) * 100), 100)
                tui.scroll_region.update_status(
                    _build_footer_status(config, pct, plan_mode=agent._plan_mode)
                )
                tui.scroll_region.update_hint("")
            continue
        except EOFError:
            break

    # Teardown scroll region before exit
    if _scroll_mode and tui.scroll_region._active:
        tui.scroll_region.teardown()
        _active_scroll_region = None
    # Save on exit
    session.save()
    # Evolution: record session end and optionally generate insights
    try:
        _evo = EvolutionEngine(config.config_dir)
        if hasattr(agent, '_evolution') and agent._evolution:
            _evo = agent._evolution
        _evo.record_session_end()
        if _evo.should_generate_insights() and client:
            _sidecar = config.sidecar_model or config.model
            if _sidecar:
                _evo.generate_insights(client, _sidecar)
    except Exception:
        pass
    # Save readline history on exit (moved from per-input to exit-only)
    if HAS_READLINE:
        try:
            readline.write_history_file(config.history_file)
        except Exception:
            pass
    # Cleanup file watcher
    try:
        agent.file_watcher.stop()
    except Exception:
        pass
    # Cleanup MCP server subprocesses
    for mcp in _mcp_clients:
        try:
            mcp.stop()
        except Exception:
            pass
    print(f"\n  {_ansi(chr(27)+'[38;5;51m')}✦ Goodbye! ✦{C.RESET}")
    sys.exit(0)  # Normal exit


if __name__ == "__main__":
    main()
